struct run {
  struct run *next;
}

struct {
  struct spinlock lock;
  struct run *freelist;
  uint64 npage;
}

void kinit() {
  initlock(&kmem.lock, "kmem");
  kmem.freelist = 0;
  kmem.npage = 0;
  freerange(kernel_end, (void *)PHYSTOP);
  printf("kernel_end: %p, phystop: %p\n", kernel_end, (void *)PHYSTOP);
  debug_print("kinit\n");
}

void freerange(void *pa_start, void *pa_end) {
  char *p;
  p = (char *)PGROUNDUP((uint64)pa_start);
  for (; p + PGSIZE <= (char *)pa_end; p += PGSIZE)
    kfree(p);
}

void kfree(void *pa) {
  struct run *r;

  if (((uint64)pa % PGSIZE) != 0 || (char *)pa < kernel_end ||
      (uint64)pa >= PHYSTOP)
    panic("kfree");

  // Fill with junk to catch dangling refs.
  memset(pa, 1, PGSIZE);

  r = (struct run *)pa;

  acquire(&kmem.lock);
  r->next = kmem.freelist;
  kmem.freelist = r;
  kmem.npage++;
  release(&kmem.lock);
}

void *kalloc(void) {
  struct run *r;

  acquire(&kmem.lock);
  r = kmem.freelist;
  if (r) {
    kmem.freelist = r->next;
    kmem.npage--;
  }
  release(&kmem.lock);

  if (r)
    memset((char *)r, 5, PGSIZE); // fill with junk
  else {
    printf("kalloc out of memory\n");
  }
  return (void *)r;
}

uint64 freemem_amount(void) {
  uint64 amount = 0;
  acquire(&kmem.lock);
  amount = kmem.npage;
  release(&kmem.lock);
  return amount << PGSHIFT;
}

