  f1->gp = f2->gp;
  f1->tp = f2->tp;
  f1->t0 = f2->t0;
  f1->t1 = f2->t1;
  f1->t2 = f2->t2;
  f1->s0 = f2->s0;
  f1->s1 = f2->s1;
  f1->a0 = f2->a0;
  f1->a1 = f2->a1;
  f1->a2 = f2->a2;
  f1->a3 = f2->a3;
  f1->a4 = f2->a4;
  f1->a5 = f2->a5;
  f1->a6 = f2->a6;
  f1->a7 = f2->a7;
  f1->s2 = f2->s2;
  f1->s3 = f2->s3;
  f1->s4 = f2->s4;
  f1->s5 = f2->s5;
  f1->s6 = f2->s6;
