  f1->t4 = f2->t4;
  f1->t5 = f2->t5;
  f1->t6 = f2->t6;
}

static struct proc *allocproc(void) {
  struct proc *p;

  for (p = proc; p < &proc[NPROC]; p++) {
    acquire(&p->lock);
    if (p->state == UNUSED) {
      goto found;
    } else {
      release(&p->lock);
    }
  }
  return NULL;

found:
  p->pid = allocpid();
  freemem_amount();
  // printf("alloc proc:%d freemem_mount:%p\n", p->pid, freemem_amount());
  p->vma = NULL;
  p->filelimit = NOFILE;
  p->ktime = 1;
  p->utime = 1;
  p->uid = 0;
  p->gid = 0;
  p->pgid = 0;
  p->thread_num = 0;
  p->char_count = 0;
  p->clear_child_tid = NULL;
  memset(p->sigaction, 0, sizeof(p->sigaction));
  memset(p->sig_set.__val, 0, sizeof(p->sig_set));
  memset(p->sig_pending.__val, 0, sizeof(p->sig_pending));
  // Allocate a trapframe page.
  if ((p->trapframe = (struct trapframe *)kalloc()) == NULL) {
    release(&p->lock);
    return NULL;
  }

  // An empty user page table.
  // And an identical kernel page table for this proc.
  if ((p->pagetable = proc_pagetable(p)) == NULL ||
      (p->kpagetable = proc_kpagetable(p)) == NULL) {
    freeproc(p);
    release(&p->lock);
    return NULL;
  }
  p->kstack = PROCVKSTACK(get_proc_addr_num(p));

  p->exec_close = kalloc();
  for (int fd = 0; fd < NOFILE; fd++)
    p->exec_close[fd] = 0;

  // Set up new context to start executing at forkret,
  // which returns to user space.
  memset(&p->context, 0, sizeof(p->context));
  p->context.ra = (uint64)forkret;
  p->context.sp = p->kstack + KSTACKSIZE;
  p->main_thread = allocNewThread();
  copycontext(&p->main_thread->context, &p->context);
  p->thread_num++;
  p->main_thread->p = p;
  p->main_thread->sz = p->sz;
  p->main_thread->clear_child_tid = p->clear_child_tid;
  p->main_thread->kstack = p->kstack;
  p->thread_queue = p->main_thread;
  if (mappages(p->kpagetable, p->kstack - PGSIZE, PGSIZE,
               (uint64)(p->main_thread->trapframe), PTE_R | PTE_W) < 0)
    panic("allocproc: map thread trapframe failed");
  p->main_thread->vtf = p->kstack - PGSIZE;
  return p;
}

static void freeproc(struct proc *p) {
  if (p->trapframe)
    kfree((void *)p->trapframe);

  kfree((void *)p->exec_close);
  p->trapframe = 0;

  thread *t = p->thread_queue;
  while (NULL != t) {
    thread *tmp = t->next_thread;
    if (NULL != t->next_thread)
      t->next_thread->pre_thread = NULL;
    t->state = t_UNUSED;
    t->next_thread = free_thread;
    if (NULL != free_thread)
      free_thread->pre_thread = t;
    free_thread = t;
    kfree((void *)t->trapframe);
    if (t->kstack != p->kstack) {
      vmunmap(p->kpagetable, t->kstack, 1, 0);
      kfree((void *)t->kstack_pa);
    }
    t = tmp;
  }

  if (p->kpagetable) {
    kvmfree(p->kpagetable, 1, p);
  }
  p->kpagetable = 0;
  if (p->pagetable) {
    free_vma_list(p);
    proc_freepagetable(p->pagetable, p->sz);
  }
  // TODO: free threads
  freemem_amount();
  // printf("free proc : %d freemem_mount:%p\n",p->pid, freemem_amount());
  p->pagetable = 0;
  p->vma = NULL;
  p->sz = 0;
  p->pid = 0;
  p->main_thread->state = t_UNUSED;
  p->main_thread = 0;
  p->parent = 0;
  p->name[0] = 0;
  p->chan = 0;
  p->killed = 0;
  p->xstate = 0;
  p->state = UNUSED;
}

pagetable_t proc_pagetable(struct proc *p) {
  pagetable_t pagetable;

  // An empty page table.
  pagetable = uvmcreate();
  if (pagetable == 0)
    return NULL;

  if (NULL == vma_init(p)) {
    uvmfree(pagetable, 0);
    return NULL;
  }
  // map the trampoline code (for system call return)
  // at the highest user virtual address.
  // only the supervisor uses it, on the way
  // to/from user space, so not PTE_U.
  if (mappages(pagetable, TRAMPOLINE, PGSIZE, (uint64)trampoline,
               PTE_R | PTE_X) < 0) {
    uvmfree(pagetable, 0);
    return NULL;
  }

  // map the trapframe just below TRAMPOLINE, for trampoline.S.
  if (mappages(pagetable, TRAPFRAME, PGSIZE, (uint64)(p->trapframe),
               PTE_R | PTE_W) < 0) {
    vmunmap(pagetable, TRAMPOLINE, 1, 0);
    uvmfree(pagetable, 0);
    return NULL;
  }
  if (mappages(pagetable, SIGTRAMPOLINE, PGSIZE, (uint64)signalTrampoline,
               PTE_R | PTE_X | PTE_U) < 0) {
    vmunmap(pagetable, TRAMPOLINE, 1, 0);
    vmunmap(pagetable, TRAPFRAME, 1, 0);
    uvmfree(pagetable, 0);
    return NULL;
  }

  return pagetable;
}

void proc_freepagetable(pagetable_t pagetable, uint64 sz) {
  vmunmap(pagetable, TRAMPOLINE, 1, 0);
  vmunmap(pagetable, TRAPFRAME, 1, 0);
  uvmfree(pagetable, sz);
}

void userinit(void) {
  struct proc *p;

  p = allocproc();
  initproc = p;

  // allocate one user page and copy init's instructions
  // and data into it.
  uvminit(p->pagetable, p->kpagetable, initcode, initcodesize);
  p->sz = initcodesize;
  p->sz = PGROUNDUP(p->sz);

  // uvmclear(p->pagetable, p->sz - stacksize);
  alloc_vma_stack(p);
  p->trapframe->sp = get_proc_sp(p); // user stack pointer

  // prepare for the very first "return" from kernel to user.
  p->trapframe->epc = 0x0; // user program counter

  safestrcpy(p->name, "initcode", sizeof(p->name));

  p->state = RUNNABLE;

  p->tmask = 0;

  copytrapframe(p->main_thread->trapframe, p->trapframe);
  p->main_thread->state = t_RUNNABLE;

  release(&p->lock);
#ifdef DEBUG
  printf("userinit\n");
#endif
}

int growproc(int n) {
  uint sz;
  struct proc *p = myproc();

  sz = p->sz;
  if (n > 0) {
    if ((sz = uvmalloc(p->pagetable, p->kpagetable, sz, sz + n,
                       PTE_R | PTE_W)) == 0) {
      return -1;
    }
  } else if (n < 0) {
    sz = uvmdealloc(p->pagetable, p->kpagetable, sz, sz + n);
  }
  p->sz = sz;
  return 0;
}

int fork(void) {
  int i, pid;
  struct proc *np;
  struct proc *p = myproc();

  // Allocate process.
  if ((np = allocproc()) == NULL) {
    return -1;
  }

  // Copy user memory from parent to child.
  if (uvmcopy(p->pagetable, np->pagetable, np->kpagetable, p->sz) < 0) {
    freeproc(np);
    release(&np->lock);
    return -1;
  }

  struct vma *nvma = vma_copy(np, p->vma);
  if (NULL != nvma) {
    nvma = nvma->next;
    while (nvma != np->vma) {
      if (vma_map(p->pagetable, np->pagetable, nvma) < 0) {
        printf("clone: vma deep mapping failed\n");
        return -1;
      }
      nvma = nvma->next;
    }
  }
  /*
  if (NULL == (nvma = vma_copy(p,np->vma))) {
    printf("clone failed\n");
    return -1;
  }
  np ->vma = nvma;
  nvma = nvma->next;
  while (nvma != p->vma) {
    if (vma_map(p->pagetable,np->pagetable,nvma) < 0) {
      printf("clone: vma deep mapping failed\n");
      return -1;
    }
    nvma = nvma->next;
  }
  */

  np->sz = p->sz;

  np->parent = p;

  // copy tracing mask from parent.
  np->tmask = p->tmask;

  // copy saved user registers.
  *(np->trapframe) = *(p->trapframe);

  // Cause fork to return 0 in the child.
  np->trapframe->a0 = 0;
  copytrapframe(np->main_thread->trapframe, np->trapframe);
  // increment reference counts on open file descriptors.
  for (i = 0; i < NOFILE; i++)
    if (p->ofile[i])
      np->ofile[i] = filedup(p->ofile[i]);
  np->cwd = edup(p->cwd);

  safestrcpy(np->name, p->name, sizeof(p->name));

  pid = np->pid;

  np->state = RUNNABLE;
  np->main_thread->state = t_RUNNABLE;

  release(&np->lock);

  return pid;
}

void reparent(struct proc *p) {
  struct proc *pp;

  for (pp = proc; pp < &proc[NPROC]; pp++) {
    // this code uses pp->parent without holding pp->lock.
    // acquiring the lock first could cause a deadlock
    // if pp or a child of pp were also in exit()
    // and about to try to lock p.
    if (pp->parent == p) {
      // pp->parent can't change between the check and the acquire()
      // because only the parent changes it, and we're the parent.
      acquire(&pp->lock);
      pp->parent = initproc;
      // we should wake up init here, but that would require
      // initproc->lock, which would be a deadlock, since we hold
      // the lock on one of init's children (pp). this is why
      // exit() always wakes init (before acquiring any locks).
      release(&pp->lock);
    }
  }
}

void exit(int status) {
  struct proc *p = myproc();
  // if(p->pid == 3){ printf("pid 3 exit status %d ra:%p\n", r_ra());}

  if (p == initproc)
    panic("init exiting");

  // Close all open files.
  for (int fd = 0; fd < NOFILE; fd++) {
    if (p->ofile[fd]) {
      struct file *f = p->ofile[fd];
      fileclose(f);
      p->ofile[fd] = 0;
    }
  }

  eput(p->cwd);
  p->cwd = 0;
  checkup1(p);
  // we might re-parent a child to init. we can't be precise about
  // waking up init, since we can't acquire its lock once we've
  // acquired any other proc lock. so wake up init whether that's
  // necessary or not. init may miss this wakeup, but that seems
  // harmless.
  acquire(&initproc->lock);
  wakeup1(initproc);
  release(&initproc->lock);

  // grab a copy of p->parent, to ensure that we unlock the same
  // parent we locked. in case our parent gives us away to init while
  // we're waiting for the parent lock. we may then race with an
  // exiting parent, but the result will be a harmless spurious wakeup
  // to a dead or wrong process; proc structs are never re-allocated
  // as anything else.
  acquire(&p->lock);
  struct proc *original_parent = p->parent;
  release(&p->lock);

  // we need the parent's lock in order to wake it up from wait().
  // the parent-then-child rule says we have to lock it first.
  acquire(&original_parent->lock);

  acquire(&p->lock);

  // Give any children to init.
  reparent(p);

  // Parent might be sleeping in wait().
  wakeup1(original_parent);
  // Parent might be sleeping in wait4pid().
  if (original_parent->chan == p && original_parent->state == SLEEPING) {
    original_parent->state = RUNNABLE;
  }

  p->xstate = status;
  p->state = ZOMBIE;
  p->main_thread->state = t_ZOMBIE;

  release(&original_parent->lock);

  // Jump into the scheduler, never to return.
  sched();
  panic("zombie exit");
}

int wait(uint64 addr) {
  struct proc *np;
  int havekids, pid;
  struct proc *p = myproc();

  // hold p->lock for the whole time to avoid lost
  // wakeups from a child's exit().
  acquire(&p->lock);

  for (;;) {
    // Scan through table looking for exited children.
    havekids = 0;
    for (np = proc; np < &proc[NPROC]; np++) {
      // this code uses np->parent without holding np->lock.
      // acquiring the lock first would cause a deadlock,
      // since np might be an ancestor, and we already hold p->lock.
      if (np->parent == p) {
        // np->parent can't change between the check and the acquire()
        // because only the parent changes it, and we're the parent.
        acquire(&np->lock);
        havekids = 1;
        if (np->state == ZOMBIE) {
          // Found one.
          pid = np->pid;
          if (addr != 0 && copyout(p->pagetable, addr, (char *)&np->xstate,
                                   sizeof(np->xstate)) < 0) {
            release(&np->lock);
            release(&p->lock);
            return -1;
          }
          freeproc(np);
          release(&np->lock);
          release(&p->lock);
          return pid;
        }
        release(&np->lock);
      }
    }

    // No point waiting if we don't have any children.
    if (!havekids || p->killed) {
      release(&p->lock);
      return -1;
    }

    // Wait for a child to exit.
    sleep(p, &p->lock); // DOC: wait-sleep
  }
}

void scheduler(void) {
  struct proc *p;
  struct cpu *c = mycpu();
  extern pagetable_t kernel_pagetable;

  c->proc = 0;
  for (;;) {
    // Avoid deadlock by ensuring that devices can interrupt.
    intr_on();

    int found = 0;
    for (p = proc; p < &proc[NPROC]; p++) {
      acquire(&p->lock);
      if (p->state == RUNNABLE) {
        // Switch to chosen process.  It is the process's job
        // to release its lock and then reacquire it
        // before jumping back to us.
        // printf("[scheduler]found runnable proc with pid: %d\n", p->pid);

        // TODO: 改进线程枚举算法
