void sem_init(struct semaphore *sem, uint8 value) {
  // debug_print("sem_init %p\n", sem);
  sem->value = value;
  sem->valid = 1;
  initlock(&sem->lock, "semaphore");
}

void sem_wait(struct semaphore *sem) {
  // debug_print("sem_wait %p\n", sem);
  acquire(&sem->lock);
  while (sem->value <= 0) {
    sleep(sem, &sem->lock);
  }
  sem->value--;
  release(&sem->lock);
}

uint32 sem_wait_with_milli_timeout(struct semaphore *sem,
                                   time_t milli_timeout) {
  // debug_print("sem_wait_with_milli_timeout %p\n", sem);
  time_t begin, end;
  begin = get_timeval().tv_usec;
  end = begin + milli_timeout * 1000;
  acquire(&sem->lock);
  while (sem->value <= 0) {
    end = get_timeval().tv_usec;
    if (milli_timeout * 1000 <= end - begin) {
      release(&sem->lock);
      return milli_timeout;
    }
    sleep(sem, &sem->lock);
  }
  sem->value--;
  release(&sem->lock);
  return end - begin;
}

void sem_post(struct semaphore *sem) {
  // debug_print("sem_post %p\n", sem);
  acquire(&sem->lock);
  sem->value++;
  wakeup(sem);
  release(&sem->lock);
}

void sem_destroy(struct semaphore *sem) {
  // debug_print("sem_destroy %p\n", sem);
  acquire(&sem->lock);
  sem->value = 0;
  sem->valid = 0;
  release(&sem->lock);
}

void sem_set_invalid(struct semaphore *sem) {
  // debug_print("sem_set_invalid %p\n", sem);
  acquire(&sem->lock);
  sem->valid = 0;
  release(&sem->lock);
}

int sem_is_valid(struct semaphore *sem) {
  // debug_print("sem_is_valid %p\n", sem);
  int valid;
  acquire(&sem->lock);
  valid = sem->valid;
  release(&sem->lock);
  return valid;
}

int set_sigaction(int signum, sigaction const *act, sigaction *oldact) {

  struct proc *p = myproc();
  if (p->sigaction[signum].__sigaction_handler.sa_handler != NULL &&
      oldact != NULL) {
    *oldact = p->sigaction[signum];
  }
  if (act != NULL) {
    p->sigaction[signum] = *act;
  }
  return 0;
}

int sigprocmask(int how, __sigset_t *set, __sigset_t *oldset) {
  struct proc *p = myproc();

  for (int i = 0; i < SIGSET_LEN; i++) {
    if (oldset != NULL) {
      oldset->__val[i] = p->sig_set.__val[i];
    }
    if (set == NULL)
      continue;
    switch (how) {
    case SIG_BLOCK:
      p->sig_set.__val[i] |= set->__val[i];
      break;
    case SIG_UNBLOCK:
      p->sig_set.__val[i] &= ~(set->__val[i]);
      break;
    case SIG_SETMASK:
      p->sig_set.__val[i] = set->__val[i];
      break;
    default:
      break;
      // panic("invalid how\n");
    }
  }
  // SIGTERM SIGKILL SIGSTOP cannot be masked
  p->sig_set.__val[0] &= 1ul << SIGTERM | 1ul << SIGKILL | 1ul << SIGSTOP;
  return 0;
}

uint64 rt_sigreturn(void) {
  struct proc *p = myproc();
  memcpy(p->trapframe, p->sig_tf, sizeof(struct trapframe));
  kfree(p->sig_tf);
  p->sig_tf = 0;
  return p->trapframe->a0;
}

void sighandle(void) {
  struct proc *p = myproc();
  int signum = p->killed;
  // debug_print("sighandle %p a0:%d a7:%d\n", p->sig_pending.__val[0],
  // p->trapframe->a0, p->trapframe->a7);
  if (p->sigaction[signum].__sigaction_handler.sa_handler != NULL) {
    p->sig_tf = kalloc();
    memcpy(p->sig_tf, p->trapframe, sizeof(struct trapframe));
    p->trapframe->epc =
        (uint64)p->sigaction[signum].__sigaction_handler.sa_handler;
    p->trapframe->ra = (uint64)SIGTRAMPOLINE;
    p->trapframe->sp = p->trapframe->sp - PGSIZE;
    debug_print("sighandle epc:%p ra:%p\n", p->trapframe->epc,
                p->trapframe->ra);
    p->sig_pending.__val[0] &= ~(1ul << signum);
    if (p->sig_pending.__val[0] == 0) {
      p->killed = 0;
    }
  } else {
    exit(-1);
  }
}

void initsleeplock(struct sleeplock *lk, char *name) {
  initlock(&lk->lk, "sleep lock");
  lk->name = name;
  lk->locked = 0;
  lk->pid = 0;
}

void acquiresleep(struct sleeplock *lk) {
  acquire(&lk->lk);
  while (lk->locked) {
    sleep(lk, &lk->lk);
  }
  lk->locked = 1;
  lk->pid = myproc()->pid;
  release(&lk->lk);
}

void releasesleep(struct sleeplock *lk) {
  acquire(&lk->lk);
  lk->locked = 0;
  lk->pid = 0;
  wakeup(lk);
  release(&lk->lk);
}

int holdingsleep(struct sleeplock *lk) {
  int r;

  acquire(&lk->lk);
  r = lk->locked && (lk->pid == myproc()->pid);
  release(&lk->lk);
  return r;
}

