void wnstr(wchar *dst, char const *src, int len) {
  while (len-- && *src) {
    *(uchar *)dst = *src++;
    dst++;
  }

  *dst = 0;
}

void snstr(char *dst, wchar const *src, int len) {
  while (len-- && *src) {
    *dst++ = (uchar)(*src & 0xff);
    src++;
  }
  while (len-- > 0)
    *dst++ = 0;
}

int wcsncmp(wchar const *s1, wchar const *s2, int len) {
  int ret = 0;

  while (len-- && *s1) {
    ret = (int)(*s1++ - *s2++);
    if (ret)
      break;
  }

  return ret;
}

