uint64 sys_fstatat(void) {
  int fd, flags;
  uint64 st;
  char pathname[FAT32_MAX_FILENAME];
  struct file *fp;
  struct dirent *dp, *ep;

  if (argfd(0, &fd, &fp) < 0 && fd != AT_FDCWD)
    return -24; // 打开文件太多
  if (argstr(1, pathname, FAT32_MAX_FILENAME + 1) < 0 || argaddr(2, &st) < 0 ||
      argint(3, &flags) < 0)
    return -1;

  // debug_print("fstatat: fd:%d pathname:%s st:%p
  // flags:%d\n",fd,pathname,st,flags);
  struct proc *p = myproc();
  if (AT_FDCWD == fd)
    dp = NULL;
  else {
    if (pathname[0] != '/' && fp == NULL)
      return -24;
    dp = fp ? fp->ep : NULL;
    if (dp && !(dp->attribute & ATTR_DIRECTORY))
      return -1;
  }

  int t1 = -1;

  if (strncmp(pathname, "/dev/null", 9) == 0)
    t1 = 0;

  ep = new_ename(dp, pathname);
  if (NULL == ep && t1 == -1)
    return -2;

  struct kstat kst;
  if (t1 == -1) {
    elock(ep);
    ekstat(ep, &kst);
    eunlock(ep);
    eput(ep);
  } else {
    ekstat(ep, &kst);
  }

  // print_kstat(&kst);
  if (copyout(p->pagetable, st, (char *)&kst, sizeof(kst)) < 0)
    return -1;

  return 0;
}

static void get_parent_name(char *path, char *pname, char *name) {
  int len = strlen(path);
  strncpy(pname, path, len + 1);
  int i = len - 1;

  if (pname[i] == '/') {
    i--;
  }

  for (; i >= 0; --i) {
    if (pname[i] == '/') {
      pname[i] = 0;
      break;
    }
  }
  int len2 = strlen(pname);
  strncpy(name, path + len2 + 1, len - len2 + 1);
}

static struct dirent *create(char *path, short type, int mode) {
  struct dirent *ep, *dp;
  // printf("path:%s\n", path);
  char name[FAT32_MAX_FILENAME + 1];
  char pname[FAT32_MAX_FILENAME + 1];
  if (type == T_DIR) {
    mode = ATTR_DIRECTORY;
  } else if (mode & O_RDONLY) {
    mode = ATTR_READ_ONLY;
  } else {
    mode = 0;
  }

  if ((dp = enameparent(path, name)) == NULL) {
    get_parent_name(path, pname, name);
    // printf("name:%s\n", name);
    // printf("pname:%s\n", pname);
    dp = create(pname, T_DIR, O_RDWR);
    if (dp == NULL) {
      return NULL;
    }
  } else {
    elock(dp);
  }

  if ((ep = ealloc(dp, name, mode)) == NULL) {
    eunlock(dp);
    eput(dp);
    return NULL;
  }

  if ((type == T_DIR && !(ep->attribute & ATTR_DIRECTORY)) ||
      (type == T_FILE && (ep->attribute & ATTR_DIRECTORY))) {
    eunlock(dp);
    eput(ep);
    eput(dp);
    // printf("here1!\n");
    return NULL;
  }

  eunlock(dp);
  eput(dp);
  elock(ep);
  // printf("here2!\n");
  return ep;
}

uint64 open(char *path, int omode) {
  int fd;
  struct file *f;
  struct dirent *ep;

  if (omode & O_CREATE) {
    ep = create(path, T_FILE, omode);
    if (ep == NULL) {
      return -1;
    }
  } else {
    if ((ep = ename(path)) == NULL) {
      return -1;
    }
    elock(ep);
    if ((ep->attribute & ATTR_DIRECTORY) && omode != O_RDONLY) {
      eunlock(ep);
      eput(ep);
      return -1;
    }
  }

  if ((f = filealloc()) == NULL || (fd = fdalloc(f)) < 0) {
    if (f) {
      fileclose(f);
    }
    eunlock(ep);
    eput(ep);
    return -1;
  }

  if (!(ep->attribute & ATTR_DIRECTORY) && (omode & O_TRUNC)) {
    etrunc(ep);
  }

  f->type = FD_ENTRY;
  f->off = (omode & O_APPEND) ? ep->file_size : 0;
  f->ep = ep;
  f->readable = !(omode & O_WRONLY);
  f->writable = (omode & O_WRONLY) || (omode & O_RDWR);

  eunlock(ep);
  return fd;
}

