  /*
  if (argstr(1,path,FAT32_MAX_FILENAME + 1) < 0 || argint(2,&mode) < 0 ||
  argint(3,&flags) < 0) { return -1;
  }
  */
  if (argstr(1, path, FAT32_MAX_FILENAME + 1) < 0)
    return -1;
