    }
  }

  return -24;
}

uint64 sys_fcntl(void) {
  int fd, cmd;
  uint64 arg;
  struct file *f;
  struct proc *p = myproc();
  if (argfd(0, &fd, &f) < 0 || argint(1, &cmd) < 0 || argaddr(2, &arg) < 0)
    return -1;
  if (F_GETFD == cmd)
    return p->exec_close[fd];
  else if (F_SETFD == cmd)
    p->exec_close[fd] = arg;
  else if (F_DUPFD == cmd) {
    if ((fd = fdalloc2(f, arg)) < 0)
      return fd;
    filedup(f);

    return fd;
  } else if (F_DUPFD_CLOEXEC == cmd) {
    if ((fd = fdalloc2(f, arg)) < 0)
      return fd;
    filedup(f);
    p->exec_close[fd] = 1;

    return fd;
  } else if (F_GETFL == cmd) {
    // handle O_NONBLOCK here; we just need special handling
    uint64 ret = 0;
    if (f->type == FD_SOCK) {
      if (f->socket_type & SOCK_NONBLOCK)
        ret |= O_NONBLOCK;
    }
    return ret;
  }

  return 0;
}

