static int argfd(int n, int *pfd, struct file **pf) {
  int fd = -1;
  struct file *f = NULL;
  if (pfd)
    *pfd = -1;
  if (pf)
    *pf = NULL;
  struct proc *p = myproc();
  if (argint(n, &fd) < 0)
    return -1;
  if (pfd)
    *pfd = fd;
  if (fd < 0 || fd >= NOFILEMAX(p) || (f = p->ofile[fd]) == NULL)
    return -1;
  if (pf)
    *pf = f;
  return 0;
}

