void threadInit() {
  for (int i = 0; i < THREAD_NUM; i++) {
    threads[i].state = t_UNUSED;
    threads[i].pre_thread = NULL;
    threads[i].next_thread = NULL;
    if (i != 0) {
      threads[i].pre_thread = &threads[i - 1];
    }
    if (i + 1 < THREAD_NUM) {
      threads[i].next_thread = &threads[i + 1];
    }
  }
  free_thread = &threads[0];
}

