pte_t *walk(pagetable_t pagetable, uint64 va, int alloc) {

  if (va >= MAXVA)
    panic("walk");

  for (int level = 2; level > 0; level--) {
    pte_t *pte = &pagetable[PX(level, va)];
    if (*pte & PTE_V) {
      pagetable = (pagetable_t)PTE2PA(*pte);
    } else {
      if (!alloc || (pagetable = (pde_t *)kalloc()) == NULL) {
        // printf("walk: not valid\n");
        return NULL;
      }
      memset(pagetable, 0, PGSIZE);
      *pte = PA2PTE(pagetable) | PTE_V;
    }
  }
  return &pagetable[PX(0, va)];
}

uint64 walkaddr(pagetable_t pagetable, uint64 va) {
  pte_t *pte;
  uint64 pa;

  if (va >= MAXVA) {
    debug_print("walkaddr: va >= MAXVA\n");
    return NULL;
  }

  pte = walk(pagetable, va, 0);
  if (pte == 0) {
    printf("walkaddr: pte == 0\n");
    return NULL;
  }
  if ((*pte & PTE_V) == 0) {
    debug_print("va :%p walkaddr: *pte & PTE_V == 0\n", va);
    return NULL;
  }
  if ((*pte & PTE_U) == 0) {
    debug_print("walkaddr: *pte & PTE_U == 0\n");
    return NULL;
  }
  pa = PTE2PA(*pte);
  return pa;
}

void kvmmap(uint64 va, uint64 pa, uint64 sz, int perm) {
  if (mappages(kernel_pagetable, va, sz, pa, perm) != 0)
    panic("kvmmap");
}

uint64 kwalkaddr(pagetable_t kpt, uint64 va) {
  uint64 off = va % PGSIZE;
  pte_t *pte;
  uint64 pa;

  pte = walk(kpt, va, 0);
  if (pte == 0)
    panic("kvmpa");
  if ((*pte & PTE_V) == 0)
    panic("kvmpa");
  pa = PTE2PA(*pte);
  return pa + off;
}

int mappages(pagetable_t pagetable, uint64 va, uint64 size, uint64 pa,
             int perm) {
  // for visionfive 2
  perm |= PTE_A | PTE_D;
  uint64 a, last;
  pte_t *pte;

  a = PGROUNDDOWN(va);
  last = PGROUNDDOWN(va + size - 1);

  for (;;) {
    if ((pte = walk(pagetable, a, 1)) == NULL)
      return -1;
    if (*pte & PTE_V) {
      printf("mappages:%p %p\n", a, PTE2PA(*pte));
      panic("remap");
    }

    *pte = PA2PTE(pa) | perm | PTE_V;
    if (a == last)
      break;
    a += PGSIZE;
    pa += PGSIZE;
  }
  return 0;
}

void vmunmap(pagetable_t pagetable, uint64 va, uint64 npages, int do_free) {
  uint64 a;
  pte_t *pte;

  if ((va % PGSIZE) != 0)
    panic("vmunmap: not aligned");

  for (a = va; a < va + npages * PGSIZE; a += PGSIZE) {
    if ((pte = walk(pagetable, a, 0)) == 0)
      panic("vmunmap: walk");
    if ((*pte & PTE_V) == 0)
      panic("vmunmap: not mapped");
    if (PTE_FLAGS(*pte) == PTE_V)
      panic("vmunmap: not a leaf");
    if (do_free) {
      uint64 pa = PTE2PA(*pte);
      kfree((void *)pa);
    }
    *pte = 0;
  }
}

pagetable_t uvmcreate() {
  pagetable_t pagetable;
  pagetable = (pagetable_t)kalloc();
  if (pagetable == NULL)
    return NULL;
  memset(pagetable, 0, PGSIZE);
  return pagetable;
}

void uvminit(pagetable_t pagetable, pagetable_t kpagetable, uchar *src,
             uint sz) {
  char *mem;
  uint64 i;
  for (i = 0; i + PGSIZE < sz; i += PGSIZE) {
    mem = kalloc();
    // printf("[uvminit]kalloc: %p\n", mem);
    memset(mem, 0, PGSIZE);
    mappages(pagetable, i, PGSIZE, (uint64)mem, PTE_W | PTE_R | PTE_X | PTE_U);
    mappages(kpagetable, i, PGSIZE, (uint64)mem, PTE_W | PTE_R | PTE_X);
    memmove(mem, src + i, PGSIZE);
  }
  mem = kalloc();
  memset(mem, 0, PGSIZE);
  mappages(pagetable, i, PGSIZE, (uint64)mem, PTE_W | PTE_R | PTE_X | PTE_U);
  mappages(kpagetable, i, PGSIZE, (uint64)mem, PTE_W | PTE_R | PTE_X);
  memmove(mem, src + i, sz % PGSIZE);
  debug_print("uvminit done sz:%d\n", sz);
  // for (int i = 0; i < sz; i ++) {
  //   printf("[uvminit]mem: %p, %x\n", mem + i, mem[i]);
  // }
}

uint64 uvmalloc1(pagetable_t pagetable, uint64 start, uint64 end, int perm) {
  char *mem;
  uint64 a;
  if (start >= end)
    return -1;
  for (a = start; a < end; a += PGSIZE) {
    mem = kalloc();
    if (mem == NULL) {
      uvmdealloc1(pagetable, start, a);
      printf("uvmalloc kalloc failed\n");
      return -1;
    }
    memset(mem, 0, PGSIZE);
    if (mappages(pagetable, a, PGSIZE, (uint64)mem, perm) != 0) {
      kfree(mem);
      uvmdealloc1(pagetable, start, a);
      printf("[uvmalloc]map user page failed\n");
      return -1;
    }
  }
  return 0;
}

uint64 uvmdealloc1(pagetable_t pagetable, uint64 start, uint64 end) {

  if (start >= end)
    return -1;
  if (PGROUNDUP(start) <= PGROUNDUP(end)) {
    int npages = (PGROUNDUP(end) - PGROUNDUP(start)) / PGSIZE;
    vmunmap(pagetable, PGROUNDUP(start), npages, 1);
  }

  return 0;
}

uint64 uvmalloc(pagetable_t pagetable, pagetable_t kpagetable, uint64 oldsz,
                uint64 newsz, int perm) {
  char *mem;
  uint64 a;

  if (newsz < oldsz)
    return oldsz;

  oldsz = PGROUNDUP(oldsz);
  for (a = oldsz; a < newsz; a += PGSIZE) {
    mem = kalloc();
    if (mem == NULL) {
      uvmdealloc(pagetable, kpagetable, a, oldsz);
      return 0;
    }
    memset(mem, 0, PGSIZE);
    if (mappages(pagetable, a, PGSIZE, (uint64)mem, perm | PTE_U) != 0) {
      kfree(mem);
      uvmdealloc(pagetable, kpagetable, a, oldsz);
      return 0;
    }
    if (mappages(kpagetable, a, PGSIZE, (uint64)mem, perm) != 0) {
      int npages = (a - oldsz) / PGSIZE;
      vmunmap(pagetable, oldsz, npages + 1,
              1); // plus the page allocated above.
      vmunmap(kpagetable, oldsz, npages, 0);
      return 0;
    }
  }
  return newsz;
}

uint64 uvmdealloc(pagetable_t pagetable, pagetable_t kpagetable, uint64 oldsz,
                  uint64 newsz) {
  if (newsz >= oldsz)
    return oldsz;

  if (PGROUNDUP(newsz) < PGROUNDUP(oldsz)) {
    int npages = (PGROUNDUP(oldsz) - PGROUNDUP(newsz)) / PGSIZE;
    vmunmap(kpagetable, PGROUNDUP(newsz), npages, 0);
    vmunmap(pagetable, PGROUNDUP(newsz), npages, 1);
  }

  return newsz;
}

void freewalk(pagetable_t pagetable) {
  // there are 2^9 = 512 PTEs in a page table.
  for (int i = 0; i < 512; i++) {
    pte_t pte = pagetable[i];
    if ((pte & PTE_V) && (pte & (PTE_R | PTE_W | PTE_X)) == 0) {
      // this PTE points to a lower-level page table.
      uint64 child = PTE2PA(pte);
      freewalk((pagetable_t)child);
      pagetable[i] = 0;
    } else if (pte & PTE_V) {
      // panic("freewalk: leaf");
      continue;
    }
  }
  kfree((void *)pagetable);
}

void uvmfree(pagetable_t pagetable, uint64 sz) {
  if (sz > 0)
    vmunmap(pagetable, 0, PGROUNDUP(sz) / PGSIZE, 1);
  freewalk(pagetable);
}

int uvmcopy(pagetable_t old, pagetable_t new, pagetable_t knew, uint64 sz) {
  pte_t *pte;
  uint64 pa, i = 0, ki = 0;
  uint flags;
  char *mem;

  while (i < sz) {
    if ((pte = walk(old, i, 0)) == NULL)
      panic("uvmcopy: pte should exist");
    if ((*pte & PTE_V) == 0)
      panic("uvmcopy: page not present");
    pa = PTE2PA(*pte);
    flags = PTE_FLAGS(*pte);
    if ((mem = kalloc()) == NULL)
      goto err;
    memmove(mem, (char *)pa, PGSIZE);
    if (mappages(new, i, PGSIZE, (uint64)mem, flags) != 0) {
      kfree(mem);
      goto err;
    }
    i += PGSIZE;
    if (mappages(knew, ki, PGSIZE, (uint64)mem, flags & ~PTE_U) != 0) {
      goto err;
    }
    ki += PGSIZE;
  }
  return 0;

err:
  vmunmap(knew, 0, ki / PGSIZE, 0);
  vmunmap(new, 0, i / PGSIZE, 1);
  return -1;
}

void uvmclear(pagetable_t pagetable, uint64 va) {
  pte_t *pte;

  pte = walk(pagetable, va, 0);
  if (pte == NULL)
    panic("uvmclear");
  *pte &= ~PTE_U;
}

int copyout_zero(pagetable_t pagetable, uint64 dstva, uint64 len) {
  uint64 n, va0, pa0;

  while (len > 0) {
    va0 = PGROUNDDOWN(dstva);
    pa0 = walkaddr(pagetable, va0);
    if (pa0 == NULL)
      return -1;
    n = PGSIZE - (dstva - va0);
    if (n > len)
      n = len;

    memset((void *)(pa0 + (dstva - va0)), 0, n);

    len -= n;
    dstva = va0 + PGSIZE;
  }
  return 0;
}

int copyout(pagetable_t pagetable, uint64 dstva, char *src, uint64 len) {
  uint64 n, va0, pa0;

  while (len > 0) {
    va0 = PGROUNDDOWN(dstva);
    pa0 = walkaddr(pagetable, va0);
    if (pa0 == NULL)
      return -1;
    n = PGSIZE - (dstva - va0);
    if (n > len)
      n = len;
    memmove((void *)(pa0 + (dstva - va0)), src, n);

    len -= n;
    src += n;
    dstva = va0 + PGSIZE;
  }
  return 0;
}

