struct altcp_pcb *altcp_new_ip_type(altcp_allocator_t *allocator,
                                    u8_t ip_type) {
  struct altcp_pcb *conn;
  if (allocator == NULL) {
    /* no allocator given, create a simple TCP connection */
    return altcp_tcp_new_ip_type(ip_type);
