  LWIP_DEBUGF(IP_DEBUG, ("+-------------------------------+\n"));
  LWIP_DEBUGF(IP_DEBUG,
              ("|  %3" U16_F "  |  %3" U16_F "  |  %3" U16_F "  |  %3" U16_F
               "  | (src)\n",
               ip4_addr1_16_val(iphdr->src), ip4_addr2_16_val(iphdr->src),
