               "  | (dest)\n",
               ip4_addr1_16_val(iphdr->dest), ip4_addr2_16_val(iphdr->dest),
               ip4_addr3_16_val(iphdr->dest), ip4_addr4_16_val(iphdr->dest)));
  LWIP_DEBUGF(IP_DEBUG, ("+-------------------------------+\n"));
