  netif->rs_count = LWIP_ND6_MAX_MULTICAST_SOLICIT;
#endif /* LWIP_IPV6_SEND_ROUTER_SOLICIT */
}

static inline u16_t
LWIP_PLATFORM_HTONS(u16_t n)
{
  return ((n & 0xff) << 8) | ((n & 0xff00) >> 8);
}

static inline u32_t
LWIP_PLATFORM_HTONL(u32_t n)
{
  return ((n & 0xff) << 24) |
    ((n & 0xff00) << 8) |
    ((n & 0xff0000UL) >> 8) |
    ((n & 0xff000000UL) >> 24);
}

