int
get_srp_secret(unit, client, server, secret, am_server)
    int unit;
    char *client;
    char *server;
    char *secret;
    int am_server;
{
    FILE *fp;
    int ret;
    char *filename;
    struct wordlist *addrs, *opts;

    if (!am_server && ppp_settings.passwd[0] != '\0') {
	strlcpy(secret, ppp_settings.passwd, MAXWORDLEN);
    } else {
	filename = _PATH_SRPFILE;
	addrs = NULL;

	fp = fopen(filename, "r");
	if (fp == NULL) {
	    ppp_error(("Can't open srp secret file %s: %m", filename));
	    return 0;
	}
	check_access(fp, filename);

	secret[0] = '\0';
	ret = scan_authfile(fp, client, server, secret, &addrs, &opts,
	    filename, am_server);
	fclose(fp);
	if (ret < 0)
	    return 0;

	if (am_server)
	    set_allowed_addrs(unit, addrs, opts);
	else if (opts != NULL)
	    free_wordlist(opts);
	if (addrs != NULL)
	    free_wordlist(addrs);
    }

    return 1;
}

static void
set_allowed_addrs(unit, addrs, opts)
    int unit;
    struct wordlist *addrs;
    struct wordlist *opts;
{
    int n;
    struct wordlist *ap, **plink;
    struct permitted_ip *ip;
    char *ptr_word, *ptr_mask;
    struct hostent *hp;
    struct netent *np;
    u32_t a, mask, ah, offset;
    struct ipcp_options *wo = &ipcp_wantoptions[unit];
    u32_t suggested_ip = 0;

    if (addresses[unit] != NULL)
	free(addresses[unit]);
    addresses[unit] = NULL;
    if (extra_options != NULL)
	free_wordlist(extra_options);
    extra_options = opts;

    /*
     * Count the number of IP addresses given.
     */
    n = wordlist_count(addrs) + wordlist_count(noauth_addrs);
    if (n == 0)
	return;
    ip = (struct permitted_ip *) malloc((n + 1) * sizeof(struct permitted_ip));
    if (ip == 0)
	return;

    /* temporarily append the noauth_addrs list to addrs */
    for (plink = &addrs; *plink != NULL; plink = &(*plink)->next)
	;
    *plink = noauth_addrs;

    n = 0;
    for (ap = addrs; ap != NULL; ap = ap->next) {
	/* "-" means no addresses authorized, "*" means any address allowed */
	ptr_word = ap->word;
	if (strcmp(ptr_word, "-") == 0)
	    break;
	if (strcmp(ptr_word, "*") == 0) {
	    ip[n].permit = 1;
	    ip[n].base = ip[n].mask = 0;
	    ++n;
	    break;
	}

	ip[n].permit = 1;
	if (*ptr_word == '!') {
	    ip[n].permit = 0;
	    ++ptr_word;
	}

	mask = ~ (u32_t) 0;
	offset = 0;
	ptr_mask = strchr (ptr_word, '/');
	if (ptr_mask != NULL) {
	    int bit_count;
	    char *endp;

	    bit_count = (int) strtol (ptr_mask+1, &endp, 10);
	    if (bit_count <= 0 || bit_count > 32) {
		ppp_warn(("invalid address length %v in auth. address list",
		     ptr_mask+1));
		continue;
	    }
	    bit_count = 32 - bit_count;	/* # bits in host part */
	    if (*endp == '+') {
		offset = ifunit + 1;
		++endp;
	    }
	    if (*endp != 0) {
		ppp_warn(("invalid address length syntax: %v", ptr_mask+1));
		continue;
	    }
	    *ptr_mask = '\0';
	    mask <<= bit_count;
	}

	hp = gethostbyname(ptr_word);
	if (hp != NULL && hp->h_addrtype == AF_INET) {
	    a = *(u32_t *)hp->h_addr;
	} else {
	    np = getnetbyname (ptr_word);
	    if (np != NULL && np->n_addrtype == AF_INET) {
		a = lwip_htonl ((u32_t)np->n_net);
		if (ptr_mask == NULL) {
		    /* calculate appropriate mask for net */
		    ah = lwip_ntohl(a);
		    if (IN_CLASSA(ah))
			mask = IN_CLASSA_NET;
		    else if (IN_CLASSB(ah))
			mask = IN_CLASSB_NET;
		    else if (IN_CLASSC(ah))
			mask = IN_CLASSC_NET;
		}
	    } else {
		a = inet_addr (ptr_word);
	    }
	}

	if (ptr_mask != NULL)
	    *ptr_mask = '/';

	if (a == (u32_t)-1L) {
	    ppp_warn(("unknown host %s in auth. address list", ap->word));
	    continue;
	}
	if (offset != 0) {
	    if (offset >= ~mask) {
		ppp_warn(("interface unit %d too large for subnet %v",
		     ifunit, ptr_word));
		continue;
	    }
	    a = lwip_htonl((lwip_ntohl(a) & mask) + offset);
	    mask = ~(u32_t)0;
	}
	ip[n].mask = lwip_htonl(mask);
	ip[n].base = a & ip[n].mask;
	++n;
	if (~mask == 0 && suggested_ip == 0)
	    suggested_ip = a;
    }
    *plink = NULL;

    ip[n].permit = 0;		/* make the last entry forbid all addresses */
    ip[n].base = 0;		/* to terminate the list */
    ip[n].mask = 0;

    addresses[unit] = ip;

    /*
     * If the address given for the peer isn't authorized, or if
     * the user hasn't given one, AND there is an authorized address
     * which is a single host, then use that if we find one.
     */
    if (suggested_ip != 0
	&& (wo->hisaddr == 0 || !auth_ip_addr(unit, wo->hisaddr))) {
	wo->hisaddr = suggested_ip;
	/*
	 * Do we insist on this address?  No, if there are other
	 * addresses authorized than the suggested one.
	 */
	if (n > 1)
	    wo->accept_remote = 1;
    }
}

int
auth_ip_addr(unit, addr)
    int unit;
    u32_t addr;
{
    int ok;

    /* don't allow loopback or multicast address */
    if (bad_ip_adrs(addr))
	return 0;

    if (allowed_address_hook) {
	ok = allowed_address_hook(addr);
	if (ok >= 0) return ok;
    }

    if (addresses[unit] != NULL) {
	ok = ip_addr_check(addr, addresses[unit]);
	if (ok >= 0)
	    return ok;
    }

    if (auth_required)
	return 0;		/* no addresses authorized */
    return allow_any_ip || privileged || !have_route_to(addr);
}

static int
ip_addr_check(addr, addrs)
    u32_t addr;
    struct permitted_ip *addrs;
{
    for (; ; ++addrs)
	if ((addr & addrs->mask) == addrs->base)
	    return addrs->permit;
}

int
bad_ip_adrs(addr)
    u32_t addr;
{
    addr = lwip_ntohl(addr);
    return (addr >> IN_CLASSA_NSHIFT) == IN_LOOPBACKNET
	|| IN_MULTICAST(addr) || IN_BADCLASS(addr);
}

static int
some_ip_ok(addrs)
    struct wordlist *addrs;
{
    for (; addrs != 0; addrs = addrs->next) {
	if (addrs->word[0] == '-')
	    break;
	if (addrs->word[0] != '!')
	    return 1;		/* some IP address is allowed */
    }
    return 0;
}

int
auth_number()
{
    struct wordlist *wp = permitted_numbers;
    int l;

    /* Allow all if no authorization list. */
    if (!wp)
	return 1;

    /* Allow if we have a match in the authorization list. */
    while (wp) {
	/* trailing '*' wildcard */
	l = strlen(wp->word);
	if ((wp->word)[l - 1] == '*')
	    l--;
	if (!strncasecmp(wp->word, remote_number, l))
	    return 1;
	wp = wp->next;
    }

    return 0;
}

static void
check_access(f, filename)
    FILE *f;
    char *filename;
{
    struct stat sbuf;

    if (fstat(fileno(f), &sbuf) < 0) {
	ppp_warn(("cannot stat secret file %s: %m", filename));
    } else if ((sbuf.st_mode & (S_IRWXG | S_IRWXO)) != 0) {
	ppp_warn(("Warning - secret file %s has world and/or group access",
	     filename));
    }
}

static int
scan_authfile(f, client, server, secret, addrs, opts, filename, flags)
    FILE *f;
    char *client;
    char *server;
    char *secret;
    struct wordlist **addrs;
    struct wordlist **opts;
    char *filename;
    int flags;
{
    int newline, xxx;
    int got_flag, best_flag;
    FILE *sf;
    struct wordlist *ap, *addr_list, *alist, **app;
    char word[MAXWORDLEN];
    char atfile[MAXWORDLEN];
    char lsecret[MAXWORDLEN];
    char *cp;

    if (addrs != NULL)
	*addrs = NULL;
    if (opts != NULL)
	*opts = NULL;
    addr_list = NULL;
    if (!getword(f, word, &newline, filename))
	return -1;		/* file is empty??? */
    newline = 1;
    best_flag = -1;
    for (;;) {
	/*
	 * Skip until we find a word at the start of a line.
	 */
	while (!newline && getword(f, word, &newline, filename))
	    ;
	if (!newline)
	    break;		/* got to end of file */

	/*
	 * Got a client - check if it's a match or a wildcard.
	 */
	got_flag = 0;
	if (client != NULL && strcmp(word, client) != 0 && !ISWILD(word)) {
	    newline = 0;
	    continue;
	}
	if (!ISWILD(word))
	    got_flag = NONWILD_CLIENT;

	/*
	 * Now get a server and check if it matches.
	 */
	if (!getword(f, word, &newline, filename))
	    break;
	if (newline)
	    continue;
	if (!ISWILD(word)) {
	    if (server != NULL && strcmp(word, server) != 0)
		continue;
	    got_flag |= NONWILD_SERVER;
	}

	/*
	 * Got some sort of a match - see if it's better than what
	 * we have already.
	 */
	if (got_flag <= best_flag)
	    continue;

	/*
	 * Get the secret.
	 */
	if (!getword(f, word, &newline, filename))
	    break;
	if (newline)
	    continue;

	/*
	 * SRP-SHA1 authenticator should never be reading secrets from
	 * a file.  (Authenticatee may, though.)
	 */
	if (flags && ((cp = strchr(word, ':')) == NULL ||
	    strchr(cp + 1, ':') == NULL))
	    continue;

	if (secret != NULL) {
	    /*
	     * Special syntax: @/pathname means read secret from file.
	     */
	    if (word[0] == '@' && word[1] == '/') {
		strlcpy(atfile, word+1, sizeof(atfile));
		if ((sf = fopen(atfile, "r")) == NULL) {
		    ppp_warn(("can't open indirect secret file %s", atfile));
		    continue;
		}
		check_access(sf, atfile);
		if (!getword(sf, word, &xxx, atfile)) {
		    ppp_warn(("no secret in indirect secret file %s", atfile));
		    fclose(sf);
		    continue;
		}
		fclose(sf);
	    }
	    strlcpy(lsecret, word, sizeof(lsecret));
	}

	/*
	 * Now read address authorization info and make a wordlist.
	 */
	app = &alist;
	for (;;) {
	    if (!getword(f, word, &newline, filename) || newline)
		break;
	    ap = (struct wordlist *)
		    malloc(sizeof(struct wordlist) + strlen(word) + 1);
	    if (ap == NULL)
		novm("authorized addresses");
	    ap->word = (char *) (ap + 1);
	    strcpy(ap->word, word);
	    *app = ap;
	    app = &ap->next;
	}
	*app = NULL;

	/*
	 * This is the best so far; remember it.
	 */
	best_flag = got_flag;
	if (addr_list)
	    free_wordlist(addr_list);
	addr_list = alist;
	if (secret != NULL)
	    strlcpy(secret, lsecret, MAXWORDLEN);

	if (!newline)
	    break;
    }

    /* scan for a -- word indicating the start of options */
    for (app = &addr_list; (ap = *app) != NULL; app = &ap->next)
	if (strcmp(ap->word, "--") == 0)
	    break;
    /* ap = start of options */
    if (ap != NULL) {
	ap = ap->next;		/* first option */
	free(*app);			/* free the "--" word */
	*app = NULL;		/* terminate addr list */
    }
    if (opts != NULL)
	*opts = ap;
    else if (ap != NULL)
	free_wordlist(ap);
    if (addrs != NULL)
	*addrs = addr_list;
    else if (addr_list != NULL)
	free_wordlist(addr_list);

    return best_flag;
}

static int
wordlist_count(wp)
    struct wordlist *wp;
{
    int n;

    for (n = 0; wp != NULL; wp = wp->next)
	++n;
    return n;
}

static void
free_wordlist(wp)
    struct wordlist *wp;
{
    struct wordlist *next;

    while (wp != NULL) {
	next = wp->next;
	free(wp);
	wp = next;
    }
}

static int setbsdcomp(argv)
char **argv;
{
  int rbits, abits;
  char *str, *endp;

  str = *argv;
  abits = rbits = strtol(str, &endp, 0);
  if (endp != str && *endp == ',') {
    str = endp + 1;
    abits = strtol(str, &endp, 0);
  }
  if (*endp != 0 || endp == str) {
    option_error("invalid parameter '%s' for bsdcomp option", *argv);
    return 0;
  }
  if ((rbits != 0 && (rbits < BSD_MIN_BITS || rbits > BSD_MAX_BITS)) ||
      (abits != 0 && (abits < BSD_MIN_BITS || abits > BSD_MAX_BITS))) {
    option_error("bsdcomp option values must be 0 or %d .. %d", BSD_MIN_BITS,
                 BSD_MAX_BITS);
    return 0;
  }
  if (rbits > 0) {
    ccp_wantoptions[0].bsd_compress = 1;
    ccp_wantoptions[0].bsd_bits = rbits;
  } else
    ccp_wantoptions[0].bsd_compress = 0;
  if (abits > 0) {
    ccp_allowoptions[0].bsd_compress = 1;
    ccp_allowoptions[0].bsd_bits = abits;
  } else
    ccp_allowoptions[0].bsd_compress = 0;
  ppp_slprintf(bsd_value, sizeof(bsd_value), rbits == abits ? "%d" : "%d,%d",
               rbits, abits);

  return 1;
}

static int setdeflate(argv)
char **argv;
{
  int rbits, abits;
  char *str, *endp;

  str = *argv;
  abits = rbits = strtol(str, &endp, 0);
  if (endp != str && *endp == ',') {
    str = endp + 1;
    abits = strtol(str, &endp, 0);
  }
  if (*endp != 0 || endp == str) {
    option_error("invalid parameter '%s' for deflate option", *argv);
    return 0;
  }
  if ((rbits != 0 && (rbits < DEFLATE_MIN_SIZE || rbits > DEFLATE_MAX_SIZE)) ||
      (abits != 0 && (abits < DEFLATE_MIN_SIZE || abits > DEFLATE_MAX_SIZE))) {
    option_error("deflate option values must be 0 or %d .. %d",
                 DEFLATE_MIN_SIZE, DEFLATE_MAX_SIZE);
    return 0;
  }
  if (rbits == DEFLATE_MIN_SIZE || abits == DEFLATE_MIN_SIZE) {
    if (rbits == DEFLATE_MIN_SIZE)
      rbits = DEFLATE_MIN_WORKS;
    if (abits == DEFLATE_MIN_SIZE)
      abits = DEFLATE_MIN_WORKS;
    warn("deflate option value of %d changed to %d to avoid zlib bug",
         DEFLATE_MIN_SIZE, DEFLATE_MIN_WORKS);
  }
  if (rbits > 0) {
    ccp_wantoptions[0].deflate = 1;
    ccp_wantoptions[0].deflate_size = rbits;
  } else
    ccp_wantoptions[0].deflate = 0;
  if (abits > 0) {
    ccp_allowoptions[0].deflate = 1;
    ccp_allowoptions[0].deflate_size = abits;
  } else
    ccp_allowoptions[0].deflate = 0;
  ppp_slprintf(deflate_value, sizeof(deflate_value),
               rbits == abits ? "%d" : "%d,%d", rbits, abits);

  return 1;
}

static void ccp_init(ppp_pcb *pcb) {
  fsm *f = &pcb->ccp_fsm;

  f->pcb = pcb;
  f->protocol = PPP_CCP;
  f->callbacks = &ccp_callbacks;
  fsm_init(f);

#if 0  /* Not necessary, everything is cleared in ppp_new() */
    memset(wo, 0, sizeof(*wo));
    memset(go, 0, sizeof(*go));
    memset(ao, 0, sizeof(*ao));
    memset(ho, 0, sizeof(*ho));
#endif /* 0 */

#if DEFLATE_SUPPORT
  wo->deflate = 1;
  wo->deflate_size = DEFLATE_MAX_SIZE;
  wo->deflate_correct = 1;
  wo->deflate_draft = 1;
  ao->deflate = 1;
  ao->deflate_size = DEFLATE_MAX_SIZE;
  ao->deflate_correct = 1;
  ao->deflate_draft = 1;
#endif /* DEFLATE_SUPPORT */

#if BSDCOMPRESS_SUPPORT
  wo->bsd_compress = 1;
  wo->bsd_bits = BSD_MAX_BITS;
  ao->bsd_compress = 1;
  ao->bsd_bits = BSD_MAX_BITS;
#endif /* BSDCOMPRESS_SUPPORT */

#if PREDICTOR_SUPPORT
  ao->predictor_1 = 1;
#endif /* PREDICTOR_SUPPORT */
}

static void ccp_open(ppp_pcb *pcb) {
  fsm *f = &pcb->ccp_fsm;
  ccp_options *go = &pcb->ccp_gotoptions;

  if (f->state != PPP_FSM_OPENED)
    ccp_set(pcb, 1, 0, 0, 0);

  /*
   * Find out which compressors the kernel supports before
   * deciding whether to open in silent mode.
   */
  ccp_resetci(f);
  if (!ccp_anycompress(go))
    f->flags |= OPT_SILENT;

  fsm_open(f);
}

static void ccp_close(ppp_pcb *pcb, const char *reason) {
  fsm *f = &pcb->ccp_fsm;
  ccp_set(pcb, 0, 0, 0, 0);
  fsm_close(f, reason);
}

static void ccp_lowerup(ppp_pcb *pcb) {
  fsm *f = &pcb->ccp_fsm;
  fsm_lowerup(f);
}

static void ccp_lowerdown(ppp_pcb *pcb) {
  fsm *f = &pcb->ccp_fsm;
  fsm_lowerdown(f);
}

static void ccp_input(ppp_pcb *pcb, u_char *p, int len) {
  fsm *f = &pcb->ccp_fsm;
  ccp_options *go = &pcb->ccp_gotoptions;
  int oldstate;

  /*
   * Check for a terminate-request so we can print a message.
   */
  oldstate = f->state;
  fsm_input(f, p, len);
  if (oldstate == PPP_FSM_OPENED && p[0] == TERMREQ &&
      f->state != PPP_FSM_OPENED) {
    ppp_notice(("Compression disabled by peer."));
#if MPPE_SUPPORT
    if (go->mppe) {
      ppp_error(("MPPE disabled, closing LCP"));
      lcp_close(pcb, "MPPE disabled by peer");
    }
#endif /* MPPE_SUPPORT */
  }

  /*
   * If we get a terminate-ack and we're not asking for compression,
   * close CCP.
   */
  if (oldstate == PPP_FSM_REQSENT && p[0] == TERMACK && !ccp_anycompress(go))
    ccp_close(pcb, "No compression negotiated");
}

static int ccp_extcode(fsm *f, int code, int id, u_char *p, int len) {
  ppp_pcb *pcb = f->pcb;
  LWIP_UNUSED_ARG(p);
  LWIP_UNUSED_ARG(len);

  switch (code) {
  case CCP_RESETREQ:
    if (f->state != PPP_FSM_OPENED)
      break;
    ccp_reset_comp(pcb);
    /* send a reset-ack, which the transmitter will see and
       reset its compression state. */
    fsm_sdata(f, CCP_RESETACK, id, NULL, 0);
    break;

  case CCP_RESETACK:
    if ((pcb->ccp_localstate & RACK_PENDING) && id == f->reqid) {
      pcb->ccp_localstate &= ~(RACK_PENDING | RREQ_REPEAT);
      UNTIMEOUT(ccp_rack_timeout, f);
      ccp_reset_decomp(pcb);
    }
    break;

  default:
    return 0;
  }

  return 1;
}

static void ccp_protrej(ppp_pcb *pcb) {
  fsm *f = &pcb->ccp_fsm;
#if MPPE_SUPPORT
  ccp_options *go = &pcb->ccp_gotoptions;
#endif /* MPPE_SUPPORT */

  ccp_set(pcb, 0, 0, 0, 0);
  fsm_lowerdown(f);

#if MPPE_SUPPORT
  if (go->mppe) {
    ppp_error(("MPPE required but peer negotiation failed"));
    lcp_close(pcb, "MPPE required but peer negotiation failed");
  }
#endif /* MPPE_SUPPORT */
}

static void ccp_resetci(fsm *f) {
  ppp_pcb *pcb = f->pcb;
  ccp_options *go = &pcb->ccp_gotoptions;
  ccp_options *wo = &pcb->ccp_wantoptions;
#if MPPE_SUPPORT
  ccp_options *ao = &pcb->ccp_allowoptions;
#endif /* MPPE_SUPPORT */
#if DEFLATE_SUPPORT || BSDCOMPRESS_SUPPORT || PREDICTOR_SUPPORT
  u_char opt_buf[CCP_MAX_OPTION_LENGTH];
#endif /* DEFLATE_SUPPORT || BSDCOMPRESS_SUPPORT || PREDICTOR_SUPPORT */
#if DEFLATE_SUPPORT || BSDCOMPRESS_SUPPORT
  int res;
#endif /* DEFLATE_SUPPORT || BSDCOMPRESS_SUPPORT */

#if MPPE_SUPPORT
  if (pcb->settings.require_mppe) {
    wo->mppe = ao->mppe = (pcb->settings.refuse_mppe_40 ? 0 : MPPE_OPT_40) |
                          (pcb->settings.refuse_mppe_128 ? 0 : MPPE_OPT_128);
  }
#endif /* MPPE_SUPPORT */

  *go = *wo;
  pcb->ccp_all_rejected = 0;

#if MPPE_SUPPORT
  if (go->mppe) {
    int auth_mschap_bits = pcb->auth_done;
    int numbits;

    /*
     * Start with a basic sanity check: mschap[v2] auth must be in
     * exactly one direction.  RFC 3079 says that the keys are
     * 'derived from the credentials of the peer that initiated the call',
     * however the PPP protocol doesn't have such a concept, and pppd
     * cannot get this info externally.  Instead we do the best we can.
     * NB: If MPPE is required, all other compression opts are invalid.
     *     So, we return right away if we can't do it.
     */

    /* Leave only the mschap auth bits set */
    auth_mschap_bits &=
        (CHAP_MS_WITHPEER | CHAP_MS_PEER | CHAP_MS2_WITHPEER | CHAP_MS2_PEER);
    /* Count the mschap auths */
    auth_mschap_bits >>= CHAP_MS_SHIFT;
    numbits = 0;
    do {
      numbits += auth_mschap_bits & 1;
      auth_mschap_bits >>= 1;
    } while (auth_mschap_bits);
    if (numbits > 1) {
      ppp_error(("MPPE required, but auth done in both directions."));
      lcp_close(pcb, "MPPE required but not available");
      return;
    }
    if (!numbits) {
      ppp_error(("MPPE required, but MS-CHAP[v2] auth not performed."));
      lcp_close(pcb, "MPPE required but not available");
      return;
    }

    /* A plugin (eg radius) may not have obtained key material. */
    if (!pcb->mppe_keys_set) {
      ppp_error(("MPPE required, but keys are not available.  "
                 "Possible plugin problem?"));
      lcp_close(pcb, "MPPE required but not available");
      return;
    }

    /* LM auth not supported for MPPE */
    if (pcb->auth_done & (CHAP_MS_WITHPEER | CHAP_MS_PEER)) {
      /* This might be noise */
      if (go->mppe & MPPE_OPT_40) {
        ppp_notice(("Disabling 40-bit MPPE; MS-CHAP LM not supported"));
        go->mppe &= ~MPPE_OPT_40;
        wo->mppe &= ~MPPE_OPT_40;
      }
    }

    /* Last check: can we actually negotiate something? */
    if (!(go->mppe & (MPPE_OPT_40 | MPPE_OPT_128))) {
      /* Could be misconfig, could be 40-bit disabled above. */
      ppp_error(("MPPE required, but both 40-bit and 128-bit disabled."));
      lcp_close(pcb, "MPPE required but not available");
      return;
    }

    /* sync options */
    ao->mppe = go->mppe;
    /* MPPE is not compatible with other compression types */
#if BSDCOMPRESS_SUPPORT
    ao->bsd_compress = go->bsd_compress = 0;
#endif /* BSDCOMPRESS_SUPPORT */
#if PREDICTOR_SUPPORT
    ao->predictor_1 = go->predictor_1 = 0;
    ao->predictor_2 = go->predictor_2 = 0;
#endif /* PREDICTOR_SUPPORT */
#if DEFLATE_SUPPORT
    ao->deflate = go->deflate = 0;
#endif /* DEFLATE_SUPPORT */
  }
#endif /* MPPE_SUPPORT */

  /*
   * Check whether the kernel knows about the various
   * compression methods we might request.
   */
#if BSDCOMPRESS_SUPPORT
  /* FIXME: we don't need to test if BSD compress is available
   * if BSDCOMPRESS_SUPPORT is set, it is.
   */
  if (go->bsd_compress) {
    opt_buf[0] = CI_BSD_COMPRESS;
    opt_buf[1] = CILEN_BSD_COMPRESS;
    for (;;) {
      if (go->bsd_bits < BSD_MIN_BITS) {
        go->bsd_compress = 0;
        break;
      }
      opt_buf[2] = BSD_MAKE_OPT(BSD_CURRENT_VERSION, go->bsd_bits);
      res = ccp_test(pcb, opt_buf, CILEN_BSD_COMPRESS, 0);
      if (res > 0) {
        break;
      } else if (res < 0) {
        go->bsd_compress = 0;
        break;
      }
      go->bsd_bits--;
    }
  }
#endif /* BSDCOMPRESS_SUPPORT */
#if DEFLATE_SUPPORT
  /* FIXME: we don't need to test if deflate is available
   * if DEFLATE_SUPPORT is set, it is.
   */
  if (go->deflate) {
    if (go->deflate_correct) {
      opt_buf[0] = CI_DEFLATE;
      opt_buf[1] = CILEN_DEFLATE;
      opt_buf[3] = DEFLATE_CHK_SEQUENCE;
      for (;;) {
        if (go->deflate_size < DEFLATE_MIN_WORKS) {
          go->deflate_correct = 0;
          break;
        }
        opt_buf[2] = DEFLATE_MAKE_OPT(go->deflate_size);
        res = ccp_test(pcb, opt_buf, CILEN_DEFLATE, 0);
        if (res > 0) {
          break;
        } else if (res < 0) {
          go->deflate_correct = 0;
          break;
        }
        go->deflate_size--;
      }
    }
    if (go->deflate_draft) {
      opt_buf[0] = CI_DEFLATE_DRAFT;
      opt_buf[1] = CILEN_DEFLATE;
      opt_buf[3] = DEFLATE_CHK_SEQUENCE;
      for (;;) {
        if (go->deflate_size < DEFLATE_MIN_WORKS) {
          go->deflate_draft = 0;
          break;
        }
        opt_buf[2] = DEFLATE_MAKE_OPT(go->deflate_size);
        res = ccp_test(pcb, opt_buf, CILEN_DEFLATE, 0);
        if (res > 0) {
          break;
        } else if (res < 0) {
          go->deflate_draft = 0;
          break;
        }
        go->deflate_size--;
      }
    }
    if (!go->deflate_correct && !go->deflate_draft)
      go->deflate = 0;
  }
#endif /* DEFLATE_SUPPORT */
#if PREDICTOR_SUPPORT
  /* FIXME: we don't need to test if predictor is available,
   * if PREDICTOR_SUPPORT is set, it is.
   */
  if (go->predictor_1) {
    opt_buf[0] = CI_PREDICTOR_1;
    opt_buf[1] = CILEN_PREDICTOR_1;
    if (ccp_test(pcb, opt_buf, CILEN_PREDICTOR_1, 0) <= 0)
      go->predictor_1 = 0;
  }
  if (go->predictor_2) {
    opt_buf[0] = CI_PREDICTOR_2;
    opt_buf[1] = CILEN_PREDICTOR_2;
    if (ccp_test(pcb, opt_buf, CILEN_PREDICTOR_2, 0) <= 0)
      go->predictor_2 = 0;
  }
#endif /* PREDICTOR_SUPPORT */
}

static void ccp_addci(fsm *f, u_char *p, int *lenp) {
  ppp_pcb *pcb = f->pcb;
  ccp_options *go = &pcb->ccp_gotoptions;
  u_char *p0 = p;

  /*
   * Add the compression types that we can receive, in decreasing
   * preference order.
   */
#if MPPE_SUPPORT
  if (go->mppe) {
    p[0] = CI_MPPE;
    p[1] = CILEN_MPPE;
    MPPE_OPTS_TO_CI(go->mppe, &p[2]);
    mppe_init(pcb, &pcb->mppe_decomp, go->mppe);
    p += CILEN_MPPE;
  }
#endif /* MPPE_SUPPORT */
#if DEFLATE_SUPPORT
  if (go->deflate) {
    if (go->deflate_correct) {
      p[0] = CI_DEFLATE;
      p[1] = CILEN_DEFLATE;
      p[2] = DEFLATE_MAKE_OPT(go->deflate_size);
      p[3] = DEFLATE_CHK_SEQUENCE;
      p += CILEN_DEFLATE;
    }
    if (go->deflate_draft) {
      p[0] = CI_DEFLATE_DRAFT;
      p[1] = CILEN_DEFLATE;
      p[2] = p[2 - CILEN_DEFLATE];
      p[3] = DEFLATE_CHK_SEQUENCE;
      p += CILEN_DEFLATE;
    }
  }
#endif /* DEFLATE_SUPPORT */
#if BSDCOMPRESS_SUPPORT
  if (go->bsd_compress) {
    p[0] = CI_BSD_COMPRESS;
    p[1] = CILEN_BSD_COMPRESS;
    p[2] = BSD_MAKE_OPT(BSD_CURRENT_VERSION, go->bsd_bits);
    p += CILEN_BSD_COMPRESS;
  }
#endif /* BSDCOMPRESS_SUPPORT */
#if PREDICTOR_SUPPORT
  /* XXX Should Predictor 2 be preferable to Predictor 1? */
  if (go->predictor_1) {
    p[0] = CI_PREDICTOR_1;
    p[1] = CILEN_PREDICTOR_1;
    p += CILEN_PREDICTOR_1;
  }
  if (go->predictor_2) {
    p[0] = CI_PREDICTOR_2;
    p[1] = CILEN_PREDICTOR_2;
    p += CILEN_PREDICTOR_2;
  }
#endif /* PREDICTOR_SUPPORT */

  go->method = (p > p0) ? p0[0] : 0;

  *lenp = p - p0;
}

static int ccp_ackci(fsm *f, u_char *p, int len) {
  ppp_pcb *pcb = f->pcb;
  ccp_options *go = &pcb->ccp_gotoptions;
#if BSDCOMPRESS_SUPPORT || PREDICTOR_SUPPORT
  u_char *p0 = p;
#endif /* BSDCOMPRESS_SUPPORT || PREDICTOR_SUPPORT */

#if MPPE_SUPPORT
  if (go->mppe) {
    u_char opt_buf[CILEN_MPPE];

    opt_buf[0] = CI_MPPE;
    opt_buf[1] = CILEN_MPPE;
    MPPE_OPTS_TO_CI(go->mppe, &opt_buf[2]);
    if (len < CILEN_MPPE || memcmp(opt_buf, p, CILEN_MPPE))
      return 0;
    p += CILEN_MPPE;
    len -= CILEN_MPPE;
    /* XXX Cope with first/fast ack */
    if (len == 0)
      return 1;
  }
#endif /* MPPE_SUPPORT */
#if DEFLATE_SUPPORT
  if (go->deflate) {
    if (len < CILEN_DEFLATE ||
        p[0] != (go->deflate_correct ? CI_DEFLATE : CI_DEFLATE_DRAFT) ||
        p[1] != CILEN_DEFLATE || p[2] != DEFLATE_MAKE_OPT(go->deflate_size) ||
        p[3] != DEFLATE_CHK_SEQUENCE)
      return 0;
    p += CILEN_DEFLATE;
    len -= CILEN_DEFLATE;
    /* XXX Cope with first/fast ack */
    if (len == 0)
      return 1;
    if (go->deflate_correct && go->deflate_draft) {
      if (len < CILEN_DEFLATE || p[0] != CI_DEFLATE_DRAFT ||
          p[1] != CILEN_DEFLATE || p[2] != DEFLATE_MAKE_OPT(go->deflate_size) ||
          p[3] != DEFLATE_CHK_SEQUENCE)
        return 0;
      p += CILEN_DEFLATE;
      len -= CILEN_DEFLATE;
    }
  }
#endif /* DEFLATE_SUPPORT */
#if BSDCOMPRESS_SUPPORT
  if (go->bsd_compress) {
    if (len < CILEN_BSD_COMPRESS || p[0] != CI_BSD_COMPRESS ||
        p[1] != CILEN_BSD_COMPRESS ||
        p[2] != BSD_MAKE_OPT(BSD_CURRENT_VERSION, go->bsd_bits))
      return 0;
    p += CILEN_BSD_COMPRESS;
    len -= CILEN_BSD_COMPRESS;
    /* XXX Cope with first/fast ack */
    if (p == p0 && len == 0)
      return 1;
  }
#endif /* BSDCOMPRESS_SUPPORT */
#if PREDICTOR_SUPPORT
  if (go->predictor_1) {
    if (len < CILEN_PREDICTOR_1 || p[0] != CI_PREDICTOR_1 ||
        p[1] != CILEN_PREDICTOR_1)
      return 0;
    p += CILEN_PREDICTOR_1;
    len -= CILEN_PREDICTOR_1;
    /* XXX Cope with first/fast ack */
    if (p == p0 && len == 0)
      return 1;
  }
  if (go->predictor_2) {
    if (len < CILEN_PREDICTOR_2 || p[0] != CI_PREDICTOR_2 ||
        p[1] != CILEN_PREDICTOR_2)
      return 0;
    p += CILEN_PREDICTOR_2;
    len -= CILEN_PREDICTOR_2;
    /* XXX Cope with first/fast ack */
    if (p == p0 && len == 0)
      return 1;
  }
#endif /* PREDICTOR_SUPPORT */

  if (len != 0)
    return 0;
  return 1;
}

static int ccp_nakci(fsm *f, u_char *p, int len, int treat_as_reject) {
  ppp_pcb *pcb = f->pcb;
  ccp_options *go = &pcb->ccp_gotoptions;
  ccp_options no;   /* options we've seen already */
  ccp_options try_; /* options to ask for next time */
  LWIP_UNUSED_ARG(treat_as_reject);
#if !MPPE_SUPPORT && !DEFLATE_SUPPORT && !BSDCOMPRESS_SUPPORT
  LWIP_UNUSED_ARG(p);
  LWIP_UNUSED_ARG(len);
#endif /* !MPPE_SUPPORT && !DEFLATE_SUPPORT && !BSDCOMPRESS_SUPPORT */

  memset(&no, 0, sizeof(no));
  try_ = *go;

#if MPPE_SUPPORT
  if (go->mppe && len >= CILEN_MPPE && p[0] == CI_MPPE && p[1] == CILEN_MPPE) {
    no.mppe = 1;
    /*
     * Peer wants us to use a different strength or other setting.
     * Fail if we aren't willing to use his suggestion.
     */
    MPPE_CI_TO_OPTS(&p[2], try_.mppe);
    if ((try_.mppe & MPPE_OPT_STATEFUL) && pcb->settings.refuse_mppe_stateful) {
      ppp_error(("Refusing MPPE stateful mode offered by peer"));
      try_.mppe = 0;
    } else if (((go->mppe | MPPE_OPT_STATEFUL) & try_.mppe) != try_.mppe) {
      /* Peer must have set options we didn't request (suggest) */
      try_.mppe = 0;
    }

    if (!try_.mppe) {
      ppp_error(("MPPE required but peer negotiation failed"));
      lcp_close(pcb, "MPPE required but peer negotiation failed");
    }
  }
#endif /* MPPE_SUPPORT */
#if DEFLATE_SUPPORT
  if (go->deflate && len >= CILEN_DEFLATE &&
      p[0] == (go->deflate_correct ? CI_DEFLATE : CI_DEFLATE_DRAFT) &&
      p[1] == CILEN_DEFLATE) {
    no.deflate = 1;
    /*
     * Peer wants us to use a different code size or something.
     * Stop asking for Deflate if we don't understand his suggestion.
     */
    if (DEFLATE_METHOD(p[2]) != DEFLATE_METHOD_VAL ||
        DEFLATE_SIZE(p[2]) < DEFLATE_MIN_WORKS || p[3] != DEFLATE_CHK_SEQUENCE)
      try_.deflate = 0;
    else if (DEFLATE_SIZE(p[2]) < go->deflate_size)
      try_.deflate_size = DEFLATE_SIZE(p[2]);
    p += CILEN_DEFLATE;
    len -= CILEN_DEFLATE;
    if (go->deflate_correct && go->deflate_draft && len >= CILEN_DEFLATE &&
        p[0] == CI_DEFLATE_DRAFT && p[1] == CILEN_DEFLATE) {
      p += CILEN_DEFLATE;
      len -= CILEN_DEFLATE;
    }
  }
#endif /* DEFLATE_SUPPORT */
#if BSDCOMPRESS_SUPPORT
  if (go->bsd_compress && len >= CILEN_BSD_COMPRESS &&
      p[0] == CI_BSD_COMPRESS && p[1] == CILEN_BSD_COMPRESS) {
    no.bsd_compress = 1;
    /*
     * Peer wants us to use a different number of bits
     * or a different version.
     */
    if (BSD_VERSION(p[2]) != BSD_CURRENT_VERSION)
      try_.bsd_compress = 0;
    else if (BSD_NBITS(p[2]) < go->bsd_bits)
      try_.bsd_bits = BSD_NBITS(p[2]);
    p += CILEN_BSD_COMPRESS;
    len -= CILEN_BSD_COMPRESS;
  }
#endif /* BSDCOMPRESS_SUPPORT */

  /*
   * Predictor-1 and 2 have no options, so they can't be Naked.
   *
   * There may be remaining options but we ignore them.
   */

  if (f->state != PPP_FSM_OPENED)
    *go = try_;
  return 1;
}

static int ccp_rejci(fsm *f, u_char *p, int len) {
  ppp_pcb *pcb = f->pcb;
  ccp_options *go = &pcb->ccp_gotoptions;
  ccp_options try_; /* options to request next time */

  try_ = *go;

  /*
   * Cope with empty configure-rejects by ceasing to send
   * configure-requests.
   */
  if (len == 0 && pcb->ccp_all_rejected)
    return -1;

#if MPPE_SUPPORT
  if (go->mppe && len >= CILEN_MPPE && p[0] == CI_MPPE && p[1] == CILEN_MPPE) {
    ppp_error(("MPPE required but peer refused"));
    lcp_close(pcb, "MPPE required but peer refused");
    p += CILEN_MPPE;
    len -= CILEN_MPPE;
  }
#endif /* MPPE_SUPPORT */
#if DEFLATE_SUPPORT
  if (go->deflate_correct && len >= CILEN_DEFLATE && p[0] == CI_DEFLATE &&
      p[1] == CILEN_DEFLATE) {
    if (p[2] != DEFLATE_MAKE_OPT(go->deflate_size) ||
        p[3] != DEFLATE_CHK_SEQUENCE)
      return 0; /* Rej is bad */
    try_.deflate_correct = 0;
    p += CILEN_DEFLATE;
    len -= CILEN_DEFLATE;
  }
  if (go->deflate_draft && len >= CILEN_DEFLATE && p[0] == CI_DEFLATE_DRAFT &&
      p[1] == CILEN_DEFLATE) {
    if (p[2] != DEFLATE_MAKE_OPT(go->deflate_size) ||
        p[3] != DEFLATE_CHK_SEQUENCE)
      return 0; /* Rej is bad */
    try_.deflate_draft = 0;
    p += CILEN_DEFLATE;
    len -= CILEN_DEFLATE;
  }
  if (!try_.deflate_correct && !try_.deflate_draft)
    try_.deflate = 0;
#endif /* DEFLATE_SUPPORT */
#if BSDCOMPRESS_SUPPORT
  if (go->bsd_compress && len >= CILEN_BSD_COMPRESS &&
      p[0] == CI_BSD_COMPRESS && p[1] == CILEN_BSD_COMPRESS) {
    if (p[2] != BSD_MAKE_OPT(BSD_CURRENT_VERSION, go->bsd_bits))
      return 0;
    try_.bsd_compress = 0;
    p += CILEN_BSD_COMPRESS;
    len -= CILEN_BSD_COMPRESS;
  }
#endif /* BSDCOMPRESS_SUPPORT */
#if PREDICTOR_SUPPORT
  if (go->predictor_1 && len >= CILEN_PREDICTOR_1 && p[0] == CI_PREDICTOR_1 &&
      p[1] == CILEN_PREDICTOR_1) {
    try_.predictor_1 = 0;
    p += CILEN_PREDICTOR_1;
    len -= CILEN_PREDICTOR_1;
  }
  if (go->predictor_2 && len >= CILEN_PREDICTOR_2 && p[0] == CI_PREDICTOR_2 &&
      p[1] == CILEN_PREDICTOR_2) {
    try_.predictor_2 = 0;
    p += CILEN_PREDICTOR_2;
    len -= CILEN_PREDICTOR_2;
  }
#endif /* PREDICTOR_SUPPORT */

  if (len != 0)
    return 0;

  if (f->state != PPP_FSM_OPENED)
    *go = try_;

  return 1;
}

static int ccp_reqci(fsm *f, u_char *p, int *lenp, int dont_nak) {
  ppp_pcb *pcb = f->pcb;
  ccp_options *ho = &pcb->ccp_hisoptions;
  ccp_options *ao = &pcb->ccp_allowoptions;
  int ret, newret;
#if DEFLATE_SUPPORT || BSDCOMPRESS_SUPPORT
  int res;
  int nb;
#endif /* DEFLATE_SUPPORT || BSDCOMPRESS_SUPPORT */
  u_char *p0, *retp;
  int len, clen, type;
#if MPPE_SUPPORT
  u8_t rej_for_ci_mppe = 1; /* Are we rejecting based on a bad/missing */
                            /* CI_MPPE, or due to other options?       */
#endif                      /* MPPE_SUPPORT */

  ret = CONFACK;
  retp = p0 = p;
  len = *lenp;

  memset(ho, 0, sizeof(ccp_options));
  ho->method = (len > 0) ? p[0] : 0;

  while (len > 0) {
    newret = CONFACK;
    if (len < 2 || p[1] < 2 || p[1] > len) {
      /* length is bad */
      clen = len;
      newret = CONFREJ;

    } else {
      type = p[0];
      clen = p[1];

      switch (type) {
#if MPPE_SUPPORT
      case CI_MPPE:
        if (!ao->mppe || clen != CILEN_MPPE) {
          newret = CONFREJ;
          break;
        }
        MPPE_CI_TO_OPTS(&p[2], ho->mppe);

        /* Nak if anything unsupported or unknown are set. */
        if (ho->mppe & MPPE_OPT_UNSUPPORTED) {
          newret = CONFNAK;
          ho->mppe &= ~MPPE_OPT_UNSUPPORTED;
        }
        if (ho->mppe & MPPE_OPT_UNKNOWN) {
          newret = CONFNAK;
          ho->mppe &= ~MPPE_OPT_UNKNOWN;
        }

        /* Check state opt */
        if (ho->mppe & MPPE_OPT_STATEFUL) {
          /*
           * We can Nak and request stateless, but it's a
           * lot easier to just assume the peer will request
           * it if he can do it; stateful mode is bad over
           * the Internet -- which is where we expect MPPE.
           */
          if (pcb->settings.refuse_mppe_stateful) {
            ppp_error(("Refusing MPPE stateful mode offered by peer"));
            newret = CONFREJ;
            break;
          }
        }

        /* Find out which of {S,L} are set. */
        if ((ho->mppe & MPPE_OPT_128) && (ho->mppe & MPPE_OPT_40)) {
          /* Both are set, negotiate the strongest. */
          newret = CONFNAK;
          if (ao->mppe & MPPE_OPT_128)
            ho->mppe &= ~MPPE_OPT_40;
          else if (ao->mppe & MPPE_OPT_40)
            ho->mppe &= ~MPPE_OPT_128;
          else {
            newret = CONFREJ;
            break;
          }
        } else if (ho->mppe & MPPE_OPT_128) {
          if (!(ao->mppe & MPPE_OPT_128)) {
            newret = CONFREJ;
            break;
          }
        } else if (ho->mppe & MPPE_OPT_40) {
          if (!(ao->mppe & MPPE_OPT_40)) {
            newret = CONFREJ;
            break;
          }
        } else {
          /* Neither are set. */
          /* We cannot accept this.  */
          newret = CONFNAK;
          /* Give the peer our idea of what can be used,
             so it can choose and confirm */
          ho->mppe = ao->mppe;
        }

        /* rebuild the opts */
        MPPE_OPTS_TO_CI(ho->mppe, &p[2]);
        if (newret == CONFACK) {
          int mtu;

          mppe_init(pcb, &pcb->mppe_comp, ho->mppe);
          /*
           * We need to decrease the interface MTU by MPPE_PAD
           * because MPPE frames **grow**.  The kernel [must]
           * allocate MPPE_PAD extra bytes in xmit buffers.
           */
          mtu = ppp_netif_get_mtu(pcb);
          if (mtu)
            ppp_netif_set_mtu(pcb, mtu - MPPE_PAD);
          else
            newret = CONFREJ;
        }

        /*
         * We have accepted MPPE or are willing to negotiate
         * MPPE parameters.  A CONFREJ is due to subsequent
         * (non-MPPE) processing.
         */
        rej_for_ci_mppe = 0;
        break;
#endif /* MPPE_SUPPORT */
#if DEFLATE_SUPPORT
      case CI_DEFLATE:
      case CI_DEFLATE_DRAFT:
        if (!ao->deflate || clen != CILEN_DEFLATE ||
            (!ao->deflate_correct && type == CI_DEFLATE) ||
            (!ao->deflate_draft && type == CI_DEFLATE_DRAFT)) {
          newret = CONFREJ;
          break;
        }

        ho->deflate = 1;
        ho->deflate_size = nb = DEFLATE_SIZE(p[2]);
        if (DEFLATE_METHOD(p[2]) != DEFLATE_METHOD_VAL ||
            p[3] != DEFLATE_CHK_SEQUENCE || nb > ao->deflate_size ||
            nb < DEFLATE_MIN_WORKS) {
          newret = CONFNAK;
          if (!dont_nak) {
            p[2] = DEFLATE_MAKE_OPT(ao->deflate_size);
            p[3] = DEFLATE_CHK_SEQUENCE;
            /* fall through to test this #bits below */
          } else
            break;
        }

        /*
         * Check whether we can do Deflate with the window
         * size they want.  If the window is too big, reduce
         * it until the kernel can cope and nak with that.
         * We only check this for the first option.
         */
        if (p == p0) {
          for (;;) {
            res = ccp_test(pcb, p, CILEN_DEFLATE, 1);
            if (res > 0)
              break; /* it's OK now */
            if (res < 0 || nb == DEFLATE_MIN_WORKS || dont_nak) {
              newret = CONFREJ;
              p[2] = DEFLATE_MAKE_OPT(ho->deflate_size);
              break;
            }
            newret = CONFNAK;
            --nb;
            p[2] = DEFLATE_MAKE_OPT(nb);
          }
        }
        break;
#endif /* DEFLATE_SUPPORT */
#if BSDCOMPRESS_SUPPORT
      case CI_BSD_COMPRESS:
        if (!ao->bsd_compress || clen != CILEN_BSD_COMPRESS) {
          newret = CONFREJ;
          break;
        }

        ho->bsd_compress = 1;
        ho->bsd_bits = nb = BSD_NBITS(p[2]);
        if (BSD_VERSION(p[2]) != BSD_CURRENT_VERSION || nb > ao->bsd_bits ||
            nb < BSD_MIN_BITS) {
          newret = CONFNAK;
          if (!dont_nak) {
            p[2] = BSD_MAKE_OPT(BSD_CURRENT_VERSION, ao->bsd_bits);
            /* fall through to test this #bits below */
          } else
            break;
        }

        /*
         * Check whether we can do BSD-Compress with the code
         * size they want.  If the code size is too big, reduce
         * it until the kernel can cope and nak with that.
         * We only check this for the first option.
         */
        if (p == p0) {
          for (;;) {
            res = ccp_test(pcb, p, CILEN_BSD_COMPRESS, 1);
            if (res > 0)
              break;
            if (res < 0 || nb == BSD_MIN_BITS || dont_nak) {
              newret = CONFREJ;
              p[2] = BSD_MAKE_OPT(BSD_CURRENT_VERSION, ho->bsd_bits);
              break;
            }
            newret = CONFNAK;
            --nb;
            p[2] = BSD_MAKE_OPT(BSD_CURRENT_VERSION, nb);
          }
        }
        break;
#endif /* BSDCOMPRESS_SUPPORT */
#if PREDICTOR_SUPPORT
      case CI_PREDICTOR_1:
        if (!ao->predictor_1 || clen != CILEN_PREDICTOR_1) {
          newret = CONFREJ;
          break;
        }

        ho->predictor_1 = 1;
        if (p == p0 && ccp_test(pcb, p, CILEN_PREDICTOR_1, 1) <= 0) {
          newret = CONFREJ;
        }
        break;

      case CI_PREDICTOR_2:
        if (!ao->predictor_2 || clen != CILEN_PREDICTOR_2) {
          newret = CONFREJ;
          break;
        }

        ho->predictor_2 = 1;
        if (p == p0 && ccp_test(pcb, p, CILEN_PREDICTOR_2, 1) <= 0) {
          newret = CONFREJ;
        }
        break;
#endif /* PREDICTOR_SUPPORT */

      default:
        newret = CONFREJ;
      }
    }

    if (newret == CONFNAK && dont_nak)
      newret = CONFREJ;
    if (!(newret == CONFACK || (newret == CONFNAK && ret == CONFREJ))) {
      /* we're returning this option */
      if (newret == CONFREJ && ret == CONFNAK)
        retp = p0;
      ret = newret;
      if (p != retp)
        MEMCPY(retp, p, clen);
      retp += clen;
    }

    p += clen;
    len -= clen;
  }

  if (ret != CONFACK) {
    if (ret == CONFREJ && *lenp == retp - p0)
      pcb->ccp_all_rejected = 1;
    else
      *lenp = retp - p0;
  }
#if MPPE_SUPPORT
  if (ret == CONFREJ && ao->mppe && rej_for_ci_mppe) {
    ppp_error(("MPPE required but peer negotiation failed"));
    lcp_close(pcb, "MPPE required but peer negotiation failed");
  }
#endif /* MPPE_SUPPORT */
  return ret;
}

static const char *method_name(ccp_options *opt, ccp_options *opt2) {
  static char result[64];
#if !DEFLATE_SUPPORT && !BSDCOMPRESS_SUPPORT
  LWIP_UNUSED_ARG(opt2);
#endif /* !DEFLATE_SUPPORT && !BSDCOMPRESS_SUPPORT */

  if (!ccp_anycompress(opt))
    return "(none)";
  switch (opt->method) {
#if MPPE_SUPPORT
  case CI_MPPE: {
    char *p = result;
    char *q = result + sizeof(result); /* 1 past result */

    ppp_slprintf(p, q - p, "MPPE ");
    p += 5;
    if (opt->mppe & MPPE_OPT_128) {
      ppp_slprintf(p, q - p, "128-bit ");
      p += 8;
    }
    if (opt->mppe & MPPE_OPT_40) {
      ppp_slprintf(p, q - p, "40-bit ");
      p += 7;
    }
    if (opt->mppe & MPPE_OPT_STATEFUL)
      ppp_slprintf(p, q - p, "stateful");
    else
      ppp_slprintf(p, q - p, "stateless");

    break;
  }
#endif /* MPPE_SUPPORT */
#if DEFLATE_SUPPORT
  case CI_DEFLATE:
  case CI_DEFLATE_DRAFT:
    if (opt2 != NULL && opt2->deflate_size != opt->deflate_size)
      ppp_slprintf(result, sizeof(result), "Deflate%s (%d/%d)",
                   (opt->method == CI_DEFLATE_DRAFT ? "(old#)" : ""),
                   opt->deflate_size, opt2->deflate_size);
    else
      ppp_slprintf(result, sizeof(result), "Deflate%s (%d)",
                   (opt->method == CI_DEFLATE_DRAFT ? "(old#)" : ""),
                   opt->deflate_size);
    break;
#endif /* DEFLATE_SUPPORT */
#if BSDCOMPRESS_SUPPORT
  case CI_BSD_COMPRESS:
    if (opt2 != NULL && opt2->bsd_bits != opt->bsd_bits)
      ppp_slprintf(result, sizeof(result), "BSD-Compress (%d/%d)",
                   opt->bsd_bits, opt2->bsd_bits);
    else
      ppp_slprintf(result, sizeof(result), "BSD-Compress (%d)", opt->bsd_bits);
    break;
#endif /* BSDCOMPRESS_SUPPORT */
#if PREDICTOR_SUPPORT
  case CI_PREDICTOR_1:
    return "Predictor 1";
  case CI_PREDICTOR_2:
    return "Predictor 2";
#endif /* PREDICTOR_SUPPORT */
  default:
    ppp_slprintf(result, sizeof(result), "Method %d", opt->method);
  }
  return result;
}

static void ccp_up(fsm *f) {
  ppp_pcb *pcb = f->pcb;
  ccp_options *go = &pcb->ccp_gotoptions;
  ccp_options *ho = &pcb->ccp_hisoptions;
  char method1[64];

  ccp_set(pcb, 1, 1, go->method, ho->method);
  if (ccp_anycompress(go)) {
    if (ccp_anycompress(ho)) {
      if (go->method == ho->method) {
        ppp_notice(("%s compression enabled", method_name(go, ho)));
      } else {
        ppp_strlcpy(method1, method_name(go, NULL), sizeof(method1));
        ppp_notice(
            ("%s / %s compression enabled", method1, method_name(ho, NULL)));
      }
    } else
      ppp_notice(("%s receive compression enabled", method_name(go, NULL)));
  } else if (ccp_anycompress(ho))
    ppp_notice(("%s transmit compression enabled", method_name(ho, NULL)));
#if MPPE_SUPPORT
  if (go->mppe) {
    continue_networks(pcb); /* Bring up IP et al */
  }
#endif /* MPPE_SUPPORT */
}

static void ccp_down(fsm *f) {
  ppp_pcb *pcb = f->pcb;
#if MPPE_SUPPORT
  ccp_options *go = &pcb->ccp_gotoptions;
#endif /* MPPE_SUPPORT */

  if (pcb->ccp_localstate & RACK_PENDING)
    UNTIMEOUT(ccp_rack_timeout, f);
  pcb->ccp_localstate = 0;
  ccp_set(pcb, 1, 0, 0, 0);
#if MPPE_SUPPORT
  if (go->mppe) {
    go->mppe = 0;
    if (pcb->lcp_fsm.state == PPP_FSM_OPENED) {
      /* If LCP is not already going down, make sure it does. */
      ppp_error(("MPPE disabled"));
      lcp_close(pcb, "MPPE disabled");
    }
  }
#endif /* MPPE_SUPPORT */
}

static int ccp_printpkt(const u_char *p, int plen,
                        void (*printer)(void *, const char *, ...), void *arg) {
  const u_char *p0, *optend;
  int code, id, len;
  int optlen;

  p0 = p;
  if (plen < HEADERLEN)
    return 0;
  code = p[0];
  id = p[1];
  len = (p[2] << 8) + p[3];
  if (len < HEADERLEN || len > plen)
    return 0;

  if (code >= 1 && code <= (int)LWIP_ARRAYSIZE(ccp_codenames) &&
      ccp_codenames[code - 1] != NULL)
    printer(arg, " %s", ccp_codenames[code - 1]);
  else
    printer(arg, " code=0x%x", code);
  printer(arg, " id=0x%x", id);
  len -= HEADERLEN;
  p += HEADERLEN;

  switch (code) {
  case CONFREQ:
  case CONFACK:
  case CONFNAK:
  case CONFREJ:
    /* print list of possible compression methods */
    while (len >= 2) {
      code = p[0];
      optlen = p[1];
      if (optlen < 2 || optlen > len)
        break;
      printer(arg, " <");
      len -= optlen;
      optend = p + optlen;
      switch (code) {
#if MPPE_SUPPORT
      case CI_MPPE:
        if (optlen >= CILEN_MPPE) {
          u_char mppe_opts;

          MPPE_CI_TO_OPTS(&p[2], mppe_opts);
          printer(arg, "mppe %s %s %s %s %s %s%s",
                  (p[2] & MPPE_H_BIT) ? "+H" : "-H",
                  (p[5] & MPPE_M_BIT) ? "+M" : "-M",
                  (p[5] & MPPE_S_BIT) ? "+S" : "-S",
                  (p[5] & MPPE_L_BIT) ? "+L" : "-L",
                  (p[5] & MPPE_D_BIT) ? "+D" : "-D",
                  (p[5] & MPPE_C_BIT) ? "+C" : "-C",
                  (mppe_opts & MPPE_OPT_UNKNOWN) ? " +U" : "");
          if (mppe_opts & MPPE_OPT_UNKNOWN)
            printer(arg, " (%.2x %.2x %.2x %.2x)", p[2], p[3], p[4], p[5]);
          p += CILEN_MPPE;
        }
        break;
#endif /* MPPE_SUPPORT */
#if DEFLATE_SUPPORT
      case CI_DEFLATE:
      case CI_DEFLATE_DRAFT:
        if (optlen >= CILEN_DEFLATE) {
          printer(arg, "deflate%s %d",
                  (code == CI_DEFLATE_DRAFT ? "(old#)" : ""),
                  DEFLATE_SIZE(p[2]));
          if (DEFLATE_METHOD(p[2]) != DEFLATE_METHOD_VAL)
            printer(arg, " method %d", DEFLATE_METHOD(p[2]));
          if (p[3] != DEFLATE_CHK_SEQUENCE)
            printer(arg, " check %d", p[3]);
          p += CILEN_DEFLATE;
        }
        break;
#endif /* DEFLATE_SUPPORT */
#if BSDCOMPRESS_SUPPORT
      case CI_BSD_COMPRESS:
        if (optlen >= CILEN_BSD_COMPRESS) {
          printer(arg, "bsd v%d %d", BSD_VERSION(p[2]), BSD_NBITS(p[2]));
          p += CILEN_BSD_COMPRESS;
        }
        break;
#endif /* BSDCOMPRESS_SUPPORT */
#if PREDICTOR_SUPPORT
      case CI_PREDICTOR_1:
        if (optlen >= CILEN_PREDICTOR_1) {
          printer(arg, "predictor 1");
          p += CILEN_PREDICTOR_1;
        }
        break;
      case CI_PREDICTOR_2:
        if (optlen >= CILEN_PREDICTOR_2) {
          printer(arg, "predictor 2");
          p += CILEN_PREDICTOR_2;
        }
        break;
#endif /* PREDICTOR_SUPPORT */
      default:
        break;
      }
      while (p < optend)
        printer(arg, " %.2x", *p++);
      printer(arg, ">");
    }
    break;

  case TERMACK:
  case TERMREQ:
    if (len > 0 && *p >= ' ' && *p < 0x7f) {
      ppp_print_string(p, len, printer, arg);
      p += len;
      len = 0;
    }
    break;
  default:
    break;
  }

  /* dump out the rest of the packet in hex */
  while (--len >= 0)
    printer(arg, " %.2x", *p++);

  return p - p0;
}

static void ccp_datainput(ppp_pcb *pcb, u_char *pkt, int len) {
  fsm *f;
#if MPPE_SUPPORT
  ccp_options *go = &pcb->ccp_gotoptions;
#endif /* MPPE_SUPPORT */
  LWIP_UNUSED_ARG(pkt);
  LWIP_UNUSED_ARG(len);

  f = &pcb->ccp_fsm;
  if (f->state == PPP_FSM_OPENED) {
    if (ccp_fatal_error(pcb)) {
      /*
       * Disable compression by taking CCP down.
       */
      ppp_error(("Lost compression sync: disabling compression"));
      ccp_close(pcb, "Lost compression sync");
#if MPPE_SUPPORT
      /*
       * If we were doing MPPE, we must also take the link down.
       */
      if (go->mppe) {
        ppp_error(("Too many MPPE errors, closing LCP"));
        lcp_close(pcb, "Too many MPPE errors");
      }
#endif /* MPPE_SUPPORT */
    } else {
      /*
       * Send a reset-request to reset the peer's compressor.
       * We don't do that if we are still waiting for an
       * acknowledgement to a previous reset-request.
       */
      if (!(pcb->ccp_localstate & RACK_PENDING)) {
        fsm_sdata(f, CCP_RESETREQ, f->reqid = ++f->id, NULL, 0);
        TIMEOUT(ccp_rack_timeout, f, RACKTIMEOUT);
        pcb->ccp_localstate |= RACK_PENDING;
      } else
        pcb->ccp_localstate |= RREQ_REPEAT;
    }
  }
}

void ccp_resetrequest(ppp_pcb *pcb) {
  fsm *f = &pcb->ccp_fsm;

  if (f->state != PPP_FSM_OPENED)
    return;

  /*
   * Send a reset-request to reset the peer's compressor.
   * We don't do that if we are still waiting for an
   * acknowledgement to a previous reset-request.
   */
  if (!(pcb->ccp_localstate & RACK_PENDING)) {
    fsm_sdata(f, CCP_RESETREQ, f->reqid = ++f->id, NULL, 0);
    TIMEOUT(ccp_rack_timeout, f, RACKTIMEOUT);
    pcb->ccp_localstate |= RACK_PENDING;
  } else
    pcb->ccp_localstate |= RREQ_REPEAT;
}

static void ccp_rack_timeout(void *arg) {
  fsm *f = (fsm *)arg;
  ppp_pcb *pcb = f->pcb;

  if (f->state == PPP_FSM_OPENED && (pcb->ccp_localstate & RREQ_REPEAT)) {
    fsm_sdata(f, CCP_RESETREQ, f->reqid, NULL, 0);
    TIMEOUT(ccp_rack_timeout, f, RACKTIMEOUT);
    pcb->ccp_localstate &= ~RREQ_REPEAT;
  } else
    pcb->ccp_localstate &= ~RACK_PENDING;
}

static void chap_md5_generate_challenge(ppp_pcb *pcb, unsigned char *cp) {
  int clen;
  LWIP_UNUSED_ARG(pcb);

  clen = MD5_MIN_CHALLENGE + magic_pow(MD5_MIN_MAX_POWER_OF_TWO_CHALLENGE);
  *cp++ = clen;
  magic_random_bytes(cp, clen);
}

static int chap_md5_verify_response(ppp_pcb *pcb, int id, const char *name,
                                    const unsigned char *secret, int secret_len,
                                    const unsigned char *challenge,
                                    const unsigned char *response,
                                    char *message, int message_space) {
  lwip_md5_context ctx;
  unsigned char idbyte = id;
  unsigned char hash[MD5_HASH_SIZE];
  int challenge_len, response_len;
  LWIP_UNUSED_ARG(name);
  LWIP_UNUSED_ARG(pcb);

  challenge_len = *challenge++;
  response_len = *response++;
  if (response_len == MD5_HASH_SIZE) {
    /* Generate hash of ID, secret, challenge */
    lwip_md5_init(&ctx);
    lwip_md5_starts(&ctx);
    lwip_md5_update(&ctx, &idbyte, 1);
    lwip_md5_update(&ctx, secret, secret_len);
    lwip_md5_update(&ctx, challenge, challenge_len);
    lwip_md5_finish(&ctx, hash);
    lwip_md5_free(&ctx);

    /* Test if our hash matches the peer's response */
    if (memcmp(hash, response, MD5_HASH_SIZE) == 0) {
      ppp_slprintf(message, message_space, "Access granted");
      return 1;
    }
  }
  ppp_slprintf(message, message_space, "Access denied");
  return 0;
}

static void chap_md5_make_response(ppp_pcb *pcb, unsigned char *response,
                                   int id, const char *our_name,
                                   const unsigned char *challenge,
                                   const char *secret, int secret_len,
                                   unsigned char *private_) {
  lwip_md5_context ctx;
  unsigned char idbyte = id;
  int challenge_len = *challenge++;
  LWIP_UNUSED_ARG(our_name);
  LWIP_UNUSED_ARG(private_);
  LWIP_UNUSED_ARG(pcb);

  lwip_md5_init(&ctx);
  lwip_md5_starts(&ctx);
  lwip_md5_update(&ctx, &idbyte, 1);
  lwip_md5_update(&ctx, (const u_char *)secret, secret_len);
  lwip_md5_update(&ctx, challenge, challenge_len);
  lwip_md5_finish(&ctx, &response[1]);
  lwip_md5_free(&ctx);
  response[0] = MD5_HASH_SIZE;
}

static void chap_init(ppp_pcb *pcb) {
  LWIP_UNUSED_ARG(pcb);

#if 0 /* Not necessary, everything is cleared in ppp_new() */
	memset(&pcb->chap_client, 0, sizeof(chap_client_state));
#if PPP_SERVER
	memset(&pcb->chap_server, 0, sizeof(chap_server_state));
#endif /* PPP_SERVER */
#endif /* 0 */
}

static void chap_lowerup(ppp_pcb *pcb) {

  pcb->chap_client.flags |= LOWERUP;
#if PPP_SERVER
  pcb->chap_server.flags |= LOWERUP;
  if (pcb->chap_server.flags & AUTH_STARTED)
    chap_timeout(pcb);
#endif /* PPP_SERVER */
}

static void chap_lowerdown(ppp_pcb *pcb) {

  pcb->chap_client.flags = 0;
#if PPP_SERVER
  if (pcb->chap_server.flags & TIMEOUT_PENDING)
    UNTIMEOUT(chap_timeout, pcb);
  pcb->chap_server.flags = 0;
#endif /* PPP_SERVER */
}

void chap_auth_peer(ppp_pcb *pcb, const char *our_name, int digest_code) {
  const struct chap_digest_type *dp;
  int i;

  if (pcb->chap_server.flags & AUTH_STARTED) {
    ppp_error(("CHAP: peer authentication already started!"));
    return;
  }
  for (i = 0; (dp = chap_digests[i]) != NULL; ++i)
    if (dp->code == digest_code)
      break;
  if (dp == NULL)
    ppp_fatal(("CHAP digest 0x%x requested but not available", digest_code));

  pcb->chap_server.digest = dp;
  pcb->chap_server.name = our_name;
  /* Start with a random ID value */
  pcb->chap_server.id = magic();
  pcb->chap_server.flags |= AUTH_STARTED;
  if (pcb->chap_server.flags & LOWERUP)
    chap_timeout(pcb);
}

void chap_auth_with_peer(ppp_pcb *pcb, const char *our_name, int digest_code) {
  const struct chap_digest_type *dp;
  int i;

  if (NULL == our_name)
    return;

  if (pcb->chap_client.flags & AUTH_STARTED) {
    ppp_error(("CHAP: authentication with peer already started!"));
    return;
  }
  for (i = 0; (dp = chap_digests[i]) != NULL; ++i)
    if (dp->code == digest_code)
      break;

  if (dp == NULL)
    ppp_fatal(("CHAP digest 0x%x requested but not available", digest_code));

  pcb->chap_client.digest = dp;
  pcb->chap_client.name = our_name;
  pcb->chap_client.flags |= AUTH_STARTED;
}

static void chap_timeout(void *arg) {
  ppp_pcb *pcb = (ppp_pcb *)arg;
  struct pbuf *p;

  pcb->chap_server.flags &= ~TIMEOUT_PENDING;
  if ((pcb->chap_server.flags & CHALLENGE_VALID) == 0) {
    pcb->chap_server.challenge_xmits = 0;
    chap_generate_challenge(pcb);
    pcb->chap_server.flags |= CHALLENGE_VALID;
  } else if (pcb->chap_server.challenge_xmits >=
             pcb->settings.chap_max_transmits) {
    pcb->chap_server.flags &= ~CHALLENGE_VALID;
    pcb->chap_server.flags |= AUTH_DONE | AUTH_FAILED;
    auth_peer_fail(pcb, PPP_CHAP);
    return;
  }

  p = pbuf_alloc(PBUF_RAW, (u16_t)(pcb->chap_server.challenge_pktlen),
                 PBUF_RAM);
  if (NULL == p)
    return;
  if (p->tot_len != p->len) {
    pbuf_free(p);
    return;
  }
  MEMCPY(p->payload, pcb->chap_server.challenge,
         pcb->chap_server.challenge_pktlen);
  ppp_write(pcb, p);
  ++pcb->chap_server.challenge_xmits;
  pcb->chap_server.flags |= TIMEOUT_PENDING;
  TIMEOUT(chap_timeout, arg, pcb->settings.chap_timeout_time);
}

static void chap_generate_challenge(ppp_pcb *pcb) {
  int clen = 1, nlen, len;
  unsigned char *p;

  p = pcb->chap_server.challenge;
  MAKEHEADER(p, PPP_CHAP);
  p += CHAP_HDRLEN;
  pcb->chap_server.digest->generate_challenge(pcb, p);
  clen = *p;
  nlen = strlen(pcb->chap_server.name);
  memcpy(p + 1 + clen, pcb->chap_server.name, nlen);

  len = CHAP_HDRLEN + 1 + clen + nlen;
  pcb->chap_server.challenge_pktlen = PPP_HDRLEN + len;

  p = pcb->chap_server.challenge + PPP_HDRLEN;
  p[0] = CHAP_CHALLENGE;
  p[1] = ++pcb->chap_server.id;
  p[2] = len >> 8;
  p[3] = len;
}

static int chap_verify_response(ppp_pcb *pcb, const char *name,
                                const char *ourname, int id,
                                const struct chap_digest_type *digest,
                                const unsigned char *challenge,
                                const unsigned char *response, char *message,
                                int message_space) {
  int ok;
  unsigned char secret[MAXSECRETLEN];
  int secret_len;

  /* Get the secret that the peer is supposed to know */
  if (!get_secret(pcb, name, ourname, (char *)secret, &secret_len, 1)) {
    ppp_error(("No CHAP secret found for authenticating %q", name));
    return 0;
  }
  ok = digest->verify_response(pcb, id, name, secret, secret_len, challenge,
                               response, message, message_space);
  memset(secret, 0, sizeof(secret));

  return ok;
}

static void chap_respond(ppp_pcb *pcb, int id, unsigned char *pkt, int len) {
  int clen, nlen;
  int secret_len;
  struct pbuf *p;
  u_char *outp;
  char rname[MAXNAMELEN + 1];
  char secret[MAXSECRETLEN + 1];

  p = pbuf_alloc(PBUF_RAW, (u16_t)(RESP_MAX_PKTLEN), PBUF_RAM);
  if (NULL == p)
    return;
  if (p->tot_len != p->len) {
    pbuf_free(p);
    return;
  }

  if ((pcb->chap_client.flags & (LOWERUP | AUTH_STARTED)) !=
      (LOWERUP | AUTH_STARTED))
    return; /* not ready */
  if (len < 2 || len < pkt[0] + 1)
    return; /* too short */
  clen = pkt[0];
  nlen = len - (clen + 1);

  /* Null terminate and clean remote name. */
  ppp_slprintf(rname, sizeof(rname), "%.*v", nlen, pkt + clen + 1);

#if PPP_REMOTENAME
  /* Microsoft doesn't send their name back in the PPP packet */
  if (pcb->settings.explicit_remote ||
      (pcb->settings.remote_name[0] != 0 && rname[0] == 0))
    strlcpy(rname, pcb->settings.remote_name, sizeof(rname));
#endif /* PPP_REMOTENAME */

  /* get secret for authenticating ourselves with the specified host */
  if (!get_secret(pcb, pcb->chap_client.name, rname, secret, &secret_len, 0)) {
    secret_len = 0; /* assume null secret if can't find one */
    ppp_warn(("No CHAP secret found for authenticating us to %q", rname));
  }

  outp = (u_char *)p->payload;
  MAKEHEADER(outp, PPP_CHAP);
  outp += CHAP_HDRLEN;

  pcb->chap_client.digest->make_response(pcb, outp, id, pcb->chap_client.name,
                                         pkt, secret, secret_len,
                                         pcb->chap_client.priv);
  memset(secret, 0, secret_len);

  clen = *outp;
  nlen = strlen(pcb->chap_client.name);
  memcpy(outp + clen + 1, pcb->chap_client.name, nlen);

  outp = (u_char *)p->payload + PPP_HDRLEN;
  len = CHAP_HDRLEN + clen + 1 + nlen;
  outp[0] = CHAP_RESPONSE;
  outp[1] = id;
  outp[2] = len >> 8;
  outp[3] = len;

  pbuf_realloc(p, PPP_HDRLEN + len);
  ppp_write(pcb, p);
}

static void chap_handle_status(ppp_pcb *pcb, int code, int id,
                               unsigned char *pkt, int len) {
  const char *msg = NULL;
  LWIP_UNUSED_ARG(id);

  if ((pcb->chap_client.flags & (AUTH_DONE | AUTH_STARTED | LOWERUP)) !=
      (AUTH_STARTED | LOWERUP))
    return;
  pcb->chap_client.flags |= AUTH_DONE;

  if (code == CHAP_SUCCESS) {
    /* used for MS-CHAP v2 mutual auth, yuck */
    if (pcb->chap_client.digest->check_success != NULL) {
      if (!(*pcb->chap_client.digest->check_success)(pcb, pkt, len,
                                                     pcb->chap_client.priv))
        code = CHAP_FAILURE;
    } else
      msg = "CHAP authentication succeeded";
  } else {
    if (pcb->chap_client.digest->handle_failure != NULL)
      (*pcb->chap_client.digest->handle_failure)(pcb, pkt, len);
    else
      msg = "CHAP authentication failed";
  }
  if (msg) {
    if (len > 0)
      ppp_info(("%s: %.*v", msg, len, pkt));
    else
      ppp_info(("%s", msg));
  }
  if (code == CHAP_SUCCESS)
    auth_withpeer_success(pcb, PPP_CHAP, pcb->chap_client.digest->code);
  else {
    pcb->chap_client.flags |= AUTH_FAILED;
    ppp_error(("CHAP authentication failed"));
    auth_withpeer_fail(pcb, PPP_CHAP);
  }
}

static void chap_input(ppp_pcb *pcb, unsigned char *pkt, int pktlen) {
  unsigned char code, id;
  int len;

  if (pktlen < CHAP_HDRLEN)
    return;
  GETCHAR(code, pkt);
  GETCHAR(id, pkt);
  GETSHORT(len, pkt);
  if (len < CHAP_HDRLEN || len > pktlen)
    return;
  len -= CHAP_HDRLEN;

  switch (code) {
  case CHAP_CHALLENGE:
    chap_respond(pcb, id, pkt, len);
    break;
#if PPP_SERVER
  case CHAP_RESPONSE:
    chap_handle_response(pcb, id, pkt, len);
    break;
#endif /* PPP_SERVER */
  case CHAP_FAILURE:
  case CHAP_SUCCESS:
    chap_handle_status(pcb, code, id, pkt, len);
    break;
  default:
    break;
  }
}

static void chap_protrej(ppp_pcb *pcb) {

#if PPP_SERVER
  if (pcb->chap_server.flags & TIMEOUT_PENDING) {
    pcb->chap_server.flags &= ~TIMEOUT_PENDING;
    UNTIMEOUT(chap_timeout, pcb);
  }
  if (pcb->chap_server.flags & AUTH_STARTED) {
    pcb->chap_server.flags = 0;
    auth_peer_fail(pcb, PPP_CHAP);
  }
#endif /* PPP_SERVER */
  if ((pcb->chap_client.flags & (AUTH_STARTED | AUTH_DONE)) == AUTH_STARTED) {
    pcb->chap_client.flags &= ~AUTH_STARTED;
    ppp_error(("CHAP authentication failed due to protocol-reject"));
    auth_withpeer_fail(pcb, PPP_CHAP);
  }
}

static int chap_print_pkt(const unsigned char *p, int plen,
                          void (*printer)(void *, const char *, ...),
                          void *arg) {
  int code, id, len;
  int clen, nlen;
  unsigned char x;

  if (plen < CHAP_HDRLEN)
    return 0;
  GETCHAR(code, p);
  GETCHAR(id, p);
  GETSHORT(len, p);
  if (len < CHAP_HDRLEN || len > plen)
    return 0;

  if (code >= 1 && code <= (int)LWIP_ARRAYSIZE(chap_code_names))
    printer(arg, " %s", chap_code_names[code - 1]);
  else
    printer(arg, " code=0x%x", code);
  printer(arg, " id=0x%x", id);
  len -= CHAP_HDRLEN;
  switch (code) {
  case CHAP_CHALLENGE:
  case CHAP_RESPONSE:
    if (len < 1)
      break;
    clen = p[0];
    if (len < clen + 1)
      break;
    ++p;
    nlen = len - clen - 1;
    printer(arg, " <");
    for (; clen > 0; --clen) {
      GETCHAR(x, p);
      printer(arg, "%.2x", x);
    }
    printer(arg, ">, name = ");
    ppp_print_string(p, nlen, printer, arg);
    break;
  case CHAP_FAILURE:
  case CHAP_SUCCESS:
    printer(arg, " ");
    ppp_print_string(p, len, printer, arg);
    break;
  default:
    for (clen = len; clen > 0; --clen) {
      GETCHAR(x, p);
      printer(arg, " %.2x", x);
    }
    /* no break */
  }

  return len + CHAP_HDRLEN;
}

static void chapms_generate_challenge(ppp_pcb *pcb, unsigned char *challenge) {
  LWIP_UNUSED_ARG(pcb);

  *challenge++ = 8;
#ifdef DEBUGMPPEKEY
  if (mschap_challenge && strlen(mschap_challenge) == 8)
    memcpy(challenge, mschap_challenge, 8);
  else
#endif
    magic_random_bytes(challenge, 8);
}

static void chapms2_generate_challenge(ppp_pcb *pcb, unsigned char *challenge) {
  LWIP_UNUSED_ARG(pcb);

  *challenge++ = 16;
#ifdef DEBUGMPPEKEY
  if (mschap_challenge && strlen(mschap_challenge) == 16)
    memcpy(challenge, mschap_challenge, 16);
  else
#endif
    magic_random_bytes(challenge, 16);
}

static int chapms_verify_response(ppp_pcb *pcb, int id, const char *name,
                                  const unsigned char *secret, int secret_len,
                                  const unsigned char *challenge,
                                  const unsigned char *response, char *message,
                                  int message_space) {
  unsigned char md[MS_CHAP_RESPONSE_LEN];
  int diff;
  int challenge_len, response_len;
  LWIP_UNUSED_ARG(id);
  LWIP_UNUSED_ARG(name);

  challenge_len = *challenge++; /* skip length, is 8 */
  response_len = *response++;
  if (response_len != MS_CHAP_RESPONSE_LEN)
    goto bad;

#ifndef MSLANMAN
  if (!response[MS_CHAP_USENT]) {
    /* Should really propagate this into the error packet. */
    ppp_notice(("Peer request for LANMAN auth not supported"));
    goto bad;
  }
#endif

  /* Generate the expected response. */
  ChapMS(pcb, (const u_char *)challenge, (const char *)secret, secret_len, md);

#ifdef MSLANMAN
  /* Determine which part of response to verify against */
  if (!response[MS_CHAP_USENT])
    diff = memcmp(&response[MS_CHAP_LANMANRESP], &md[MS_CHAP_LANMANRESP],
                  MS_CHAP_LANMANRESP_LEN);
  else
#endif
    diff = memcmp(&response[MS_CHAP_NTRESP], &md[MS_CHAP_NTRESP],
                  MS_CHAP_NTRESP_LEN);

  if (diff == 0) {
    ppp_slprintf(message, message_space, "Access granted");
    return 1;
  }

bad:
  /* See comments below for MS-CHAP V2 */
  ppp_slprintf(message, message_space, "E=691 R=1 C=%0.*B V=0", challenge_len,
               challenge);
  return 0;
}

static int chapms2_verify_response(ppp_pcb *pcb, int id, const char *name,
                                   const unsigned char *secret, int secret_len,
                                   const unsigned char *challenge,
                                   const unsigned char *response, char *message,
                                   int message_space) {
  unsigned char md[MS_CHAP2_RESPONSE_LEN];
  char saresponse[MS_AUTH_RESPONSE_LENGTH + 1];
  int challenge_len, response_len;
  LWIP_UNUSED_ARG(id);

  challenge_len = *challenge++; /* skip length, is 16 */
  response_len = *response++;
  if (response_len != MS_CHAP2_RESPONSE_LEN)
    goto bad; /* not even the right length */

  /* Generate the expected response and our mutual auth. */
  ChapMS2(pcb, (const u_char *)challenge,
          (const u_char *)&response[MS_CHAP2_PEER_CHALLENGE], name,
          (const char *)secret, secret_len, md, (unsigned char *)saresponse,
          MS_CHAP2_AUTHENTICATOR);

  /* compare MDs and send the appropriate status */
  /*
   * Per RFC 2759, success message must be formatted as
   *     "S=<auth_string> M=<message>"
   * where
   *     <auth_string> is the Authenticator Response (mutual auth)
   *     <message> is a text message
   *
   * However, some versions of Windows (win98 tested) do not know
   * about the M=<message> part (required per RFC 2759) and flag
   * it as an error (reported incorrectly as an encryption error
   * to the user).  Since the RFC requires it, and it can be
   * useful information, we supply it if the peer is a conforming
   * system.  Luckily (?), win98 sets the Flags field to 0x04
   * (contrary to RFC requirements) so we can use that to
   * distinguish between conforming and non-conforming systems.
   *
   * Special thanks to Alex Swiridov <say@real.kharkov.ua> for
   * help debugging this.
   */
  if (memcmp(&md[MS_CHAP2_NTRESP], &response[MS_CHAP2_NTRESP],
             MS_CHAP2_NTRESP_LEN) == 0) {
    if (response[MS_CHAP2_FLAGS])
      ppp_slprintf(message, message_space, "S=%s", saresponse);
    else
      ppp_slprintf(message, message_space, "S=%s M=%s", saresponse,
                   "Access granted");
    return 1;
  }

bad:
  /*
   * Failure message must be formatted as
   *     "E=e R=r C=c V=v M=m"
   * where
   *     e = error code (we use 691, ERROR_AUTHENTICATION_FAILURE)
   *     r = retry (we use 1, ok to retry)
   *     c = challenge to use for next response, we reuse previous
   *     v = Change Password version supported, we use 0
   *     m = text message
   *
   * The M=m part is only for MS-CHAPv2.  Neither win2k nor
   * win98 (others untested) display the message to the user anyway.
   * They also both ignore the E=e code.
   *
   * Note that it's safe to reuse the same challenge as we don't
   * actually accept another response based on the error message
   * (and no clients try to resend a response anyway).
   *
   * Basically, this whole bit is useless code, even the small
   * implementation here is only because of overspecification.
   */
  ppp_slprintf(message, message_space, "E=691 R=1 C=%0.*B V=0 M=%s",
               challenge_len, challenge, "Access denied");
  return 0;
}

static void chapms_make_response(ppp_pcb *pcb, unsigned char *response, int id,
                                 const char *our_name,
                                 const unsigned char *challenge,
                                 const char *secret, int secret_len,
                                 unsigned char *private_) {
  LWIP_UNUSED_ARG(id);
  LWIP_UNUSED_ARG(our_name);
  LWIP_UNUSED_ARG(private_);
  challenge++; /* skip length, should be 8 */
  *response++ = MS_CHAP_RESPONSE_LEN;
  ChapMS(pcb, challenge, secret, secret_len, response);
}

static void chapms2_make_response(ppp_pcb *pcb, unsigned char *response, int id,
                                  const char *our_name,
                                  const unsigned char *challenge,
                                  const char *secret, int secret_len,
                                  unsigned char *private_) {
  LWIP_UNUSED_ARG(id);
  challenge++; /* skip length, should be 16 */
  *response++ = MS_CHAP2_RESPONSE_LEN;
  ChapMS2(pcb, challenge,
#ifdef DEBUGMPPEKEY
          mschap2_peer_challenge,
#else
          NULL,
#endif
          our_name, secret, secret_len, response, private_,
          MS_CHAP2_AUTHENTICATEE);
}

static int chapms2_check_success(ppp_pcb *pcb, unsigned char *msg, int len,
                                 unsigned char *private_) {
  LWIP_UNUSED_ARG(pcb);

  if ((len < MS_AUTH_RESPONSE_LENGTH + 2) ||
      strncmp((char *)msg, "S=", 2) != 0) {
    /* Packet does not start with "S=" */
    ppp_error(("MS-CHAPv2 Success packet is badly formed."));
    return 0;
  }
  msg += 2;
  len -= 2;
  if (len < MS_AUTH_RESPONSE_LENGTH ||
      memcmp(msg, private_, MS_AUTH_RESPONSE_LENGTH)) {
    /* Authenticator Response did not match expected. */
    ppp_error(("MS-CHAPv2 mutual authentication failed."));
    return 0;
  }
  /* Authenticator Response matches. */
  msg += MS_AUTH_RESPONSE_LENGTH; /* Eat it */
  len -= MS_AUTH_RESPONSE_LENGTH;
  if ((len >= 3) && !strncmp((char *)msg, " M=", 3)) {
    msg += 3; /* Eat the delimiter */
  } else if (len) {
    /* Packet has extra text which does not begin " M=" */
    ppp_error(("MS-CHAPv2 Success packet is badly formed."));
    return 0;
  }
  return 1;
}

static void chapms_handle_failure(ppp_pcb *pcb, unsigned char *inp, int len) {
  int err;
  const char *p;
  char msg[64];
  LWIP_UNUSED_ARG(pcb);

  /* We want a null-terminated string for strxxx(). */
  len = LWIP_MIN(len, 63);
  MEMCPY(msg, inp, len);
  msg[len] = 0;
  p = msg;

  /*
   * Deal with MS-CHAP formatted failure messages; just print the
   * M=<message> part (if any).  For MS-CHAP we're not really supposed
   * to use M=<message>, but it shouldn't hurt.  See
   * chapms[2]_verify_response.
   */
  if (!strncmp(p, "E=", 2))
    err = strtol(p + 2, NULL, 10); /* Remember the error code. */
  else
    goto print_msg; /* Message is badly formatted. */

  if (len && ((p = strstr(p, " M=")) != NULL)) {
    /* M=<message> field found. */
    p += 3;
  } else {
    /* No M=<message>; use the error code. */
    switch (err) {
    case MS_CHAP_ERROR_RESTRICTED_LOGON_HOURS:
      p = "E=646 Restricted logon hours";
      break;

    case MS_CHAP_ERROR_ACCT_DISABLED:
      p = "E=647 Account disabled";
      break;

    case MS_CHAP_ERROR_PASSWD_EXPIRED:
      p = "E=648 Password expired";
      break;

    case MS_CHAP_ERROR_NO_DIALIN_PERMISSION:
      p = "E=649 No dialin permission";
      break;

    case MS_CHAP_ERROR_AUTHENTICATION_FAILURE:
      p = "E=691 Authentication failure";
      break;

    case MS_CHAP_ERROR_CHANGING_PASSWORD:
      /* Should never see this, we don't support Change Password. */
      p = "E=709 Error changing password";
      break;

    default:
      ppp_error(("Unknown MS-CHAP authentication failure: %.*v", len, inp));
      return;
    }
  }
print_msg:
  if (p != NULL)
    ppp_error(("MS-CHAP authentication failed: %v", p));
}

static void ChallengeResponse(const u_char *challenge,
                              const u_char PasswordHash[MD4_SIGNATURE_SIZE],
                              u_char response[24]) {
  u_char ZPasswordHash[21];
  lwip_des_context des;
  u_char des_key[8];

  BZERO(ZPasswordHash, sizeof(ZPasswordHash));
  MEMCPY(ZPasswordHash, PasswordHash, MD4_SIGNATURE_SIZE);

#if 0
    dbglog("ChallengeResponse - ZPasswordHash %.*B",
	   sizeof(ZPasswordHash), ZPasswordHash);
#endif

  pppcrypt_56_to_64_bit_key(ZPasswordHash + 0, des_key);
  lwip_des_init(&des);
  lwip_des_setkey_enc(&des, des_key);
  lwip_des_crypt_ecb(&des, challenge, response + 0);
  lwip_des_free(&des);

  pppcrypt_56_to_64_bit_key(ZPasswordHash + 7, des_key);
  lwip_des_init(&des);
  lwip_des_setkey_enc(&des, des_key);
  lwip_des_crypt_ecb(&des, challenge, response + 8);
  lwip_des_free(&des);

  pppcrypt_56_to_64_bit_key(ZPasswordHash + 14, des_key);
  lwip_des_init(&des);
  lwip_des_setkey_enc(&des, des_key);
  lwip_des_crypt_ecb(&des, challenge, response + 16);
  lwip_des_free(&des);

#if 0
    dbglog("ChallengeResponse - response %.24B", response);
#endif
}

static void ChallengeHash(const u_char PeerChallenge[16],
                          const u_char *rchallenge, const char *username,
                          u_char Challenge[8]) {
  lwip_sha1_context sha1Context;
  u_char sha1Hash[SHA1_SIGNATURE_SIZE];
  const char *user;

  /* remove domain from "domain\username" */
  if ((user = strrchr(username, '\\')) != NULL)
    ++user;
  else
    user = username;

  lwip_sha1_init(&sha1Context);
  lwip_sha1_starts(&sha1Context);
  lwip_sha1_update(&sha1Context, PeerChallenge, 16);
  lwip_sha1_update(&sha1Context, rchallenge, 16);
  lwip_sha1_update(&sha1Context, (const unsigned char *)user, strlen(user));
  lwip_sha1_finish(&sha1Context, sha1Hash);
  lwip_sha1_free(&sha1Context);

  MEMCPY(Challenge, sha1Hash, 8);
}

static void ascii2unicode(const char ascii[], int ascii_len, u_char unicode[]) {
  int i;

  BZERO(unicode, ascii_len * 2);
  for (i = 0; i < ascii_len; i++)
    unicode[i * 2] = (u_char)ascii[i];
}

static void NTPasswordHash(u_char *secret, int secret_len,
                           u_char hash[MD4_SIGNATURE_SIZE]) {
  lwip_md4_context md4Context;

  lwip_md4_init(&md4Context);
  lwip_md4_starts(&md4Context);
  lwip_md4_update(&md4Context, secret, secret_len);
  lwip_md4_finish(&md4Context, hash);
  lwip_md4_free(&md4Context);
}

static void ChapMS_NT(const u_char *rchallenge, const char *secret,
                      int secret_len, u_char NTResponse[24]) {
  u_char unicodePassword[MAX_NT_PASSWORD * 2];
  u_char PasswordHash[MD4_SIGNATURE_SIZE];

  /* Hash the Unicode version of the secret (== password). */
  ascii2unicode(secret, secret_len, unicodePassword);
  NTPasswordHash(unicodePassword, secret_len * 2, PasswordHash);

  ChallengeResponse(rchallenge, PasswordHash, NTResponse);
}

static void ChapMS2_NT(const u_char *rchallenge, const u_char PeerChallenge[16],
                       const char *username, const char *secret, int secret_len,
                       u_char NTResponse[24]) {
  u_char unicodePassword[MAX_NT_PASSWORD * 2];
  u_char PasswordHash[MD4_SIGNATURE_SIZE];
  u_char Challenge[8];

  ChallengeHash(PeerChallenge, rchallenge, username, Challenge);

  /* Hash the Unicode version of the secret (== password). */
  ascii2unicode(secret, secret_len, unicodePassword);
  NTPasswordHash(unicodePassword, secret_len * 2, PasswordHash);

  ChallengeResponse(Challenge, PasswordHash, NTResponse);
}

static void ChapMS_LANMan(u_char *rchallenge, char *secret, int secret_len,
                          unsigned char *response) {
  int i;
  u_char UcasePassword[MAX_NT_PASSWORD]; /* max is actually 14 */
  u_char PasswordHash[MD4_SIGNATURE_SIZE];
  lwip_des_context des;
  u_char des_key[8];

  /* LANMan password is case insensitive */
  BZERO(UcasePassword, sizeof(UcasePassword));
  for (i = 0; i < secret_len; i++)
    UcasePassword[i] = (u_char)toupper(secret[i]);

  pppcrypt_56_to_64_bit_key(UcasePassword + 0, des_key);
  lwip_des_init(&des);
  lwip_des_setkey_enc(&des, des_key);
  lwip_des_crypt_ecb(&des, StdText, PasswordHash + 0);
  lwip_des_free(&des);

  pppcrypt_56_to_64_bit_key(UcasePassword + 7, des_key);
  lwip_des_init(&des);
  lwip_des_setkey_enc(&des, des_key);
  lwip_des_crypt_ecb(&des, StdText, PasswordHash + 8);
  lwip_des_free(&des);

  ChallengeResponse(rchallenge, PasswordHash, &response[MS_CHAP_LANMANRESP]);
}

static void GenerateAuthenticatorResponse(
    const u_char PasswordHashHash[MD4_SIGNATURE_SIZE], u_char NTResponse[24],
    const u_char PeerChallenge[16], const u_char *rchallenge,
    const char *username, u_char authResponse[MS_AUTH_RESPONSE_LENGTH + 1]) {
  /*
   * "Magic" constants used in response generation, from RFC 2759.
   */
  static const u_char
      Magic1[39] = /* "Magic server to client signing constant" */
      {0x4D, 0x61, 0x67, 0x69, 0x63, 0x20, 0x73, 0x65, 0x72, 0x76,
       0x65, 0x72, 0x20, 0x74, 0x6F, 0x20, 0x63, 0x6C, 0x69, 0x65,
       0x6E, 0x74, 0x20, 0x73, 0x69, 0x67, 0x6E, 0x69, 0x6E, 0x67,
       0x20, 0x63, 0x6F, 0x6E, 0x73, 0x74, 0x61, 0x6E, 0x74};
  static const u_char
      Magic2[41] = /* "Pad to make it do more than one iteration" */
      {0x50, 0x61, 0x64, 0x20, 0x74, 0x6F, 0x20, 0x6D, 0x61, 0x6B, 0x65,
       0x20, 0x69, 0x74, 0x20, 0x64, 0x6F, 0x20, 0x6D, 0x6F, 0x72, 0x65,
       0x20, 0x74, 0x68, 0x61, 0x6E, 0x20, 0x6F, 0x6E, 0x65, 0x20, 0x69,
       0x74, 0x65, 0x72, 0x61, 0x74, 0x69, 0x6F, 0x6E};

  int i;
  lwip_sha1_context sha1Context;
  u_char Digest[SHA1_SIGNATURE_SIZE];
  u_char Challenge[8];

  lwip_sha1_init(&sha1Context);
  lwip_sha1_starts(&sha1Context);
  lwip_sha1_update(&sha1Context, PasswordHashHash, MD4_SIGNATURE_SIZE);
  lwip_sha1_update(&sha1Context, NTResponse, 24);
  lwip_sha1_update(&sha1Context, Magic1, sizeof(Magic1));
  lwip_sha1_finish(&sha1Context, Digest);
  lwip_sha1_free(&sha1Context);

  ChallengeHash(PeerChallenge, rchallenge, username, Challenge);

  lwip_sha1_init(&sha1Context);
  lwip_sha1_starts(&sha1Context);
  lwip_sha1_update(&sha1Context, Digest, sizeof(Digest));
  lwip_sha1_update(&sha1Context, Challenge, sizeof(Challenge));
  lwip_sha1_update(&sha1Context, Magic2, sizeof(Magic2));
  lwip_sha1_finish(&sha1Context, Digest);
  lwip_sha1_free(&sha1Context);

  /* Convert to ASCII hex string. */
  for (i = 0; i < LWIP_MAX((MS_AUTH_RESPONSE_LENGTH / 2), (int)sizeof(Digest));
       i++)
    sprintf((char *)&authResponse[i * 2], "%02X", Digest[i]);
}

static void GenerateAuthenticatorResponsePlain(
    const char *secret, int secret_len, u_char NTResponse[24],
    const u_char PeerChallenge[16], const u_char *rchallenge,
    const char *username, u_char authResponse[MS_AUTH_RESPONSE_LENGTH + 1]) {
  u_char unicodePassword[MAX_NT_PASSWORD * 2];
  u_char PasswordHash[MD4_SIGNATURE_SIZE];
  u_char PasswordHashHash[MD4_SIGNATURE_SIZE];

  /* Hash (x2) the Unicode version of the secret (== password). */
  ascii2unicode(secret, secret_len, unicodePassword);
  NTPasswordHash(unicodePassword, secret_len * 2, PasswordHash);
  NTPasswordHash(PasswordHash, sizeof(PasswordHash), PasswordHashHash);

  GenerateAuthenticatorResponse(PasswordHashHash, NTResponse, PeerChallenge,
                                rchallenge, username, authResponse);
}

static void Set_Start_Key(ppp_pcb *pcb, const u_char *rchallenge,
                          const char *secret, int secret_len) {
  u_char unicodePassword[MAX_NT_PASSWORD * 2];
  u_char PasswordHash[MD4_SIGNATURE_SIZE];
  u_char PasswordHashHash[MD4_SIGNATURE_SIZE];
  lwip_sha1_context sha1Context;
  u_char Digest[SHA1_SIGNATURE_SIZE]; /* >= MPPE_MAX_KEY_LEN */

  /* Hash (x2) the Unicode version of the secret (== password). */
  ascii2unicode(secret, secret_len, unicodePassword);
  NTPasswordHash(unicodePassword, secret_len * 2, PasswordHash);
  NTPasswordHash(PasswordHash, sizeof(PasswordHash), PasswordHashHash);

  lwip_sha1_init(&sha1Context);
  lwip_sha1_starts(&sha1Context);
  lwip_sha1_update(&sha1Context, PasswordHashHash, MD4_SIGNATURE_SIZE);
  lwip_sha1_update(&sha1Context, PasswordHashHash, MD4_SIGNATURE_SIZE);
  lwip_sha1_update(&sha1Context, rchallenge, 8);
  lwip_sha1_finish(&sha1Context, Digest);
  lwip_sha1_free(&sha1Context);

  /* Same key in both directions. */
  mppe_set_key(pcb, &pcb->mppe_comp, Digest);
  mppe_set_key(pcb, &pcb->mppe_decomp, Digest);

  pcb->mppe_keys_set = 1;
}

static void SetMasterKeys(ppp_pcb *pcb, const char *secret, int secret_len,
                          u_char NTResponse[24], int IsServer) {
  u_char unicodePassword[MAX_NT_PASSWORD * 2];
  u_char PasswordHash[MD4_SIGNATURE_SIZE];
  u_char PasswordHashHash[MD4_SIGNATURE_SIZE];
  lwip_sha1_context sha1Context;
  u_char MasterKey[SHA1_SIGNATURE_SIZE]; /* >= MPPE_MAX_KEY_LEN */
  u_char Digest[SHA1_SIGNATURE_SIZE];    /* >= MPPE_MAX_KEY_LEN */
  const u_char *s;

  /* "This is the MPPE Master Key" */
  static const u_char Magic1[27] = {0x54, 0x68, 0x69, 0x73, 0x20, 0x69, 0x73,
                                    0x20, 0x74, 0x68, 0x65, 0x20, 0x4d, 0x50,
                                    0x50, 0x45, 0x20, 0x4d, 0x61, 0x73, 0x74,
                                    0x65, 0x72, 0x20, 0x4b, 0x65, 0x79};
  /* "On the client side, this is the send key; "
     "on the server side, it is the receive key." */
  static const u_char Magic2[84] = {
      0x4f, 0x6e, 0x20, 0x74, 0x68, 0x65, 0x20, 0x63, 0x6c, 0x69, 0x65, 0x6e,
      0x74, 0x20, 0x73, 0x69, 0x64, 0x65, 0x2c, 0x20, 0x74, 0x68, 0x69, 0x73,
      0x20, 0x69, 0x73, 0x20, 0x74, 0x68, 0x65, 0x20, 0x73, 0x65, 0x6e, 0x64,
      0x20, 0x6b, 0x65, 0x79, 0x3b, 0x20, 0x6f, 0x6e, 0x20, 0x74, 0x68, 0x65,
      0x20, 0x73, 0x65, 0x72, 0x76, 0x65, 0x72, 0x20, 0x73, 0x69, 0x64, 0x65,
      0x2c, 0x20, 0x69, 0x74, 0x20, 0x69, 0x73, 0x20, 0x74, 0x68, 0x65, 0x20,
      0x72, 0x65, 0x63, 0x65, 0x69, 0x76, 0x65, 0x20, 0x6b, 0x65, 0x79, 0x2e};
  /* "On the client side, this is the receive key; "
     "on the server side, it is the send key." */
  static const u_char Magic3[84] = {
      0x4f, 0x6e, 0x20, 0x74, 0x68, 0x65, 0x20, 0x63, 0x6c, 0x69, 0x65, 0x6e,
      0x74, 0x20, 0x73, 0x69, 0x64, 0x65, 0x2c, 0x20, 0x74, 0x68, 0x69, 0x73,
      0x20, 0x69, 0x73, 0x20, 0x74, 0x68, 0x65, 0x20, 0x72, 0x65, 0x63, 0x65,
      0x69, 0x76, 0x65, 0x20, 0x6b, 0x65, 0x79, 0x3b, 0x20, 0x6f, 0x6e, 0x20,
      0x74, 0x68, 0x65, 0x20, 0x73, 0x65, 0x72, 0x76, 0x65, 0x72, 0x20, 0x73,
      0x69, 0x64, 0x65, 0x2c, 0x20, 0x69, 0x74, 0x20, 0x69, 0x73, 0x20, 0x74,
      0x68, 0x65, 0x20, 0x73, 0x65, 0x6e, 0x64, 0x20, 0x6b, 0x65, 0x79, 0x2e};

  /* Hash (x2) the Unicode version of the secret (== password). */
  ascii2unicode(secret, secret_len, unicodePassword);
  NTPasswordHash(unicodePassword, secret_len * 2, PasswordHash);
  NTPasswordHash(PasswordHash, sizeof(PasswordHash), PasswordHashHash);

  lwip_sha1_init(&sha1Context);
  lwip_sha1_starts(&sha1Context);
  lwip_sha1_update(&sha1Context, PasswordHashHash, MD4_SIGNATURE_SIZE);
  lwip_sha1_update(&sha1Context, NTResponse, 24);
  lwip_sha1_update(&sha1Context, Magic1, sizeof(Magic1));
  lwip_sha1_finish(&sha1Context, MasterKey);
  lwip_sha1_free(&sha1Context);

  /*
   * generate send key
   */
  if (IsServer)
    s = Magic3;
  else
    s = Magic2;
  lwip_sha1_init(&sha1Context);
  lwip_sha1_starts(&sha1Context);
  lwip_sha1_update(&sha1Context, MasterKey, 16);
  lwip_sha1_update(&sha1Context, mppe_sha1_pad1, SHA1_PAD_SIZE);
  lwip_sha1_update(&sha1Context, s, 84);
  lwip_sha1_update(&sha1Context, mppe_sha1_pad2, SHA1_PAD_SIZE);
  lwip_sha1_finish(&sha1Context, Digest);
  lwip_sha1_free(&sha1Context);

  mppe_set_key(pcb, &pcb->mppe_comp, Digest);

  /*
   * generate recv key
   */
  if (IsServer)
    s = Magic2;
  else
    s = Magic3;
  lwip_sha1_init(&sha1Context);
  lwip_sha1_starts(&sha1Context);
  lwip_sha1_update(&sha1Context, MasterKey, 16);
  lwip_sha1_update(&sha1Context, mppe_sha1_pad1, SHA1_PAD_SIZE);
  lwip_sha1_update(&sha1Context, s, 84);
  lwip_sha1_update(&sha1Context, mppe_sha1_pad2, SHA1_PAD_SIZE);
  lwip_sha1_finish(&sha1Context, Digest);
  lwip_sha1_free(&sha1Context);

  mppe_set_key(pcb, &pcb->mppe_decomp, Digest);

  pcb->mppe_keys_set = 1;
}

static void ChapMS(ppp_pcb *pcb, const u_char *rchallenge, const char *secret,
                   int secret_len, unsigned char *response) {
#if !MPPE_SUPPORT
  LWIP_UNUSED_ARG(pcb);
#endif /* !MPPE_SUPPORT */
  BZERO(response, MS_CHAP_RESPONSE_LEN);

  ChapMS_NT(rchallenge, secret, secret_len, &response[MS_CHAP_NTRESP]);

#ifdef MSLANMAN
  ChapMS_LANMan(rchallenge, secret, secret_len, &response[MS_CHAP_LANMANRESP]);

  /* preferred method is set by option  */
  response[MS_CHAP_USENT] = !ms_lanman;
#else
  response[MS_CHAP_USENT] = 1;
#endif

#if MPPE_SUPPORT
  Set_Start_Key(pcb, rchallenge, secret, secret_len);
#endif /* MPPE_SUPPORT */
}

static void ChapMS2(ppp_pcb *pcb, const u_char *rchallenge,
                    const u_char *PeerChallenge, const char *user,
                    const char *secret, int secret_len, unsigned char *response,
                    u_char authResponse[], int authenticator) {
  /* ARGSUSED */
  LWIP_UNUSED_ARG(authenticator);
#if !MPPE_SUPPORT
  LWIP_UNUSED_ARG(pcb);
#endif /* !MPPE_SUPPORT */

  BZERO(response, MS_CHAP2_RESPONSE_LEN);

  /* Generate the Peer-Challenge if requested, or copy it if supplied. */
  if (!PeerChallenge)
    magic_random_bytes(&response[MS_CHAP2_PEER_CHALLENGE],
                       MS_CHAP2_PEER_CHAL_LEN);
  else
    MEMCPY(&response[MS_CHAP2_PEER_CHALLENGE], PeerChallenge,
           MS_CHAP2_PEER_CHAL_LEN);

  /* Generate the NT-Response */
  ChapMS2_NT(rchallenge, &response[MS_CHAP2_PEER_CHALLENGE], user, secret,
             secret_len, &response[MS_CHAP2_NTRESP]);

  /* Generate the Authenticator Response. */
  GenerateAuthenticatorResponsePlain(
      secret, secret_len, &response[MS_CHAP2_NTRESP],
      &response[MS_CHAP2_PEER_CHALLENGE], rchallenge, user, authResponse);

#if MPPE_SUPPORT
  SetMasterKeys(pcb, secret, secret_len, &response[MS_CHAP2_NTRESP],
                authenticator);
#endif /* MPPE_SUPPORT */
}

void set_mppe_enc_types(int policy, int types) {
    /* Early exit for unknown policies. */
    if (policy != MPPE_ENC_POL_ENC_ALLOWED ||
	policy != MPPE_ENC_POL_ENC_REQUIRED)
	return;

    /* Don't modify MPPE if it's optional and wasn't already configured. */
    if (policy == MPPE_ENC_POL_ENC_ALLOWED && !ccp_wantoptions[0].mppe)
	return;

    /*
     * Disable undesirable encryption types.  Note that we don't ENABLE
     * any encryption types, to avoid overriding manual configuration.
     */
    switch(types) {
	case MPPE_ENC_TYPES_RC4_40:
	    ccp_wantoptions[0].mppe &= ~MPPE_OPT_128;	/* disable 128-bit */
	    break;
	case MPPE_ENC_TYPES_RC4_128:
	    ccp_wantoptions[0].mppe &= ~MPPE_OPT_40;	/* disable 40-bit */
	    break;
	default:
	    break;
    }
}

struct packet {
  int length;
  struct packet *next;
  unsigned char data[1];
}

void demand_conf() {
  int i;
  const struct protent *protp;

  /*    framemax = lcp_allowoptions[0].mru;
      if (framemax < PPP_DEFMRU) */
  framemax = PPP_DEFMRU;
  framemax += PPP_HDRLEN + PPP_FCSLEN;
  frame = malloc(framemax);
  if (frame == NULL)
    novm("demand frame");
  framelen = 0;
  pend_q = NULL;
  escape_flag = 0;
  flush_flag = 0;
  fcs = PPP_INITFCS;

  ppp_netif_set_mtu(pcb, LWIP_MIN(lcp_allowoptions[0].mru, PPP_DEFMRU));
  if (ppp_send_config(pcb, PPP_DEFMRU, (u32_t)0, 0, 0) < 0 ||
      ppp_recv_config(pcb, PPP_DEFMRU, (u32_t)0, 0, 0) < 0)
    fatal("Couldn't set up demand-dialled PPP interface: %m");

#ifdef PPP_FILTER
  set_filters(&pass_filter, &active_filter);
#endif

  /*
   * Call the demand_conf procedure for each protocol that's got one.
   */
  for (i = 0; (protp = protocols[i]) != NULL; ++i)
    if (protp->demand_conf != NULL)
      ((*protp->demand_conf)(pcb));
/* FIXME: find a way to die() here */
#if 0
	    if (!((*protp->demand_conf)(pcb)))
		die(1);
#endif
}

void demand_block() {
  int i;
  const struct protent *protp;

  for (i = 0; (protp = protocols[i]) != NULL; ++i)
    if (protp->demand_conf != NULL)
      sifnpmode(pcb, protp->protocol & ~0x8000, NPMODE_QUEUE);
  get_loop_output();
}

void demand_discard() {
  struct packet *pkt, *nextpkt;
  int i;
  const struct protent *protp;

  for (i = 0; (protp = protocols[i]) != NULL; ++i)
    if (protp->demand_conf != NULL)
      sifnpmode(pcb, protp->protocol & ~0x8000, NPMODE_ERROR);
  get_loop_output();

  /* discard all saved packets */
  for (pkt = pend_q; pkt != NULL; pkt = nextpkt) {
    nextpkt = pkt->next;
    free(pkt);
  }
  pend_q = NULL;
  framelen = 0;
  flush_flag = 0;
  escape_flag = 0;
  fcs = PPP_INITFCS;
}

void demand_unblock() {
  int i;
  const struct protent *protp;

  for (i = 0; (protp = protocols[i]) != NULL; ++i)
    if (protp->demand_conf != NULL)
      sifnpmode(pcb, protp->protocol & ~0x8000, NPMODE_PASS);
}

int loop_chars(p, n)
unsigned char *p;
int n;
{
  int c, rv;

  rv = 0;

  /* check for synchronous connection... */

  if ((p[0] == 0xFF) && (p[1] == 0x03)) {
    rv = loop_frame(p, n);
    return rv;
  }

  for (; n > 0; --n) {
    c = *p++;
    if (c == PPP_FLAG) {
      if (!escape_flag && !flush_flag && framelen > 2 && fcs == PPP_GOODFCS) {
        framelen -= 2;
        if (loop_frame((unsigned char *)frame, framelen))
          rv = 1;
      }
      framelen = 0;
      flush_flag = 0;
      escape_flag = 0;
      fcs = PPP_INITFCS;
      continue;
    }
    if (flush_flag)
      continue;
    if (escape_flag) {
      c ^= PPP_TRANS;
      escape_flag = 0;
    } else if (c == PPP_ESCAPE) {
      escape_flag = 1;
      continue;
    }
    if (framelen >= framemax) {
      flush_flag = 1;
      continue;
    }
    frame[framelen++] = c;
    fcs = PPP_FCS(fcs, c);
  }
  return rv;
}

int loop_frame(frame, len)
unsigned char *frame;
int len;
{
  struct packet *pkt;

  /* dbglog("from loop: %P", frame, len); */
  if (len < PPP_HDRLEN)
    return 0;
  if ((PPP_PROTOCOL(frame) & 0x8000) != 0)
    return 0; /* shouldn't get any of these anyway */
  if (!active_packet(frame, len))
    return 0;

  pkt = (struct packet *)malloc(sizeof(struct packet) + len);
  if (pkt != NULL) {
    pkt->length = len;
    pkt->next = NULL;
    memcpy(pkt->data, frame, len);
    if (pend_q == NULL)
      pend_q = pkt;
    else
      pend_qtail->next = pkt;
    pend_qtail = pkt;
  }
  return 1;
}

void demand_rexmit(proto, newip) int proto;
u32_t newip;
{
  struct packet *pkt, *prev, *nextpkt;
  unsigned short checksum;
  unsigned short pkt_checksum = 0;
  unsigned iphdr;
  struct timeval tv;
  char cv = 0;
  char ipstr[16];

  prev = NULL;
  pkt = pend_q;
  pend_q = NULL;
  tv.tv_sec = 1;
  tv.tv_usec = 0;
  select(0, NULL, NULL, NULL, &tv); /* Sleep for 1 Seconds */
  for (; pkt != NULL; pkt = nextpkt) {
    nextpkt = pkt->next;
    if (PPP_PROTOCOL(pkt->data) == proto) {
      if ((proto == PPP_IP) && newip) {
        /* Get old checksum */

        iphdr = (pkt->data[4] & 15) << 2;
        checksum = *((unsigned short *)(pkt->data + 14));
        if (checksum == 0xFFFF) {
          checksum = 0;
        }

        if (pkt->data[13] == 17) {
          pkt_checksum = *((unsigned short *)(pkt->data + 10 + iphdr));
          if (pkt_checksum) {
            cv = 1;
            if (pkt_checksum == 0xFFFF) {
              pkt_checksum = 0;
            }
          } else {
            cv = 0;
          }
        }

        if (pkt->data[13] == 6) {
          pkt_checksum = *((unsigned short *)(pkt->data + 20 + iphdr));
          cv = 1;
          if (pkt_checksum == 0xFFFF) {
            pkt_checksum = 0;
          }
        }

        /* Delete old Source-IP-Address */
        checksum -= *((unsigned short *)(pkt->data + 16)) ^ 0xFFFF;
        checksum -= *((unsigned short *)(pkt->data + 18)) ^ 0xFFFF;

        pkt_checksum -= *((unsigned short *)(pkt->data + 16)) ^ 0xFFFF;
        pkt_checksum -= *((unsigned short *)(pkt->data + 18)) ^ 0xFFFF;

        /* Change Source-IP-Address */
        *((u32_t *)(pkt->data + 16)) = newip;

        /* Add new Source-IP-Address */
        checksum += *((unsigned short *)(pkt->data + 16)) ^ 0xFFFF;
        checksum += *((unsigned short *)(pkt->data + 18)) ^ 0xFFFF;

        pkt_checksum += *((unsigned short *)(pkt->data + 16)) ^ 0xFFFF;
        pkt_checksum += *((unsigned short *)(pkt->data + 18)) ^ 0xFFFF;

        /* Write new checksum */
        if (!checksum) {
          checksum = 0xFFFF;
        }
        *((unsigned short *)(pkt->data + 14)) = checksum;
        if (pkt->data[13] == 6) {
          *((unsigned short *)(pkt->data + 20 + iphdr)) = pkt_checksum;
        }
        if (cv && (pkt->data[13] == 17)) {
          *((unsigned short *)(pkt->data + 10 + iphdr)) = pkt_checksum;
        }

        /* Log Packet */
        strcpy(ipstr, inet_ntoa(*((struct in_addr *)(pkt->data + 16))));
        if (pkt->data[13] == 1) {
          syslog(LOG_INFO, "Open ICMP %s -> %s\n", ipstr,
                 inet_ntoa(*((struct in_addr *)(pkt->data + 20))));
        } else {
          syslog(LOG_INFO, "Open %s %s:%d -> %s:%d\n",
                 pkt->data[13] == 6 ? "TCP" : "UDP", ipstr,
                 ntohs(*((short *)(pkt->data + iphdr + 4))),
                 inet_ntoa(*((struct in_addr *)(pkt->data + 20))),
                 ntohs(*((short *)(pkt->data + iphdr + 6))));
        }
      }
      output(pcb, pkt->data, pkt->length);
      free(pkt);
    } else {
      if (prev == NULL)
        pend_q = pkt;
      else
        prev->next = pkt;
      prev = pkt;
    }
  }
  pend_qtail = prev;
  if (prev != NULL)
    prev->next = NULL;
}

static int active_packet(p, len)
unsigned char *p;
int len;
{
  int proto, i;
  const struct protent *protp;

  if (len < PPP_HDRLEN)
    return 0;
  proto = PPP_PROTOCOL(p);
#ifdef PPP_FILTER
  p[0] = 1; /* outbound packet indicator */
  if ((pass_filter.bf_len != 0 &&
       bpf_filter(pass_filter.bf_insns, p, len, len) == 0) ||
      (active_filter.bf_len != 0 &&
       bpf_filter(active_filter.bf_insns, p, len, len) == 0)) {
    p[0] = 0xff;
    return 0;
  }
  p[0] = 0xff;
#endif
  for (i = 0; (protp = protocols[i]) != NULL; ++i) {
    if (protp->protocol < 0xC000 && (protp->protocol & ~0x8000) == proto) {
      if (protp->active_pkt == NULL)
        return 1;
      return (*protp->active_pkt)(p, len);
    }
  }
  return 0; /* not a supported protocol !!?? */
}

static const char *eap_state_name(enum eap_state_code esc) {
  static const char *state_names[] = {EAP_STATES};

  return (state_names[(int)esc]);
}

static void eap_init(ppp_pcb *pcb) {

  BZERO(&pcb->eap, sizeof(eap_state));
#if PPP_SERVER
  pcb->eap.es_server.ea_id = magic();
#endif /* PPP_SERVER */
}

static void eap_client_timeout(void *arg) {
  ppp_pcb *pcb = (ppp_pcb *)arg;

  if (!eap_client_active(pcb))
    return;

  ppp_error(("EAP: timeout waiting for Request from peer"));
  auth_withpeer_fail(pcb, PPP_EAP);
  pcb->eap.es_client.ea_state = eapBadAuth;
}

void eap_authwithpeer(ppp_pcb *pcb, const char *localname) {

  if (NULL == localname)
    return;

  /* Save the peer name we're given */
  pcb->eap.es_client.ea_name = localname;
  pcb->eap.es_client.ea_namelen = strlen(localname);

  pcb->eap.es_client.ea_state = eapListen;

  /*
   * Start a timer so that if the other end just goes
   * silent, we don't sit here waiting forever.
   */
  if (pcb->settings.eap_req_time > 0)
    TIMEOUT(eap_client_timeout, pcb, pcb->settings.eap_req_time);
}

static void eap_send_failure(ppp_pcb *pcb) {
  struct pbuf *p;
  u_char *outp;

  p = pbuf_alloc(PBUF_RAW, (u16_t)(PPP_HDRLEN + EAP_HEADERLEN), PBUF_RAM);
  if (NULL == p)
    return;
  if (p->tot_len != p->len) {
    pbuf_free(p);
    return;
  }

  outp = (u_char *)p->payload;

  MAKEHEADER(outp, PPP_EAP);

  PUTCHAR(EAP_FAILURE, outp);
  pcb->eap.es_server.ea_id++;
  PUTCHAR(pcb->eap.es_server.ea_id, outp);
  PUTSHORT(EAP_HEADERLEN, outp);

  ppp_write(pcb, p);

  pcb->eap.es_server.ea_state = eapBadAuth;
  auth_peer_fail(pcb, PPP_EAP);
}

static void eap_send_success(ppp_pcb *pcb) {
  struct pbuf *p;
  u_char *outp;

  p = pbuf_alloc(PBUF_RAW, (u16_t)(PPP_HDRLEN + EAP_HEADERLEN), PBUF_RAM);
  if (NULL == p)
    return;
  if (p->tot_len != p->len) {
    pbuf_free(p);
    return;
  }

  outp = (u_char *)p->payload;

  MAKEHEADER(outp, PPP_EAP);

  PUTCHAR(EAP_SUCCESS, outp);
  pcb->eap.es_server.ea_id++;
  PUTCHAR(pcb->eap.es_server.ea_id, outp);
  PUTSHORT(EAP_HEADERLEN, outp);

  ppp_write(pcb, p);

  auth_peer_success(pcb, PPP_EAP, 0, pcb->eap.es_server.ea_peer,
                    pcb->eap.es_server.ea_peerlen);
}

static bool pncrypt_setkey(int timeoffs) {
  struct tm *tp;
  char tbuf[9];
  SHA1_CTX ctxt;
  u_char dig[SHA_DIGESTSIZE];
  time_t reftime;

  if (pn_secret == NULL)
    return (0);
  reftime = time(NULL) + timeoffs;
  tp = localtime(&reftime);
  SHA1Init(&ctxt);
  SHA1Update(&ctxt, pn_secret, strlen(pn_secret));
  strftime(tbuf, sizeof(tbuf), "%Y%m%d", tp);
  SHA1Update(&ctxt, tbuf, strlen(tbuf));
  SHA1Final(dig, &ctxt);
  /* FIXME: if we want to do SRP, we need to find a way to pass the PolarSSL
   * des_context instead of using static memory */
  return (DesSetkey(dig));
}

struct b64state {
  u32_t bs_bits;
  int bs_offs;
}

static int b64enc(bs, inp, inlen, outp)
struct b64state *bs;
u_char *inp;
int inlen;
u_char *outp;
{
  int outlen = 0;

  while (inlen > 0) {
    bs->bs_bits = (bs->bs_bits << 8) | *inp++;
    inlen--;
    bs->bs_offs += 8;
    if (bs->bs_offs >= 24) {
      *outp++ = base64[(bs->bs_bits >> 18) & 0x3F];
      *outp++ = base64[(bs->bs_bits >> 12) & 0x3F];
      *outp++ = base64[(bs->bs_bits >> 6) & 0x3F];
      *outp++ = base64[bs->bs_bits & 0x3F];
      outlen += 4;
      bs->bs_offs = 0;
      bs->bs_bits = 0;
    }
  }
  return (outlen);
}

static int b64flush(bs, outp)
struct b64state *bs;
u_char *outp;
{
  int outlen = 0;

  if (bs->bs_offs == 8) {
    *outp++ = base64[(bs->bs_bits >> 2) & 0x3F];
    *outp++ = base64[(bs->bs_bits << 4) & 0x3F];
    outlen = 2;
  } else if (bs->bs_offs == 16) {
    *outp++ = base64[(bs->bs_bits >> 10) & 0x3F];
    *outp++ = base64[(bs->bs_bits >> 4) & 0x3F];
    *outp++ = base64[(bs->bs_bits << 2) & 0x3F];
    outlen = 3;
  }
  bs->bs_offs = 0;
  bs->bs_bits = 0;
  return (outlen);
}

static int b64dec(bs, inp, inlen, outp)
struct b64state *bs;
u_char *inp;
int inlen;
u_char *outp;
{
  int outlen = 0;
  char *cp;

  while (inlen > 0) {
    if ((cp = strchr(base64, *inp++)) == NULL)
      break;
    bs->bs_bits = (bs->bs_bits << 6) | (cp - base64);
    inlen--;
    bs->bs_offs += 6;
    if (bs->bs_offs >= 8) {
      *outp++ = bs->bs_bits >> (bs->bs_offs - 8);
      outlen++;
      bs->bs_offs -= 8;
    }
  }
  return (outlen);
}

static void eap_figure_next_state(ppp_pcb *pcb, int status) {
#ifdef USE_SRP
  unsigned char secbuf[MAXSECRETLEN], clear[8], *sp, *dp;
  struct t_pw tpw;
  struct t_confent *tce, mytce;
  char *cp, *cp2;
  struct t_server *ts;
  int id, i, plen, toffs;
  u_char vals[2];
  struct b64state bs;
#endif /* USE_SRP */

  pcb->settings.eap_timeout_time = pcb->eap.es_savedtime;
  switch (pcb->eap.es_server.ea_state) {
  case eapBadAuth:
    return;

  case eapIdentify:
#ifdef USE_SRP
    /* Discard any previous session. */
    ts = (struct t_server *)pcb->eap.es_server.ea_session;
    if (ts != NULL) {
      t_serverclose(ts);
      pcb->eap.es_server.ea_session = NULL;
      pcb->eap.es_server.ea_skey = NULL;
    }
#endif /* USE_SRP */
    if (status != 0) {
      pcb->eap.es_server.ea_state = eapBadAuth;
      break;
    }
#ifdef USE_SRP
    /* If we've got a pseudonym, try to decode to real name. */
    if (pcb->eap.es_server.ea_peerlen > SRP_PSEUDO_LEN &&
        strncmp(pcb->eap.es_server.ea_peer, SRP_PSEUDO_ID, SRP_PSEUDO_LEN) ==
            0 &&
        (pcb->eap.es_server.ea_peerlen - SRP_PSEUDO_LEN) * 3 / 4 <
            sizeof(secbuf)) {
      BZERO(&bs, sizeof(bs));
      plen = b64dec(&bs, pcb->eap.es_server.ea_peer + SRP_PSEUDO_LEN,
                    pcb->eap.es_server.ea_peerlen - SRP_PSEUDO_LEN, secbuf);
      toffs = 0;
      for (i = 0; i < 5; i++) {
        pncrypt_setkey(toffs);
        toffs -= 86400;
        /* FIXME: if we want to do SRP, we need to find a way to pass the
         * PolarSSL des_context instead of using static memory */
        if (!DesDecrypt(secbuf, clear)) {
          ppp_dbglog(("no DES here; cannot decode "
                      "pseudonym"));
          return;
        }
        id = *(unsigned char *)clear;
        if (id + 1 <= plen && id + 9 > plen)
          break;
      }
      if (plen % 8 == 0 && i < 5) {
        /*
         * Note that this is always shorter than the
         * original stored string, so there's no need
         * to realloc.
         */
        if ((i = plen = *(unsigned char *)clear) > 7)
          i = 7;
        pcb->eap.es_server.ea_peerlen = plen;
        dp = (unsigned char *)pcb->eap.es_server.ea_peer;
        MEMCPY(dp, clear + 1, i);
        plen -= i;
        dp += i;
        sp = secbuf + 8;
        while (plen > 0) {
          /* FIXME: if we want to do SRP, we need to find a way to pass the
           * PolarSSL des_context instead of using static memory */
          (void)DesDecrypt(sp, dp);
          sp += 8;
          dp += 8;
          plen -= 8;
        }
        pcb->eap.es_server.ea_peer[pcb->eap.es_server.ea_peerlen] = '\0';
        ppp_dbglog(("decoded pseudonym to \"%.*q\"",
                    pcb->eap.es_server.ea_peerlen, pcb->eap.es_server.ea_peer));
      } else {
        ppp_dbglog(("failed to decode real name"));
        /* Stay in eapIdentfy state; requery */
        break;
      }
    }
    /* Look up user in secrets database. */
    if (get_srp_secret(pcb->eap.es_unit, pcb->eap.es_server.ea_peer,
                       pcb->eap.es_server.ea_name, (char *)secbuf, 1) != 0) {
      /* Set up default in case SRP entry is bad */
      pcb->eap.es_server.ea_state = eapMD5Chall;
      /* Get t_confent based on index in srp-secrets */
      id = strtol((char *)secbuf, &cp, 10);
      if (*cp++ != ':' || id < 0)
        break;
      if (id == 0) {
        mytce.index = 0;
        mytce.modulus.data = (u_char *)wkmodulus;
        mytce.modulus.len = sizeof(wkmodulus);
        mytce.generator.data = (u_char *)"\002";
        mytce.generator.len = 1;
        tce = &mytce;
      } else if ((tce = gettcid(id)) != NULL) {
        /*
         * Client will have to verify this modulus/
         * generator combination, and that will take
         * a while.  Lengthen the timeout here.
         */
        if (pcb->settings.eap_timeout_time > 0 &&
            pcb->settings.eap_timeout_time < 30)
          pcb->settings.eap_timeout_time = 30;
      } else {
        break;
      }
      if ((cp2 = strchr(cp, ':')) == NULL)
        break;
      *cp2++ = '\0';
      tpw.pebuf.name = pcb->eap.es_server.ea_peer;
      tpw.pebuf.password.len = t_fromb64((char *)tpw.pwbuf, cp);
      tpw.pebuf.password.data = tpw.pwbuf;
      tpw.pebuf.salt.len = t_fromb64((char *)tpw.saltbuf, cp2);
      tpw.pebuf.salt.data = tpw.saltbuf;
      if ((ts = t_serveropenraw(&tpw.pebuf, tce)) == NULL)
        break;
      pcb->eap.es_server.ea_session = (void *)ts;
      pcb->eap.es_server.ea_state = eapSRP1;
      vals[0] = pcb->eap.es_server.ea_id + 1;
      vals[1] = EAPT_SRP;
      t_serveraddexdata(ts, vals, 2);
      /* Generate B; must call before t_servergetkey() */
      t_servergenexp(ts);
      break;
    }
#endif /* USE_SRP */
    pcb->eap.es_server.ea_state = eapMD5Chall;
    break;

  case eapSRP1:
#ifdef USE_SRP
    ts = (struct t_server *)pcb->eap.es_server.ea_session;
    if (ts != NULL && status != 0) {
      t_serverclose(ts);
      pcb->eap.es_server.ea_session = NULL;
      pcb->eap.es_server.ea_skey = NULL;
    }
#endif /* USE_SRP */
    if (status == 1) {
      pcb->eap.es_server.ea_state = eapMD5Chall;
    } else if (status != 0 || pcb->eap.es_server.ea_session == NULL) {
      pcb->eap.es_server.ea_state = eapBadAuth;
    } else {
      pcb->eap.es_server.ea_state = eapSRP2;
    }
    break;

  case eapSRP2:
#ifdef USE_SRP
    ts = (struct t_server *)pcb->eap.es_server.ea_session;
    if (ts != NULL && status != 0) {
      t_serverclose(ts);
      pcb->eap.es_server.ea_session = NULL;
      pcb->eap.es_server.ea_skey = NULL;
    }
#endif /* USE_SRP */
    if (status != 0 || pcb->eap.es_server.ea_session == NULL) {
      pcb->eap.es_server.ea_state = eapBadAuth;
    } else {
      pcb->eap.es_server.ea_state = eapSRP3;
    }
    break;

  case eapSRP3:
  case eapSRP4:
#ifdef USE_SRP
    ts = (struct t_server *)pcb->eap.es_server.ea_session;
    if (ts != NULL && status != 0) {
      t_serverclose(ts);
      pcb->eap.es_server.ea_session = NULL;
      pcb->eap.es_server.ea_skey = NULL;
    }
#endif /* USE_SRP */
    if (status != 0 || pcb->eap.es_server.ea_session == NULL) {
      pcb->eap.es_server.ea_state = eapBadAuth;
    } else {
      pcb->eap.es_server.ea_state = eapOpen;
    }
    break;

  case eapMD5Chall:
    if (status != 0) {
      pcb->eap.es_server.ea_state = eapBadAuth;
    } else {
      pcb->eap.es_server.ea_state = eapOpen;
    }
    break;

  default:
    pcb->eap.es_server.ea_state = eapBadAuth;
    break;
  }
  if (pcb->eap.es_server.ea_state == eapBadAuth)
    eap_send_failure(pcb);
}

static void eap_send_request(ppp_pcb *pcb) {
  struct pbuf *p;
  u_char *outp;
  u_char *lenloc;
  int outlen;
  int len;
  const char *str;
#ifdef USE_SRP
  struct t_server *ts;
  u_char clear[8], cipher[8], dig[SHA_DIGESTSIZE], *optr, *cp;
  int i, j;
  struct b64state b64;
  SHA1_CTX ctxt;
#endif /* USE_SRP */

  /* Handle both initial auth and restart */
  if (pcb->eap.es_server.ea_state < eapIdentify &&
      pcb->eap.es_server.ea_state != eapInitial) {
    pcb->eap.es_server.ea_state = eapIdentify;
#if PPP_REMOTENAME
    if (pcb->settings.explicit_remote && pcb->remote_name) {
      /*
       * If we already know the peer's
       * unauthenticated name, then there's no
       * reason to ask.  Go to next state instead.
       */
      int len = (int)strlen(pcb->remote_name);
      if (len > MAXNAMELEN) {
        len = MAXNAMELEN;
      }
      MEMCPY(pcb->eap.es_server.ea_peer, pcb->remote_name, len);
      pcb->eap.es_server.ea_peer[len] = '\0';
      pcb->eap.es_server.ea_peerlen = len;
      eap_figure_next_state(pcb, 0);
    }
#endif /* PPP_REMOTENAME */
  }

  if (pcb->settings.eap_max_transmits > 0 &&
      pcb->eap.es_server.ea_requests >= pcb->settings.eap_max_transmits) {
    if (pcb->eap.es_server.ea_responses > 0)
      ppp_error(("EAP: too many Requests sent"));
    else
      ppp_error(("EAP: no response to Requests"));
    eap_send_failure(pcb);
    return;
  }

  p = pbuf_alloc(PBUF_RAW, (u16_t)(PPP_CTRL_PBUF_UNKNOWN_SIZE), PBUF_RAM);
  if (NULL == p)
    return;
  if (p->tot_len != p->len) {
    pbuf_free(p);
    return;
  }

  outp = (u_char *)p->payload;

  MAKEHEADER(outp, PPP_EAP);

  PUTCHAR(EAP_REQUEST, outp);
  PUTCHAR(pcb->eap.es_server.ea_id, outp);
  lenloc = outp;
  INCPTR(2, outp);

  switch (pcb->eap.es_server.ea_state) {
  case eapIdentify:
    PUTCHAR(EAPT_IDENTITY, outp);
    str = "Name";
    len = strlen(str);
    MEMCPY(outp, str, len);
    INCPTR(len, outp);
    break;

  case eapMD5Chall:
    PUTCHAR(EAPT_MD5CHAP, outp);
    /*
     * pick a random challenge length between
     * EAP_MIN_CHALLENGE_LENGTH and EAP_MAX_CHALLENGE_LENGTH
     */
    pcb->eap.es_challen = EAP_MIN_CHALLENGE_LENGTH +
                          magic_pow(EAP_MIN_MAX_POWER_OF_TWO_CHALLENGE_LENGTH);
    PUTCHAR(pcb->eap.es_challen, outp);
    magic_random_bytes(pcb->eap.es_challenge, pcb->eap.es_challen);
    MEMCPY(outp, pcb->eap.es_challenge, pcb->eap.es_challen);
    INCPTR(pcb->eap.es_challen, outp);
    MEMCPY(outp, pcb->eap.es_server.ea_name, pcb->eap.es_server.ea_namelen);
    INCPTR(pcb->eap.es_server.ea_namelen, outp);
    break;

#ifdef USE_SRP
  case eapSRP1:
    PUTCHAR(EAPT_SRP, outp);
    PUTCHAR(EAPSRP_CHALLENGE, outp);

    PUTCHAR(pcb->eap.es_server.ea_namelen, outp);
    MEMCPY(outp, pcb->eap.es_server.ea_name, pcb->eap.es_server.ea_namelen);
    INCPTR(pcb->eap.es_server.ea_namelen, outp);

    ts = (struct t_server *)pcb->eap.es_server.ea_session;
    assert(ts != NULL);
    PUTCHAR(ts->s.len, outp);
    MEMCPY(outp, ts->s.data, ts->s.len);
    INCPTR(ts->s.len, outp);

    if (ts->g.len == 1 && ts->g.data[0] == 2) {
      PUTCHAR(0, outp);
    } else {
      PUTCHAR(ts->g.len, outp);
      MEMCPY(outp, ts->g.data, ts->g.len);
      INCPTR(ts->g.len, outp);
    }

    if (ts->n.len != sizeof(wkmodulus) ||
        BCMP(ts->n.data, wkmodulus, sizeof(wkmodulus)) != 0) {
      MEMCPY(outp, ts->n.data, ts->n.len);
      INCPTR(ts->n.len, outp);
    }
    break;

  case eapSRP2:
    PUTCHAR(EAPT_SRP, outp);
    PUTCHAR(EAPSRP_SKEY, outp);

    ts = (struct t_server *)pcb->eap.es_server.ea_session;
    assert(ts != NULL);
    MEMCPY(outp, ts->B.data, ts->B.len);
    INCPTR(ts->B.len, outp);
    break;

  case eapSRP3:
    PUTCHAR(EAPT_SRP, outp);
    PUTCHAR(EAPSRP_SVALIDATOR, outp);
    PUTLONG(SRPVAL_EBIT, outp);
    ts = (struct t_server *)pcb->eap.es_server.ea_session;
    assert(ts != NULL);
    MEMCPY(outp, t_serverresponse(ts), SHA_DIGESTSIZE);
    INCPTR(SHA_DIGESTSIZE, outp);

    if (pncrypt_setkey(0)) {
      /* Generate pseudonym */
      optr = outp;
      cp = (unsigned char *)pcb->eap.es_server.ea_peer;
      if ((j = i = pcb->eap.es_server.ea_peerlen) > 7)
        j = 7;
      clear[0] = i;
      MEMCPY(clear + 1, cp, j);
      i -= j;
      cp += j;
      /* FIXME: if we want to do SRP, we need to find a way to pass the PolarSSL
       * des_context instead of using static memory */
      if (!DesEncrypt(clear, cipher)) {
        ppp_dbglog(("no DES here; not generating pseudonym"));
        break;
      }
      BZERO(&b64, sizeof(b64));
      outp++; /* space for pseudonym length */
      outp += b64enc(&b64, cipher, 8, outp);
      while (i >= 8) {
        /* FIXME: if we want to do SRP, we need to find a way to pass the
         * PolarSSL des_context instead of using static memory */
        (void)DesEncrypt(cp, cipher);
        outp += b64enc(&b64, cipher, 8, outp);
        cp += 8;
        i -= 8;
      }
      if (i > 0) {
        MEMCPY(clear, cp, i);
        cp += i;
        magic_random_bytes(cp, 8 - i);
        /* FIXME: if we want to do SRP, we need to find a way to pass the
         * PolarSSL des_context instead of using static memory */
        (void)DesEncrypt(clear, cipher);
        outp += b64enc(&b64, cipher, 8, outp);
      }
      outp += b64flush(&b64, outp);

      /* Set length and pad out to next 20 octet boundary */
      i = outp - optr - 1;
      *optr = i;
      i %= SHA_DIGESTSIZE;
      if (i != 0) {
        magic_random_bytes(outp, SHA_DIGESTSIZE - i);
        INCPTR(SHA_DIGESTSIZE - i, outp);
      }

      /* Obscure the pseudonym with SHA1 hash */
      SHA1Init(&ctxt);
      SHA1Update(&ctxt, &pcb->eap.es_server.ea_id, 1);
      SHA1Update(&ctxt, pcb->eap.es_server.ea_skey, SESSION_KEY_LEN);
      SHA1Update(&ctxt, pcb->eap.es_server.ea_peer,
                 pcb->eap.es_server.ea_peerlen);
      while (optr < outp) {
        SHA1Final(dig, &ctxt);
        cp = dig;
        while (cp < dig + SHA_DIGESTSIZE)
          *optr++ ^= *cp++;
        SHA1Init(&ctxt);
        SHA1Update(&ctxt, &pcb->eap.es_server.ea_id, 1);
        SHA1Update(&ctxt, pcb->eap.es_server.ea_skey, SESSION_KEY_LEN);
        SHA1Update(&ctxt, optr - SHA_DIGESTSIZE, SHA_DIGESTSIZE);
      }
    }
    break;

  case eapSRP4:
    PUTCHAR(EAPT_SRP, outp);
    PUTCHAR(EAPSRP_LWRECHALLENGE, outp);
    pcb->eap.es_challen = EAP_MIN_CHALLENGE_LENGTH +
                          magic_pow(EAP_MIN_MAX_POWER_OF_TWO_CHALLENGE_LENGTH);
    magic_random_bytes(pcb->eap.es_challenge, pcb->eap.es_challen);
    MEMCPY(outp, pcb->eap.es_challenge, pcb->eap.es_challen);
    INCPTR(pcb->eap.es_challen, outp);
    break;
#endif /* USE_SRP */

  default:
    return;
  }

  outlen = (outp - (unsigned char *)p->payload) - PPP_HDRLEN;
  PUTSHORT(outlen, lenloc);

  pbuf_realloc(p, outlen + PPP_HDRLEN);
  ppp_write(pcb, p);

  pcb->eap.es_server.ea_requests++;

  if (pcb->settings.eap_timeout_time > 0)
    TIMEOUT(eap_server_timeout, pcb, pcb->settings.eap_timeout_time);
}

void eap_authpeer(ppp_pcb *pcb, const char *localname) {

  /* Save the name we're given. */
  pcb->eap.es_server.ea_name = localname;
  pcb->eap.es_server.ea_namelen = strlen(localname);

  pcb->eap.es_savedtime = pcb->settings.eap_timeout_time;

  /* Lower layer up yet? */
  if (pcb->eap.es_server.ea_state == eapInitial ||
      pcb->eap.es_server.ea_state == eapPending) {
    pcb->eap.es_server.ea_state = eapPending;
    return;
  }

  pcb->eap.es_server.ea_state = eapPending;

  /* ID number not updated here intentionally; hashed into M1 */
  eap_send_request(pcb);
}

static void eap_server_timeout(void *arg) {
  ppp_pcb *pcb = (ppp_pcb *)arg;

  if (!eap_server_active(pcb))
    return;

  /* EAP ID number must not change on timeout. */
  eap_send_request(pcb);
}

static void eap_rechallenge(void *arg) {
  ppp_pcb *pcb = (ppp_pcb *)arg;

  if (pcb->eap.es_server.ea_state != eapOpen &&
      pcb->eap.es_server.ea_state != eapSRP4)
    return;

  pcb->eap.es_server.ea_requests = 0;
  pcb->eap.es_server.ea_state = eapIdentify;
  eap_figure_next_state(pcb, 0);
  pcb->eap.es_server.ea_id++;
  eap_send_request(pcb);
}

static void srp_lwrechallenge(void *arg) {
  ppp_pcb *pcb = (ppp_pcb *)arg;

  if (pcb->eap.es_server.ea_state != eapOpen ||
      pcb->eap.es_server.ea_type != EAPT_SRP)
    return;

  pcb->eap.es_server.ea_requests = 0;
  pcb->eap.es_server.ea_state = eapSRP4;
  pcb->eap.es_server.ea_id++;
  eap_send_request(pcb);
}

static void eap_lowerup(ppp_pcb *pcb) {
  pcb->eap.es_client.ea_state = eapClosed;
#if PPP_SERVER
  pcb->eap.es_server.ea_state = eapClosed;
#endif /* PPP_SERVER */
}

static void eap_lowerdown(ppp_pcb *pcb) {

  if (eap_client_active(pcb) && pcb->settings.eap_req_time > 0) {
    UNTIMEOUT(eap_client_timeout, pcb);
  }
#if PPP_SERVER
  if (eap_server_active(pcb)) {
    if (pcb->settings.eap_timeout_time > 0) {
      UNTIMEOUT(eap_server_timeout, pcb);
    }
  } else {
    if ((pcb->eap.es_server.ea_state == eapOpen ||
         pcb->eap.es_server.ea_state == eapSRP4) &&
        pcb->eap.es_rechallenge > 0) {
      UNTIMEOUT(eap_rechallenge, (void *)pcb);
    }
    if (pcb->eap.es_server.ea_state == eapOpen &&
        pcb->eap.es_lwrechallenge > 0) {
      UNTIMEOUT(srp_lwrechallenge, (void *)pcb);
    }
  }

  pcb->eap.es_client.ea_state = pcb->eap.es_server.ea_state = eapInitial;
  pcb->eap.es_client.ea_requests = pcb->eap.es_server.ea_requests = 0;
#endif /* PPP_SERVER */
}

static void eap_protrej(ppp_pcb *pcb) {

  if (eap_client_active(pcb)) {
    ppp_error(("EAP authentication failed due to Protocol-Reject"));
    auth_withpeer_fail(pcb, PPP_EAP);
  }
#if PPP_SERVER
  if (eap_server_active(pcb)) {
    ppp_error(("EAP authentication of peer failed on Protocol-Reject"));
    auth_peer_fail(pcb, PPP_EAP);
  }
#endif /* PPP_SERVER */
  eap_lowerdown(pcb);
}

static void eap_send_response(ppp_pcb *pcb, u_char id, u_char typenum,
                              const u_char *str, int lenstr) {
  struct pbuf *p;
  u_char *outp;
  int msglen;

  msglen = EAP_HEADERLEN + sizeof(u_char) + lenstr;
  p = pbuf_alloc(PBUF_RAW, (u16_t)(PPP_HDRLEN + msglen), PBUF_RAM);
  if (NULL == p)
    return;
  if (p->tot_len != p->len) {
    pbuf_free(p);
    return;
  }

  outp = (u_char *)p->payload;

  MAKEHEADER(outp, PPP_EAP);

  PUTCHAR(EAP_RESPONSE, outp);
  PUTCHAR(id, outp);
  pcb->eap.es_client.ea_id = id;
  PUTSHORT(msglen, outp);
  PUTCHAR(typenum, outp);
  if (lenstr > 0) {
    MEMCPY(outp, str, lenstr);
  }

  ppp_write(pcb, p);
}

static void eap_chap_response(ppp_pcb *pcb, u_char id, u_char *hash,
                              const char *name, int namelen) {
  struct pbuf *p;
  u_char *outp;
  int msglen;

  msglen = EAP_HEADERLEN + 2 * sizeof(u_char) + MD5_SIGNATURE_SIZE + namelen;
  p = pbuf_alloc(PBUF_RAW, (u16_t)(PPP_HDRLEN + msglen), PBUF_RAM);
  if (NULL == p)
    return;
  if (p->tot_len != p->len) {
    pbuf_free(p);
    return;
  }

  outp = (u_char *)p->payload;

  MAKEHEADER(outp, PPP_EAP);

  PUTCHAR(EAP_RESPONSE, outp);
  PUTCHAR(id, outp);
  pcb->eap.es_client.ea_id = id;
  PUTSHORT(msglen, outp);
  PUTCHAR(EAPT_MD5CHAP, outp);
  PUTCHAR(MD5_SIGNATURE_SIZE, outp);
  MEMCPY(outp, hash, MD5_SIGNATURE_SIZE);
  INCPTR(MD5_SIGNATURE_SIZE, outp);
  if (namelen > 0) {
    MEMCPY(outp, name, namelen);
  }

  ppp_write(pcb, p);
}

static void eap_srp_response(esp, id, subtypenum, str, lenstr) eap_state *esp;
u_char id;
u_char subtypenum;
u_char *str;
int lenstr;
{
  ppp_pcb *pcb = &ppp_pcb_list[pcb->eap.es_unit];
  struct pbuf *p;
  u_char *outp;
  int msglen;

  msglen = EAP_HEADERLEN + 2 * sizeof(u_char) + lenstr;
  p = pbuf_alloc(PBUF_RAW, (u16_t)(PPP_HDRLEN + msglen), PBUF_RAM);
  if (NULL == p)
    return;
  if (p->tot_len != p->len) {
    pbuf_free(p);
    return;
  }

  outp = p->payload;

  MAKEHEADER(outp, PPP_EAP);

  PUTCHAR(EAP_RESPONSE, outp);
  PUTCHAR(id, outp);
  pcb->eap.es_client.ea_id = id;
  PUTSHORT(msglen, outp);
  PUTCHAR(EAPT_SRP, outp);
  PUTCHAR(subtypenum, outp);
  if (lenstr > 0) {
    MEMCPY(outp, str, lenstr);
  }

  ppp_write(pcb, p);
}

static void eap_srpval_response(esp, id, flags, str) eap_state *esp;
u_char id;
u32_t flags;
u_char *str;
{
  ppp_pcb *pcb = &ppp_pcb_list[pcb->eap.es_unit];
  struct pbuf *p;
  u_char *outp;
  int msglen;

  msglen = EAP_HEADERLEN + 2 * sizeof(u_char) + sizeof(u32_t) + SHA_DIGESTSIZE;
  p = pbuf_alloc(PBUF_RAW, (u16_t)(PPP_HDRLEN + msglen), PBUF_RAM);
  if (NULL == p)
    return;
  if (p->tot_len != p->len) {
    pbuf_free(p);
    return;
  }

  outp = p->payload;

  MAKEHEADER(outp, PPP_EAP);

  PUTCHAR(EAP_RESPONSE, outp);
  PUTCHAR(id, outp);
  pcb->eap.es_client.ea_id = id;
  PUTSHORT(msglen, outp);
  PUTCHAR(EAPT_SRP, outp);
  PUTCHAR(EAPSRP_CVALIDATOR, outp);
  PUTLONG(flags, outp);
  MEMCPY(outp, str, SHA_DIGESTSIZE);

  ppp_write(pcb, p);
}

static void eap_send_nak(ppp_pcb *pcb, u_char id, u_char type) {
  struct pbuf *p;
  u_char *outp;
  int msglen;

  msglen = EAP_HEADERLEN + 2 * sizeof(u_char);
  p = pbuf_alloc(PBUF_RAW, (u16_t)(PPP_HDRLEN + msglen), PBUF_RAM);
  if (NULL == p)
    return;
  if (p->tot_len != p->len) {
    pbuf_free(p);
    return;
  }

  outp = (u_char *)p->payload;

  MAKEHEADER(outp, PPP_EAP);

  PUTCHAR(EAP_RESPONSE, outp);
  PUTCHAR(id, outp);
  pcb->eap.es_client.ea_id = id;
  PUTSHORT(msglen, outp);
  PUTCHAR(EAPT_NAK, outp);
  PUTCHAR(type, outp);

  ppp_write(pcb, p);
}

static char *name_of_pn_file() {
  char *user, *path, *file;
  struct passwd *pw;
  size_t pl;
  static bool pnlogged = 0;

  pw = getpwuid(getuid());
  if (pw == NULL || (user = pw->pw_dir) == NULL || user[0] == 0) {
    errno = EINVAL;
    return (NULL);
  }
  file = _PATH_PSEUDONYM;
  pl = strlen(user) + strlen(file) + 2;
  path = malloc(pl);
  if (path == NULL)
    return (NULL);
  (void)slprintf(path, pl, "%s/%s", user, file);
  if (!pnlogged) {
    ppp_dbglog(("pseudonym file: %s", path));
    pnlogged = 1;
  }
  return (path);
}

static int open_pn_file(modebits)
mode_t modebits;
{
  char *path;
  int fd, err;

  if ((path = name_of_pn_file()) == NULL)
    return (-1);
  fd = open(path, modebits, S_IRUSR | S_IWUSR);
  err = errno;
  free(path);
  errno = err;
  return (fd);
}

static void remove_pn_file() {
  char *path;

  if ((path = name_of_pn_file()) != NULL) {
    (void)unlink(path);
    (void)free(path);
  }
}

static void write_pseudonym(esp, inp, len, id) eap_state *esp;
u_char *inp;
int len, id;
{
  u_char val;
  u_char *datp, *digp;
  SHA1_CTX ctxt;
  u_char dig[SHA_DIGESTSIZE];
  int dsize, fd, olen = len;

  /*
   * Do the decoding by working backwards.  This eliminates the need
   * to save the decoded output in a separate buffer.
   */
  val = id;
  while (len > 0) {
    if ((dsize = len % SHA_DIGESTSIZE) == 0)
      dsize = SHA_DIGESTSIZE;
    len -= dsize;
    datp = inp + len;
    SHA1Init(&ctxt);
    SHA1Update(&ctxt, &val, 1);
    SHA1Update(&ctxt, pcb->eap.es_client.ea_skey, SESSION_KEY_LEN);
    if (len > 0) {
      SHA1Update(&ctxt, datp, SHA_DIGESTSIZE);
    } else {
      SHA1Update(&ctxt, pcb->eap.es_client.ea_name,
                 pcb->eap.es_client.ea_namelen);
    }
    SHA1Final(dig, &ctxt);
    for (digp = dig; digp < dig + SHA_DIGESTSIZE; digp++)
      *datp++ ^= *digp;
  }

  /* Now check that the result is sane */
  if (olen <= 0 || *inp + 1 > olen) {
    ppp_dbglog(("EAP: decoded pseudonym is unusable <%.*B>", olen, inp));
    return;
  }

  /* Save it away */
  fd = open_pn_file(O_WRONLY | O_CREAT | O_TRUNC);
  if (fd < 0) {
    ppp_dbglog(("EAP: error saving pseudonym: %m"));
    return;
  }
  len = write(fd, inp + 1, *inp);
  if (close(fd) != -1 && len == *inp) {
    ppp_dbglog(("EAP: saved pseudonym"));
    pcb->eap.es_usedpseudo = 0;
  } else {
    ppp_dbglog(("EAP: failed to save pseudonym"));
    remove_pn_file();
  }
}

static void eap_request(ppp_pcb *pcb, u_char *inp, int id, int len) {
  u_char typenum;
  u_char vallen;
  int secret_len;
  char secret[MAXSECRETLEN];
  char rhostname[MAXNAMELEN];
  lwip_md5_context mdContext;
  u_char hash[MD5_SIGNATURE_SIZE];
#ifdef USE_SRP
  struct t_client *tc;
  struct t_num sval, gval, Nval, *Ap, Bval;
  u_char vals[2];
  SHA1_CTX ctxt;
  u_char dig[SHA_DIGESTSIZE];
  int fd;
#endif /* USE_SRP */

  /*
   * Ignore requests if we're not open
   */
  if (pcb->eap.es_client.ea_state <= eapClosed)
    return;

  /*
   * Note: we update es_client.ea_id *only if* a Response
   * message is being generated.  Otherwise, we leave it the
   * same for duplicate detection purposes.
   */

  pcb->eap.es_client.ea_requests++;
  if (pcb->settings.eap_allow_req != 0 &&
      pcb->eap.es_client.ea_requests > pcb->settings.eap_allow_req) {
    ppp_info(("EAP: received too many Request messages"));
    if (pcb->settings.eap_req_time > 0) {
      UNTIMEOUT(eap_client_timeout, pcb);
    }
    auth_withpeer_fail(pcb, PPP_EAP);
    return;
  }

  if (len <= 0) {
    ppp_error(("EAP: empty Request message discarded"));
    return;
  }

  GETCHAR(typenum, inp);
  len--;

  switch (typenum) {
  case EAPT_IDENTITY:
    if (len > 0)
      ppp_info(("EAP: Identity prompt \"%.*q\"", len, inp));
#ifdef USE_SRP
    if (pcb->eap.es_usepseudo &&
        (pcb->eap.es_usedpseudo == 0 ||
         (pcb->eap.es_usedpseudo == 1 && id == pcb->eap.es_client.ea_id))) {
      pcb->eap.es_usedpseudo = 1;
      /* Try to get a pseudonym */
      if ((fd = open_pn_file(O_RDONLY)) >= 0) {
        strcpy(rhostname, SRP_PSEUDO_ID);
        len = read(fd, rhostname + SRP_PSEUDO_LEN,
                   sizeof(rhostname) - SRP_PSEUDO_LEN);
        /* XXX NAI unsupported */
        if (len > 0) {
          eap_send_response(pcb, id, typenum, rhostname, len + SRP_PSEUDO_LEN);
        }
        (void)close(fd);
        if (len > 0)
          break;
      }
    }
    /* Stop using pseudonym now. */
    if (pcb->eap.es_usepseudo && pcb->eap.es_usedpseudo != 2) {
      remove_pn_file();
      pcb->eap.es_usedpseudo = 2;
    }
#endif /* USE_SRP */
    eap_send_response(pcb, id, typenum,
                      (const u_char *)pcb->eap.es_client.ea_name,
                      pcb->eap.es_client.ea_namelen);
    break;

  case EAPT_NOTIFICATION:
    if (len > 0)
      ppp_info(("EAP: Notification \"%.*q\"", len, inp));
    eap_send_response(pcb, id, typenum, NULL, 0);
    break;

  case EAPT_NAK:
    /*
     * Avoid the temptation to send Response Nak in reply
     * to Request Nak here.  It can only lead to trouble.
     */
    ppp_warn(("EAP: unexpected Nak in Request; ignored"));
    /* Return because we're waiting for something real. */
    return;

  case EAPT_MD5CHAP:
    if (len < 1) {
      ppp_error(("EAP: received MD5-Challenge with no data"));
      /* Bogus request; wait for something real. */
      return;
    }
    GETCHAR(vallen, inp);
    len--;
    if (vallen < 8 || vallen > len) {
      ppp_error(("EAP: MD5-Challenge with bad length %d (8..%d)", vallen, len));
      /* Try something better. */
      eap_send_nak(pcb, id, EAPT_SRP);
      break;
    }

    /* Not so likely to happen. */
    if (len - vallen >= (int)sizeof(rhostname)) {
      ppp_dbglog(("EAP: trimming really long peer name down"));
      MEMCPY(rhostname, inp + vallen, sizeof(rhostname) - 1);
      rhostname[sizeof(rhostname) - 1] = '\0';
    } else {
      MEMCPY(rhostname, inp + vallen, len - vallen);
      rhostname[len - vallen] = '\0';
    }

#if PPP_REMOTENAME
    /* In case the remote doesn't give us his name. */
    if (pcb->settings.explicit_remote ||
        (pcb->settings.remote_name[0] != '\0' && vallen == len))
      strlcpy(rhostname, pcb->settings.remote_name, sizeof(rhostname));
#endif /* PPP_REMOTENAME */

    /*
     * Get the secret for authenticating ourselves with
     * the specified host.
     */
    if (!get_secret(pcb, pcb->eap.es_client.ea_name, rhostname, secret,
                    &secret_len, 0)) {
      ppp_dbglog(("EAP: no MD5 secret for auth to %q", rhostname));
      eap_send_nak(pcb, id, EAPT_SRP);
      break;
    }
    lwip_md5_init(&mdContext);
    lwip_md5_starts(&mdContext);
    typenum = id;
    lwip_md5_update(&mdContext, &typenum, 1);
    lwip_md5_update(&mdContext, (u_char *)secret, secret_len);
    BZERO(secret, sizeof(secret));
    lwip_md5_update(&mdContext, inp, vallen);
    lwip_md5_finish(&mdContext, hash);
    lwip_md5_free(&mdContext);
    eap_chap_response(pcb, id, hash, pcb->eap.es_client.ea_name,
                      pcb->eap.es_client.ea_namelen);
    break;

#ifdef USE_SRP
  case EAPT_SRP:
    if (len < 1) {
      ppp_error(("EAP: received empty SRP Request"));
      /* Bogus request; wait for something real. */
      return;
    }

    /* Get subtype */
    GETCHAR(vallen, inp);
    len--;
    switch (vallen) {
    case EAPSRP_CHALLENGE:
      tc = NULL;
      if (pcb->eap.es_client.ea_session != NULL) {
        tc = (struct t_client *)pcb->eap.es_client.ea_session;
        /*
         * If this is a new challenge, then start
         * over with a new client session context.
         * Otherwise, just resend last response.
         */
        if (id != pcb->eap.es_client.ea_id) {
          t_clientclose(tc);
          pcb->eap.es_client.ea_session = NULL;
          tc = NULL;
        }
      }
      /* No session key just yet */
      pcb->eap.es_client.ea_skey = NULL;
      if (tc == NULL) {
        int rhostnamelen;

        GETCHAR(vallen, inp);
        len--;
        if (vallen >= len) {
          ppp_error(("EAP: badly-formed SRP Challenge"
                     " (name)"));
          /* Ignore badly-formed messages */
          return;
        }
        MEMCPY(rhostname, inp, vallen);
        rhostname[vallen] = '\0';
        INCPTR(vallen, inp);
        len -= vallen;

        /*
         * In case the remote doesn't give us his name,
         * use configured name.
         */
        if (explicit_remote || (remote_name[0] != '\0' && vallen == 0)) {
          strlcpy(rhostname, remote_name, sizeof(rhostname));
        }

        rhostnamelen = (int)strlen(rhostname);
        if (rhostnamelen > MAXNAMELEN) {
          rhostnamelen = MAXNAMELEN;
        }
        MEMCPY(pcb->eap.es_client.ea_peer, rhostname, rhostnamelen);
        pcb->eap.es_client.ea_peer[rhostnamelen] = '\0';
        pcb->eap.es_client.ea_peerlen = rhostnamelen;

        GETCHAR(vallen, inp);
        len--;
        if (vallen >= len) {
          ppp_error(("EAP: badly-formed SRP Challenge"
                     " (s)"));
          /* Ignore badly-formed messages */
          return;
        }
        sval.data = inp;
        sval.len = vallen;
        INCPTR(vallen, inp);
        len -= vallen;

        GETCHAR(vallen, inp);
        len--;
        if (vallen > len) {
          ppp_error(("EAP: badly-formed SRP Challenge"
                     " (g)"));
          /* Ignore badly-formed messages */
          return;
        }
        /* If no generator present, then use value 2 */
        if (vallen == 0) {
          gval.data = (u_char *)"\002";
          gval.len = 1;
        } else {
          gval.data = inp;
          gval.len = vallen;
        }
        INCPTR(vallen, inp);
        len -= vallen;

        /*
         * If no modulus present, then use well-known
         * value.
         */
        if (len == 0) {
          Nval.data = (u_char *)wkmodulus;
          Nval.len = sizeof(wkmodulus);
        } else {
          Nval.data = inp;
          Nval.len = len;
        }
        tc = t_clientopen(pcb->eap.es_client.ea_name, &Nval, &gval, &sval);
        if (tc == NULL) {
          eap_send_nak(pcb, id, EAPT_MD5CHAP);
          break;
        }
        pcb->eap.es_client.ea_session = (void *)tc;

        /* Add Challenge ID & type to verifier */
        vals[0] = id;
        vals[1] = EAPT_SRP;
        t_clientaddexdata(tc, vals, 2);
      }
      Ap = t_clientgenexp(tc);
      eap_srp_response(esp, id, EAPSRP_CKEY, Ap->data, Ap->len);
      break;

    case EAPSRP_SKEY:
      tc = (struct t_client *)pcb->eap.es_client.ea_session;
      if (tc == NULL) {
        ppp_warn(("EAP: peer sent Subtype 2 without 1"));
        eap_send_nak(pcb, id, EAPT_MD5CHAP);
        break;
      }
      if (pcb->eap.es_client.ea_skey != NULL) {
        /*
         * ID number should not change here.  Warn
         * if it does (but otherwise ignore).
         */
        if (id != pcb->eap.es_client.ea_id) {
          ppp_warn(("EAP: ID changed from %d to %d "
                    "in SRP Subtype 2 rexmit",
                    pcb->eap.es_client.ea_id, id));
        }
      } else {
        if (get_srp_secret(pcb->eap.es_unit, pcb->eap.es_client.ea_name,
                           pcb->eap.es_client.ea_peer, secret, 0) == 0) {
          /*
           * Can't work with this peer because
           * the secret is missing.  Just give
           * up.
           */
          eap_send_nak(pcb, id, EAPT_MD5CHAP);
          break;
        }
        Bval.data = inp;
        Bval.len = len;
        t_clientpasswd(tc, secret);
        BZERO(secret, sizeof(secret));
        pcb->eap.es_client.ea_skey = t_clientgetkey(tc, &Bval);
        if (pcb->eap.es_client.ea_skey == NULL) {
          /* Server is rogue; stop now */
          ppp_error(("EAP: SRP server is rogue"));
          goto client_failure;
        }
      }
      eap_srpval_response(esp, id, SRPVAL_EBIT, t_clientresponse(tc));
      break;

    case EAPSRP_SVALIDATOR:
      tc = (struct t_client *)pcb->eap.es_client.ea_session;
      if (tc == NULL || pcb->eap.es_client.ea_skey == NULL) {
        ppp_warn(("EAP: peer sent Subtype 3 without 1/2"));
        eap_send_nak(pcb, id, EAPT_MD5CHAP);
        break;
      }
      /*
       * If we're already open, then this ought to be a
       * duplicate.  Otherwise, check that the server is
       * who we think it is.
       */
      if (pcb->eap.es_client.ea_state == eapOpen) {
        if (id != pcb->eap.es_client.ea_id) {
          ppp_warn(("EAP: ID changed from %d to %d "
                    "in SRP Subtype 3 rexmit",
                    pcb->eap.es_client.ea_id, id));
        }
      } else {
        len -= sizeof(u32_t) + SHA_DIGESTSIZE;
        if (len < 0 || t_clientverify(tc, inp + sizeof(u32_t)) != 0) {
          ppp_error(("EAP: SRP server verification "
                     "failed"));
          goto client_failure;
        }
        GETLONG(pcb->eap.es_client.ea_keyflags, inp);
        /* Save pseudonym if user wants it. */
        if (len > 0 && pcb->eap.es_usepseudo) {
          INCPTR(SHA_DIGESTSIZE, inp);
          write_pseudonym(esp, inp, len, id);
        }
      }
      /*
       * We've verified our peer.  We're now mostly done,
       * except for waiting on the regular EAP Success
       * message.
       */
      eap_srp_response(esp, id, EAPSRP_ACK, NULL, 0);
      break;

    case EAPSRP_LWRECHALLENGE:
      if (len < 4) {
        ppp_warn(("EAP: malformed Lightweight rechallenge"));
        return;
      }
      SHA1Init(&ctxt);
      vals[0] = id;
      SHA1Update(&ctxt, vals, 1);
      SHA1Update(&ctxt, pcb->eap.es_client.ea_skey, SESSION_KEY_LEN);
      SHA1Update(&ctxt, inp, len);
      SHA1Update(&ctxt, pcb->eap.es_client.ea_name,
                 pcb->eap.es_client.ea_namelen);
      SHA1Final(dig, &ctxt);
      eap_srp_response(esp, id, EAPSRP_LWRECHALLENGE, dig, SHA_DIGESTSIZE);
      break;

    default:
      ppp_error(("EAP: unknown SRP Subtype %d", vallen));
      eap_send_nak(pcb, id, EAPT_MD5CHAP);
      break;
    }
    break;
#endif /* USE_SRP */

  default:
    ppp_info(("EAP: unknown authentication type %d; Naking", typenum));
    eap_send_nak(pcb, id, EAPT_SRP);
    break;
  }

  if (pcb->settings.eap_req_time > 0) {
    UNTIMEOUT(eap_client_timeout, pcb);
    TIMEOUT(eap_client_timeout, pcb, pcb->settings.eap_req_time);
  }
  return;

#ifdef USE_SRP
client_failure:
  pcb->eap.es_client.ea_state = eapBadAuth;
  if (pcb->settings.eap_req_time > 0) {
    UNTIMEOUT(eap_client_timeout, (void *)esp);
  }
  pcb->eap.es_client.ea_session = NULL;
  t_clientclose(tc);
  auth_withpeer_fail(pcb, PPP_EAP);
#endif /* USE_SRP */
}

static void eap_response(ppp_pcb *pcb, u_char *inp, int id, int len) {
  u_char typenum;
  u_char vallen;
  int secret_len;
  char secret[MAXSECRETLEN];
  char rhostname[MAXNAMELEN];
  lwip_md5_context mdContext;
  u_char hash[MD5_SIGNATURE_SIZE];
#ifdef USE_SRP
  struct t_server *ts;
  struct t_num A;
  SHA1_CTX ctxt;
  u_char dig[SHA_DIGESTSIZE];
#endif /* USE_SRP */

  /*
   * Ignore responses if we're not open
   */
  if (pcb->eap.es_server.ea_state <= eapClosed)
    return;

  if (pcb->eap.es_server.ea_id != id) {
    ppp_dbglog(("EAP: discarding Response %d; expected ID %d", id,
                pcb->eap.es_server.ea_id));
    return;
  }

  pcb->eap.es_server.ea_responses++;

  if (len <= 0) {
    ppp_error(("EAP: empty Response message discarded"));
    return;
  }

  GETCHAR(typenum, inp);
  len--;

  switch (typenum) {
  case EAPT_IDENTITY:
    if (pcb->eap.es_server.ea_state != eapIdentify) {
      ppp_dbglog(("EAP discarding unwanted Identify \"%.q\"", len, inp));
      break;
    }
    ppp_info(("EAP: unauthenticated peer name \"%.*q\"", len, inp));
    if (len > MAXNAMELEN) {
      len = MAXNAMELEN;
    }
    MEMCPY(pcb->eap.es_server.ea_peer, inp, len);
    pcb->eap.es_server.ea_peer[len] = '\0';
    pcb->eap.es_server.ea_peerlen = len;
    eap_figure_next_state(pcb, 0);
    break;

  case EAPT_NOTIFICATION:
    ppp_dbglog(("EAP unexpected Notification; response discarded"));
    break;

  case EAPT_NAK:
    if (len < 1) {
      ppp_info(("EAP: Nak Response with no suggested protocol"));
      eap_figure_next_state(pcb, 1);
      break;
    }

    GETCHAR(vallen, inp);
    len--;

    if (
#if PPP_REMOTENAME
        !pcb->explicit_remote &&
#endif /* PPP_REMOTENAME */
        pcb->eap.es_server.ea_state == eapIdentify) {
      /* Peer cannot Nak Identify Request */
      eap_figure_next_state(pcb, 1);
      break;
    }

    switch (vallen) {
    case EAPT_SRP:
      /* Run through SRP validator selection again. */
      pcb->eap.es_server.ea_state = eapIdentify;
      eap_figure_next_state(pcb, 0);
      break;

    case EAPT_MD5CHAP:
      pcb->eap.es_server.ea_state = eapMD5Chall;
      break;

    default:
      ppp_dbglog(("EAP: peer requesting unknown Type %d", vallen));
      switch (pcb->eap.es_server.ea_state) {
      case eapSRP1:
      case eapSRP2:
      case eapSRP3:
        pcb->eap.es_server.ea_state = eapMD5Chall;
        break;
      case eapMD5Chall:
      case eapSRP4:
        pcb->eap.es_server.ea_state = eapIdentify;
        eap_figure_next_state(pcb, 0);
        break;
      default:
        break;
      }
      break;
    }
    break;

  case EAPT_MD5CHAP:
    if (pcb->eap.es_server.ea_state != eapMD5Chall) {
      ppp_error(("EAP: unexpected MD5-Response"));
      eap_figure_next_state(pcb, 1);
      break;
    }
    if (len < 1) {
      ppp_error(("EAP: received MD5-Response with no data"));
      eap_figure_next_state(pcb, 1);
      break;
    }
    GETCHAR(vallen, inp);
    len--;
    if (vallen != 16 || vallen > len) {
      ppp_error(("EAP: MD5-Response with bad length %d", vallen));
      eap_figure_next_state(pcb, 1);
      break;
    }

    /* Not so likely to happen. */
    if (len - vallen >= (int)sizeof(rhostname)) {
      ppp_dbglog(("EAP: trimming really long peer name down"));
      MEMCPY(rhostname, inp + vallen, sizeof(rhostname) - 1);
      rhostname[sizeof(rhostname) - 1] = '\0';
    } else {
      MEMCPY(rhostname, inp + vallen, len - vallen);
      rhostname[len - vallen] = '\0';
    }

#if PPP_REMOTENAME
    /* In case the remote doesn't give us his name. */
    if (explicit_remote || (remote_name[0] != '\0' && vallen == len))
      strlcpy(rhostname, remote_name, sizeof(rhostname));
#endif /* PPP_REMOTENAME */

    /*
     * Get the secret for authenticating the specified
     * host.
     */
    if (!get_secret(pcb, rhostname, pcb->eap.es_server.ea_name, secret,
                    &secret_len, 1)) {
      ppp_dbglog(("EAP: no MD5 secret for auth of %q", rhostname));
      eap_send_failure(pcb);
      break;
    }
    lwip_md5_init(&mdContext);
    lwip_md5_starts(&mdContext);
    lwip_md5_update(&mdContext, &pcb->eap.es_server.ea_id, 1);
    lwip_md5_update(&mdContext, (u_char *)secret, secret_len);
    BZERO(secret, sizeof(secret));
    lwip_md5_update(&mdContext, pcb->eap.es_challenge, pcb->eap.es_challen);
    lwip_md5_finish(&mdContext, hash);
    lwip_md5_free(&mdContext);
    if (BCMP(hash, inp, MD5_SIGNATURE_SIZE) != 0) {
      eap_send_failure(pcb);
      break;
    }
    pcb->eap.es_server.ea_type = EAPT_MD5CHAP;
    eap_send_success(pcb);
    eap_figure_next_state(pcb, 0);
    if (pcb->eap.es_rechallenge != 0)
      TIMEOUT(eap_rechallenge, pcb, pcb->eap.es_rechallenge);
    break;

#ifdef USE_SRP
  case EAPT_SRP:
    if (len < 1) {
      ppp_error(("EAP: empty SRP Response"));
      eap_figure_next_state(pcb, 1);
      break;
    }
    GETCHAR(typenum, inp);
    len--;
    switch (typenum) {
    case EAPSRP_CKEY:
      if (pcb->eap.es_server.ea_state != eapSRP1) {
        ppp_error(("EAP: unexpected SRP Subtype 1 Response"));
        eap_figure_next_state(pcb, 1);
        break;
      }
      A.data = inp;
      A.len = len;
      ts = (struct t_server *)pcb->eap.es_server.ea_session;
      assert(ts != NULL);
      pcb->eap.es_server.ea_skey = t_servergetkey(ts, &A);
      if (pcb->eap.es_server.ea_skey == NULL) {
        /* Client's A value is bogus; terminate now */
        ppp_error(("EAP: bogus A value from client"));
        eap_send_failure(pcb);
      } else {
        eap_figure_next_state(pcb, 0);
      }
      break;

    case EAPSRP_CVALIDATOR:
      if (pcb->eap.es_server.ea_state != eapSRP2) {
        ppp_error(("EAP: unexpected SRP Subtype 2 Response"));
        eap_figure_next_state(pcb, 1);
        break;
      }
      if (len < sizeof(u32_t) + SHA_DIGESTSIZE) {
        ppp_error(
            ("EAP: M1 length %d < %d", len, sizeof(u32_t) + SHA_DIGESTSIZE));
        eap_figure_next_state(pcb, 1);
        break;
      }
      GETLONG(pcb->eap.es_server.ea_keyflags, inp);
      ts = (struct t_server *)pcb->eap.es_server.ea_session;
      assert(ts != NULL);
      if (t_serververify(ts, inp)) {
        ppp_info(("EAP: unable to validate client identity"));
        eap_send_failure(pcb);
        break;
      }
      eap_figure_next_state(pcb, 0);
      break;

    case EAPSRP_ACK:
      if (pcb->eap.es_server.ea_state != eapSRP3) {
        ppp_error(("EAP: unexpected SRP Subtype 3 Response"));
        eap_send_failure(esp);
        break;
      }
      pcb->eap.es_server.ea_type = EAPT_SRP;
      eap_send_success(pcb, esp);
      eap_figure_next_state(pcb, 0);
      if (pcb->eap.es_rechallenge != 0)
        TIMEOUT(eap_rechallenge, pcb, pcb->eap.es_rechallenge);
      if (pcb->eap.es_lwrechallenge != 0)
        TIMEOUT(srp_lwrechallenge, pcb, pcb->eap.es_lwrechallenge);
      break;

    case EAPSRP_LWRECHALLENGE:
      if (pcb->eap.es_server.ea_state != eapSRP4) {
        ppp_info(("EAP: unexpected SRP Subtype 4 Response"));
        return;
      }
      if (len != SHA_DIGESTSIZE) {
        ppp_error(("EAP: bad Lightweight rechallenge "
                   "response"));
        return;
      }
      SHA1Init(&ctxt);
      vallen = id;
      SHA1Update(&ctxt, &vallen, 1);
      SHA1Update(&ctxt, pcb->eap.es_server.ea_skey, SESSION_KEY_LEN);
      SHA1Update(&ctxt, pcb->eap.es_challenge, pcb->eap.es_challen);
      SHA1Update(&ctxt, pcb->eap.es_server.ea_peer,
                 pcb->eap.es_server.ea_peerlen);
      SHA1Final(dig, &ctxt);
      if (BCMP(dig, inp, SHA_DIGESTSIZE) != 0) {
        ppp_error(("EAP: failed Lightweight rechallenge"));
        eap_send_failure(pcb);
        break;
      }
      pcb->eap.es_server.ea_state = eapOpen;
      if (pcb->eap.es_lwrechallenge != 0)
        TIMEOUT(srp_lwrechallenge, esp, pcb->eap.es_lwrechallenge);
      break;
    }
    break;
#endif /* USE_SRP */

  default:
    /* This can't happen. */
    ppp_error(("EAP: unknown Response type %d; ignored", typenum));
    return;
  }

  if (pcb->settings.eap_timeout_time > 0) {
    UNTIMEOUT(eap_server_timeout, pcb);
  }

  if (pcb->eap.es_server.ea_state != eapBadAuth &&
      pcb->eap.es_server.ea_state != eapOpen) {
    pcb->eap.es_server.ea_id++;
    eap_send_request(pcb);
  }
}

static void eap_success(ppp_pcb *pcb, u_char *inp, int id, int len) {
  LWIP_UNUSED_ARG(id);

  if (pcb->eap.es_client.ea_state != eapOpen && !eap_client_active(pcb)) {
    ppp_dbglog(("EAP unexpected success message in state %s (%d)",
                eap_state_name(pcb->eap.es_client.ea_state),
                pcb->eap.es_client.ea_state));
    return;
  }

  if (pcb->settings.eap_req_time > 0) {
    UNTIMEOUT(eap_client_timeout, pcb);
  }

  if (len > 0) {
    /* This is odd.  The spec doesn't allow for this. */
    PRINTMSG(inp, len);
  }

  pcb->eap.es_client.ea_state = eapOpen;
  auth_withpeer_success(pcb, PPP_EAP, 0);
}

static void eap_failure(ppp_pcb *pcb, u_char *inp, int id, int len) {
  LWIP_UNUSED_ARG(id);

  /*
   * Ignore failure messages if we're not open
   */
  if (pcb->eap.es_client.ea_state <= eapClosed)
    return;

  if (!eap_client_active(pcb)) {
    ppp_dbglog(("EAP unexpected failure message in state %s (%d)",
                eap_state_name(pcb->eap.es_client.ea_state),
                pcb->eap.es_client.ea_state));
  }

  if (pcb->settings.eap_req_time > 0) {
    UNTIMEOUT(eap_client_timeout, pcb);
  }

  if (len > 0) {
    /* This is odd.  The spec doesn't allow for this. */
    PRINTMSG(inp, len);
  }

  pcb->eap.es_client.ea_state = eapBadAuth;

  ppp_error(("EAP: peer reports authentication failure"));
  auth_withpeer_fail(pcb, PPP_EAP);
}

static void eap_input(ppp_pcb *pcb, u_char *inp, int inlen) {
  u_char code, id;
  int len;

  /*
   * Parse header (code, id and length).  If packet too short,
   * drop it.
   */
  if (inlen < EAP_HEADERLEN) {
    ppp_error(("EAP: packet too short: %d < %d", inlen, EAP_HEADERLEN));
    return;
  }
  GETCHAR(code, inp);
  GETCHAR(id, inp);
  GETSHORT(len, inp);
  if (len < EAP_HEADERLEN || len > inlen) {
    ppp_error(("EAP: packet has illegal length field %d (%d..%d)", len,
               EAP_HEADERLEN, inlen));
    return;
  }
  len -= EAP_HEADERLEN;

  /* Dispatch based on message code */
  switch (code) {
  case EAP_REQUEST:
    eap_request(pcb, inp, id, len);
    break;

#if PPP_SERVER
  case EAP_RESPONSE:
    eap_response(pcb, inp, id, len);
    break;
#endif /* PPP_SERVER */

  case EAP_SUCCESS:
    eap_success(pcb, inp, id, len);
    break;

  case EAP_FAILURE:
    eap_failure(pcb, inp, id, len);
    break;

  default: /* XXX Need code reject */
    /* Note: it's not legal to send EAP Nak here. */
    ppp_warn(("EAP: unknown code %d received", code));
    break;
  }
}

static int eap_printpkt(const u_char *inp, int inlen,
                        void (*printer)(void *, const char *, ...), void *arg) {
  int code, id, len, rtype, vallen;
  const u_char *pstart;
  u32_t uval;

  if (inlen < EAP_HEADERLEN)
    return (0);
  pstart = inp;
  GETCHAR(code, inp);
  GETCHAR(id, inp);
  GETSHORT(len, inp);
  if (len < EAP_HEADERLEN || len > inlen)
    return (0);

  if (code >= 1 && code <= (int)LWIP_ARRAYSIZE(eap_codenames))
    printer(arg, " %s", eap_codenames[code - 1]);
  else
    printer(arg, " code=0x%x", code);
  printer(arg, " id=0x%x", id);
  len -= EAP_HEADERLEN;
  switch (code) {
  case EAP_REQUEST:
    if (len < 1) {
      printer(arg, " <missing type>");
      break;
    }
    GETCHAR(rtype, inp);
    len--;
    if (rtype >= 1 && rtype <= (int)LWIP_ARRAYSIZE(eap_typenames))
      printer(arg, " %s", eap_typenames[rtype - 1]);
    else
      printer(arg, " type=0x%x", rtype);
    switch (rtype) {
    case EAPT_IDENTITY:
    case EAPT_NOTIFICATION:
      if (len > 0) {
        printer(arg, " <Message ");
        ppp_print_string(inp, len, printer, arg);
        printer(arg, ">");
        INCPTR(len, inp);
        len = 0;
      } else {
        printer(arg, " <No message>");
      }
      break;

    case EAPT_MD5CHAP:
      if (len <= 0)
        break;
      GETCHAR(vallen, inp);
      len--;
      if (vallen > len)
        goto truncated;
      printer(arg, " <Value%.*B>", vallen, inp);
      INCPTR(vallen, inp);
      len -= vallen;
      if (len > 0) {
        printer(arg, " <Name ");
        ppp_print_string(inp, len, printer, arg);
        printer(arg, ">");
        INCPTR(len, inp);
        len = 0;
      } else {
        printer(arg, " <No name>");
      }
      break;

    case EAPT_SRP:
      if (len < 3)
        goto truncated;
      GETCHAR(vallen, inp);
      len--;
      printer(arg, "-%d", vallen);
      switch (vallen) {
      case EAPSRP_CHALLENGE:
        GETCHAR(vallen, inp);
        len--;
        if (vallen >= len)
          goto truncated;
        if (vallen > 0) {
          printer(arg, " <Name ");
          ppp_print_string(inp, vallen, printer, arg);
          printer(arg, ">");
        } else {
          printer(arg, " <No name>");
        }
        INCPTR(vallen, inp);
        len -= vallen;
        GETCHAR(vallen, inp);
        len--;
        if (vallen >= len)
          goto truncated;
        printer(arg, " <s%.*B>", vallen, inp);
        INCPTR(vallen, inp);
        len -= vallen;
        GETCHAR(vallen, inp);
        len--;
        if (vallen > len)
          goto truncated;
        if (vallen == 0) {
          printer(arg, " <Default g=2>");
        } else {
          printer(arg, " <g%.*B>", vallen, inp);
        }
        INCPTR(vallen, inp);
        len -= vallen;
        if (len == 0) {
          printer(arg, " <Default N>");
        } else {
          printer(arg, " <N%.*B>", len, inp);
          INCPTR(len, inp);
          len = 0;
        }
        break;

      case EAPSRP_SKEY:
        printer(arg, " <B%.*B>", len, inp);
        INCPTR(len, inp);
        len = 0;
        break;

      case EAPSRP_SVALIDATOR:
        if (len < (int)sizeof(u32_t))
          break;
        GETLONG(uval, inp);
        len -= sizeof(u32_t);
        if (uval & SRPVAL_EBIT) {
          printer(arg, " E");
          uval &= ~SRPVAL_EBIT;
        }
        if (uval != 0) {
          printer(arg, " f<%X>", uval);
        }
        if ((vallen = len) > SHA_DIGESTSIZE)
          vallen = SHA_DIGESTSIZE;
        printer(arg, " <M2%.*B%s>", len, inp, len < SHA_DIGESTSIZE ? "?" : "");
        INCPTR(vallen, inp);
        len -= vallen;
        if (len > 0) {
          printer(arg, " <PN%.*B>", len, inp);
          INCPTR(len, inp);
          len = 0;
        }
        break;

      case EAPSRP_LWRECHALLENGE:
        printer(arg, " <Challenge%.*B>", len, inp);
        INCPTR(len, inp);
        len = 0;
        break;
      default:
        break;
      }
      break;
    default:
      break;
    }
    break;

  case EAP_RESPONSE:
    if (len < 1)
      break;
    GETCHAR(rtype, inp);
    len--;
    if (rtype >= 1 && rtype <= (int)LWIP_ARRAYSIZE(eap_typenames))
      printer(arg, " %s", eap_typenames[rtype - 1]);
    else
      printer(arg, " type=0x%x", rtype);
    switch (rtype) {
    case EAPT_IDENTITY:
      if (len > 0) {
        printer(arg, " <Name ");
        ppp_print_string(inp, len, printer, arg);
        printer(arg, ">");
        INCPTR(len, inp);
        len = 0;
      }
      break;

    case EAPT_NAK:
      if (len <= 0) {
        printer(arg, " <missing hint>");
        break;
      }
      GETCHAR(rtype, inp);
      len--;
      printer(arg, " <Suggested-type %02X", rtype);
      if (rtype >= 1 && rtype < (int)LWIP_ARRAYSIZE(eap_typenames))
        printer(arg, " (%s)", eap_typenames[rtype - 1]);
      printer(arg, ">");
      break;

    case EAPT_MD5CHAP:
      if (len <= 0) {
        printer(arg, " <missing length>");
        break;
      }
      GETCHAR(vallen, inp);
      len--;
      if (vallen > len)
        goto truncated;
      printer(arg, " <Value%.*B>", vallen, inp);
      INCPTR(vallen, inp);
      len -= vallen;
      if (len > 0) {
        printer(arg, " <Name ");
        ppp_print_string(inp, len, printer, arg);
        printer(arg, ">");
        INCPTR(len, inp);
        len = 0;
      } else {
        printer(arg, " <No name>");
      }
      break;

    case EAPT_SRP:
      if (len < 1)
        goto truncated;
      GETCHAR(vallen, inp);
      len--;
      printer(arg, "-%d", vallen);
      switch (vallen) {
      case EAPSRP_CKEY:
        printer(arg, " <A%.*B>", len, inp);
        INCPTR(len, inp);
        len = 0;
        break;

      case EAPSRP_CVALIDATOR:
        if (len < (int)sizeof(u32_t))
          break;
        GETLONG(uval, inp);
        len -= sizeof(u32_t);
        if (uval & SRPVAL_EBIT) {
          printer(arg, " E");
          uval &= ~SRPVAL_EBIT;
        }
        if (uval != 0) {
          printer(arg, " f<%X>", uval);
        }
        printer(arg, " <M1%.*B%s>", len, inp, len == SHA_DIGESTSIZE ? "" : "?");
        INCPTR(len, inp);
        len = 0;
        break;

      case EAPSRP_ACK:
        break;

      case EAPSRP_LWRECHALLENGE:
        printer(arg, " <Response%.*B%s>", len, inp,
                len == SHA_DIGESTSIZE ? "" : "?");
        if ((vallen = len) > SHA_DIGESTSIZE)
          vallen = SHA_DIGESTSIZE;
        INCPTR(vallen, inp);
        len -= vallen;
        break;
      default:
        break;
      }
      break;
    default:
      break;
    }
    break;

  case EAP_SUCCESS: /* No payload expected for these! */
  case EAP_FAILURE:
  default:
    break;

  truncated:
    printer(arg, " <truncated>");
    break;
  }

  if (len > 8)
    printer(arg, "%8B...", inp);
  else if (len > 0)
    printer(arg, "%.*B", len, inp);
  INCPTR(len, inp);

  return (inp - pstart);
}

static void ecp_init(unit) int unit;
{
  fsm *f = &ecp_fsm[unit];

  f->unit = unit;
  f->protocol = PPP_ECP;
  f->callbacks = &ecp_callbacks;
  fsm_init(f);

#if 0  /* Not necessary, everything is cleared in ppp_new() */
    memset(&ecp_wantoptions[unit],  0, sizeof(ecp_options));
    memset(&ecp_gotoptions[unit],   0, sizeof(ecp_options));
    memset(&ecp_allowoptions[unit], 0, sizeof(ecp_options));
    memset(&ecp_hisoptions[unit],   0, sizeof(ecp_options));
#endif /* 0 */
}

static int ecp_printpkt(p, plen, printer, arg) const u_char *p;
int plen;
void (*printer)(void *, char *, ...);
void *arg;
{ return 0; }

char *eui64_ntoa(eui64_t e) {
  static char buf[20];

  sprintf(buf, "%02x%02x:%02x%02x:%02x%02x:%02x%02x", e.e8[0], e.e8[1], e.e8[2],
          e.e8[3], e.e8[4], e.e8[5], e.e8[6], e.e8[7]);
  return buf;
}

void fsm_init(fsm *f) {
  ppp_pcb *pcb = f->pcb;
  f->state = PPP_FSM_INITIAL;
  f->flags = 0;
  f->id = 0; /* XXX Start with random id? */
  f->maxnakloops = pcb->settings.fsm_max_nak_loops;
  f->term_reason_len = 0;
}

void fsm_lowerup(fsm *f) {
  switch (f->state) {
  case PPP_FSM_INITIAL:
    f->state = PPP_FSM_CLOSED;
    break;

  case PPP_FSM_STARTING:
    if (f->flags & OPT_SILENT)
      f->state = PPP_FSM_STOPPED;
    else {
      /* Send an initial configure-request */
      fsm_sconfreq(f, 0);
      f->state = PPP_FSM_REQSENT;
    }
    break;

  default:
    FSMDEBUG(("%s: Up event in state %d!", PROTO_NAME(f), f->state));
    /* no break */
  }
}

void fsm_lowerdown(fsm *f) {
  switch (f->state) {
  case PPP_FSM_CLOSED:
    f->state = PPP_FSM_INITIAL;
    break;

  case PPP_FSM_STOPPED:
    f->state = PPP_FSM_STARTING;
    if (f->callbacks->starting)
      (*f->callbacks->starting)(f);
    break;

  case PPP_FSM_CLOSING:
    f->state = PPP_FSM_INITIAL;
    UNTIMEOUT(fsm_timeout, f); /* Cancel timeout */
    break;

  case PPP_FSM_STOPPING:
  case PPP_FSM_REQSENT:
  case PPP_FSM_ACKRCVD:
  case PPP_FSM_ACKSENT:
    f->state = PPP_FSM_STARTING;
    UNTIMEOUT(fsm_timeout, f); /* Cancel timeout */
    break;

  case PPP_FSM_OPENED:
    if (f->callbacks->down)
      (*f->callbacks->down)(f);
    f->state = PPP_FSM_STARTING;
    break;

  default:
    FSMDEBUG(("%s: Down event in state %d!", PROTO_NAME(f), f->state));
    /* no break */
  }
}

void fsm_open(fsm *f) {
  switch (f->state) {
  case PPP_FSM_INITIAL:
    f->state = PPP_FSM_STARTING;
    if (f->callbacks->starting)
      (*f->callbacks->starting)(f);
    break;

  case PPP_FSM_CLOSED:
    if (f->flags & OPT_SILENT)
      f->state = PPP_FSM_STOPPED;
    else {
      /* Send an initial configure-request */
      fsm_sconfreq(f, 0);
      f->state = PPP_FSM_REQSENT;
    }
    break;

  case PPP_FSM_CLOSING:
    f->state = PPP_FSM_STOPPING;
    /* fall through */
    /* no break */
  case PPP_FSM_STOPPED:
  case PPP_FSM_OPENED:
    if (f->flags & OPT_RESTART) {
      fsm_lowerdown(f);
      fsm_lowerup(f);
    }
    break;
  default:
    break;
  }
}

static void terminate_layer(fsm *f, int nextstate) {
  ppp_pcb *pcb = f->pcb;

  if (f->state != PPP_FSM_OPENED)
    UNTIMEOUT(fsm_timeout, f); /* Cancel timeout */
  else if (f->callbacks->down)
    (*f->callbacks->down)(f); /* Inform upper layers we're down */

  /* Init restart counter and send Terminate-Request */
  f->retransmits = pcb->settings.fsm_max_term_transmits;
  fsm_sdata(f, TERMREQ, f->reqid = ++f->id, (const u_char *)f->term_reason,
            f->term_reason_len);

  if (f->retransmits == 0) {
    /*
     * User asked for no terminate requests at all; just close it.
     * We've already fired off one Terminate-Request just to be nice
     * to the peer, but we're not going to wait for a reply.
     */
    f->state = nextstate == PPP_FSM_CLOSING ? PPP_FSM_CLOSED : PPP_FSM_STOPPED;
    if (f->callbacks->finished)
      (*f->callbacks->finished)(f);
    return;
  }

  TIMEOUT(fsm_timeout, f, pcb->settings.fsm_timeout_time);
  --f->retransmits;

  f->state = nextstate;
}

void fsm_close(fsm *f, const char *reason) {
  f->term_reason = reason;
  f->term_reason_len =
      (reason == NULL ? 0 : (u8_t)LWIP_MIN(strlen(reason), 0xFF));
  switch (f->state) {
  case PPP_FSM_STARTING:
    f->state = PPP_FSM_INITIAL;
    break;
  case PPP_FSM_STOPPED:
    f->state = PPP_FSM_CLOSED;
    break;
  case PPP_FSM_STOPPING:
    f->state = PPP_FSM_CLOSING;
    break;

  case PPP_FSM_REQSENT:
  case PPP_FSM_ACKRCVD:
  case PPP_FSM_ACKSENT:
  case PPP_FSM_OPENED:
    terminate_layer(f, PPP_FSM_CLOSING);
    break;
  default:
    break;
  }
}

static void fsm_timeout(void *arg) {
  fsm *f = (fsm *)arg;
  ppp_pcb *pcb = f->pcb;

  switch (f->state) {
  case PPP_FSM_CLOSING:
  case PPP_FSM_STOPPING:
    if (f->retransmits <= 0) {
      /*
       * We've waited for an ack long enough.  Peer probably heard us.
       */
      f->state =
          (f->state == PPP_FSM_CLOSING) ? PPP_FSM_CLOSED : PPP_FSM_STOPPED;
      if (f->callbacks->finished)
        (*f->callbacks->finished)(f);
    } else {
      /* Send Terminate-Request */
      fsm_sdata(f, TERMREQ, f->reqid = ++f->id, (const u_char *)f->term_reason,
                f->term_reason_len);
      TIMEOUT(fsm_timeout, f, pcb->settings.fsm_timeout_time);
      --f->retransmits;
    }
    break;

  case PPP_FSM_REQSENT:
  case PPP_FSM_ACKRCVD:
  case PPP_FSM_ACKSENT:
    if (f->retransmits <= 0) {
      ppp_warn(("%s: timeout sending Config-Requests", PROTO_NAME(f)));
      f->state = PPP_FSM_STOPPED;
      if ((f->flags & OPT_PASSIVE) == 0 && f->callbacks->finished)
        (*f->callbacks->finished)(f);

    } else {
      /* Retransmit the configure-request */
      if (f->callbacks->retransmit)
        (*f->callbacks->retransmit)(f);
      fsm_sconfreq(f, 1); /* Re-send Configure-Request */
      if (f->state == PPP_FSM_ACKRCVD)
        f->state = PPP_FSM_REQSENT;
    }
    break;

  default:
    FSMDEBUG(("%s: Timeout event in state %d!", PROTO_NAME(f), f->state));
    /* no break */
  }
}

void fsm_input(fsm *f, u_char *inpacket, int l) {
  u_char *inp;
  u_char code, id;
  int len;

  /*
   * Parse header (code, id and length).
   * If packet too short, drop it.
   */
  inp = inpacket;
  if (l < HEADERLEN) {
    FSMDEBUG(("fsm_input(%x): Rcvd short header.", f->protocol));
    return;
  }
  GETCHAR(code, inp);
  GETCHAR(id, inp);
  GETSHORT(len, inp);
  if (len < HEADERLEN) {
    FSMDEBUG(("fsm_input(%x): Rcvd illegal length.", f->protocol));
    return;
  }
  if (len > l) {
    FSMDEBUG(("fsm_input(%x): Rcvd short packet.", f->protocol));
    return;
  }
  len -= HEADERLEN; /* subtract header length */

  if (f->state == PPP_FSM_INITIAL || f->state == PPP_FSM_STARTING) {
    FSMDEBUG(
        ("fsm_input(%x): Rcvd packet in state %d.", f->protocol, f->state));
    return;
  }

  /*
   * Action depends on code.
   */
  switch (code) {
  case CONFREQ:
    fsm_rconfreq(f, id, inp, len);
    break;

  case CONFACK:
    fsm_rconfack(f, id, inp, len);
    break;

  case CONFNAK:
  case CONFREJ:
    fsm_rconfnakrej(f, code, id, inp, len);
    break;

  case TERMREQ:
    fsm_rtermreq(f, id, inp, len);
    break;

  case TERMACK:
    fsm_rtermack(f);
    break;

  case CODEREJ:
    fsm_rcoderej(f, inp, len);
    break;

  default:
    if (!f->callbacks->extcode ||
        !(*f->callbacks->extcode)(f, code, id, inp, len))
      fsm_sdata(f, CODEREJ, ++f->id, inpacket, len + HEADERLEN);
    break;
  }
}

static void fsm_rconfreq(fsm *f, u_char id, u_char *inp, int len) {
  int code, reject_if_disagree;

  switch (f->state) {
  case PPP_FSM_CLOSED:
    /* Go away, we're closed */
    fsm_sdata(f, TERMACK, id, NULL, 0);
    return;
  case PPP_FSM_CLOSING:
  case PPP_FSM_STOPPING:
    return;

  case PPP_FSM_OPENED:
    /* Go down and restart negotiation */
    if (f->callbacks->down)
      (*f->callbacks->down)(f); /* Inform upper layers */
    fsm_sconfreq(f, 0);         /* Send initial Configure-Request */
    f->state = PPP_FSM_REQSENT;
    break;

  case PPP_FSM_STOPPED:
    /* Negotiation started by our peer */
    fsm_sconfreq(f, 0); /* Send initial Configure-Request */
    f->state = PPP_FSM_REQSENT;
    break;
  default:
    break;
  }

  /*
   * Pass the requested configuration options
   * to protocol-specific code for checking.
   */
  if (f->callbacks->reqci) { /* Check CI */
    reject_if_disagree = (f->nakloops >= f->maxnakloops);
    code = (*f->callbacks->reqci)(f, inp, &len, reject_if_disagree);
  } else if (len)
    code = CONFREJ; /* Reject all CI */
  else
    code = CONFACK;

  /* send the Ack, Nak or Rej to the peer */
  fsm_sdata(f, code, id, inp, len);

  if (code == CONFACK) {
    if (f->state == PPP_FSM_ACKRCVD) {
      UNTIMEOUT(fsm_timeout, f); /* Cancel timeout */
      f->state = PPP_FSM_OPENED;
      if (f->callbacks->up)
        (*f->callbacks->up)(f); /* Inform upper layers */
    } else
      f->state = PPP_FSM_ACKSENT;
    f->nakloops = 0;

  } else {
    /* we sent CONFACK or CONFREJ */
    if (f->state != PPP_FSM_ACKRCVD)
      f->state = PPP_FSM_REQSENT;
    if (code == CONFNAK)
      ++f->nakloops;
  }
}

static void fsm_rconfack(fsm *f, int id, u_char *inp, int len) {
  ppp_pcb *pcb = f->pcb;

  if (id != f->reqid || f->seen_ack) /* Expected id? */
    return;                          /* Nope, toss... */
  if (!(f->callbacks->ackci ? (*f->callbacks->ackci)(f, inp, len)
                            : (len == 0))) {
    /* Ack is bad - ignore it */
    ppp_error(("Received bad configure-ack: %P", inp, len));
    return;
  }
  f->seen_ack = 1;
  f->rnakloops = 0;

  switch (f->state) {
  case PPP_FSM_CLOSED:
  case PPP_FSM_STOPPED:
    fsm_sdata(f, TERMACK, id, NULL, 0);
    break;

  case PPP_FSM_REQSENT:
    f->state = PPP_FSM_ACKRCVD;
    f->retransmits = pcb->settings.fsm_max_conf_req_transmits;
    break;

  case PPP_FSM_ACKRCVD:
    /* Huh? an extra valid Ack? oh well... */
    UNTIMEOUT(fsm_timeout, f); /* Cancel timeout */
    fsm_sconfreq(f, 0);
    f->state = PPP_FSM_REQSENT;
    break;

  case PPP_FSM_ACKSENT:
    UNTIMEOUT(fsm_timeout, f); /* Cancel timeout */
    f->state = PPP_FSM_OPENED;
    f->retransmits = pcb->settings.fsm_max_conf_req_transmits;
    if (f->callbacks->up)
      (*f->callbacks->up)(f); /* Inform upper layers */
    break;

  case PPP_FSM_OPENED:
    /* Go down and restart negotiation */
    if (f->callbacks->down)
      (*f->callbacks->down)(f); /* Inform upper layers */
    fsm_sconfreq(f, 0);         /* Send initial Configure-Request */
    f->state = PPP_FSM_REQSENT;
    break;
  default:
    break;
  }
}

static void fsm_rconfnakrej(fsm *f, int code, int id, u_char *inp, int len) {
  int ret;
  int treat_as_reject;

  if (id != f->reqid || f->seen_ack) /* Expected id? */
    return;                          /* Nope, toss... */

  if (code == CONFNAK) {
    ++f->rnakloops;
    treat_as_reject = (f->rnakloops >= f->maxnakloops);
    if (f->callbacks->nakci == NULL ||
        !(ret = f->callbacks->nakci(f, inp, len, treat_as_reject))) {
      ppp_error(("Received bad configure-nak: %P", inp, len));
      return;
    }
  } else {
    f->rnakloops = 0;
    if (f->callbacks->rejci == NULL ||
        !(ret = f->callbacks->rejci(f, inp, len))) {
      ppp_error(("Received bad configure-rej: %P", inp, len));
      return;
    }
  }

  f->seen_ack = 1;

  switch (f->state) {
  case PPP_FSM_CLOSED:
  case PPP_FSM_STOPPED:
    fsm_sdata(f, TERMACK, id, NULL, 0);
    break;

  case PPP_FSM_REQSENT:
  case PPP_FSM_ACKSENT:
    /* They didn't agree to what we wanted - try another request */
    UNTIMEOUT(fsm_timeout, f); /* Cancel timeout */
    if (ret < 0)
      f->state = PPP_FSM_STOPPED; /* kludge for stopping CCP */
    else
      fsm_sconfreq(f, 0); /* Send Configure-Request */
    break;

  case PPP_FSM_ACKRCVD:
    /* Got a Nak/reject when we had already had an Ack?? oh well... */
    UNTIMEOUT(fsm_timeout, f); /* Cancel timeout */
    fsm_sconfreq(f, 0);
    f->state = PPP_FSM_REQSENT;
    break;

  case PPP_FSM_OPENED:
    /* Go down and restart negotiation */
    if (f->callbacks->down)
      (*f->callbacks->down)(f); /* Inform upper layers */
    fsm_sconfreq(f, 0);         /* Send initial Configure-Request */
    f->state = PPP_FSM_REQSENT;
    break;
  default:
    break;
  }
}

static void fsm_rtermreq(fsm *f, int id, u_char *p, int len) {
  ppp_pcb *pcb = f->pcb;

  switch (f->state) {
  case PPP_FSM_ACKRCVD:
  case PPP_FSM_ACKSENT:
    f->state = PPP_FSM_REQSENT; /* Start over but keep trying */
    break;

  case PPP_FSM_OPENED:
    if (len > 0) {
      ppp_info(("%s terminated by peer (%0.*v)", PROTO_NAME(f), len, p));
    } else
      ppp_info(("%s terminated by peer", PROTO_NAME(f)));
    f->retransmits = 0;
    f->state = PPP_FSM_STOPPING;
    if (f->callbacks->down)
      (*f->callbacks->down)(f); /* Inform upper layers */
    TIMEOUT(fsm_timeout, f, pcb->settings.fsm_timeout_time);
    break;
  default:
    break;
  }

  fsm_sdata(f, TERMACK, id, NULL, 0);
}

static void fsm_rtermack(fsm *f) {
  switch (f->state) {
  case PPP_FSM_CLOSING:
    UNTIMEOUT(fsm_timeout, f);
    f->state = PPP_FSM_CLOSED;
    if (f->callbacks->finished)
      (*f->callbacks->finished)(f);
    break;
  case PPP_FSM_STOPPING:
    UNTIMEOUT(fsm_timeout, f);
    f->state = PPP_FSM_STOPPED;
    if (f->callbacks->finished)
      (*f->callbacks->finished)(f);
    break;

  case PPP_FSM_ACKRCVD:
    f->state = PPP_FSM_REQSENT;
    break;

  case PPP_FSM_OPENED:
    if (f->callbacks->down)
      (*f->callbacks->down)(f); /* Inform upper layers */
    fsm_sconfreq(f, 0);
    f->state = PPP_FSM_REQSENT;
    break;
  default:
    break;
  }
}

static void fsm_rcoderej(fsm *f, u_char *inp, int len) {
  u_char code, id;

  if (len < HEADERLEN) {
    FSMDEBUG(("fsm_rcoderej: Rcvd short Code-Reject packet!"));
    return;
  }
  GETCHAR(code, inp);
  GETCHAR(id, inp);
  ppp_warn(
      ("%s: Rcvd Code-Reject for code %d, id %d", PROTO_NAME(f), code, id));

  if (f->state == PPP_FSM_ACKRCVD)
    f->state = PPP_FSM_REQSENT;
}

void fsm_protreject(fsm *f) {
  switch (f->state) {
  case PPP_FSM_CLOSING:
    UNTIMEOUT(fsm_timeout, f); /* Cancel timeout */
                               /* fall through */
                               /* no break */
  case PPP_FSM_CLOSED:
    f->state = PPP_FSM_CLOSED;
    if (f->callbacks->finished)
      (*f->callbacks->finished)(f);
    break;

  case PPP_FSM_STOPPING:
  case PPP_FSM_REQSENT:
  case PPP_FSM_ACKRCVD:
  case PPP_FSM_ACKSENT:
    UNTIMEOUT(fsm_timeout, f); /* Cancel timeout */
                               /* fall through */
                               /* no break */
  case PPP_FSM_STOPPED:
    f->state = PPP_FSM_STOPPED;
    if (f->callbacks->finished)
      (*f->callbacks->finished)(f);
    break;

  case PPP_FSM_OPENED:
    terminate_layer(f, PPP_FSM_STOPPING);
    break;

  default:
    FSMDEBUG(
        ("%s: Protocol-reject event in state %d!", PROTO_NAME(f), f->state));
    /* no break */
  }
}

static void fsm_sconfreq(fsm *f, int retransmit) {
  ppp_pcb *pcb = f->pcb;
  struct pbuf *p;
  u_char *outp;
  int cilen;

  if (f->state != PPP_FSM_REQSENT && f->state != PPP_FSM_ACKRCVD &&
      f->state != PPP_FSM_ACKSENT) {
    /* Not currently negotiating - reset options */
    if (f->callbacks->resetci)
      (*f->callbacks->resetci)(f);
    f->nakloops = 0;
    f->rnakloops = 0;
  }

  if (!retransmit) {
    /* New request - reset retransmission counter, use new ID */
    f->retransmits = pcb->settings.fsm_max_conf_req_transmits;
    f->reqid = ++f->id;
  }

  f->seen_ack = 0;

  /*
   * Make up the request packet
   */
  if (f->callbacks->cilen && f->callbacks->addci) {
    cilen = (*f->callbacks->cilen)(f);
    if (cilen > pcb->peer_mru - HEADERLEN)
      cilen = pcb->peer_mru - HEADERLEN;
  } else
    cilen = 0;

  p = pbuf_alloc(PBUF_RAW, (u16_t)(cilen + HEADERLEN + PPP_HDRLEN), PBUF_RAM);
  if (NULL == p)
    return;
  if (p->tot_len != p->len) {
    pbuf_free(p);
    return;
  }

  /* send the request to our peer */
  outp = (u_char *)p->payload;
  MAKEHEADER(outp, f->protocol);
  PUTCHAR(CONFREQ, outp);
  PUTCHAR(f->reqid, outp);
  PUTSHORT(cilen + HEADERLEN, outp);
  if (cilen != 0) {
    (*f->callbacks->addci)(f, outp, &cilen);
    LWIP_ASSERT("cilen == p->len - HEADERLEN - PPP_HDRLEN",
                cilen == p->len - HEADERLEN - PPP_HDRLEN);
  }

  ppp_write(pcb, p);

  /* start the retransmit timer */
  --f->retransmits;
  TIMEOUT(fsm_timeout, f, pcb->settings.fsm_timeout_time);
}

void fsm_sdata(fsm *f, u_char code, u_char id, const u_char *data,
               int datalen) {
  ppp_pcb *pcb = f->pcb;
  struct pbuf *p;
  u_char *outp;
  int outlen;

  /* Adjust length to be smaller than MTU */
  if (datalen > pcb->peer_mru - HEADERLEN)
    datalen = pcb->peer_mru - HEADERLEN;
  outlen = datalen + HEADERLEN;

  p = pbuf_alloc(PBUF_RAW, (u16_t)(outlen + PPP_HDRLEN), PBUF_RAM);
  if (NULL == p)
    return;
  if (p->tot_len != p->len) {
    pbuf_free(p);
    return;
  }

  outp = (u_char *)p->payload;
  if (datalen) /* && data != outp + PPP_HDRLEN + HEADERLEN)  -- was only for
                  fsm_sconfreq() */
    MEMCPY(outp + PPP_HDRLEN + HEADERLEN, data, datalen);
  MAKEHEADER(outp, f->protocol);
  PUTCHAR(code, outp);
  PUTCHAR(id, outp);
  PUTSHORT(outlen, outp);
  ppp_write(pcb, p);
}

static int setvjslots(argv)
char **argv;
{
  int value;

  if (!int_option(*argv, &value))
    return 0;

  if (value < 2 || value > 16) {
    option_error("vj-max-slots value must be between 2 and 16");
    return 0;
  }
  ipcp_wantoptions[0].maxslotindex = ipcp_allowoptions[0].maxslotindex =
      value - 1;
  slprintf(vj_value, sizeof(vj_value), "%d", value);
  return 1;
}

static int setdnsaddr(argv)
char **argv;
{
  u32_t dns;
  struct hostent *hp;

  dns = inet_addr(*argv);
  if (dns == (u32_t)-1) {
    if ((hp = gethostbyname(*argv)) == NULL) {
      option_error("invalid address parameter '%s' for ms-dns option", *argv);
      return 0;
    }
    dns = *(u32_t *)hp->h_addr;
  }

  /* We take the last 2 values given, the 2nd-last as the primary
     and the last as the secondary.  If only one is given it
     becomes both primary and secondary. */
  if (ipcp_allowoptions[0].dnsaddr[1] == 0)
    ipcp_allowoptions[0].dnsaddr[0] = dns;
  else
    ipcp_allowoptions[0].dnsaddr[0] = ipcp_allowoptions[0].dnsaddr[1];

  /* always set the secondary address value. */
  ipcp_allowoptions[0].dnsaddr[1] = dns;

  return (1);
}

static int setwinsaddr(argv)
char **argv;
{
  u32_t wins;
  struct hostent *hp;

  wins = inet_addr(*argv);
  if (wins == (u32_t)-1) {
    if ((hp = gethostbyname(*argv)) == NULL) {
      option_error("invalid address parameter '%s' for ms-wins option", *argv);
      return 0;
    }
    wins = *(u32_t *)hp->h_addr;
  }

  /* We take the last 2 values given, the 2nd-last as the primary
     and the last as the secondary.  If only one is given it
     becomes both primary and secondary. */
  if (ipcp_allowoptions[0].winsaddr[1] == 0)
    ipcp_allowoptions[0].winsaddr[0] = wins;
  else
    ipcp_allowoptions[0].winsaddr[0] = ipcp_allowoptions[0].winsaddr[1];

  /* always set the secondary address value. */
  ipcp_allowoptions[0].winsaddr[1] = wins;

  return (1);
}

int setipaddr(arg, argv, doit)
char *arg;
char **argv;
int doit;
{
  struct hostent *hp;
  char *colon;
  u32_t local, remote;
  ipcp_options *wo = &ipcp_wantoptions[0];
  static int prio_local = 0, prio_remote = 0;

  /*
   * IP address pair separated by ":".
   */
  if ((colon = strchr(arg, ':')) == NULL)
    return 0;
  if (!doit)
    return 1;

  /*
   * If colon first character, then no local addr.
   */
  if (colon != arg && option_priority >= prio_local) {
    *colon = '\0';
    if ((local = inet_addr(arg)) == (u32_t)-1) {
      if ((hp = gethostbyname(arg)) == NULL) {
        option_error("unknown host: %s", arg);
        return 0;
      }
      local = *(u32_t *)hp->h_addr;
    }
    if (bad_ip_adrs(local)) {
      option_error("bad local IP address %s", ip_ntoa(local));
      return 0;
    }
    if (local != 0)
      wo->ouraddr = local;
    *colon = ':';
    prio_local = option_priority;
  }

  /*
   * If colon last character, then no remote addr.
   */
  if (*++colon != '\0' && option_priority >= prio_remote) {
    if ((remote = inet_addr(colon)) == (u32_t)-1) {
      if ((hp = gethostbyname(colon)) == NULL) {
        option_error("unknown host: %s", colon);
        return 0;
      }
      remote = *(u32_t *)hp->h_addr;
      if (remote_name[0] == 0)
        strlcpy(remote_name, colon, sizeof(remote_name));
    }
    if (bad_ip_adrs(remote)) {
      option_error("bad remote IP address %s", ip_ntoa(remote));
      return 0;
    }
    if (remote != 0)
      wo->hisaddr = remote;
    prio_remote = option_priority;
  }

  return 1;
}

static void printipaddr(opt, printer, arg) option_t *opt;
void (*printer)(void *, char *, ...);
void *arg;
{
  ipcp_options *wo = &ipcp_wantoptions[0];

  if (wo->ouraddr != 0)
    printer(arg, "%I", wo->ouraddr);
  printer(arg, ":");
  if (wo->hisaddr != 0)
    printer(arg, "%I", wo->hisaddr);
}

static int setnetmask(argv)
char **argv;
{
  u32_t mask;
  int n;
  char *p;

  /*
   * Unfortunately, if we use inet_addr, we can't tell whether
   * a result of all 1s is an error or a valid 255.255.255.255.
   */
  p = *argv;
  n = parse_dotted_ip(p, &mask);

  mask = lwip_htonl(mask);

  if (n == 0 || p[n] != 0 || (netmask & ~mask) != 0) {
    option_error("invalid netmask value '%s'", *argv);
    return 0;
  }

  netmask = mask;
  slprintf(netmask_str, sizeof(netmask_str), "%I", mask);

  return (1);
}

int parse_dotted_ip(p, vp)
char *p;
u32_t *vp;
{
  int n;
  u32_t v, b;
  char *endp, *p0 = p;

  v = 0;
  for (n = 3;; --n) {
    b = strtoul(p, &endp, 0);
    if (endp == p)
      return 0;
    if (b > 255) {
      if (n < 3)
        return 0;
      /* accept e.g. 0xffffff00 */
      *vp = b;
      return endp - p0;
    }
    v |= b << (n * 8);
    p = endp;
    if (n == 0)
      break;
    if (*p != '.')
      return 0;
    ++p;
  }
  *vp = v;
  return p - p0;
}

static void ipcp_init(ppp_pcb *pcb) {
  fsm *f = &pcb->ipcp_fsm;

  ipcp_options *wo = &pcb->ipcp_wantoptions;
  ipcp_options *ao = &pcb->ipcp_allowoptions;

  f->pcb = pcb;
  f->protocol = PPP_IPCP;
  f->callbacks = &ipcp_callbacks;
  fsm_init(f);

  /*
   * Some 3G modems use repeated IPCP NAKs as a way of stalling
   * until they can contact a server on the network, so we increase
   * the default number of NAKs we accept before we start treating
   * them as rejects.
   */
  f->maxnakloops = 100;

#if 0  /* Not necessary, everything is cleared in ppp_new() */
    memset(wo, 0, sizeof(*wo));
    memset(ao, 0, sizeof(*ao));
#endif /* 0 */

  wo->neg_addr = wo->old_addrs = 1;
#if VJ_SUPPORT
  wo->neg_vj = 1;
  wo->vj_protocol = IPCP_VJ_COMP;
  wo->maxslotindex = MAX_STATES - 1; /* really max index */
  wo->cflag = 1;
#endif /* VJ_SUPPORT */

#if 0  /* UNUSED */
    /* wanting default route by default */
    wo->default_route = 1;
#endif /* UNUSED */

  ao->neg_addr = ao->old_addrs = 1;
#if VJ_SUPPORT
  /* max slots and slot-id compression are currently hardwired in */
  /* ppp_if.c to 16 and 1, this needs to be changed (among other */
  /* things) gmc */

  ao->neg_vj = 1;
  ao->maxslotindex = MAX_STATES - 1;
  ao->cflag = 1;
#endif /* #if VJ_SUPPORT */

#if 0  /* UNUSED */
    /*
     * XXX These control whether the user may use the proxyarp
     * and defaultroute options.
     */
    ao->proxy_arp = 1;
    ao->default_route = 1;
#endif /* UNUSED */
}

static void ipcp_open(ppp_pcb *pcb) {
  fsm *f = &pcb->ipcp_fsm;
  fsm_open(f);
  pcb->ipcp_is_open = 1;
}

static void ipcp_close(ppp_pcb *pcb, const char *reason) {
  fsm *f = &pcb->ipcp_fsm;
  fsm_close(f, reason);
}

static void ipcp_lowerup(ppp_pcb *pcb) {
  fsm *f = &pcb->ipcp_fsm;
  fsm_lowerup(f);
}

static void ipcp_lowerdown(ppp_pcb *pcb) {
  fsm *f = &pcb->ipcp_fsm;
  fsm_lowerdown(f);
}

static void ipcp_input(ppp_pcb *pcb, u_char *p, int len) {
  fsm *f = &pcb->ipcp_fsm;
  fsm_input(f, p, len);
}

static void ipcp_protrej(ppp_pcb *pcb) {
  fsm *f = &pcb->ipcp_fsm;
  fsm_lowerdown(f);
}

static void ipcp_resetci(fsm *f) {
  ppp_pcb *pcb = f->pcb;
  ipcp_options *wo = &pcb->ipcp_wantoptions;
  ipcp_options *go = &pcb->ipcp_gotoptions;
  ipcp_options *ao = &pcb->ipcp_allowoptions;

  wo->req_addr =
      (wo->neg_addr || wo->old_addrs) && (ao->neg_addr || ao->old_addrs);
  if (wo->ouraddr == 0)
    wo->accept_local = 1;
  if (wo->hisaddr == 0)
    wo->accept_remote = 1;
#if LWIP_DNS
  wo->req_dns1 = wo->req_dns2 =
      pcb->settings.usepeerdns; /* Request DNS addresses from the peer */
#endif                          /* LWIP_DNS */
  *go = *wo;
  if (!pcb->ask_for_local)
    go->ouraddr = 0;
#if 0  /* UNUSED */
    if (ip_choose_hook) {
	ip_choose_hook(&wo->hisaddr);
	if (wo->hisaddr) {
	    wo->accept_remote = 0;
	}
    }
#endif /* UNUSED */
  BZERO(&pcb->ipcp_hisoptions, sizeof(ipcp_options));
}

static int ipcp_nakci(fsm *f, u_char *p, int len, int treat_as_reject) {
  ppp_pcb *pcb = f->pcb;
  ipcp_options *go = &pcb->ipcp_gotoptions;
  u_char citype, cilen, *next;
#if VJ_SUPPORT
  u_char cimaxslotindex, cicflag;
  u_short cishort;
#endif /* VJ_SUPPORT */
  u32_t ciaddr1, ciaddr2, l;
#if LWIP_DNS
  u32_t cidnsaddr;
#endif               /* LWIP_DNS */
  ipcp_options no;   /* options we've seen Naks for */
  ipcp_options try_; /* options to request next time */

  BZERO(&no, sizeof(no));
  try_ = *go;

  /*
   * Any Nak'd CIs must be in exactly the same order that we sent.
   * Check packet length and CI length at each step.
   * If we find any deviations, then this packet is bad.
   */
#define NAKCIADDRS(opt, neg, code)                                             \
  if ((neg) && (cilen = p[1]) == CILEN_ADDRS && len >= cilen && p[0] == opt) { \
    len -= cilen;                                                              \
    INCPTR(2, p);                                                              \
    GETLONG(l, p);                                                             \
    ciaddr1 = lwip_htonl(l);                                                   \
    GETLONG(l, p);                                                             \
    ciaddr2 = lwip_htonl(l);                                                   \
    no.old_addrs = 1;                                                          \
    code                                                                       \
  }

#if VJ_SUPPORT
#define NAKCIVJ(opt, neg, code)                                                \
  if (go->neg && ((cilen = p[1]) == CILEN_COMPRESS || cilen == CILEN_VJ) &&    \
      len >= cilen && p[0] == opt) {                                           \
    len -= cilen;                                                              \
    INCPTR(2, p);                                                              \
    GETSHORT(cishort, p);                                                      \
    no.neg = 1;                                                                \
    code                                                                       \
  }
#endif /* VJ_SUPPORT */

#define NAKCIADDR(opt, neg, code)                                              \
  if (go->neg && (cilen = p[1]) == CILEN_ADDR && len >= cilen &&               \
      p[0] == opt) {                                                           \
    len -= cilen;                                                              \
    INCPTR(2, p);                                                              \
    GETLONG(l, p);                                                             \
    ciaddr1 = lwip_htonl(l);                                                   \
    no.neg = 1;                                                                \
    code                                                                       \
  }

#if LWIP_DNS
#define NAKCIDNS(opt, neg, code)                                               \
  if (go->neg && ((cilen = p[1]) == CILEN_ADDR) && len >= cilen &&             \
      p[0] == opt) {                                                           \
    len -= cilen;                                                              \
    INCPTR(2, p);                                                              \
    GETLONG(l, p);                                                             \
    cidnsaddr = lwip_htonl(l);                                                 \
    no.neg = 1;                                                                \
    code                                                                       \
  }
#endif /* LWIP_DNS */

  /*
   * Accept the peer's idea of {our,his} address, if different
   * from our idea, only if the accept_{local,remote} flag is set.
   */
  NAKCIADDRS(
      CI_ADDRS, !go->neg_addr && go->old_addrs,
      if (treat_as_reject) { try_.old_addrs = 0; } else {
        if (go->accept_local && ciaddr1) {
          /* take his idea of our address */
          try_.ouraddr = ciaddr1;
        }
        if (go->accept_remote && ciaddr2) {
          /* take his idea of his address */
          try_.hisaddr = ciaddr2;
        }
      });

#if VJ_SUPPORT
  /*
   * Accept the peer's value of maxslotindex provided that it
   * is less than what we asked for.  Turn off slot-ID compression
   * if the peer wants.  Send old-style compress-type option if
   * the peer wants.
   */
  NAKCIVJ(
      CI_COMPRESSTYPE, neg_vj,
      if (treat_as_reject) { try_.neg_vj = 0; } else if (cilen == CILEN_VJ) {
        GETCHAR(cimaxslotindex, p);
        GETCHAR(cicflag, p);
        if (cishort == IPCP_VJ_COMP) {
          try_.old_vj = 0;
          if (cimaxslotindex < go->maxslotindex)
            try_.maxslotindex = cimaxslotindex;
          if (!cicflag)
            try_.cflag = 0;
        } else {
          try_.neg_vj = 0;
        }
      } else {
        if (cishort == IPCP_VJ_COMP || cishort == IPCP_VJ_COMP_OLD) {
          try_.old_vj = 1;
          try_.vj_protocol = cishort;
        } else {
          try_.neg_vj = 0;
        }
      });
#endif /* VJ_SUPPORT */

  NAKCIADDR(
      CI_ADDR, neg_addr,
      if (treat_as_reject) {
        try_.neg_addr = 0;
        try_.old_addrs = 0;
      } else if (go->accept_local && ciaddr1) {
        /* take his idea of our address */
        try_.ouraddr = ciaddr1;
      });

#if LWIP_DNS
  NAKCIDNS(
      CI_MS_DNS1, req_dns1, if (treat_as_reject) { try_.req_dns1 = 0; } else {
        try_.dnsaddr[0] = cidnsaddr;
      });

  NAKCIDNS(
      CI_MS_DNS2, req_dns2, if (treat_as_reject) { try_.req_dns2 = 0; } else {
        try_.dnsaddr[1] = cidnsaddr;
      });
#endif /* #if LWIP_DNS */

  /*
   * There may be remaining CIs, if the peer is requesting negotiation
   * on an option that we didn't include in our request packet.
   * If they want to negotiate about IP addresses, we comply.
   * If they want us to ask for compression, we refuse.
   * If they want us to ask for ms-dns, we do that, since some
   * peers get huffy if we don't.
   */
  while (len >= CILEN_VOID) {
    GETCHAR(citype, p);
    GETCHAR(cilen, p);
    if (cilen < CILEN_VOID || (len -= cilen) < 0)
      goto bad;
    next = p + cilen - 2;

    switch (citype) {
#if VJ_SUPPORT
    case CI_COMPRESSTYPE:
      if (go->neg_vj || no.neg_vj ||
          (cilen != CILEN_VJ && cilen != CILEN_COMPRESS))
        goto bad;
      no.neg_vj = 1;
      break;
#endif /* VJ_SUPPORT */
    case CI_ADDRS:
      if ((!go->neg_addr && go->old_addrs) || no.old_addrs ||
          cilen != CILEN_ADDRS)
        goto bad;
      try_.neg_addr = 0;
      GETLONG(l, p);
      ciaddr1 = lwip_htonl(l);
      if (ciaddr1 && go->accept_local)
        try_.ouraddr = ciaddr1;
      GETLONG(l, p);
      ciaddr2 = lwip_htonl(l);
      if (ciaddr2 && go->accept_remote)
        try_.hisaddr = ciaddr2;
      no.old_addrs = 1;
      break;
    case CI_ADDR:
      if (go->neg_addr || no.neg_addr || cilen != CILEN_ADDR)
        goto bad;
      try_.old_addrs = 0;
      GETLONG(l, p);
      ciaddr1 = lwip_htonl(l);
      if (ciaddr1 && go->accept_local)
        try_.ouraddr = ciaddr1;
      if (try_.ouraddr != 0)
        try_.neg_addr = 1;
      no.neg_addr = 1;
      break;
#if LWIP_DNS
    case CI_MS_DNS1:
      if (go->req_dns1 || no.req_dns1 || cilen != CILEN_ADDR)
        goto bad;
      GETLONG(l, p);
      try_.dnsaddr[0] = lwip_htonl(l);
      try_.req_dns1 = 1;
      no.req_dns1 = 1;
      break;
    case CI_MS_DNS2:
      if (go->req_dns2 || no.req_dns2 || cilen != CILEN_ADDR)
        goto bad;
      GETLONG(l, p);
      try_.dnsaddr[1] = lwip_htonl(l);
      try_.req_dns2 = 1;
      no.req_dns2 = 1;
      break;
#endif /* LWIP_DNS */
#if 0  /* UNUSED - WINS */
	case CI_MS_WINS1:
	case CI_MS_WINS2:
	    if (cilen != CILEN_ADDR)
		goto bad;
	    GETLONG(l, p);
	    ciaddr1 = lwip_htonl(l);
	    if (ciaddr1)
		try_.winsaddr[citype == CI_MS_WINS2] = ciaddr1;
	    break;
#endif /* UNUSED - WINS */
    default:
      break;
    }
    p = next;
  }

  /*
   * OK, the Nak is good.  Now we can update state.
   * If there are any remaining options, we ignore them.
   */
  if (f->state != PPP_FSM_OPENED)
    *go = try_;

  return 1;

bad:
  IPCPDEBUG(("ipcp_nakci: received bad Nak!"));
  return 0;
}

static int ipcp_rejci(fsm *f, u_char *p, int len) {
  ppp_pcb *pcb = f->pcb;
  ipcp_options *go = &pcb->ipcp_gotoptions;
  u_char cilen;
#if VJ_SUPPORT
  u_char cimaxslotindex, ciflag;
  u_short cishort;
#endif /* VJ_SUPPORT */
  u32_t cilong;
  ipcp_options try_; /* options to request next time */

  try_ = *go;
  /*
   * Any Rejected CIs must be in exactly the same order that we sent.
   * Check packet length and CI length at each step.
   * If we find any deviations, then this packet is bad.
   */
#define REJCIADDRS(opt, neg, val1, val2)                                       \
  if ((neg) && (cilen = p[1]) == CILEN_ADDRS && len >= cilen && p[0] == opt) { \
    u32_t l;                                                                   \
    len -= cilen;                                                              \
    INCPTR(2, p);                                                              \
    GETLONG(l, p);                                                             \
    cilong = lwip_htonl(l);                                                    \
    /* Check rejected value. */                                                \
    if (cilong != val1)                                                        \
      goto bad;                                                                \
    GETLONG(l, p);                                                             \
    cilong = lwip_htonl(l);                                                    \
    /* Check rejected value. */                                                \
    if (cilong != val2)                                                        \
      goto bad;                                                                \
    try_.old_addrs = 0;                                                        \
  }

static int ipcp_reqci(fsm *f, u_char *inp, int *len, int reject_if_disagree) {
  ppp_pcb *pcb = f->pcb;
  ipcp_options *wo = &pcb->ipcp_wantoptions;
  ipcp_options *ho = &pcb->ipcp_hisoptions;
  ipcp_options *ao = &pcb->ipcp_allowoptions;
  u_char *cip, *next;    /* Pointer to current and next CIs */
  u_short cilen, citype; /* Parsed len, type */
#if VJ_SUPPORT
  u_short cishort;            /* Parsed short value */
#endif                        /* VJ_SUPPORT */
  u32_t tl, ciaddr1, ciaddr2; /* Parsed address values */
  int rc = CONFACK;           /* Final packet return code */
  int orc;                    /* Individual option return code */
  u_char *p;                  /* Pointer to next char to parse */
  u_char *ucp = inp;          /* Pointer to current output char */
  int l = *len;               /* Length left */
#if VJ_SUPPORT
  u_char maxslotindex, cflag;
#endif /* VJ_SUPPORT */
#if LWIP_DNS
  int d;
#endif /* LWIP_DNS */

  /*
   * Reset all his options.
   */
  BZERO(ho, sizeof(*ho));

  /*
   * Process all his options.
   */
  next = inp;
  while (l) {
    orc = CONFACK;  /* Assume success */
    cip = p = next; /* Remember beginning of CI */
    if (l < 2 ||    /* Not enough data for CI header or */
        p[1] < 2 || /*  CI length too small or */
        p[1] > l) { /*  CI length too big? */
      IPCPDEBUG(("ipcp_reqci: bad CI length!"));
      orc = CONFREJ; /* Reject bad CI */
      cilen = l;     /* Reject till end of packet */
      l = 0;         /* Don't loop again */
      goto endswitch;
    }
    GETCHAR(citype, p); /* Parse CI type */
    GETCHAR(cilen, p);  /* Parse CI length */
    l -= cilen;         /* Adjust remaining length */
    next += cilen;      /* Step to next CI */

    switch (citype) { /* Check CI type */
    case CI_ADDRS:
      if (!ao->old_addrs || ho->neg_addr ||
          cilen != CILEN_ADDRS) { /* Check CI length */
        orc = CONFREJ;            /* Reject CI */
        break;
      }

      /*
       * If he has no address, or if we both have his address but
       * disagree about it, then NAK it with our idea.
       * In particular, if we don't know his address, but he does,
       * then accept it.
       */
      GETLONG(tl, p); /* Parse source address (his) */
      ciaddr1 = lwip_htonl(tl);
      if (ciaddr1 != wo->hisaddr && (ciaddr1 == 0 || !wo->accept_remote)) {
        orc = CONFNAK;
        if (!reject_if_disagree) {
          DECPTR(sizeof(u32_t), p);
          tl = lwip_ntohl(wo->hisaddr);
          PUTLONG(tl, p);
        }
      } else if (ciaddr1 == 0 && wo->hisaddr == 0) {
        /*
         * If neither we nor he knows his address, reject the option.
         */
        orc = CONFREJ;
        wo->req_addr = 0; /* don't NAK with 0.0.0.0 later */
        break;
      }

      /*
       * If he doesn't know our address, or if we both have our address
       * but disagree about it, then NAK it with our idea.
       */
      GETLONG(tl, p); /* Parse destination address (ours) */
      ciaddr2 = lwip_htonl(tl);
      if (ciaddr2 != wo->ouraddr) {
        if (ciaddr2 == 0 || !wo->accept_local) {
          orc = CONFNAK;
          if (!reject_if_disagree) {
            DECPTR(sizeof(u32_t), p);
            tl = lwip_ntohl(wo->ouraddr);
            PUTLONG(tl, p);
          }
        } else {
          wo->ouraddr = ciaddr2; /* accept peer's idea */
        }
      }

      ho->old_addrs = 1;
      ho->hisaddr = ciaddr1;
      ho->ouraddr = ciaddr2;
      break;

    case CI_ADDR:
      if (!ao->neg_addr || ho->old_addrs ||
          cilen != CILEN_ADDR) { /* Check CI length */
        orc = CONFREJ;           /* Reject CI */
        break;
      }

      /*
       * If he has no address, or if we both have his address but
       * disagree about it, then NAK it with our idea.
       * In particular, if we don't know his address, but he does,
       * then accept it.
       */
      GETLONG(tl, p); /* Parse source address (his) */
      ciaddr1 = lwip_htonl(tl);
      if (ciaddr1 != wo->hisaddr && (ciaddr1 == 0 || !wo->accept_remote)) {
        orc = CONFNAK;
        if (!reject_if_disagree) {
          DECPTR(sizeof(u32_t), p);
          tl = lwip_ntohl(wo->hisaddr);
          PUTLONG(tl, p);
        }
      } else if (ciaddr1 == 0 && wo->hisaddr == 0) {
        /*
         * Don't ACK an address of 0.0.0.0 - reject it instead.
         */
        orc = CONFREJ;
        wo->req_addr = 0; /* don't NAK with 0.0.0.0 later */
        break;
      }

      ho->neg_addr = 1;
      ho->hisaddr = ciaddr1;
      break;

#if LWIP_DNS
    case CI_MS_DNS1:
    case CI_MS_DNS2:
      /* Microsoft primary or secondary DNS request */
      d = citype == CI_MS_DNS2;

      /* If we do not have a DNS address then we cannot send it */
      if (ao->dnsaddr[d] == 0 || cilen != CILEN_ADDR) { /* Check CI length */
        orc = CONFREJ;                                  /* Reject CI */
        break;
      }
      GETLONG(tl, p);
      if (lwip_htonl(tl) != ao->dnsaddr[d]) {
        DECPTR(sizeof(u32_t), p);
        tl = lwip_ntohl(ao->dnsaddr[d]);
        PUTLONG(tl, p);
        orc = CONFNAK;
      }
      break;
#endif /* LWIP_DNS */

#if 0  /* UNUSED - WINS */
	case CI_MS_WINS1:
	case CI_MS_WINS2:
	    /* Microsoft primary or secondary WINS request */
	    d = citype == CI_MS_WINS2;

	    /* If we do not have a DNS address then we cannot send it */
	    if (ao->winsaddr[d] == 0 ||
		cilen != CILEN_ADDR) {	/* Check CI length */
		orc = CONFREJ;		/* Reject CI */
		break;
	    }
	    GETLONG(tl, p);
	    if (lwip_htonl(tl) != ao->winsaddr[d]) {
                DECPTR(sizeof(u32_t), p);
		tl = lwip_ntohl(ao->winsaddr[d]);
		PUTLONG(tl, p);
		orc = CONFNAK;
            }
            break;
#endif /* UNUSED - WINS */

#if VJ_SUPPORT
    case CI_COMPRESSTYPE:
      if (!ao->neg_vj || (cilen != CILEN_VJ && cilen != CILEN_COMPRESS)) {
        orc = CONFREJ;
        break;
      }
      GETSHORT(cishort, p);

      if (!(cishort == IPCP_VJ_COMP ||
            (cishort == IPCP_VJ_COMP_OLD && cilen == CILEN_COMPRESS))) {
        orc = CONFREJ;
        break;
      }

      ho->neg_vj = 1;
      ho->vj_protocol = cishort;
      if (cilen == CILEN_VJ) {
        GETCHAR(maxslotindex, p);
        if (maxslotindex > ao->maxslotindex) {
          orc = CONFNAK;
          if (!reject_if_disagree) {
            DECPTR(1, p);
            PUTCHAR(ao->maxslotindex, p);
          }
        }
        GETCHAR(cflag, p);
        if (cflag && !ao->cflag) {
          orc = CONFNAK;
          if (!reject_if_disagree) {
            DECPTR(1, p);
            PUTCHAR(wo->cflag, p);
          }
        }
        ho->maxslotindex = maxslotindex;
        ho->cflag = cflag;
      } else {
        ho->old_vj = 1;
        ho->maxslotindex = MAX_STATES - 1;
        ho->cflag = 1;
      }
      break;
#endif /* VJ_SUPPORT */

    default:
      orc = CONFREJ;
      break;
    }
  endswitch:
    if (orc == CONFACK && /* Good CI */
        rc != CONFACK)    /*  but prior CI wasn't? */
      continue;           /* Don't send this one */

    if (orc == CONFNAK) {     /* Nak this CI? */
      if (reject_if_disagree) /* Getting fed up with sending NAKs? */
        orc = CONFREJ;        /* Get tough if so */
      else {
        if (rc == CONFREJ)   /* Rejecting prior CI? */
          continue;          /* Don't send this one */
        if (rc == CONFACK) { /* Ack'd all prior CIs? */
          rc = CONFNAK;      /* Not anymore... */
          ucp = inp;         /* Backup */
        }
      }
    }

    if (orc == CONFREJ && /* Reject this CI */
        rc != CONFREJ) {  /*  but no prior ones? */
      rc = CONFREJ;
      ucp = inp; /* Backup */
    }

    /* Need to move CI? */
    if (ucp != cip)
      MEMCPY(ucp, cip, cilen); /* Move it */

    /* Update output pointer */
    INCPTR(cilen, ucp);
  }

  /*
   * If we aren't rejecting this packet, and we want to negotiate
   * their address, and they didn't send their address, then we
   * send a NAK with a CI_ADDR option appended.  We assume the
   * input buffer is long enough that we can append the extra
   * option safely.
   */
  if (rc != CONFREJ && !ho->neg_addr && !ho->old_addrs && wo->req_addr &&
      !reject_if_disagree && !pcb->settings.noremoteip) {
    if (rc == CONFACK) {
      rc = CONFNAK;
      ucp = inp;        /* reset pointer */
      wo->req_addr = 0; /* don't ask again */
    }
    PUTCHAR(CI_ADDR, ucp);
    PUTCHAR(CILEN_ADDR, ucp);
    tl = lwip_ntohl(wo->hisaddr);
    PUTLONG(tl, ucp);
  }

  *len = ucp - inp; /* Compute output length */
  IPCPDEBUG(("ipcp: returning Configure-%s", CODENAME(rc)));
  return (rc); /* Return final code */
}

static void
ip_check_options()
{
    struct hostent *hp;
    u32_t local;
    ipcp_options *wo = &ipcp_wantoptions[0];

    /*
     * Default our local IP address based on our hostname.
     * If local IP address already given, don't bother.
     */
    if (wo->ouraddr == 0 && !disable_defaultip) {
	/*
	 * Look up our hostname (possibly with domain name appended)
	 * and take the first IP address as our local IP address.
	 * If there isn't an IP address for our hostname, too bad.
	 */
	wo->accept_local = 1;	/* don't insist on this default value */
	if ((hp = gethostbyname(hostname)) != NULL) {
	    local = *(u32_t *)hp->h_addr;
	    if (local != 0 && !bad_ip_adrs(local))
		wo->ouraddr = local;
	}
    }
    ask_for_local = wo->ouraddr != 0 || !disable_defaultip;
}

static int ip_demand_conf(u)
int u;
{
  ppp_pcb *pcb = &ppp_pcb_list[u];
  ipcp_options *wo = &ipcp_wantoptions[u];

  if (wo->hisaddr == 0 && !pcb->settings.noremoteip) {
    /* make up an arbitrary address for the peer */
    wo->hisaddr = lwip_htonl(0x0a707070 + ifunit);
    wo->accept_remote = 1;
  }
  if (wo->ouraddr == 0) {
    /* make up an arbitrary address for us */
    wo->ouraddr = lwip_htonl(0x0a404040 + ifunit);
    wo->accept_local = 1;
    ask_for_local = 0; /* don't tell the peer this address */
  }
  if (!sifaddr(pcb, wo->ouraddr, wo->hisaddr, get_mask(wo->ouraddr)))
    return 0;
  if (!sifup(pcb))
    return 0;
  if (!sifnpmode(pcb, PPP_IP, NPMODE_QUEUE))
    return 0;
#if 0  /* UNUSED */
    if (wo->default_route)
	if (sifdefaultroute(pcb, wo->ouraddr, wo->hisaddr,
		wo->replace_default_route))
	    default_route_set[u] = 1;
#endif /* UNUSED */
#if 0  /* UNUSED - PROXY ARP */
    if (wo->proxy_arp)
	if (sifproxyarp(pcb, wo->hisaddr))
	    proxy_arp_set[u] = 1;
#endif /* UNUSED - PROXY ARP */

  ppp_notice(("local  IP address %I", wo->ouraddr));
  if (wo->hisaddr)
    ppp_notice(("remote IP address %I", wo->hisaddr));

  return 1;
}

static void ipcp_up(fsm *f) {
  ppp_pcb *pcb = f->pcb;
  u32_t mask;
  ipcp_options *ho = &pcb->ipcp_hisoptions;
  ipcp_options *go = &pcb->ipcp_gotoptions;
  ipcp_options *wo = &pcb->ipcp_wantoptions;

  IPCPDEBUG(("ipcp: up"));

  /*
   * We must have a non-zero IP address for both ends of the link.
   */
  if (!ho->neg_addr && !ho->old_addrs)
    ho->hisaddr = wo->hisaddr;

  if (!(go->neg_addr || go->old_addrs) && (wo->neg_addr || wo->old_addrs) &&
      wo->ouraddr != 0) {
    ppp_error(("Peer refused to agree to our IP address"));
    ipcp_close(f->pcb, "Refused our IP address");
    return;
  }
  if (go->ouraddr == 0) {
    ppp_error(("Could not determine local IP address"));
    ipcp_close(f->pcb, "Could not determine local IP address");
    return;
  }
  if (ho->hisaddr == 0 && !pcb->settings.noremoteip) {
    ho->hisaddr = lwip_htonl(0x0a404040);
    ppp_warn(("Could not determine remote IP address: defaulting to %I",
              ho->hisaddr));
  }
#if 0  /* UNUSED */
    script_setenv("IPLOCAL", ip_ntoa(go->ouraddr), 0);
    if (ho->hisaddr != 0)
	script_setenv("IPREMOTE", ip_ntoa(ho->hisaddr), 1);
#endif /* UNUSED */

#if LWIP_DNS
  if (!go->req_dns1)
    go->dnsaddr[0] = 0;
  if (!go->req_dns2)
    go->dnsaddr[1] = 0;
#if 0  /* UNUSED */
    if (go->dnsaddr[0])
	script_setenv("DNS1", ip_ntoa(go->dnsaddr[0]), 0);
    if (go->dnsaddr[1])
	script_setenv("DNS2", ip_ntoa(go->dnsaddr[1]), 0);
#endif /* UNUSED */
  if (pcb->settings.usepeerdns && (go->dnsaddr[0] || go->dnsaddr[1])) {
    sdns(pcb, go->dnsaddr[0], go->dnsaddr[1]);
#if 0  /* UNUSED */
	script_setenv("USEPEERDNS", "1", 0);
	create_resolv(go->dnsaddr[0], go->dnsaddr[1]);
#endif /* UNUSED */
  }
#endif /* LWIP_DNS */

  /*
   * Check that the peer is allowed to use the IP address it wants.
   */
  if (ho->hisaddr != 0) {
    u32_t addr = lwip_ntohl(ho->hisaddr);
    if ((addr >> IP_CLASSA_NSHIFT) == IP_LOOPBACKNET || IP_MULTICAST(addr) ||
        IP_BADCLASS(addr)
    /*
     * For now, consider that PPP in server mode with peer required
     * to authenticate must provide the peer IP address, reject any
     * IP address wanted by peer different than the one we wanted.
     */
#if PPP_SERVER && PPP_AUTH_SUPPORT
        || (pcb->settings.auth_required && wo->hisaddr != ho->hisaddr)
#endif /* PPP_SERVER && PPP_AUTH_SUPPORT */
    ) {
      ppp_error(
          ("Peer is not authorized to use remote address %I", ho->hisaddr));
      ipcp_close(pcb, "Unauthorized remote IP address");
      return;
    }
  }
#if 0  /* Unused */
    /* Upstream checking code */
    if (ho->hisaddr != 0 && !auth_ip_addr(f->unit, ho->hisaddr)) {
	ppp_error(("Peer is not authorized to use remote address %I", ho->hisaddr));
	ipcp_close(f->unit, "Unauthorized remote IP address");
	return;
    }
#endif /* Unused */

#if VJ_SUPPORT
  /* set tcp compression */
  sifvjcomp(pcb, ho->neg_vj, ho->cflag, ho->maxslotindex);
#endif /* VJ_SUPPORT */

#if DEMAND_SUPPORT
  /*
   * If we are doing dial-on-demand, the interface is already
   * configured, so we put out any saved-up packets, then set the
   * interface to pass IP packets.
   */
  if (demand) {
    if (go->ouraddr != wo->ouraddr || ho->hisaddr != wo->hisaddr) {
      ipcp_clear_addrs(f->unit, wo->ouraddr, wo->hisaddr,
                       wo->replace_default_route);
      if (go->ouraddr != wo->ouraddr) {
        ppp_warn(("Local IP address changed to %I", go->ouraddr));
        script_setenv("OLDIPLOCAL", ip_ntoa(wo->ouraddr), 0);
        wo->ouraddr = go->ouraddr;
      } else
        script_unsetenv("OLDIPLOCAL");
      if (ho->hisaddr != wo->hisaddr && wo->hisaddr != 0) {
        ppp_warn(("Remote IP address changed to %I", ho->hisaddr));
        script_setenv("OLDIPREMOTE", ip_ntoa(wo->hisaddr), 0);
        wo->hisaddr = ho->hisaddr;
      } else
        script_unsetenv("OLDIPREMOTE");

      /* Set the interface to the new addresses */
      mask = get_mask(go->ouraddr);
      if (!sifaddr(pcb, go->ouraddr, ho->hisaddr, mask)) {
#if PPP_DEBUG
        ppp_warn(("Interface configuration failed"));
#endif /* PPP_DEBUG */
        ipcp_close(f->unit, "Interface configuration failed");
        return;
      }

      /* assign a default route through the interface if required */
      if (ipcp_wantoptions[f->unit].default_route)
        if (sifdefaultroute(pcb, go->ouraddr, ho->hisaddr,
                            wo->replace_default_route))
          default_route_set[f->unit] = 1;

#if 0  /* UNUSED - PROXY ARP */
	    /* Make a proxy ARP entry if requested. */
	    if (ho->hisaddr != 0 && ipcp_wantoptions[f->unit].proxy_arp)
		if (sifproxyarp(pcb, ho->hisaddr))
		    proxy_arp_set[f->unit] = 1;
#endif /* UNUSED - PROXY ARP */
    }
    demand_rexmit(PPP_IP, go->ouraddr);
    sifnpmode(pcb, PPP_IP, NPMODE_PASS);

  } else
#endif /* DEMAND_SUPPORT */
  {
    /*
     * Set IP addresses and (if specified) netmask.
     */
    mask = get_mask(go->ouraddr);

#if !(defined(SVR4) && (defined(SNI) || defined(__USLC__)))
    if (!sifaddr(pcb, go->ouraddr, ho->hisaddr, mask)) {
#if PPP_DEBUG
      ppp_warn(("Interface configuration failed"));
#endif /* PPP_DEBUG */
      ipcp_close(f->pcb, "Interface configuration failed");
      return;
    }
#endif

    /* bring the interface up for IP */
    if (!sifup(pcb)) {
#if PPP_DEBUG
      ppp_warn(("Interface failed to come up"));
#endif /* PPP_DEBUG */
      ipcp_close(f->pcb, "Interface configuration failed");
      return;
    }

#if (defined(SVR4) && (defined(SNI) || defined(__USLC__)))
    if (!sifaddr(pcb, go->ouraddr, ho->hisaddr, mask)) {
#if PPP_DEBUG
      ppp_warn(("Interface configuration failed"));
#endif /* PPP_DEBUG */
      ipcp_close(f->unit, "Interface configuration failed");
      return;
    }
#endif
#if DEMAND_SUPPORT
    sifnpmode(pcb, PPP_IP, NPMODE_PASS);
#endif /* DEMAND_SUPPORT */

#if 0  /* UNUSED */
	/* assign a default route through the interface if required */
	if (wo->default_route)
	    if (sifdefaultroute(pcb, go->ouraddr, ho->hisaddr,
		    wo->replace_default_route))
		    pcb->default_route_set = 1;
#endif /* UNUSED */

#if 0  /* UNUSED - PROXY ARP */
	/* Make a proxy ARP entry if requested. */
	if (ho->hisaddr != 0 && wo->proxy_arp)
	    if (sifproxyarp(pcb, ho->hisaddr))
		pcb->proxy_arp_set = 1;
#endif /* UNUSED - PROXY ARP */

    wo->ouraddr = go->ouraddr;

    ppp_notice(("local  IP address %I", go->ouraddr));
    if (ho->hisaddr != 0)
      ppp_notice(("remote IP address %I", ho->hisaddr));
#if LWIP_DNS
    if (go->dnsaddr[0])
      ppp_notice(("primary   DNS address %I", go->dnsaddr[0]));
    if (go->dnsaddr[1])
      ppp_notice(("secondary DNS address %I", go->dnsaddr[1]));
#endif /* LWIP_DNS */
  }

#if PPP_STATS_SUPPORT
  reset_link_stats(f->unit);
#endif /* PPP_STATS_SUPPORT */

  np_up(pcb, PPP_IP);
  pcb->ipcp_is_up = 1;

#if PPP_NOTIFY
  notify(ip_up_notifier, 0);
#endif /* PPP_NOTIFY */
#if 0  /* UNUSED */
    if (ip_up_hook)
	ip_up_hook();
#endif /* UNUSED */
}

static void ipcp_down(fsm *f) {
  ppp_pcb *pcb = f->pcb;
  ipcp_options *ho = &pcb->ipcp_hisoptions;
  ipcp_options *go = &pcb->ipcp_gotoptions;

  IPCPDEBUG(("ipcp: down"));
#if PPP_STATS_SUPPORT
  /* XXX a bit IPv4-centric here, we only need to get the stats
   * before the interface is marked down. */
  /* XXX more correct: we must get the stats before running the notifiers,
   * at least for the radius plugin */
  update_link_stats(f->unit);
#endif /* PPP_STATS_SUPPORT */
#if PPP_NOTIFY
  notify(ip_down_notifier, 0);
#endif /* PPP_NOTIFY */
#if 0  /* UNUSED */
    if (ip_down_hook)
	ip_down_hook();
#endif /* UNUSED */
  if (pcb->ipcp_is_up) {
    pcb->ipcp_is_up = 0;
    np_down(pcb, PPP_IP);
  }
#if VJ_SUPPORT
  sifvjcomp(pcb, 0, 0, 0);
#endif /* VJ_SUPPORT */

#if PPP_STATS_SUPPORT
  print_link_stats(); /* _after_ running the notifiers and ip_down_hook(),
                       * because print_link_stats() sets link_stats_valid
                       * to 0 (zero) */
#endif                /* PPP_STATS_SUPPORT */

#if DEMAND_SUPPORT
  /*
   * If we are doing dial-on-demand, set the interface
   * to queue up outgoing packets (for now).
   */
  if (demand) {
    sifnpmode(pcb, PPP_IP, NPMODE_QUEUE);
  } else
#endif /* DEMAND_SUPPORT */
  {
#if DEMAND_SUPPORT
    sifnpmode(pcb, PPP_IP, NPMODE_DROP);
#endif /* DEMAND_SUPPORT */
    sifdown(pcb);
    ipcp_clear_addrs(pcb, go->ouraddr, ho->hisaddr, 0);
#if LWIP_DNS
    cdns(pcb, go->dnsaddr[0], go->dnsaddr[1]);
#endif /* LWIP_DNS */
  }
}

static void ipcp_clear_addrs(ppp_pcb *pcb, u32_t ouraddr, u32_t hisaddr,
                             u8_t replacedefaultroute) {
  LWIP_UNUSED_ARG(replacedefaultroute);

#if 0  /* UNUSED - PROXY ARP */
    if (pcb->proxy_arp_set) {
	cifproxyarp(pcb, hisaddr);
	pcb->proxy_arp_set = 0;
    }
#endif /* UNUSED - PROXY ARP */
#if 0  /* UNUSED */
    /* If replacedefaultroute, sifdefaultroute will be called soon
     * with replacedefaultroute set and that will overwrite the current
     * default route. This is the case only when doing demand, otherwise
     * during demand, this cifdefaultroute would restore the old default
     * route which is not what we want in this case. In the non-demand
     * case, we'll delete the default route and restore the old if there
     * is one saved by an sifdefaultroute with replacedefaultroute.
     */
    if (!replacedefaultroute && pcb->default_route_set) {
	cifdefaultroute(pcb, ouraddr, hisaddr);
	pcb->default_route_set = 0;
    }
#endif /* UNUSED */
  cifaddr(pcb, ouraddr, hisaddr);
}

