static int ipcp_printpkt(const u_char *p, int plen,
                         void (*printer)(void *, const char *, ...),
                         void *arg) {
  int code, id, len, olen;
  const u_char *pstart, *optend;
#if VJ_SUPPORT
  u_short cishort;
#endif /* VJ_SUPPORT */
  u32_t cilong;

  if (plen < HEADERLEN)
    return 0;
  pstart = p;
  GETCHAR(code, p);
  GETCHAR(id, p);
  GETSHORT(len, p);
  if (len < HEADERLEN || len > plen)
    return 0;

  if (code >= 1 && code <= (int)LWIP_ARRAYSIZE(ipcp_codenames))
    printer(arg, " %s", ipcp_codenames[code - 1]);
  else
    printer(arg, " code=0x%x", code);
  printer(arg, " id=0x%x", id);
  len -= HEADERLEN;
  switch (code) {
  case CONFREQ:
  case CONFACK:
  case CONFNAK:
  case CONFREJ:
    /* print option list */
    while (len >= 2) {
      GETCHAR(code, p);
      GETCHAR(olen, p);
      p -= 2;
      if (olen < 2 || olen > len) {
        break;
      }
      printer(arg, " <");
      len -= olen;
      optend = p + olen;
      switch (code) {
      case CI_ADDRS:
        if (olen == CILEN_ADDRS) {
          p += 2;
          GETLONG(cilong, p);
          printer(arg, "addrs %I", lwip_htonl(cilong));
          GETLONG(cilong, p);
          printer(arg, " %I", lwip_htonl(cilong));
        }
        break;
#if VJ_SUPPORT
      case CI_COMPRESSTYPE:
        if (olen >= CILEN_COMPRESS) {
          p += 2;
          GETSHORT(cishort, p);
          printer(arg, "compress ");
          switch (cishort) {
          case IPCP_VJ_COMP:
            printer(arg, "VJ");
            break;
          case IPCP_VJ_COMP_OLD:
            printer(arg, "old-VJ");
            break;
          default:
            printer(arg, "0x%x", cishort);
          }
        }
        break;
#endif /* VJ_SUPPORT */
      case CI_ADDR:
        if (olen == CILEN_ADDR) {
          p += 2;
          GETLONG(cilong, p);
          printer(arg, "addr %I", lwip_htonl(cilong));
        }
        break;
#if LWIP_DNS
      case CI_MS_DNS1:
      case CI_MS_DNS2:
        p += 2;
        GETLONG(cilong, p);
        printer(arg, "ms-dns%d %I", (code == CI_MS_DNS1 ? 1 : 2),
                htonl(cilong));
        break;
#endif /* LWIP_DNS */
#if 0  /* UNUSED - WINS */
	    case CI_MS_WINS1:
	    case CI_MS_WINS2:
	        p += 2;
		GETLONG(cilong, p);
		printer(arg, "ms-wins %I", lwip_htonl(cilong));
		break;
#endif /* UNUSED - WINS */
      default:
        break;
      }
      while (p < optend) {
        GETCHAR(code, p);
        printer(arg, " %.2x", code);
      }
      printer(arg, ">");
    }
    break;

  case TERMACK:
  case TERMREQ:
    if (len > 0 && *p >= ' ' && *p < 0x7f) {
      printer(arg, " ");
      ppp_print_string(p, len, printer, arg);
      p += len;
      len = 0;
    }
    break;
  default:
    break;
  }

  /* print the rest of the bytes in the packet */
  for (; len > 0; --len) {
    GETCHAR(code, p);
    printer(arg, " %.2x", code);
  }

  return p - pstart;
}

static int ip_active_pkt(pkt, len)
u_char *pkt;
int len;
{
  u_char *tcp;
  int hlen;

  len -= PPP_HDRLEN;
  pkt += PPP_HDRLEN;
  if (len < IP_HDRLEN)
    return 0;
  if ((get_ipoff(pkt) & IP_OFFMASK) != 0)
    return 0;
  if (get_ipproto(pkt) != IPPROTO_TCP)
    return 1;
  hlen = get_iphl(pkt) * 4;
  if (len < hlen + TCP_HDRLEN)
    return 0;
  tcp = pkt + hlen;
  if ((get_tcpflags(tcp) & TH_FIN) != 0 && len == hlen + get_tcpoff(tcp) * 4)
    return 0;
  return 1;
}

static int setifaceid(argv)
char **argv;
{
  char *comma, *arg, c;
  ipv6cp_options *wo = &ipv6cp_wantoptions[0];
  struct in6_addr addr;
  static int prio_local, prio_remote;

#define VALIDID(a)                                                             \
  ((((a).s6_addr32[0] == 0) && ((a).s6_addr32[1] == 0)) &&                     \
   (((a).s6_addr32[2] != 0) || ((a).s6_addr32[3] != 0)))

  arg = *argv;
  if ((comma = strchr(arg, ',')) == NULL)
    comma = arg + strlen(arg);

  /*
   * If comma first character, then no local identifier
   */
  if (comma != arg) {
    c = *comma;
    *comma = '\0';

    if (inet_pton(AF_INET6, arg, &addr) == 0 || !VALIDID(addr)) {
      option_error("Illegal interface identifier (local): %s", arg);
      return 0;
    }

    if (option_priority >= prio_local) {
      eui64_copy(addr.s6_addr32[2], wo->ourid);
      wo->opt_local = 1;
      prio_local = option_priority;
    }
    *comma = c;
  }

  /*
   * If comma last character, the no remote identifier
   */
  if (*comma != 0 && *++comma != '\0') {
    if (inet_pton(AF_INET6, comma, &addr) == 0 || !VALIDID(addr)) {
      option_error("Illegal interface identifier (remote): %s", comma);
      return 0;
    }
    if (option_priority >= prio_remote) {
      eui64_copy(addr.s6_addr32[2], wo->hisid);
      wo->opt_remote = 1;
      prio_remote = option_priority;
    }
  }

  if (override_value("+ipv6", option_priority, option_source))
    ipv6cp_protent.enabled_flag = 1;
  return 1;
}

static void printifaceid(opt, printer, arg) option_t *opt;
    void (*printer)(void *, char *, ...));
    void *arg;
    {
      ipv6cp_options *wo = &ipv6cp_wantoptions[0];

      if (wo->opt_local)
        printer(arg, "%s", llv6_ntoa(wo->ourid));
      printer(arg, ",");
      if (wo->opt_remote)
        printer(arg, "%s", llv6_ntoa(wo->hisid));
    }

static char *llv6_ntoa(eui64_t ifaceid) {
      static char b[26];

      sprintf(b, "fe80::%02x%02x:%02x%02x:%02x%02x:%02x%02x", ifaceid.e8[0],
              ifaceid.e8[1], ifaceid.e8[2], ifaceid.e8[3], ifaceid.e8[4],
              ifaceid.e8[5], ifaceid.e8[6], ifaceid.e8[7]);

      return b;
    }

