      f->pcb = pcb;
      f->protocol = PPP_IPV6CP;
      f->callbacks = &ipv6cp_callbacks;
      fsm_init(f);

#if 0  /* Not necessary, everything is cleared in ppp_new() */
    memset(wo, 0, sizeof(*wo));
    memset(ao, 0, sizeof(*ao));
#endif /* 0 */

      wo->accept_local = 1;
      wo->neg_ifaceid = 1;
      ao->neg_ifaceid = 1;

#ifdef IPV6CP_COMP
      wo->neg_vj = 1;
