static void ipv6cp_resetci(fsm *f) {
      ppp_pcb *pcb = f->pcb;
      ipv6cp_options *wo = &pcb->ipv6cp_wantoptions;
      ipv6cp_options *go = &pcb->ipv6cp_gotoptions;
      ipv6cp_options *ao = &pcb->ipv6cp_allowoptions;

      wo->req_ifaceid = wo->neg_ifaceid && ao->neg_ifaceid;

      if (!wo->opt_local) {
        eui64_magic_nz(wo->ourid);
      }

      *go = *wo;
      eui64_zero(go->hisid); /* last proposed interface identifier */
    }

static int ipv6cp_cilen(fsm *f) {
      ppp_pcb *pcb = f->pcb;
      ipv6cp_options *go = &pcb->ipv6cp_gotoptions;

#ifdef IPV6CP_COMP
#define LENCIVJ(neg) (neg ? CILEN_COMPRESS : 0)
#endif /* IPV6CP_COMP */
#define LENCIIFACEID(neg) (neg ? CILEN_IFACEID : 0)

      return (LENCIIFACEID(go->neg_ifaceid) +
#ifdef IPV6CP_COMP
              LENCIVJ(go->neg_vj) +
#endif /* IPV6CP_COMP */
              0);
    }

static void ipv6cp_addci(fsm *f, u_char *ucp, int *lenp) {
      ppp_pcb *pcb = f->pcb;
      ipv6cp_options *go = &pcb->ipv6cp_gotoptions;
      int len = *lenp;

#ifdef IPV6CP_COMP
#define ADDCIVJ(opt, neg, val)                                             \
      if (neg) {                                                               \
        int vjlen = CILEN_COMPRESS;                                            \
        if (len >= vjlen) {                                                    \
          PUTCHAR(opt, ucp);                                                   \
          PUTCHAR(vjlen, ucp);                                                 \
          PUTSHORT(val, ucp);                                                  \
          len -= vjlen;                                                        \
        } else                                                                 \
          neg = 0;                                                             \
      }
#endif /* IPV6CP_COMP */

#define ADDCIIFACEID(opt, neg, val1)                                       \
      if (neg) {                                                               \
        int idlen = CILEN_IFACEID;                                             \
        if (len >= idlen) {                                                    \
          PUTCHAR(opt, ucp);                                                   \
          PUTCHAR(idlen, ucp);                                                 \
          eui64_put(val1, ucp);                                                \
          len -= idlen;                                                        \
        } else                                                                 \
          neg = 0;                                                             \
      }

      ADDCIIFACEID(CI_IFACEID, go->neg_ifaceid, go->ourid);

#ifdef IPV6CP_COMP
      ADDCIVJ(CI_COMPRESSTYPE, go->neg_vj, go->vj_protocol);
#endif /* IPV6CP_COMP */

      *lenp -= len;
    }

static int ipv6cp_ackci(fsm *f, u_char *p, int len) {
      ppp_pcb *pcb = f->pcb;
      ipv6cp_options *go = &pcb->ipv6cp_gotoptions;
      u_short cilen, citype;
#ifdef IPV6CP_COMP
      u_short cishort;
#endif /* IPV6CP_COMP */
      eui64_t ifaceid;

      /*
       * CIs must be in exactly the same order that we sent...
       * Check packet length and CI length at each step.
       * If we find any deviations, then this packet is bad.
       */

#ifdef IPV6CP_COMP
#define ACKCIVJ(opt, neg, val)                                             \
      if (neg) {                                                               \
        int vjlen = CILEN_COMPRESS;                                            \
        if ((len -= vjlen) < 0)                                                \
          goto bad;                                                            \
        GETCHAR(citype, p);                                                    \
        GETCHAR(cilen, p);                                                     \
        if (cilen != vjlen || citype != opt)                                   \
          goto bad;                                                            \
        GETSHORT(cishort, p);                                                  \
        if (cishort != val)                                                    \
          goto bad;                                                            \
      }
#endif /* IPV6CP_COMP */

#define ACKCIIFACEID(opt, neg, val1)                                       \
      if (neg) {                                                               \
        int idlen = CILEN_IFACEID;                                             \
        if ((len -= idlen) < 0)                                                \
          goto bad;                                                            \
        GETCHAR(citype, p);                                                    \
        GETCHAR(cilen, p);                                                     \
        if (cilen != idlen || citype != opt)                                   \
          goto bad;                                                            \
        eui64_get(ifaceid, p);                                                 \
        if (!eui64_equals(val1, ifaceid))                                      \
          goto bad;                                                            \
      }

      ACKCIIFACEID(CI_IFACEID, go->neg_ifaceid, go->ourid);

#ifdef IPV6CP_COMP
      ACKCIVJ(CI_COMPRESSTYPE, go->neg_vj, go->vj_protocol);
#endif /* IPV6CP_COMP */

      /*
       * If there are any remaining CIs, then this packet is bad.
       */
      if (len != 0)
        goto bad;
      return (1);

    bad:
      IPV6CPDEBUG(("ipv6cp_ackci: received bad Ack!"));
      return (0);
    }

static int ipv6cp_nakci(fsm *f, u_char *p, int len, int treat_as_reject) {
      ppp_pcb *pcb = f->pcb;
      ipv6cp_options *go = &pcb->ipv6cp_gotoptions;
      u_char citype, cilen, *next;
#ifdef IPV6CP_COMP
      u_short cishort;
#endif /* IPV6CP_COMP */
      eui64_t ifaceid;
      ipv6cp_options no;   /* options we've seen Naks for */
      ipv6cp_options try_; /* options to request next time */

      BZERO(&no, sizeof(no));
      try_ = *go;

      /*
       * Any Nak'd CIs must be in exactly the same order that we sent.
       * Check packet length and CI length at each step.
       * If we find any deviations, then this packet is bad.
       */
#define NAKCIIFACEID(opt, neg, code)                                       \
      if (go->neg && len >= (cilen = CILEN_IFACEID) && p[1] == cilen &&        \
          p[0] == opt) {                                                       \
        len -= cilen;                                                          \
        INCPTR(2, p);                                                          \
        eui64_get(ifaceid, p);                                                 \
        no.neg = 1;                                                            \
        code                                                                   \
      }

#ifdef IPV6CP_COMP
#define NAKCIVJ(opt, neg, code)                                            \
      if (go->neg && ((cilen = p[1]) == CILEN_COMPRESS) && len >= cilen &&     \
          p[0] == opt) {                                                       \
        len -= cilen;                                                          \
        INCPTR(2, p);                                                          \
        GETSHORT(cishort, p);                                                  \
        no.neg = 1;                                                            \
        code                                                                   \
      }
#endif /* IPV6CP_COMP */

      /*
       * Accept the peer's idea of {our,his} interface identifier, if different
       * from our idea, only if the accept_{local,remote} flag is set.
       */
      NAKCIIFACEID(
          CI_IFACEID, neg_ifaceid,
          if (treat_as_reject) {
            try_.neg_ifaceid = 0;
          } else if (go->accept_local) {
            while (eui64_iszero(ifaceid) ||
                   eui64_equals(ifaceid, go->hisid)) /* bad luck */
              eui64_magic(ifaceid);
            try_.ourid = ifaceid;
            IPV6CPDEBUG(("local LL address %s", llv6_ntoa(ifaceid)));
          });

#ifdef IPV6CP_COMP
      NAKCIVJ(CI_COMPRESSTYPE, neg_vj, {
        if (cishort == IPV6CP_COMP && !treat_as_reject) {
          try_.vj_protocol = cishort;
        } else {
          try_.neg_vj = 0;
        }
      });
#endif /* IPV6CP_COMP */

      /*
       * There may be remaining CIs, if the peer is requesting negotiation
       * on an option that we didn't include in our request packet.
       * If they want to negotiate about interface identifier, we comply.
       * If they want us to ask for compression, we refuse.
       */
      while (len >= CILEN_VOID) {
        GETCHAR(citype, p);
        GETCHAR(cilen, p);
        if (cilen < CILEN_VOID || (len -= cilen) < 0)
          goto bad;
        next = p + cilen - 2;

        switch (citype) {
#ifdef IPV6CP_COMP
        case CI_COMPRESSTYPE:
          if (go->neg_vj || no.neg_vj || (cilen != CILEN_COMPRESS))
            goto bad;
          no.neg_vj = 1;
          break;
#endif /* IPV6CP_COMP */
        case CI_IFACEID:
          if (go->neg_ifaceid || no.neg_ifaceid || cilen != CILEN_IFACEID)
            goto bad;
          try_.neg_ifaceid = 1;
          eui64_get(ifaceid, p);
          if (go->accept_local) {
            while (eui64_iszero(ifaceid) ||
                   eui64_equals(ifaceid, go->hisid)) /* bad luck */
              eui64_magic(ifaceid);
            try_.ourid = ifaceid;
          }
          no.neg_ifaceid = 1;
          break;
        default:
          break;
        }
        p = next;
      }

      /* If there is still anything left, this packet is bad. */
      if (len != 0)
        goto bad;

      /*
       * OK, the Nak is good.  Now we can update state.
       */
      if (f->state != PPP_FSM_OPENED)
        *go = try_;

      return 1;

    bad:
      IPV6CPDEBUG(("ipv6cp_nakci: received bad Nak!"));
      return 0;
    }

static int ipv6cp_rejci(fsm *f, u_char *p, int len) {
      ppp_pcb *pcb = f->pcb;
      ipv6cp_options *go = &pcb->ipv6cp_gotoptions;
      u_char cilen;
#ifdef IPV6CP_COMP
      u_short cishort;
#endif /* IPV6CP_COMP */
      eui64_t ifaceid;
      ipv6cp_options try_; /* options to request next time */

      try_ = *go;
      /*
       * Any Rejected CIs must be in exactly the same order that we sent.
       * Check packet length and CI length at each step.
       * If we find any deviations, then this packet is bad.
       */
#define REJCIIFACEID(opt, neg, val1)                                       \
      if (go->neg && len >= (cilen = CILEN_IFACEID) && p[1] == cilen &&        \
          p[0] == opt) {                                                       \
        len -= cilen;                                                          \
        INCPTR(2, p);                                                          \
        eui64_get(ifaceid, p);                                                 \
        /* Check rejected value. */                                            \
        if (!eui64_equals(ifaceid, val1))                                      \
          goto bad;                                                            \
        try_.neg = 0;                                                          \
      }

static int ipv6cp_reqci(fsm *f, u_char *inp, int *len,
                            int reject_if_disagree) {
      ppp_pcb *pcb = f->pcb;
      ipv6cp_options *wo = &pcb->ipv6cp_wantoptions;
      ipv6cp_options *ho = &pcb->ipv6cp_hisoptions;
      ipv6cp_options *ao = &pcb->ipv6cp_allowoptions;
      ipv6cp_options *go = &pcb->ipv6cp_gotoptions;
      u_char *cip, *next;    /* Pointer to current and next CIs */
      u_short cilen, citype; /* Parsed len, type */
#ifdef IPV6CP_COMP
      u_short cishort;   /* Parsed short value */
#endif               /* IPV6CP_COMP */
      eui64_t ifaceid;   /* Parsed interface identifier */
      int rc = CONFACK;  /* Final packet return code */
      int orc;           /* Individual option return code */
      u_char *p;         /* Pointer to next char to parse */
      u_char *ucp = inp; /* Pointer to current output char */
      int l = *len;      /* Length left */

      /*
       * Reset all his options.
       */
      BZERO(ho, sizeof(*ho));

      /*
       * Process all his options.
       */
      next = inp;
      while (l) {
        orc = CONFACK;  /* Assume success */
        cip = p = next; /* Remember beginning of CI */
        if (l < 2 ||    /* Not enough data for CI header or */
            p[1] < 2 || /*  CI length too small or */
            p[1] > l) { /*  CI length too big? */
          IPV6CPDEBUG(("ipv6cp_reqci: bad CI length!"));
          orc = CONFREJ; /* Reject bad CI */
          cilen = l;     /* Reject till end of packet */
          l = 0;         /* Don't loop again */
          goto endswitch;
        }
        GETCHAR(citype, p); /* Parse CI type */
        GETCHAR(cilen, p);  /* Parse CI length */
        l -= cilen;         /* Adjust remaining length */
        next += cilen;      /* Step to next CI */

        switch (citype) { /* Check CI type */
        case CI_IFACEID:
          IPV6CPDEBUG(("ipv6cp: received interface identifier "));

          if (!ao->neg_ifaceid ||
              cilen != CILEN_IFACEID) { /* Check CI length */
            orc = CONFREJ;              /* Reject CI */
            break;
          }

          /*
           * If he has no interface identifier, or if we both have same
           * identifier then NAK it with new idea.
           * In particular, if we don't know his identifier, but he does,
           * then accept it.
           */
          eui64_get(ifaceid, p);
          IPV6CPDEBUG(("(%s)", llv6_ntoa(ifaceid)));
          if (eui64_iszero(ifaceid) && eui64_iszero(go->ourid)) {
            orc = CONFREJ; /* Reject CI */
            break;
          }
          if (!eui64_iszero(wo->hisid) && !eui64_equals(ifaceid, wo->hisid) &&
              eui64_iszero(go->hisid)) {

            orc = CONFNAK;
            ifaceid = wo->hisid;
            go->hisid = ifaceid;
            DECPTR(sizeof(ifaceid), p);
            eui64_put(ifaceid, p);
          } else if (eui64_iszero(ifaceid) ||
                     eui64_equals(ifaceid, go->ourid)) {
            orc = CONFNAK;
            if (eui64_iszero(go->hisid)) /* first time, try option */
              ifaceid = wo->hisid;
            while (eui64_iszero(ifaceid) ||
                   eui64_equals(ifaceid, go->ourid)) /* bad luck */
              eui64_magic(ifaceid);
            go->hisid = ifaceid;
            DECPTR(sizeof(ifaceid), p);
            eui64_put(ifaceid, p);
          }

          ho->neg_ifaceid = 1;
          ho->hisid = ifaceid;
          break;

#ifdef IPV6CP_COMP
        case CI_COMPRESSTYPE:
          IPV6CPDEBUG(("ipv6cp: received COMPRESSTYPE "));
          if (!ao->neg_vj || (cilen != CILEN_COMPRESS)) {
            orc = CONFREJ;
            break;
          }
          GETSHORT(cishort, p);
          IPV6CPDEBUG(("(%d)", cishort));

          if (!(cishort == IPV6CP_COMP)) {
            orc = CONFREJ;
            break;
          }

          ho->neg_vj = 1;
          ho->vj_protocol = cishort;
          break;
#endif /* IPV6CP_COMP */

        default:
          orc = CONFREJ;
          break;
        }

      endswitch:
        IPV6CPDEBUG((" (%s)\n", CODENAME(orc)));

        if (orc == CONFACK && /* Good CI */
            rc != CONFACK)    /*  but prior CI wasn't? */
          continue;           /* Don't send this one */

        if (orc == CONFNAK) {     /* Nak this CI? */
          if (reject_if_disagree) /* Getting fed up with sending NAKs? */
            orc = CONFREJ;        /* Get tough if so */
          else {
            if (rc == CONFREJ)   /* Rejecting prior CI? */
              continue;          /* Don't send this one */
            if (rc == CONFACK) { /* Ack'd all prior CIs? */
              rc = CONFNAK;      /* Not anymore... */
              ucp = inp;         /* Backup */
            }
          }
        }

        if (orc == CONFREJ && /* Reject this CI */
            rc != CONFREJ) {  /*  but no prior ones? */
          rc = CONFREJ;
          ucp = inp; /* Backup */
        }

        /* Need to move CI? */
        if (ucp != cip)
          MEMCPY(ucp, cip, cilen); /* Move it */

        /* Update output pointer */
        INCPTR(cilen, ucp);
      }

      /*
       * If we aren't rejecting this packet, and we want to negotiate
       * their identifier and they didn't send their identifier, then we
       * send a NAK with a CI_IFACEID option appended.  We assume the
       * input buffer is long enough that we can append the extra
       * option safely.
       */
      if (rc != CONFREJ && !ho->neg_ifaceid && wo->req_ifaceid &&
          !reject_if_disagree) {
        if (rc == CONFACK) {
          rc = CONFNAK;
          ucp = inp;           /* reset pointer */
          wo->req_ifaceid = 0; /* don't ask again */
        }
        PUTCHAR(CI_IFACEID, ucp);
        PUTCHAR(CILEN_IFACEID, ucp);
        eui64_put(wo->hisid, ucp);
      }

      *len = ucp - inp; /* Compute output length */
      IPV6CPDEBUG(("ipv6cp: returning Configure-%s", CODENAME(rc)));
      return (rc); /* Return final code */
    }

static void ipv6_check_options() {
      ipv6cp_options *wo = &ipv6cp_wantoptions[0];

      if (!ipv6cp_protent.enabled_flag)
        return;

      /*
       * Persistent link-local id is only used when user has not explicitly
       * configure/hard-code the id
       */
      if ((wo->use_persistent) && (!wo->opt_local) && (!wo->opt_remote)) {

        /*
         * On systems where there are no Ethernet interfaces used, there
         * may be other ways to obtain a persistent id. Right now, it
         * will fall back to using magic [see eui64_magic] below when
         * an EUI-48 from MAC address can't be obtained. Other possibilities
         * include obtaining EEPROM serial numbers, or some other unique
         * yet persistent number. On Sparc platforms, this is possible,
         * but too bad there's no standards yet for x86 machines.
         */
        if (ether_to_eui64(&wo->ourid)) {
          wo->opt_local = 1;
        }
      }

      if (!wo->opt_local) { /* init interface identifier */
        if (wo->use_ip && eui64_iszero(wo->ourid)) {
          eui64_setlo32(wo->ourid, lwip_ntohl(ipcp_wantoptions[0].ouraddr));
          if (!eui64_iszero(wo->ourid))
            wo->opt_local = 1;
        }

        while (eui64_iszero(wo->ourid))
          eui64_magic(wo->ourid);
      }

      if (!wo->opt_remote) {
        if (wo->use_ip && eui64_iszero(wo->hisid)) {
          eui64_setlo32(wo->hisid, lwip_ntohl(ipcp_wantoptions[0].hisaddr));
          if (!eui64_iszero(wo->hisid))
            wo->opt_remote = 1;
        }
      }

      if (demand && (eui64_iszero(wo->ourid) || eui64_iszero(wo->hisid))) {
        option_error("local/remote LL address required for demand-dialling\n");
        exit(1);
      }
    }

static int ipv6_demand_conf(int u) {
      ipv6cp_options *wo = &ipv6cp_wantoptions[u];

      if (!sif6up(u))
        return 0;

      if (!sif6addr(u, wo->ourid, wo->hisid))
        return 0;

      if (!sifnpmode(u, PPP_IPV6, NPMODE_QUEUE))
        return 0;

      ppp_notice(("ipv6_demand_conf"));
      ppp_notice(("local  LL address %s", llv6_ntoa(wo->ourid)));
      ppp_notice(("remote LL address %s", llv6_ntoa(wo->hisid)));

      return 1;
    }

static void ipv6cp_down(fsm *f) {
      ppp_pcb *pcb = f->pcb;
      ipv6cp_options *go = &pcb->ipv6cp_gotoptions;
      ipv6cp_options *ho = &pcb->ipv6cp_hisoptions;

      IPV6CPDEBUG(("ipv6cp: down"));
#if PPP_STATS_SUPPORT
      update_link_stats(f->unit);
#endif /* PPP_STATS_SUPPORT */
      if (pcb->ipv6cp_is_up) {
        pcb->ipv6cp_is_up = 0;
        np_down(f->pcb, PPP_IPV6);
      }
#ifdef IPV6CP_COMP
      sif6comp(f->unit, 0);
#endif

#if DEMAND_SUPPORT
      /*
       * If we are doing dial-on-demand, set the interface
       * to queue up outgoing packets (for now).
       */
      if (demand) {
        sifnpmode(f->pcb, PPP_IPV6, NPMODE_QUEUE);
      } else
#endif /* DEMAND_SUPPORT */
      {
#if DEMAND_SUPPORT
        sifnpmode(f->pcb, PPP_IPV6, NPMODE_DROP);
#endif /* DEMAND_SUPPORT */
        ipv6cp_clear_addrs(f->pcb, go->ourid, ho->hisid);
        sif6down(f->pcb);
      }

#if 0  /* UNUSED */
    /* Execute the ipv6-down script */
    if (ipv6cp_script_state == s_up && ipv6cp_script_pid == 0) {
	ipv6cp_script_state = s_down;
	ipv6cp_script(_PATH_IPV6DOWN);
    }
#endif /* UNUSED */
    }

static void ipv6cp_clear_addrs(ppp_pcb *pcb, eui64_t ourid, eui64_t hisid) {
      cif6addr(pcb, ourid, hisid);
    }

static void
ipv6cp_script_done(arg)
    void *arg;
{
    ipv6cp_script_pid = 0;
    switch (ipv6cp_script_state) {
    case s_up:
	if (ipv6cp_fsm[0].state != PPP_FSM_OPENED) {
	    ipv6cp_script_state = s_down;
	    ipv6cp_script(_PATH_IPV6DOWN);
	}
	break;
    case s_down:
	if (ipv6cp_fsm[0].state == PPP_FSM_OPENED) {
	    ipv6cp_script_state = s_up;
	    ipv6cp_script(_PATH_IPV6UP);
	}
	break;
    }
}

static void
ipv6cp_script(script)
    char *script;
{
    char strspeed[32], strlocal[32], strremote[32];
    char *argv[8];

    sprintf(strspeed, "%d", baud_rate);
    strcpy(strlocal, llv6_ntoa(ipv6cp_gotoptions[0].ourid));
    strcpy(strremote, llv6_ntoa(ipv6cp_hisoptions[0].hisid));

    argv[0] = script;
    argv[1] = ifname;
    argv[2] = devnam;
    argv[3] = strspeed;
    argv[4] = strlocal;
    argv[5] = strremote;
    argv[6] = ipparam;
    argv[7] = NULL;

    ipv6cp_script_pid = run_program(script, argv, 0, ipv6cp_script_done,
				    NULL, 0);
}

static int ipv6cp_printpkt(const u_char *p, int plen,
                               void (*printer)(void *, const char *, ...),
                               void *arg) {
      int code, id, len, olen;
      const u_char *pstart, *optend;
#ifdef IPV6CP_COMP
      u_short cishort;
#endif /* IPV6CP_COMP */
      eui64_t ifaceid;

      if (plen < HEADERLEN)
        return 0;
      pstart = p;
      GETCHAR(code, p);
      GETCHAR(id, p);
      GETSHORT(len, p);
      if (len < HEADERLEN || len > plen)
        return 0;

      if (code >= 1 && code <= (int)LWIP_ARRAYSIZE(ipv6cp_codenames))
        printer(arg, " %s", ipv6cp_codenames[code - 1]);
      else
        printer(arg, " code=0x%x", code);
      printer(arg, " id=0x%x", id);
      len -= HEADERLEN;
      switch (code) {
      case CONFREQ:
      case CONFACK:
      case CONFNAK:
      case CONFREJ:
        /* print option list */
        while (len >= 2) {
          GETCHAR(code, p);
          GETCHAR(olen, p);
          p -= 2;
          if (olen < 2 || olen > len) {
            break;
          }
          printer(arg, " <");
          len -= olen;
          optend = p + olen;
          switch (code) {
#ifdef IPV6CP_COMP
          case CI_COMPRESSTYPE:
            if (olen >= CILEN_COMPRESS) {
              p += 2;
              GETSHORT(cishort, p);
              printer(arg, "compress ");
              printer(arg, "0x%x", cishort);
            }
            break;
#endif /* IPV6CP_COMP */
          case CI_IFACEID:
            if (olen == CILEN_IFACEID) {
              p += 2;
              eui64_get(ifaceid, p);
              printer(arg, "addr %s", llv6_ntoa(ifaceid));
            }
            break;
          default:
            break;
          }
          while (p < optend) {
            GETCHAR(code, p);
            printer(arg, " %.2x", code);
          }
          printer(arg, ">");
        }
        break;

      case TERMACK:
      case TERMREQ:
        if (len > 0 && *p >= ' ' && *p < 0x7f) {
          printer(arg, " ");
          ppp_print_string(p, len, printer, arg);
          p += len;
          len = 0;
        }
        break;
      default:
        break;
      }

      /* print the rest of the bytes in the packet */
      for (; len > 0; --len) {
        GETCHAR(code, p);
        printer(arg, " %.2x", code);
      }

      return p - pstart;
    }

static int ipv6_active_pkt(u_char *pkt, int len) {
      u_char *tcp;

      len -= PPP_HDRLEN;
      pkt += PPP_HDRLEN;
      if (len < IP6_HDRLEN)
        return 0;
      if (get_ip6nh(pkt) == IP6_NHDR_FRAG)
        return 0;
      if (get_ip6nh(pkt) != IPPROTO_TCP)
        return 1;
      if (len < IP6_HDRLEN + TCP_HDRLEN)
        return 0;
      tcp = pkt + IP6_HDRLEN;
      if ((get_tcpflags(tcp) & TH_FIN) != 0 &&
          len == IP6_HDRLEN + get_tcpoff(tcp) * 4)
        return 0;
      return 1;
    }

static int noopt(argv)
char **argv;
{
  BZERO((char *)&lcp_wantoptions[0], sizeof(struct lcp_options));
  BZERO((char *)&lcp_allowoptions[0], sizeof(struct lcp_options));

  return (1);
}

static int setendpoint(argv)
char **argv;
{
  if (str_to_epdisc(&lcp_wantoptions[0].endpoint, *argv)) {
    lcp_wantoptions[0].neg_endpoint = 1;
    return 1;
  }
  option_error("Can't parse '%s' as an endpoint discriminator", *argv);
  return 0;
}

static void printendpoint(opt, printer, arg) option_t *opt;
void (*printer)(void *, char *, ...);
void *arg;
{ printer(arg, "%s", epdisc_to_str(&lcp_wantoptions[0].endpoint)); }

static void lcp_init(ppp_pcb *pcb) {
  fsm *f = &pcb->lcp_fsm;
  lcp_options *wo = &pcb->lcp_wantoptions;
  lcp_options *ao = &pcb->lcp_allowoptions;

  f->pcb = pcb;
  f->protocol = PPP_LCP;
  f->callbacks = &lcp_callbacks;

  fsm_init(f);

  BZERO(wo, sizeof(*wo));
  wo->neg_mru = 1;
  wo->mru = PPP_MRU;
  wo->neg_asyncmap = 1;
  wo->neg_magicnumber = 1;
  wo->neg_pcompression = 1;
  wo->neg_accompression = 1;

  BZERO(ao, sizeof(*ao));
  ao->neg_mru = 1;
  ao->mru = PPP_MAXMRU;
  ao->neg_asyncmap = 1;
#if CHAP_SUPPORT
  ao->neg_chap = 1;
  ao->chap_mdtype = CHAP_MDTYPE_SUPPORTED;
#endif /* CHAP_SUPPORT */
#if PAP_SUPPORT
  ao->neg_upap = 1;
#endif /* PAP_SUPPORT */
#if EAP_SUPPORT
  ao->neg_eap = 1;
#endif /* EAP_SUPPORT */
  ao->neg_magicnumber = 1;
  ao->neg_pcompression = 1;
  ao->neg_accompression = 1;
  ao->neg_endpoint = 1;
}

void lcp_open(ppp_pcb *pcb) {
  fsm *f = &pcb->lcp_fsm;
  lcp_options *wo = &pcb->lcp_wantoptions;

  f->flags &= ~(OPT_PASSIVE | OPT_SILENT);
  if (wo->passive)
    f->flags |= OPT_PASSIVE;
  if (wo->silent)
    f->flags |= OPT_SILENT;
  fsm_open(f);
}

void lcp_close(ppp_pcb *pcb, const char *reason) {
  fsm *f = &pcb->lcp_fsm;
  int oldstate;

  if (pcb->phase != PPP_PHASE_DEAD
#ifdef HAVE_MULTILINK
      && pcb->phase != PPP_PHASE_MASTER
#endif /* HAVE_MULTILINK */
  )
    new_phase(pcb, PPP_PHASE_TERMINATE);

  if (f->flags & DELAYED_UP) {
    UNTIMEOUT(lcp_delayed_up, f);
    f->state = PPP_FSM_STOPPED;
  }
  oldstate = f->state;

  fsm_close(f, reason);
  if (oldstate == PPP_FSM_STOPPED &&
      (f->flags & (OPT_PASSIVE | OPT_SILENT | DELAYED_UP))) {
    /*
     * This action is not strictly according to the FSM in RFC1548,
     * but it does mean that the program terminates if you do a
     * lcp_close() when a connection hasn't been established
     * because we are in passive/silent mode or because we have
     * delayed the fsm_lowerup() call and it hasn't happened yet.
     */
    f->flags &= ~DELAYED_UP;
    lcp_finished(f);
  }
}

void lcp_lowerup(ppp_pcb *pcb) {
  lcp_options *wo = &pcb->lcp_wantoptions;
  fsm *f = &pcb->lcp_fsm;
  /*
   * Don't use A/C or protocol compression on transmission,
   * but accept A/C and protocol compressed packets
   * if we are going to ask for A/C and protocol compression.
   */
  if (ppp_send_config(pcb, PPP_DEFMRU, 0xffffffff, 0, 0) < 0 ||
      ppp_recv_config(pcb, PPP_DEFMRU,
                      (pcb->settings.lax_recv ? 0 : 0xffffffff),
                      wo->neg_pcompression, wo->neg_accompression) < 0)
    return;
  pcb->peer_mru = PPP_DEFMRU;

  if (pcb->settings.listen_time != 0) {
    f->flags |= DELAYED_UP;
    TIMEOUTMS(lcp_delayed_up, f, pcb->settings.listen_time);
  } else
    fsm_lowerup(f);
}

void lcp_lowerdown(ppp_pcb *pcb) {
  fsm *f = &pcb->lcp_fsm;

  if (f->flags & DELAYED_UP) {
    f->flags &= ~DELAYED_UP;
    UNTIMEOUT(lcp_delayed_up, f);
  } else
    fsm_lowerdown(f);
}

static void lcp_delayed_up(void *arg) {
  fsm *f = (fsm *)arg;

  if (f->flags & DELAYED_UP) {
    f->flags &= ~DELAYED_UP;
    fsm_lowerup(f);
  }
}

static void lcp_input(ppp_pcb *pcb, u_char *p, int len) {
  fsm *f = &pcb->lcp_fsm;

  if (f->flags & DELAYED_UP) {
    f->flags &= ~DELAYED_UP;
    UNTIMEOUT(lcp_delayed_up, f);
    fsm_lowerup(f);
  }
  fsm_input(f, p, len);
}

static int lcp_extcode(fsm *f, int code, int id, u_char *inp, int len) {
  ppp_pcb *pcb = f->pcb;
  lcp_options *go = &pcb->lcp_gotoptions;
  u_char *magp;

  switch (code) {
  case PROTREJ:
    lcp_rprotrej(f, inp, len);
    break;

  case ECHOREQ:
    if (f->state != PPP_FSM_OPENED)
      break;
    magp = inp;
    PUTLONG(go->magicnumber, magp);
    fsm_sdata(f, ECHOREP, id, inp, len);
    break;

  case ECHOREP:
    lcp_received_echo_reply(f, id, inp, len);
    break;

  case DISCREQ:
  case IDENTIF:
  case TIMEREM:
    break;

  default:
    return 0;
  }
  return 1;
}

static void lcp_rprotrej(fsm *f, u_char *inp, int len) {
  int i;
  const struct protent *protp;
  u_short prot;
#if PPP_PROTOCOLNAME
  const char *pname;
#endif /* PPP_PROTOCOLNAME */

  if (len < 2) {
    LCPDEBUG(("lcp_rprotrej: Rcvd short Protocol-Reject packet!"));
    return;
  }

  GETSHORT(prot, inp);

  /*
   * Protocol-Reject packets received in any state other than the LCP
   * OPENED state SHOULD be silently discarded.
   */
  if (f->state != PPP_FSM_OPENED) {
    LCPDEBUG(("Protocol-Reject discarded: LCP in state %d", f->state));
    return;
  }

#if PPP_PROTOCOLNAME
  pname = protocol_name(prot);
#endif /* PPP_PROTOCOLNAME */

  /*
   * Upcall the proper Protocol-Reject routine.
   */
  for (i = 0; (protp = protocols[i]) != NULL; ++i)
    if (protp->protocol == prot) {
#if PPP_PROTOCOLNAME
      if (pname != NULL)
        ppp_dbglog(("Protocol-Reject for '%s' (0x%x) received", pname, prot));
      else
#endif /* PPP_PROTOCOLNAME */
        ppp_dbglog(("Protocol-Reject for 0x%x received", prot));
      (*protp->protrej)(f->pcb);
      return;
    }

#if PPP_PROTOCOLNAME
  if (pname != NULL)
    ppp_warn(
        ("Protocol-Reject for unsupported protocol '%s' (0x%x)", pname, prot));
  else
#endif /* #if PPP_PROTOCOLNAME */
    ppp_warn(("Protocol-Reject for unsupported protocol 0x%x", prot));
}

static void lcp_protrej(ppp_pcb *pcb) {
  /*
   * Can't reject LCP!
   */
  ppp_error(("Received Protocol-Reject for LCP!"));
  fsm_protreject(&pcb->lcp_fsm);
}

void lcp_sprotrej(ppp_pcb *pcb, u_char *p, int len) {
  fsm *f = &pcb->lcp_fsm;
  /*
   * Send back the protocol and the information field of the
   * rejected packet.  We only get here if LCP is in the OPENED state.
   */
#if 0
    p += 2;
    len -= 2;
#endif

  fsm_sdata(f, PROTREJ, ++f->id, p, len);
}

static void lcp_addci(fsm *f, u_char *ucp, int *lenp) {
  ppp_pcb *pcb = f->pcb;
  lcp_options *go = &pcb->lcp_gotoptions;
  u_char *start_ucp = ucp;

#define ADDCIVOID(opt, neg)                                                    \
  if (neg) {                                                                   \
    PUTCHAR(opt, ucp);                                                         \
    PUTCHAR(CILEN_VOID, ucp);                                                  \
  }
#define ADDCISHORT(opt, neg, val)                                              \
  if (neg) {                                                                   \
    PUTCHAR(opt, ucp);                                                         \
    PUTCHAR(CILEN_SHORT, ucp);                                                 \
    PUTSHORT(val, ucp);                                                        \
  }
#if CHAP_SUPPORT
#define ADDCICHAP(opt, neg, val)                                               \
  if (neg) {                                                                   \
    PUTCHAR((opt), ucp);                                                       \
    PUTCHAR(CILEN_CHAP, ucp);                                                  \
    PUTSHORT(PPP_CHAP, ucp);                                                   \
    PUTCHAR((CHAP_DIGEST(val)), ucp);                                          \
  }
#endif /* CHAP_SUPPORT */
#define ADDCILONG(opt, neg, val)                                               \
  if (neg) {                                                                   \
    PUTCHAR(opt, ucp);                                                         \
    PUTCHAR(CILEN_LONG, ucp);                                                  \
    PUTLONG(val, ucp);                                                         \
  }
#if LQR_SUPPORT
#define ADDCILQR(opt, neg, val)                                                \
  if (neg) {                                                                   \
    PUTCHAR(opt, ucp);                                                         \
    PUTCHAR(CILEN_LQR, ucp);                                                   \
    PUTSHORT(PPP_LQR, ucp);                                                    \
    PUTLONG(val, ucp);                                                         \
  }
#endif /* LQR_SUPPORT */
#define ADDCICHAR(opt, neg, val)                                               \
  if (neg) {                                                                   \
    PUTCHAR(opt, ucp);                                                         \
    PUTCHAR(CILEN_CHAR, ucp);                                                  \
    PUTCHAR(val, ucp);                                                         \
  }
#define ADDCIENDP(opt, neg, class, val, len)                                   \
  if (neg) {                                                                   \
    int i;                                                                     \
    PUTCHAR(opt, ucp);                                                         \
    PUTCHAR(CILEN_CHAR + len, ucp);                                            \
    PUTCHAR(class, ucp);                                                       \
    for (i = 0; i < len; ++i)                                                  \
      PUTCHAR(val[i], ucp);                                                    \
  }

  ADDCISHORT(CI_MRU, go->neg_mru && go->mru != PPP_DEFMRU, go->mru);
  ADDCILONG(CI_ASYNCMAP, go->neg_asyncmap && go->asyncmap != 0xFFFFFFFF,
            go->asyncmap);
#if EAP_SUPPORT
  ADDCISHORT(CI_AUTHTYPE, go->neg_eap, PPP_EAP);
#endif           /* EAP_SUPPORT */
#if CHAP_SUPPORT /* cannot be improved, embedding a directive within macro     \
                    arguments is not portable */
#if EAP_SUPPORT
  ADDCICHAP(CI_AUTHTYPE, !go->neg_eap && go->neg_chap, go->chap_mdtype);
#endif /* EAP_SUPPORT */
#if !EAP_SUPPORT
  ADDCICHAP(CI_AUTHTYPE, go->neg_chap, go->chap_mdtype);
#endif          /* !EAP_SUPPORT */
#endif          /* CHAP_SUPPORT */
#if PAP_SUPPORT /* cannot be improved, embedding a directive within macro      \
                   arguments is not portable */
#if EAP_SUPPORT && CHAP_SUPPORT
  ADDCISHORT(CI_AUTHTYPE, !go->neg_eap && !go->neg_chap && go->neg_upap,
             PPP_PAP);
#endif /* EAP_SUPPORT && CHAP_SUPPORT */
#if EAP_SUPPORT && !CHAP_SUPPORT
  ADDCISHORT(CI_AUTHTYPE, !go->neg_eap && go->neg_upap, PPP_PAP);
#endif /* EAP_SUPPORT && !CHAP_SUPPORT */
#if !EAP_SUPPORT && CHAP_SUPPORT
  ADDCISHORT(CI_AUTHTYPE, !go->neg_chap && go->neg_upap, PPP_PAP);
#endif /* !EAP_SUPPORT && CHAP_SUPPORT */
#if !EAP_SUPPORT && !CHAP_SUPPORT
  ADDCISHORT(CI_AUTHTYPE, go->neg_upap, PPP_PAP);
#endif /* !EAP_SUPPORT && !CHAP_SUPPORT */
#endif /* PAP_SUPPORT */
#if LQR_SUPPORT
  ADDCILQR(CI_QUALITY, go->neg_lqr, go->lqr_period);
#endif /* LQR_SUPPORT */
  ADDCICHAR(CI_CALLBACK, go->neg_cbcp, CBCP_OPT);
  ADDCILONG(CI_MAGICNUMBER, go->neg_magicnumber, go->magicnumber);
  ADDCIVOID(CI_PCOMPRESSION, go->neg_pcompression);
  ADDCIVOID(CI_ACCOMPRESSION, go->neg_accompression);
#ifdef HAVE_MULTILINK
  ADDCISHORT(CI_MRRU, go->neg_mrru, go->mrru);
#endif
  ADDCIVOID(CI_SSNHF, go->neg_ssnhf);
  ADDCIENDP(CI_EPDISC, go->neg_endpoint, go->endpoint.class_,
            go->endpoint.value, go->endpoint.length);

  if (ucp - start_ucp != *lenp) {
    /* this should never happen, because peer_mtu should be 1500 */
    ppp_error(("Bug in lcp_addci: wrong length"));
  }
}

static int lcp_nakci(fsm *f, u_char *p, int len, int treat_as_reject) {
  ppp_pcb *pcb = f->pcb;
  lcp_options *go = &pcb->lcp_gotoptions;
  lcp_options *wo = &pcb->lcp_wantoptions;
  u_char citype, cichar, *next;
  u_short cishort;
  u32_t cilong;
  lcp_options no;   /* options we've seen Naks for */
  lcp_options try_; /* options to request next time */
  int looped_back = 0;
  int cilen;

  BZERO(&no, sizeof(no));
  try_ = *go;

  /*
   * Any Nak'd CIs must be in exactly the same order that we sent.
   * Check packet length and CI length at each step.
   * If we find any deviations, then this packet is bad.
   */
#define NAKCIVOID(opt, neg)                                                    \
  if (go->neg && len >= CILEN_VOID && p[1] == CILEN_VOID && p[0] == opt) {     \
    len -= CILEN_VOID;                                                         \
    INCPTR(CILEN_VOID, p);                                                     \
    no.neg = 1;                                                                \
    try_.neg = 0;                                                              \
  }
#if CHAP_SUPPORT
#define NAKCICHAP(opt, neg, code)                                              \
  if (go->neg && len >= CILEN_CHAP && p[1] == CILEN_CHAP && p[0] == opt) {     \
    len -= CILEN_CHAP;                                                         \
    INCPTR(2, p);                                                              \
    GETSHORT(cishort, p);                                                      \
    GETCHAR(cichar, p);                                                        \
    no.neg = 1;                                                                \
    code                                                                       \
  }
#endif /* CHAP_SUPPORT */
#define NAKCICHAR(opt, neg, code)                                              \
  if (go->neg && len >= CILEN_CHAR && p[1] == CILEN_CHAR && p[0] == opt) {     \
    len -= CILEN_CHAR;                                                         \
    INCPTR(2, p);                                                              \
    GETCHAR(cichar, p);                                                        \
    no.neg = 1;                                                                \
    code                                                                       \
  }
#define NAKCISHORT(opt, neg, code)                                             \
  if (go->neg && len >= CILEN_SHORT && p[1] == CILEN_SHORT && p[0] == opt) {   \
    len -= CILEN_SHORT;                                                        \
    INCPTR(2, p);                                                              \
    GETSHORT(cishort, p);                                                      \
    no.neg = 1;                                                                \
    code                                                                       \
  }
#define NAKCILONG(opt, neg, code)                                              \
  if (go->neg && len >= CILEN_LONG && p[1] == CILEN_LONG && p[0] == opt) {     \
    len -= CILEN_LONG;                                                         \
    INCPTR(2, p);                                                              \
    GETLONG(cilong, p);                                                        \
    no.neg = 1;                                                                \
    code                                                                       \
  }
#if LQR_SUPPORT
#define NAKCILQR(opt, neg, code)                                               \
  if (go->neg && len >= CILEN_LQR && p[1] == CILEN_LQR && p[0] == opt) {       \
    len -= CILEN_LQR;                                                          \
    INCPTR(2, p);                                                              \
    GETSHORT(cishort, p);                                                      \
    GETLONG(cilong, p);                                                        \
    no.neg = 1;                                                                \
    code                                                                       \
  }
#endif /* LQR_SUPPORT */
#define NAKCIENDP(opt, neg)                                                    \
  if (go->neg && len >= CILEN_CHAR && p[0] == opt && p[1] >= CILEN_CHAR &&     \
      p[1] <= len) {                                                           \
    len -= p[1];                                                               \
    INCPTR(p[1], p);                                                           \
    no.neg = 1;                                                                \
    try_.neg = 0;                                                              \
  }

  /*
   * NOTE!  There must be no assignments to individual fields of *go in
   * the code below.  Any such assignment is a BUG!
   */
  /*
   * We don't care if they want to send us smaller packets than
   * we want.  Therefore, accept any MRU less than what we asked for,
   * but then ignore the new value when setting the MRU in the kernel.
   * If they send us a bigger MRU than what we asked, accept it, up to
   * the limit of the default MRU we'd get if we didn't negotiate.
   */
  if (go->neg_mru && go->mru != PPP_DEFMRU) {
    NAKCISHORT(CI_MRU, neg_mru,
               if (cishort <= wo->mru || cishort <= PPP_DEFMRU) try_.mru =
                   cishort;);
  }

  /*
   * Add any characters they want to our (receive-side) asyncmap.
   */
  if (go->neg_asyncmap && go->asyncmap != 0xFFFFFFFF) {
    NAKCILONG(CI_ASYNCMAP, neg_asyncmap,
              try_.asyncmap = go->asyncmap | cilong;);
  }

  /*
   * If they've nak'd our authentication-protocol, check whether
   * they are proposing a different protocol, or a different
   * hash algorithm for CHAP.
   */
  if ((0
#if CHAP_SUPPORT
       || go->neg_chap
#endif /* CHAP_SUPPORT */
#if PAP_SUPPORT
       || go->neg_upap
#endif /* PAP_SUPPORT */
#if EAP_SUPPORT
       || go->neg_eap
#endif /* EAP_SUPPORT */
       ) &&
      len >= CILEN_SHORT && p[0] == CI_AUTHTYPE && p[1] >= CILEN_SHORT &&
      p[1] <= len) {
    cilen = p[1];
    len -= cilen;
#if CHAP_SUPPORT
    no.neg_chap = go->neg_chap;
#endif /* CHAP_SUPPORT */
#if PAP_SUPPORT
    no.neg_upap = go->neg_upap;
#endif /* PAP_SUPPORT */
#if EAP_SUPPORT
    no.neg_eap = go->neg_eap;
#endif /* EAP_SUPPORT */
    INCPTR(2, p);
    GETSHORT(cishort, p);

#if PAP_SUPPORT
    if (cishort == PPP_PAP && cilen == CILEN_SHORT) {
#if EAP_SUPPORT
      /* If we were asking for EAP, then we need to stop that. */
      if (go->neg_eap)
        try_.neg_eap = 0;
      else
#endif /* EAP_SUPPORT */

#if CHAP_SUPPORT
        /* If we were asking for CHAP, then we need to stop that. */
        if (go->neg_chap)
          try_.neg_chap = 0;
        else
#endif /* CHAP_SUPPORT */

          /*
           * If we weren't asking for CHAP or EAP, then we were asking for
           * PAP, in which case this Nak is bad.
           */
          goto bad;
    } else
#endif /* PAP_SUPPORT */

#if CHAP_SUPPORT
        if (cishort == PPP_CHAP && cilen == CILEN_CHAP) {
      GETCHAR(cichar, p);
#if EAP_SUPPORT
      /* Stop asking for EAP, if we were. */
      if (go->neg_eap) {
        try_.neg_eap = 0;
        /* Try to set up to use their suggestion, if possible */
        if (CHAP_CANDIGEST(go->chap_mdtype, cichar))
          try_.chap_mdtype = CHAP_MDTYPE_D(cichar);
      } else
#endif /* EAP_SUPPORT */
        if (go->neg_chap) {
          /*
           * We were asking for our preferred algorithm, they must
           * want something different.
           */
          if (cichar != CHAP_DIGEST(go->chap_mdtype)) {
            if (CHAP_CANDIGEST(go->chap_mdtype, cichar)) {
              /* Use their suggestion if we support it ... */
              try_.chap_mdtype = CHAP_MDTYPE_D(cichar);
            } else {
              /* ... otherwise, try our next-preferred algorithm. */
              try_.chap_mdtype &= ~(CHAP_MDTYPE(try_.chap_mdtype));
              if (try_.chap_mdtype == MDTYPE_NONE) /* out of algos */
                try_.neg_chap = 0;
            }
          } else {
            /*
             * Whoops, they Nak'd our algorithm of choice
             * but then suggested it back to us.
             */
            goto bad;
          }
        } else {
          /*
           * Stop asking for PAP if we were asking for it.
           */
#if PAP_SUPPORT
          try_.neg_upap = 0;
#endif /* PAP_SUPPORT */
        }

    } else
#endif /* CHAP_SUPPORT */
    {

#if EAP_SUPPORT
      /*
       * If we were asking for EAP, and they're Conf-Naking EAP,
       * well, that's just strange.  Nobody should do that.
       */
      if (cishort == PPP_EAP && cilen == CILEN_SHORT && go->neg_eap)
        ppp_dbglog(("Unexpected Conf-Nak for EAP"));

      /*
       * We don't recognize what they're suggesting.
       * Stop asking for what we were asking for.
       */
      if (go->neg_eap)
        try_.neg_eap = 0;
      else
#endif /* EAP_SUPPORT */

#if CHAP_SUPPORT
          if (go->neg_chap)
        try_.neg_chap = 0;
      else
#endif /* CHAP_SUPPORT */

#if PAP_SUPPORT
          if (1)
        try_.neg_upap = 0;
      else
#endif /* PAP_SUPPORT */
      {
      }

      p += cilen - CILEN_SHORT;
    }
  }

#if LQR_SUPPORT
  /*
   * If they can't cope with our link quality protocol, we'll have
   * to stop asking for LQR.  We haven't got any other protocol.
   * If they Nak the reporting period, take their value XXX ?
   */
  NAKCILQR(CI_QUALITY, neg_lqr, if (cishort != PPP_LQR) try_.neg_lqr = 0;
           else try_.lqr_period = cilong;);
#endif /* LQR_SUPPORT */

  /*
   * Only implementing CBCP...not the rest of the callback options
   */
  NAKCICHAR(CI_CALLBACK, neg_cbcp, try_.neg_cbcp = 0;
            (void)cichar; /* if CHAP support is not compiled, cichar is set but
                             not used, which makes some compilers complaining */
  );

  /*
   * Check for a looped-back line.
   */
  NAKCILONG(CI_MAGICNUMBER, neg_magicnumber, try_.magicnumber = magic();
            looped_back = 1;);

  /*
   * Peer shouldn't send Nak for protocol compression or
   * address/control compression requests; they should send
   * a Reject instead.  If they send a Nak, treat it as a Reject.
   */
  NAKCIVOID(CI_PCOMPRESSION, neg_pcompression);
  NAKCIVOID(CI_ACCOMPRESSION, neg_accompression);

#ifdef HAVE_MULTILINK
  /*
   * Nak for MRRU option - accept their value if it is smaller
   * than the one we want.
   */
  if (go->neg_mrru) {
    NAKCISHORT(CI_MRRU, neg_mrru, if (treat_as_reject) try_.neg_mrru = 0;
               else if (cishort <= wo->mrru) try_.mrru = cishort;);
  }
#else  /* HAVE_MULTILINK */
  LWIP_UNUSED_ARG(treat_as_reject);
#endif /* HAVE_MULTILINK */

  /*
   * Nak for short sequence numbers shouldn't be sent, treat it
   * like a reject.
   */
  NAKCIVOID(CI_SSNHF, neg_ssnhf);

  /*
   * Nak of the endpoint discriminator option is not permitted,
   * treat it like a reject.
   */
  NAKCIENDP(CI_EPDISC, neg_endpoint);

  /*
   * There may be remaining CIs, if the peer is requesting negotiation
   * on an option that we didn't include in our request packet.
   * If we see an option that we requested, or one we've already seen
   * in this packet, then this packet is bad.
   * If we wanted to respond by starting to negotiate on the requested
   * option(s), we could, but we don't, because except for the
   * authentication type and quality protocol, if we are not negotiating
   * an option, it is because we were told not to.
   * For the authentication type, the Nak from the peer means
   * `let me authenticate myself with you' which is a bit pointless.
   * For the quality protocol, the Nak means `ask me to send you quality
   * reports', but if we didn't ask for them, we don't want them.
   * An option we don't recognize represents the peer asking to
   * negotiate some option we don't support, so ignore it.
   */
  while (len >= CILEN_VOID) {
    GETCHAR(citype, p);
    GETCHAR(cilen, p);
    if (cilen < CILEN_VOID || (len -= cilen) < 0)
      goto bad;
    next = p + cilen - 2;

    switch (citype) {
    case CI_MRU:
      if ((go->neg_mru && go->mru != PPP_DEFMRU) || no.neg_mru ||
          cilen != CILEN_SHORT)
        goto bad;
      GETSHORT(cishort, p);
      if (cishort < PPP_DEFMRU) {
        try_.neg_mru = 1;
        try_.mru = cishort;
      }
      break;
    case CI_ASYNCMAP:
      if ((go->neg_asyncmap && go->asyncmap != 0xFFFFFFFF) || no.neg_asyncmap ||
          cilen != CILEN_LONG)
        goto bad;
      break;
    case CI_AUTHTYPE:
      /* This is potentially dead code (#if !PPP_AUTH_SUPPORT)
       * Thus the double parantheses to mark the code explicitely
       * disabled when building with clang
       */
      if ((0
#if CHAP_SUPPORT
           || go->neg_chap || no.neg_chap
#endif /* CHAP_SUPPORT */
#if PAP_SUPPORT
           || go->neg_upap || no.neg_upap
#endif /* PAP_SUPPORT */
#if EAP_SUPPORT
           || go->neg_eap || no.neg_eap
#endif /* EAP_SUPPORT */
           ))
        goto bad;
      break;
    case CI_MAGICNUMBER:
      if (go->neg_magicnumber || no.neg_magicnumber || cilen != CILEN_LONG)
        goto bad;
      break;
    case CI_PCOMPRESSION:
      if (go->neg_pcompression || no.neg_pcompression || cilen != CILEN_VOID)
        goto bad;
      break;
    case CI_ACCOMPRESSION:
      if (go->neg_accompression || no.neg_accompression || cilen != CILEN_VOID)
        goto bad;
      break;
#if LQR_SUPPORT
    case CI_QUALITY:
      if (go->neg_lqr || no.neg_lqr || cilen != CILEN_LQR)
        goto bad;
      break;
#endif /* LQR_SUPPORT */
#ifdef HAVE_MULTILINK
    case CI_MRRU:
      if (go->neg_mrru || no.neg_mrru || cilen != CILEN_SHORT)
        goto bad;
      break;
#endif /* HAVE_MULTILINK */
    case CI_SSNHF:
      if (go->neg_ssnhf || no.neg_ssnhf || cilen != CILEN_VOID)
        goto bad;
      try_.neg_ssnhf = 1;
      break;
    case CI_EPDISC:
      if (go->neg_endpoint || no.neg_endpoint || cilen < CILEN_CHAR)
        goto bad;
      break;
    default:
      break;
    }
    p = next;
  }

  /*
   * OK, the Nak is good.  Now we can update state.
   * If there are any options left we ignore them.
   */
  if (f->state != PPP_FSM_OPENED) {
    if (looped_back) {
      if (++try_.numloops >= pcb->settings.lcp_loopbackfail) {
        ppp_notice(("Serial line is looped back."));
        pcb->err_code = PPPERR_LOOPBACK;
        lcp_close(f->pcb, "Loopback detected");
      }
    } else
      try_.numloops = 0;
    *go = try_;
  }

  return 1;

bad:
  LCPDEBUG(("lcp_nakci: received bad Nak!"));
  return 0;
}

static int lcp_rejci(fsm *f, u_char *p, int len) {
  ppp_pcb *pcb = f->pcb;
  lcp_options *go = &pcb->lcp_gotoptions;
  u_char cichar;
  u_short cishort;
  u32_t cilong;
  lcp_options try_; /* options to request next time */

  try_ = *go;

  /*
   * Any Rejected CIs must be in exactly the same order that we sent.
   * Check packet length and CI length at each step.
   * If we find any deviations, then this packet is bad.
   */
#define REJCIVOID(opt, neg)                                                    \
  if (go->neg && len >= CILEN_VOID && p[1] == CILEN_VOID && p[0] == opt) {     \
    len -= CILEN_VOID;                                                         \
    INCPTR(CILEN_VOID, p);                                                     \
    try_.neg = 0;                                                              \
  }
#define REJCISHORT(opt, neg, val)                                              \
  if (go->neg && len >= CILEN_SHORT && p[1] == CILEN_SHORT && p[0] == opt) {   \
    len -= CILEN_SHORT;                                                        \
    INCPTR(2, p);                                                              \
    GETSHORT(cishort, p);                                                      \
    /* Check rejected value. */                                                \
    if (cishort != val)                                                        \
      goto bad;                                                                \
    try_.neg = 0;                                                              \
  }

static void lcp_up(fsm *f) {
  ppp_pcb *pcb = f->pcb;
  lcp_options *wo = &pcb->lcp_wantoptions;
  lcp_options *ho = &pcb->lcp_hisoptions;
  lcp_options *go = &pcb->lcp_gotoptions;
  lcp_options *ao = &pcb->lcp_allowoptions;
  int mtu, mru;

  if (!go->neg_magicnumber)
    go->magicnumber = 0;
  if (!ho->neg_magicnumber)
    ho->magicnumber = 0;

  /*
   * Set our MTU to the smaller of the MTU we wanted and
   * the MRU our peer wanted.  If we negotiated an MRU,
   * set our MRU to the larger of value we wanted and
   * the value we got in the negotiation.
   * Note on the MTU: the link MTU can be the MRU the peer wanted,
   * the interface MTU is set to the lowest of that, the
   * MTU we want to use, and our link MRU.
   */
  mtu = ho->neg_mru ? ho->mru : PPP_DEFMRU;
  mru = go->neg_mru ? LWIP_MAX(wo->mru, go->mru) : PPP_DEFMRU;
#ifdef HAVE_MULTILINK
  if (!(multilink && go->neg_mrru && ho->neg_mrru))
#endif /* HAVE_MULTILINK */
    ppp_netif_set_mtu(pcb, LWIP_MIN(LWIP_MIN(mtu, mru), ao->mru));
  ppp_send_config(pcb, mtu, (ho->neg_asyncmap ? ho->asyncmap : 0xffffffff),
                  ho->neg_pcompression, ho->neg_accompression);
  ppp_recv_config(pcb, mru,
                  (pcb->settings.lax_recv ? 0
                   : go->neg_asyncmap     ? go->asyncmap
                                          : 0xffffffff),
                  go->neg_pcompression, go->neg_accompression);

  if (ho->neg_mru)
    pcb->peer_mru = ho->mru;

  lcp_echo_lowerup(f->pcb); /* Enable echo messages */

  link_established(pcb);
}

static void lcp_down(fsm *f) {
  ppp_pcb *pcb = f->pcb;
  lcp_options *go = &pcb->lcp_gotoptions;

  lcp_echo_lowerdown(f->pcb);

  link_down(pcb);

  ppp_send_config(pcb, PPP_DEFMRU, 0xffffffff, 0, 0);
  ppp_recv_config(pcb, PPP_DEFMRU,
                  (go->neg_asyncmap ? go->asyncmap : 0xffffffff),
                  go->neg_pcompression, go->neg_accompression);
  pcb->peer_mru = PPP_DEFMRU;
}

static void lcp_starting(fsm *f) {
  ppp_pcb *pcb = f->pcb;
  link_required(pcb);
}

static void lcp_finished(fsm *f) {
  ppp_pcb *pcb = f->pcb;
  link_terminated(pcb);
}

static int lcp_printpkt(const u_char *p, int plen,
                        void (*printer)(void *, const char *, ...), void *arg) {
  int code, id, len, olen, i;
  const u_char *pstart, *optend;
  u_short cishort;
  u32_t cilong;

  if (plen < HEADERLEN)
    return 0;
  pstart = p;
  GETCHAR(code, p);
  GETCHAR(id, p);
  GETSHORT(len, p);
  if (len < HEADERLEN || len > plen)
    return 0;

  if (code >= 1 && code <= (int)LWIP_ARRAYSIZE(lcp_codenames))
    printer(arg, " %s", lcp_codenames[code - 1]);
  else
    printer(arg, " code=0x%x", code);
  printer(arg, " id=0x%x", id);
  len -= HEADERLEN;
  switch (code) {
  case CONFREQ:
  case CONFACK:
  case CONFNAK:
  case CONFREJ:
    /* print option list */
    while (len >= 2) {
      GETCHAR(code, p);
      GETCHAR(olen, p);
      p -= 2;
      if (olen < 2 || olen > len) {
        break;
      }
      printer(arg, " <");
      len -= olen;
      optend = p + olen;
      switch (code) {
      case CI_MRU:
        if (olen == CILEN_SHORT) {
          p += 2;
          GETSHORT(cishort, p);
          printer(arg, "mru %d", cishort);
        }
        break;
      case CI_ASYNCMAP:
        if (olen == CILEN_LONG) {
          p += 2;
          GETLONG(cilong, p);
          printer(arg, "asyncmap 0x%x", cilong);
        }
        break;
      case CI_AUTHTYPE:
        if (olen >= CILEN_SHORT) {
          p += 2;
          printer(arg, "auth ");
          GETSHORT(cishort, p);
          switch (cishort) {
#if PAP_SUPPORT
          case PPP_PAP:
            printer(arg, "pap");
            break;
#endif /* PAP_SUPPORT */
#if CHAP_SUPPORT
          case PPP_CHAP:
            printer(arg, "chap");
            if (p < optend) {
              switch (*p) {
              case CHAP_MD5:
                printer(arg, " MD5");
                ++p;
                break;
#if MSCHAP_SUPPORT
              case CHAP_MICROSOFT:
                printer(arg, " MS");
                ++p;
                break;

              case CHAP_MICROSOFT_V2:
                printer(arg, " MS-v2");
                ++p;
                break;
#endif /* MSCHAP_SUPPORT */
              default:
                break;
              }
            }
            break;
#endif /* CHAP_SUPPORT */
#if EAP_SUPPORT
          case PPP_EAP:
            printer(arg, "eap");
            break;
#endif /* EAP_SUPPORT */
          default:
            printer(arg, "0x%x", cishort);
          }
        }
        break;
#if LQR_SUPPORT
      case CI_QUALITY:
        if (olen >= CILEN_SHORT) {
          p += 2;
          printer(arg, "quality ");
          GETSHORT(cishort, p);
          switch (cishort) {
          case PPP_LQR:
            printer(arg, "lqr");
            break;
          default:
            printer(arg, "0x%x", cishort);
          }
        }
        break;
#endif /* LQR_SUPPORT */
      case CI_CALLBACK:
        if (olen >= CILEN_CHAR) {
          p += 2;
          printer(arg, "callback ");
          GETCHAR(cishort, p);
          switch (cishort) {
          case CBCP_OPT:
            printer(arg, "CBCP");
            break;
          default:
            printer(arg, "0x%x", cishort);
          }
        }
        break;
      case CI_MAGICNUMBER:
        if (olen == CILEN_LONG) {
          p += 2;
          GETLONG(cilong, p);
          printer(arg, "magic 0x%x", cilong);
        }
        break;
      case CI_PCOMPRESSION:
        if (olen == CILEN_VOID) {
          p += 2;
          printer(arg, "pcomp");
        }
        break;
      case CI_ACCOMPRESSION:
        if (olen == CILEN_VOID) {
          p += 2;
          printer(arg, "accomp");
        }
        break;
      case CI_MRRU:
        if (olen == CILEN_SHORT) {
          p += 2;
          GETSHORT(cishort, p);
          printer(arg, "mrru %d", cishort);
        }
        break;
      case CI_SSNHF:
        if (olen == CILEN_VOID) {
          p += 2;
          printer(arg, "ssnhf");
        }
        break;
      case CI_EPDISC:
#ifdef HAVE_MULTILINK
        if (olen >= CILEN_CHAR) {
          struct epdisc epd;
          p += 2;
          GETCHAR(epd.class, p);
          epd.length = olen - CILEN_CHAR;
          if (epd.length > MAX_ENDP_LEN)
            epd.length = MAX_ENDP_LEN;
          if (epd.length > 0) {
            MEMCPY(epd.value, p, epd.length);
            p += epd.length;
          }
          printer(arg, "endpoint [%s]", epdisc_to_str(&epd));
        }
#else
        printer(arg, "endpoint");
#endif
        break;
      default:
        break;
      }
      while (p < optend) {
        GETCHAR(code, p);
        printer(arg, " %.2x", code);
      }
      printer(arg, ">");
    }
    break;

  case TERMACK:
  case TERMREQ:
    if (len > 0 && *p >= ' ' && *p < 0x7f) {
      printer(arg, " ");
      ppp_print_string(p, len, printer, arg);
      p += len;
      len = 0;
    }
    break;

  case ECHOREQ:
  case ECHOREP:
  case DISCREQ:
    if (len >= 4) {
      GETLONG(cilong, p);
      printer(arg, " magic=0x%x", cilong);
      len -= 4;
    }
    break;

  case IDENTIF:
  case TIMEREM:
    if (len >= 4) {
      GETLONG(cilong, p);
      printer(arg, " magic=0x%x", cilong);
      len -= 4;
    }
    if (code == TIMEREM) {
      if (len < 4)
        break;
      GETLONG(cilong, p);
      printer(arg, " seconds=%u", cilong);
      len -= 4;
    }
    if (len > 0) {
      printer(arg, " ");
      ppp_print_string(p, len, printer, arg);
      p += len;
      len = 0;
    }
    break;
  default:
    break;
  }

  /* print the rest of the bytes in the packet */
  for (i = 0; i < len && i < 32; ++i) {
    GETCHAR(code, p);
    printer(arg, " %.2x", code);
  }
  if (i < len) {
    printer(arg, " ...");
    p += len - i;
  }

  return p - pstart;
}

static void LcpLinkFailure(fsm *f) {
  ppp_pcb *pcb = f->pcb;
  if (f->state == PPP_FSM_OPENED) {
    ppp_info(("No response to %d echo-requests", pcb->lcp_echos_pending));
    ppp_notice(("Serial link appears to be disconnected."));
    pcb->err_code = PPPERR_PEERDEAD;
    lcp_close(pcb, "Peer not responding");
  }
}

static void LcpEchoCheck(fsm *f) {
  ppp_pcb *pcb = f->pcb;

  LcpSendEchoRequest(f);
  if (f->state != PPP_FSM_OPENED)
    return;

  /*
   * Start the timer for the next interval.
   */
  if (pcb->lcp_echo_timer_running)
    ppp_warn(("assertion lcp_echo_timer_running==0 failed"));
  TIMEOUT(LcpEchoTimeout, f, pcb->settings.lcp_echo_interval);
  pcb->lcp_echo_timer_running = 1;
}

static void LcpEchoTimeout(void *arg) {
  fsm *f = (fsm *)arg;
  ppp_pcb *pcb = f->pcb;
  if (pcb->lcp_echo_timer_running != 0) {
    pcb->lcp_echo_timer_running = 0;
    LcpEchoCheck((fsm *)arg);
  }
}

static void lcp_received_echo_reply(fsm *f, int id, u_char *inp, int len) {
  ppp_pcb *pcb = f->pcb;
  lcp_options *go = &pcb->lcp_gotoptions;
  u32_t magic_val;
  LWIP_UNUSED_ARG(id);

  /* Check the magic number - don't count replies from ourselves. */
  if (len < 4) {
    ppp_dbglog(("lcp: received short Echo-Reply, length %d", len));
    return;
  }
  GETLONG(magic_val, inp);
  if (go->neg_magicnumber && magic_val == go->magicnumber) {
    ppp_warn(("appear to have received our own echo-reply!"));
    return;
  }

  /* Reset the number of outstanding echo frames */
  pcb->lcp_echos_pending = 0;
}

static void LcpSendEchoRequest(fsm *f) {
  ppp_pcb *pcb = f->pcb;
  lcp_options *go = &pcb->lcp_gotoptions;
  u32_t lcp_magic;
  u_char pkt[4], *pktp;

  /*
   * Detect the failure of the peer at this point.
   */
  if (pcb->settings.lcp_echo_fails != 0) {
    if (pcb->lcp_echos_pending >= pcb->settings.lcp_echo_fails) {
      LcpLinkFailure(f);
      pcb->lcp_echos_pending = 0;
    }
  }

#if PPP_LCP_ADAPTIVE
  /*
   * If adaptive echos have been enabled, only send the echo request if
   * no traffic was received since the last one.
   */
  if (pcb->settings.lcp_echo_adaptive) {
    static unsigned int last_pkts_in = 0;

#if PPP_STATS_SUPPORT
    update_link_stats(f->unit);
    link_stats_valid = 0;
#endif /* PPP_STATS_SUPPORT */

    if (link_stats.pkts_in != last_pkts_in) {
      last_pkts_in = link_stats.pkts_in;
      return;
    }
  }
#endif

  /*
   * Make and send the echo request frame.
   */
  if (f->state == PPP_FSM_OPENED) {
    lcp_magic = go->magicnumber;
    pktp = pkt;
    PUTLONG(lcp_magic, pktp);
    fsm_sdata(f, ECHOREQ, pcb->lcp_echo_number++, pkt, pktp - pkt);
    ++pcb->lcp_echos_pending;
  }
}

static void lcp_echo_lowerup(ppp_pcb *pcb) {
  fsm *f = &pcb->lcp_fsm;

  /* Clear the parameters for generating echo frames */
  pcb->lcp_echos_pending = 0;
  pcb->lcp_echo_number = 0;
  pcb->lcp_echo_timer_running = 0;

  /* If a timeout interval is specified then start the timer */
  if (pcb->settings.lcp_echo_interval != 0)
    LcpEchoCheck(f);
}

static void lcp_echo_lowerdown(ppp_pcb *pcb) {
  fsm *f = &pcb->lcp_fsm;

  if (pcb->lcp_echo_timer_running != 0) {
    UNTIMEOUT(LcpEchoTimeout, f);
    pcb->lcp_echo_timer_running = 0;
  }
}

static void magic_churnrand(char *rand_data, u32_t rand_len) {
  lwip_md5_context md5_ctx;

  /* LWIP_DEBUGF(LOG_INFO, ("magic_churnrand: %u@%P\n", rand_len, rand_data));
   */
  lwip_md5_init(&md5_ctx);
  lwip_md5_starts(&md5_ctx);
  lwip_md5_update(&md5_ctx, (u_char *)magic_randpool, sizeof(magic_randpool));
  if (rand_data) {
    lwip_md5_update(&md5_ctx, (u_char *)rand_data, rand_len);
  } else {
    struct {
      /* INCLUDE fields for any system sources of randomness */
      u32_t jiffies;
#ifdef LWIP_RAND
      u32_t rand;
#endif /* LWIP_RAND */
    } sys_data;
    /* Load sys_data fields here. */
    magic_randomseed += sys_jiffies();
    sys_data.jiffies = magic_randomseed;
#ifdef LWIP_RAND
    sys_data.rand = LWIP_RAND();
#endif /* LWIP_RAND */
    lwip_md5_update(&md5_ctx, (u_char *)&sys_data, sizeof(sys_data));
  }
  lwip_md5_finish(&md5_ctx, (u_char *)magic_randpool);
  lwip_md5_free(&md5_ctx);
  /*  LWIP_DEBUGF(LOG_INFO, ("magic_churnrand: -> 0\n")); */
}

void magic_random_bytes(unsigned char *buf, u32_t buf_len) {
  lwip_md5_context md5_ctx;
  u_char tmp[MD5_HASH_SIZE];
  u32_t n;

  while (buf_len > 0) {
    lwip_md5_init(&md5_ctx);
    lwip_md5_starts(&md5_ctx);
    lwip_md5_update(&md5_ctx, (u_char *)magic_randpool, sizeof(magic_randpool));
    lwip_md5_update(&md5_ctx, (u_char *)&magic_randcount,
                    sizeof(magic_randcount));
    lwip_md5_finish(&md5_ctx, tmp);
    lwip_md5_free(&md5_ctx);
    magic_randcount++;
    n = LWIP_MIN(buf_len, MD5_HASH_SIZE);
    MEMCPY(buf, tmp, n);
    buf += n;
    buf_len -= n;
  }
}

u32_t magic(void) {
  u32_t new_rand;

  magic_random_bytes((unsigned char *)&new_rand, sizeof(new_rand));
  return new_rand;
}

void magic_init(void) {
  magic_randomseed += sys_jiffies();
#ifndef LWIP_RAND
  /* Initialize the random number generator. */
  srand((unsigned)magic_randomseed);
#endif /* LWIP_RAND */
}

void magic_randomize(void) {
#ifndef LWIP_RAND
  if (!magic_randomized) {
    magic_randomized = !0;
    magic_init();
    /* The initialization function also updates the seed. */
    return;
  }
#endif /* LWIP_RAND */
  magic_randomseed += sys_jiffies();
}

u32_t magic(void) {
#ifdef LWIP_RAND
  return (LWIP_RAND() << 16) + LWIP_RAND() + magic_randomseed;
#else  /* LWIP_RAND */
  return ((u32_t)rand() << 16) + (u32_t)rand() + magic_randomseed;
#endif /* LWIP_RAND */
}

void magic_random_bytes(unsigned char *buf, u32_t buf_len) {
  u32_t new_rand, n;

  while (buf_len > 0) {
    new_rand = magic();
    n = LWIP_MIN(buf_len, sizeof(new_rand));
    MEMCPY(buf, &new_rand, n);
    buf += n;
    buf_len -= n;
  }
}

static void mppe_rekey(ppp_mppe_state *state, int initial_key) {
  lwip_sha1_context sha1_ctx;
  u8_t sha1_digest[SHA1_SIGNATURE_SIZE];

  /*
   * Key Derivation, from RFC 3078, RFC 3079.
   * Equivalent to Get_Key() for MS-CHAP as described in RFC 3079.
   */
  lwip_sha1_init(&sha1_ctx);
  lwip_sha1_starts(&sha1_ctx);
  lwip_sha1_update(&sha1_ctx, state->master_key, state->keylen);
  lwip_sha1_update(&sha1_ctx, mppe_sha1_pad1, SHA1_PAD_SIZE);
  lwip_sha1_update(&sha1_ctx, state->session_key, state->keylen);
  lwip_sha1_update(&sha1_ctx, mppe_sha1_pad2, SHA1_PAD_SIZE);
  lwip_sha1_finish(&sha1_ctx, sha1_digest);
  lwip_sha1_free(&sha1_ctx);
  MEMCPY(state->session_key, sha1_digest, state->keylen);

  if (!initial_key) {
    lwip_arc4_init(&state->arc4);
    lwip_arc4_setup(&state->arc4, sha1_digest, state->keylen);
    lwip_arc4_crypt(&state->arc4, state->session_key, state->keylen);
    lwip_arc4_free(&state->arc4);
  }
  if (state->keylen == 8) {
    /* See RFC 3078 */
    state->session_key[0] = 0xd1;
    state->session_key[1] = 0x26;
    state->session_key[2] = 0x9e;
  }
  lwip_arc4_init(&state->arc4);
  lwip_arc4_setup(&state->arc4, state->session_key, state->keylen);
}

void mppe_set_key(ppp_pcb *pcb, ppp_mppe_state *state, u8_t *key) {
  LWIP_UNUSED_ARG(pcb);
  MEMCPY(state->master_key, key, MPPE_MAX_KEY_LEN);
}

void mppe_init(ppp_pcb *pcb, ppp_mppe_state *state, u8_t options) {
#if PPP_DEBUG
  const u8_t *debugstr = (const u8_t *)"mppe_comp_init";
  if (&pcb->mppe_decomp == state) {
    debugstr = (const u8_t *)"mppe_decomp_init";
  }
#endif /* PPP_DEBUG */

  /* Save keys. */
  MEMCPY(state->session_key, state->master_key, sizeof(state->master_key));

  if (options & MPPE_OPT_128)
    state->keylen = 16;
  else if (options & MPPE_OPT_40)
    state->keylen = 8;
  else {
    PPPDEBUG(LOG_DEBUG,
             ("%s[%d]: unknown key length\n", debugstr, pcb->netif->num));
    lcp_close(pcb, "MPPE required but peer negotiation failed");
    return;
  }
  if (options & MPPE_OPT_STATEFUL)
    state->stateful = 1;

  /* Generate the initial session key. */
  mppe_rekey(state, 1);

#if PPP_DEBUG
  {
    int i;
    char mkey[sizeof(state->master_key) * 2 + 1];
    char skey[sizeof(state->session_key) * 2 + 1];

    PPPDEBUG(LOG_DEBUG, ("%s[%d]: initialized with %d-bit %s mode\n", debugstr,
                         pcb->netif->num, (state->keylen == 16) ? 128 : 40,
                         (state->stateful) ? "stateful" : "stateless"));

    for (i = 0; i < (int)sizeof(state->master_key); i++)
      sprintf(mkey + i * 2, "%02x", state->master_key[i]);
    for (i = 0; i < (int)sizeof(state->session_key); i++)
      sprintf(skey + i * 2, "%02x", state->session_key[i]);
    PPPDEBUG(LOG_DEBUG, ("%s[%d]: keys: master: %s initial session: %s\n",
                         debugstr, pcb->netif->num, mkey, skey));
  }
#endif /* PPP_DEBUG */

  /*
   * Initialize the coherency count.  The initial value is not specified
   * in RFC 3078, but we can make a reasonable assumption that it will
   * start at 0.  Setting it to the max here makes the comp/decomp code
   * do the right thing (determined through experiment).
   */
  state->ccount = MPPE_CCOUNT_SPACE - 1;

  /*
   * Note that even though we have initialized the key table, we don't
   * set the FLUSHED bit.  This is contrary to RFC 3078, sec. 3.1.
   */
  state->bits = MPPE_BIT_ENCRYPTED;
}

void mppe_comp_reset(ppp_pcb *pcb, ppp_mppe_state *state) {
  LWIP_UNUSED_ARG(pcb);
  state->bits |= MPPE_BIT_FLUSHED;
}

err_t mppe_compress(ppp_pcb *pcb, ppp_mppe_state *state, struct pbuf **pb,
                    u16_t protocol) {
  struct pbuf *n, *np;
  u8_t *pl;
  err_t err;

  LWIP_UNUSED_ARG(pcb);

  /* TCP stack requires that we don't change the packet payload, therefore we
   * copy the whole packet before encryption.
   */
  np = pbuf_alloc(PBUF_RAW, MPPE_OVHD + sizeof(protocol) + (*pb)->tot_len,
                  PBUF_RAM);
  if (!np) {
    return ERR_MEM;
  }

  /* Hide MPPE header + protocol */
  pbuf_remove_header(np, MPPE_OVHD + sizeof(protocol));

  if ((err = pbuf_copy(np, *pb)) != ERR_OK) {
    pbuf_free(np);
    return err;
  }

  /* Reveal MPPE header + protocol */
  pbuf_add_header(np, MPPE_OVHD + sizeof(protocol));

  *pb = np;
  pl = (u8_t *)np->payload;

  state->ccount = (state->ccount + 1) % MPPE_CCOUNT_SPACE;
  PPPDEBUG(LOG_DEBUG,
           ("mppe_compress[%d]: ccount %d\n", pcb->netif->num, state->ccount));
  /* FIXME: use PUT* macros */
  pl[0] = state->ccount >> 8;
  pl[1] = state->ccount;

  if (!state->stateful ||                 /* stateless mode     */
      ((state->ccount & 0xff) == 0xff) || /* "flag" packet      */
      (state->bits & MPPE_BIT_FLUSHED)) { /* CCP Reset-Request  */
    /* We must rekey */
    if (state->stateful) {
      PPPDEBUG(LOG_DEBUG, ("mppe_compress[%d]: rekeying\n", pcb->netif->num));
    }
    mppe_rekey(state, 0);
    state->bits |= MPPE_BIT_FLUSHED;
  }
  pl[0] |= state->bits;
  state->bits &= ~MPPE_BIT_FLUSHED; /* reset for next xmit */
  pl += MPPE_OVHD;

  /* Add protocol */
  /* FIXME: add PFC support */
  pl[0] = protocol >> 8;
  pl[1] = protocol;

  /* Hide MPPE header */
  pbuf_remove_header(np, MPPE_OVHD);

  /* Encrypt packet */
  for (n = np; n != NULL; n = n->next) {
    lwip_arc4_crypt(&state->arc4, (u8_t *)n->payload, n->len);
    if (n->tot_len == n->len) {
      break;
    }
  }

  /* Reveal MPPE header */
  pbuf_add_header(np, MPPE_OVHD);

  return ERR_OK;
}

void mppe_decomp_reset(ppp_pcb *pcb, ppp_mppe_state *state) {
  LWIP_UNUSED_ARG(pcb);
  LWIP_UNUSED_ARG(state);
  return;
}

err_t mppe_decompress(ppp_pcb *pcb, ppp_mppe_state *state, struct pbuf **pb) {
  struct pbuf *n0 = *pb, *n;
  u8_t *pl;
  u16_t ccount;
  u8_t flushed;

  /* MPPE Header */
  if (n0->len < MPPE_OVHD) {
    PPPDEBUG(LOG_DEBUG, ("mppe_decompress[%d]: short pkt (%d)\n",
                         pcb->netif->num, n0->len));
    state->sanity_errors += 100;
    goto sanity_error;
  }

  pl = (u8_t *)n0->payload;
  flushed = MPPE_BITS(pl) & MPPE_BIT_FLUSHED;
  ccount = MPPE_CCOUNT(pl);
  PPPDEBUG(LOG_DEBUG,
           ("mppe_decompress[%d]: ccount %d\n", pcb->netif->num, ccount));

  /* sanity checks -- terminate with extreme prejudice */
  if (!(MPPE_BITS(pl) & MPPE_BIT_ENCRYPTED)) {
    PPPDEBUG(LOG_DEBUG, ("mppe_decompress[%d]: ENCRYPTED bit not set!\n",
                         pcb->netif->num));
    state->sanity_errors += 100;
    goto sanity_error;
  }
  if (!state->stateful && !flushed) {
    PPPDEBUG(LOG_DEBUG, ("mppe_decompress[%d]: FLUSHED bit not set in "
                         "stateless mode!\n",
                         pcb->netif->num));
    state->sanity_errors += 100;
    goto sanity_error;
  }
  if (state->stateful && ((ccount & 0xff) == 0xff) && !flushed) {
    PPPDEBUG(LOG_DEBUG, ("mppe_decompress[%d]: FLUSHED bit not set on "
                         "flag packet!\n",
                         pcb->netif->num));
    state->sanity_errors += 100;
    goto sanity_error;
  }

  /*
   * Check the coherency count.
   */

  if (!state->stateful) {
    /* Discard late packet */
    if ((ccount - state->ccount) % MPPE_CCOUNT_SPACE > MPPE_CCOUNT_SPACE / 2) {
      state->sanity_errors++;
      goto sanity_error;
    }

    /* RFC 3078, sec 8.1.  Rekey for every packet. */
    while (state->ccount != ccount) {
      mppe_rekey(state, 0);
      state->ccount = (state->ccount + 1) % MPPE_CCOUNT_SPACE;
    }
  } else {
    /* RFC 3078, sec 8.2. */
    if (!state->discard) {
      /* normal state */
      state->ccount = (state->ccount + 1) % MPPE_CCOUNT_SPACE;
      if (ccount != state->ccount) {
        /*
         * (ccount > state->ccount)
         * Packet loss detected, enter the discard state.
         * Signal the peer to rekey (by sending a CCP Reset-Request).
         */
        state->discard = 1;
        ccp_resetrequest(pcb);
        return ERR_BUF;
      }
    } else {
      /* discard state */
      if (!flushed) {
        /* ccp.c will be silent (no additional CCP Reset-Requests). */
        return ERR_BUF;
      } else {
        /* Rekey for every missed "flag" packet. */
        while ((ccount & ~0xff) != (state->ccount & ~0xff)) {
          mppe_rekey(state, 0);
          state->ccount = (state->ccount + 256) % MPPE_CCOUNT_SPACE;
        }

        /* reset */
        state->discard = 0;
        state->ccount = ccount;
        /*
         * Another problem with RFC 3078 here.  It implies that the
         * peer need not send a Reset-Ack packet.  But RFC 1962
         * requires it.  Hopefully, M$ does send a Reset-Ack; even
         * though it isn't required for MPPE synchronization, it is
         * required to reset CCP state.
         */
      }
    }
    if (flushed)
      mppe_rekey(state, 0);
  }

  /* Hide MPPE header */
  pbuf_remove_header(n0, MPPE_OVHD);

  /* Decrypt the packet. */
  for (n = n0; n != NULL; n = n->next) {
    lwip_arc4_crypt(&state->arc4, (u8_t *)n->payload, n->len);
    if (n->tot_len == n->len) {
      break;
    }
  }

  /* good packet credit */
  state->sanity_errors >>= 1;

  return ERR_OK;

sanity_error:
  if (state->sanity_errors >= SANITY_MAX) {
    /*
     * Take LCP down if the peer is sending too many bogons.
     * We don't want to do this for a single or just a few
     * instances since it could just be due to packet corruption.
     */
    lcp_close(pcb, "Too many MPPE errors");
  }
  return ERR_BUF;
}

void mp_check_options() {
  lcp_options *wo = &lcp_wantoptions[0];
  lcp_options *ao = &lcp_allowoptions[0];

  doing_multilink = 0;
  if (!multilink)
    return;
  /* if we're doing multilink, we have to negotiate MRRU */
  if (!wo->neg_mrru) {
    /* mrru not specified, default to mru */
    wo->mrru = wo->mru;
    wo->neg_mrru = 1;
  }
  ao->mrru = ao->mru;
  ao->neg_mrru = 1;

  if (!wo->neg_endpoint && !noendpoint) {
    /* get a default endpoint value */
    wo->neg_endpoint = get_default_epdisc(&wo->endpoint);
  }
}

int mp_join_bundle() {
  lcp_options *go = &lcp_gotoptions[0];
  lcp_options *ho = &lcp_hisoptions[0];
  lcp_options *ao = &lcp_allowoptions[0];
  int unit, pppd_pid;
  int l, mtu;
  char *p;
  TDB_DATA key, pid, rec;

  if (doing_multilink) {
    /* have previously joined a bundle */
    if (!go->neg_mrru || !ho->neg_mrru) {
      notice("oops, didn't get multilink on renegotiation");
      lcp_close(pcb, "multilink required");
      return 0;
    }
    /* XXX should check the peer_authname and ho->endpoint
       are the same as previously */
    return 0;
  }

  if (!go->neg_mrru || !ho->neg_mrru) {
    /* not doing multilink */
    if (go->neg_mrru)
      notice("oops, multilink negotiated only for receive");
    mtu = ho->neg_mru ? ho->mru : PPP_DEFMRU;
    if (mtu > ao->mru)
      mtu = ao->mru;
    if (demand) {
      /* already have a bundle */
      cfg_bundle(0, 0, 0, 0);
      ppp_netif_set_mtu(pcb, mtu);
      return 0;
    }
    make_new_bundle(0, 0, 0, 0);
    set_ifunit(1);
    ppp_netif_set_mtu(pcb, mtu);
    return 0;
  }

  doing_multilink = 1;

  /*
   * Find the appropriate bundle or join a new one.
   * First we make up a name for the bundle.
   * The length estimate is worst-case assuming every
   * character has to be quoted.
   */
  l = 4 * strlen(peer_authname) + 10;
  if (ho->neg_endpoint)
    l += 3 * ho->endpoint.length + 8;
  if (bundle_name)
    l += 3 * strlen(bundle_name) + 2;
  bundle_id = malloc(l);
  if (bundle_id == 0)
    novm("bundle identifier");

  p = bundle_id;
  p += slprintf(p, l - 1, "BUNDLE=\"%q\"", peer_authname);
  if (ho->neg_endpoint || bundle_name)
    *p++ = '/';
  if (ho->neg_endpoint)
    p += slprintf(p, bundle_id + l - p, "%s", epdisc_to_str(&ho->endpoint));
  if (bundle_name)
    p += slprintf(p, bundle_id + l - p, "/%v", bundle_name);

  /* Make the key for the list of links belonging to the bundle */
  l = p - bundle_id;
  blinks_id = malloc(l + 7);
  if (blinks_id == NULL)
    novm("bundle links key");
  slprintf(blinks_id, l + 7, "BUNDLE_LINKS=%s", bundle_id + 7);

  /*
   * For demand mode, we only need to configure the bundle
   * and attach the link.
   */
  mtu = LWIP_MIN(ho->mrru, ao->mru);
  if (demand) {
    cfg_bundle(go->mrru, ho->mrru, go->neg_ssnhf, ho->neg_ssnhf);
    ppp_netif_set_mtu(pcb, mtu);
    script_setenv("BUNDLE", bundle_id + 7, 1);
    return 0;
  }

  /*
   * Check if the bundle ID is already in the database.
   */
  unit = -1;
  lock_db();
  key.dptr = bundle_id;
  key.dsize = p - bundle_id;
  pid = tdb_fetch(pppdb, key);
  if (pid.dptr != NULL) {
    /* bundle ID exists, see if the pppd record exists */
    rec = tdb_fetch(pppdb, pid);
    if (rec.dptr != NULL && rec.dsize > 0) {
      /* make sure the string is null-terminated */
      rec.dptr[rec.dsize - 1] = 0;
      /* parse the interface number */
      parse_num(rec.dptr, "IFNAME=ppp", &unit);
      /* check the pid value */
      if (!parse_num(rec.dptr, "PPPD_PID=", &pppd_pid) ||
          !process_exists(pppd_pid) || !owns_unit(pid, unit))
        unit = -1;
      free(rec.dptr);
    }
    free(pid.dptr);
  }

  if (unit >= 0) {
    /* attach to existing unit */
    if (bundle_attach(unit)) {
      set_ifunit(0);
      script_setenv("BUNDLE", bundle_id + 7, 0);
      make_bundle_links(1);
      unlock_db();
      info("Link attached to %s", ifname);
      return 1;
    }
    /* attach failed because bundle doesn't exist */
  }

  /* we have to make a new bundle */
  make_new_bundle(go->mrru, ho->mrru, go->neg_ssnhf, ho->neg_ssnhf);
  set_ifunit(1);
  ppp_netif_set_mtu(pcb, mtu);
  script_setenv("BUNDLE", bundle_id + 7, 1);
  make_bundle_links(pcb);
  unlock_db();
  info("New bundle %s created", ifname);
  multilink_master = 1;
  return 0;
}

void mp_exit_bundle() {
  lock_db();
  remove_bundle_link();
  unlock_db();
}

static void sendhup(char *str) {
  int pid;

  if (parse_num(str, "PPPD_PID=", &pid) && pid != getpid()) {
    if (debug)
      dbglog("sending SIGHUP to process %d", pid);
    kill(pid, SIGHUP);
  }
}

void mp_bundle_terminated() {
  TDB_DATA key;

  bundle_terminating = 1;
  upper_layers_down(pcb);
  notice("Connection terminated.");
#if PPP_STATS_SUPPORT
  print_link_stats();
#endif /* PPP_STATS_SUPPORT */
  if (!demand) {
    remove_pidfiles();
    script_unsetenv("IFNAME");
  }

  lock_db();
  destroy_bundle();
  iterate_bundle_links(sendhup);
  key.dptr = blinks_id;
  key.dsize = strlen(blinks_id);
  tdb_delete(pppdb, key);
  unlock_db();

  new_phase(PPP_PHASE_DEAD);

  doing_multilink = 0;
  multilink_master = 0;
}

static void make_bundle_links(int append) {
  TDB_DATA key, rec;
  char *p;
  char entry[32];
  int l;

  key.dptr = blinks_id;
  key.dsize = strlen(blinks_id);
  slprintf(entry, sizeof(entry), "%s;", db_key);
  p = entry;
  if (append) {
    rec = tdb_fetch(pppdb, key);
    if (rec.dptr != NULL && rec.dsize > 0) {
      rec.dptr[rec.dsize - 1] = 0;
      if (strstr(rec.dptr, db_key) != NULL) {
        /* already in there? strange */
        warn("link entry already exists in tdb");
        return;
      }
      l = rec.dsize + strlen(entry);
      p = malloc(l);
      if (p == NULL)
        novm("bundle link list");
      slprintf(p, l, "%s%s", rec.dptr, entry);
    } else {
      warn("bundle link list not found");
    }
    if (rec.dptr != NULL)
      free(rec.dptr);
  }
  rec.dptr = p;
  rec.dsize = strlen(p) + 1;
  if (tdb_store(pppdb, key, rec, TDB_REPLACE))
    error("couldn't %s bundle link list", append ? "update" : "create");
  if (p != entry)
    free(p);
}

static void remove_bundle_link() {
  TDB_DATA key, rec;
  char entry[32];
  char *p, *q;
  int l;

  key.dptr = blinks_id;
  key.dsize = strlen(blinks_id);
  slprintf(entry, sizeof(entry), "%s;", db_key);

  rec = tdb_fetch(pppdb, key);
  if (rec.dptr == NULL || rec.dsize <= 0) {
    if (rec.dptr != NULL)
      free(rec.dptr);
    return;
  }
  rec.dptr[rec.dsize - 1] = 0;
  p = strstr(rec.dptr, entry);
  if (p != NULL) {
    q = p + strlen(entry);
    l = strlen(q) + 1;
    memmove(p, q, l);
    rec.dsize = p - rec.dptr + l;
    if (tdb_store(pppdb, key, rec, TDB_REPLACE))
      error("couldn't update bundle link list (removal)");
  }
  free(rec.dptr);
}

static void iterate_bundle_links(void (*func)(char *)) {
  TDB_DATA key, rec, pp;
  char *p, *q;

  key.dptr = blinks_id;
  key.dsize = strlen(blinks_id);
  rec = tdb_fetch(pppdb, key);
  if (rec.dptr == NULL || rec.dsize <= 0) {
    error("bundle link list not found (iterating list)");
    if (rec.dptr != NULL)
      free(rec.dptr);
    return;
  }
  p = rec.dptr;
  p[rec.dsize - 1] = 0;
  while ((q = strchr(p, ';')) != NULL) {
    *q = 0;
    key.dptr = p;
    key.dsize = q - p;
    pp = tdb_fetch(pppdb, key);
    if (pp.dptr != NULL && pp.dsize > 0) {
      pp.dptr[pp.dsize - 1] = 0;
      func(pp.dptr);
    }
    if (pp.dptr != NULL)
      free(pp.dptr);
    p = q + 1;
  }
  free(rec.dptr);
}

static int parse_num(str, key, valp)
char *str;
const char *key;
int *valp;
{
  char *p, *endp;
  int i;

  p = strstr(str, key);
  if (p != 0) {
    p += strlen(key);
    i = strtol(p, &endp, 10);
    if (endp != p && (*endp == 0 || *endp == ';')) {
      *valp = i;
      return 1;
    }
  }
  return 0;
}

static int owns_unit(key, unit)
TDB_DATA key;
int unit;
{
  char ifkey[32];
  TDB_DATA kd, vd;
  int ret = 0;

  slprintf(ifkey, sizeof(ifkey), "IFNAME=ppp%d", unit);
  kd.dptr = ifkey;
  kd.dsize = strlen(ifkey);
  vd = tdb_fetch(pppdb, kd);
  if (vd.dptr != NULL) {
    ret = vd.dsize == key.dsize && memcmp(vd.dptr, key.dptr, vd.dsize) == 0;
    free(vd.dptr);
  }
  return ret;
}

static int get_default_epdisc(ep)
struct epdisc *ep;
{
  char *p;
  struct hostent *hp;
  u32_t addr;

  /* First try for an ethernet MAC address */
  p = get_first_ethernet();
  if (p != 0 && get_if_hwaddr(ep->value, p) >= 0) {
    ep->class = EPD_MAC;
    ep->length = 6;
    return 1;
  }

  /* see if our hostname corresponds to a reasonable IP address */
  hp = gethostbyname(hostname);
  if (hp != NULL) {
    addr = *(u32_t *)hp->h_addr;
    if (!bad_ip_adrs(addr)) {
      addr = lwip_ntohl(addr);
      if (!LOCAL_IP_ADDR(addr)) {
        ep->class = EPD_IP;
        set_ip_epdisc(ep, addr);
        return 1;
      }
    }
  }

  return 0;
}

static int hexc_val(int c) {
  if (c >= 'a')
    return c - 'a' + 10;
  if (c >= 'A')
    return c - 'A' + 10;
  return c - '0';
}

int str_to_epdisc(ep, str)
struct epdisc *ep;
char *str;
{
  int i, l;
  char *p, *endp;

  for (i = EPD_NULL; i <= EPD_PHONENUM; ++i) {
    int sl = strlen(endp_class_names[i]);
    if (strncasecmp(str, endp_class_names[i], sl) == 0) {
      str += sl;
      break;
    }
  }
  if (i > EPD_PHONENUM) {
    /* not a class name, try a decimal class number */
    i = strtol(str, &endp, 10);
    if (endp == str)
      return 0; /* can't parse class number */
    str = endp;
  }
  ep->class = i;
  if (*str == 0) {
    ep->length = 0;
    return 1;
  }
  if (*str != ':' && *str != '.')
    return 0;
  ++str;

  if (i == EPD_IP) {
    u32_t addr;
    i = parse_dotted_ip(str, &addr);
    if (i == 0 || str[i] != 0)
      return 0;
    set_ip_epdisc(ep, addr);
    return 1;
  }
  if (i == EPD_MAC && get_if_hwaddr(ep->value, str) >= 0) {
    ep->length = 6;
    return 1;
  }

  p = str;
  for (l = 0; l < MAX_ENDP_LEN; ++l) {
    if (*str == 0)
      break;
    if (p <= str)
      for (p = str; isxdigit(*p); ++p)
        ;
    i = p - str;
    if (i == 0)
      return 0;
    ep->value[l] = hexc_val(*str++);
    if ((i & 1) == 0)
      ep->value[l] = (ep->value[l] << 4) + hexc_val(*str++);
    if (*str == ':' || *str == '.')
      ++str;
  }
  if (*str != 0 || (ep->class == EPD_MAC && l != 6))
    return 0;
  ep->length = l;
  return 1;
}

void ppp_set_auth(ppp_pcb *pcb, u8_t authtype, const char *user,
                  const char *passwd) {
  LWIP_ASSERT("pcb->phase == PPP_PHASE_DEAD", pcb->phase == PPP_PHASE_DEAD);

#if PAP_SUPPORT
  pcb->settings.refuse_pap = !(authtype & PPPAUTHTYPE_PAP);
#endif /* PAP_SUPPORT */
#if CHAP_SUPPORT
  pcb->settings.refuse_chap = !(authtype & PPPAUTHTYPE_CHAP);
#if MSCHAP_SUPPORT
  pcb->settings.refuse_mschap = !(authtype & PPPAUTHTYPE_MSCHAP);
  pcb->settings.refuse_mschap_v2 = !(authtype & PPPAUTHTYPE_MSCHAP_V2);
#endif /* MSCHAP_SUPPORT */
#endif /* CHAP_SUPPORT */
#if EAP_SUPPORT
  pcb->settings.refuse_eap = !(authtype & PPPAUTHTYPE_EAP);
#endif /* EAP_SUPPORT */
  pcb->settings.user = user;
  pcb->settings.passwd = passwd;
}

void ppp_set_mppe(ppp_pcb *pcb, u8_t flags) {
  LWIP_ASSERT("pcb->phase == PPP_PHASE_DEAD", pcb->phase == PPP_PHASE_DEAD);

  if (flags == PPP_MPPE_DISABLE) {
    pcb->settings.require_mppe = 0;
    return;
  }

  pcb->settings.require_mppe = 1;
  pcb->settings.refuse_mppe_stateful = !(flags & PPP_MPPE_ALLOW_STATEFUL);
  pcb->settings.refuse_mppe_40 = !!(flags & PPP_MPPE_REFUSE_40);
  pcb->settings.refuse_mppe_128 = !!(flags & PPP_MPPE_REFUSE_128);
}

void ppp_set_notify_phase_callback(ppp_pcb *pcb,
                                   ppp_notify_phase_cb_fn notify_phase_cb) {
  LWIP_ASSERT_CORE_LOCKED();
  pcb->notify_phase_cb = notify_phase_cb;
  notify_phase_cb(pcb, pcb->phase, pcb->ctx_cb);
}

err_t ppp_connect(ppp_pcb *pcb, u16_t holdoff) {
  LWIP_ASSERT_CORE_LOCKED();
  if (pcb->phase != PPP_PHASE_DEAD) {
    return ERR_ALREADY;
  }

  PPPDEBUG(LOG_DEBUG,
           ("ppp_connect[%d]: holdoff=%d\n", pcb->netif->num, holdoff));

  magic_randomize();

  if (holdoff == 0) {
    ppp_do_connect(pcb);
    return ERR_OK;
  }

  new_phase(pcb, PPP_PHASE_HOLDOFF);
  sys_timeout((u32_t)(holdoff * 1000), ppp_do_connect, pcb);
  return ERR_OK;
}

err_t ppp_listen(ppp_pcb *pcb) {
  LWIP_ASSERT_CORE_LOCKED();
  if (pcb->phase != PPP_PHASE_DEAD) {
    return ERR_ALREADY;
  }

  PPPDEBUG(LOG_DEBUG, ("ppp_listen[%d]\n", pcb->netif->num));

  magic_randomize();

  if (pcb->link_cb->listen) {
    new_phase(pcb, PPP_PHASE_INITIALIZE);
    pcb->link_cb->listen(pcb, pcb->link_ctx_cb);
    return ERR_OK;
  }
  return ERR_IF;
}

err_t ppp_close(ppp_pcb *pcb, u8_t nocarrier) {
  LWIP_ASSERT_CORE_LOCKED();

  pcb->err_code = PPPERR_USER;

  /* holdoff phase, cancel the reconnection */
  if (pcb->phase == PPP_PHASE_HOLDOFF) {
    sys_untimeout(ppp_do_connect, pcb);
    new_phase(pcb, PPP_PHASE_DEAD);
  }

  /* dead phase, nothing to do, call the status callback to be consistent */
  if (pcb->phase == PPP_PHASE_DEAD) {
    pcb->link_status_cb(pcb, pcb->err_code, pcb->ctx_cb);
    return ERR_OK;
  }

  /* Already terminating, nothing to do */
  if (pcb->phase >= PPP_PHASE_TERMINATE) {
    return ERR_INPROGRESS;
  }

  /* LCP not open, close link protocol */
  if (pcb->phase < PPP_PHASE_ESTABLISH) {
    new_phase(pcb, PPP_PHASE_DISCONNECT);
    ppp_link_terminated(pcb);
    return ERR_OK;
  }

  /*
   * Only accept carrier lost signal on the stable running phase in order
   * to prevent changing the PPP phase FSM in transition phases.
   *
   * Always using nocarrier = 0 is still recommended, this is going to
   * take a little longer time, but is a safer choice from FSM point of view.
   */
  if (nocarrier && pcb->phase == PPP_PHASE_RUNNING) {
    PPPDEBUG(LOG_DEBUG, ("ppp_close[%d]: carrier lost -> lcp_lowerdown\n",
                         pcb->netif->num));
    lcp_lowerdown(pcb);
    /* forced link termination, this will force link protocol to disconnect. */
    link_terminated(pcb);
    return ERR_OK;
  }

  /* Disconnect */
  PPPDEBUG(LOG_DEBUG,
           ("ppp_close[%d]: kill_link -> lcp_close\n", pcb->netif->num));
  /* LCP soft close request. */
  lcp_close(pcb, "User request");
  return ERR_OK;
}

err_t ppp_free(ppp_pcb *pcb) {
  err_t err;
  LWIP_ASSERT_CORE_LOCKED();
  if (pcb->phase != PPP_PHASE_DEAD) {
    return ERR_CONN;
  }

  PPPDEBUG(LOG_DEBUG, ("ppp_free[%d]\n", pcb->netif->num));

  netif_remove(pcb->netif);

  err = pcb->link_cb->free(pcb, pcb->link_ctx_cb);

  LWIP_MEMPOOL_FREE(PPP_PCB, pcb);
  return err;
}

err_t ppp_ioctl(ppp_pcb *pcb, u8_t cmd, void *arg) {
  LWIP_ASSERT_CORE_LOCKED();
  if (pcb == NULL) {
    return ERR_VAL;
  }

  switch (cmd) {
  case PPPCTLG_UPSTATUS: /* Get the PPP up status. */
    if (!arg) {
      goto fail;
    }
    *(int *)arg = (int)(0
#if PPP_IPV4_SUPPORT
                        || pcb->if4_up
#endif /* PPP_IPV4_SUPPORT */
#if PPP_IPV6_SUPPORT
                        || pcb->if6_up
#endif /* PPP_IPV6_SUPPORT */
    );
    return ERR_OK;

  case PPPCTLG_ERRCODE: /* Get the PPP error code. */
    if (!arg) {
      goto fail;
    }
    *(int *)arg = (int)(pcb->err_code);
    return ERR_OK;

  default:
    goto fail;
  }

fail:
  return ERR_VAL;
}

static void ppp_do_connect(void *arg) {
  ppp_pcb *pcb = (ppp_pcb *)arg;

  LWIP_ASSERT("pcb->phase == PPP_PHASE_DEAD || pcb->phase == PPP_PHASE_HOLDOFF",
              pcb->phase == PPP_PHASE_DEAD || pcb->phase == PPP_PHASE_HOLDOFF);

  new_phase(pcb, PPP_PHASE_INITIALIZE);
  pcb->link_cb->connect(pcb, pcb->link_ctx_cb);
}

static err_t ppp_netif_init_cb(struct netif *netif) {
  netif->name[0] = 'p';
  netif->name[1] = 'p';
#if PPP_IPV4_SUPPORT
  netif->output = ppp_netif_output_ip4;
#endif /* PPP_IPV4_SUPPORT */
#if PPP_IPV6_SUPPORT
  netif->output_ip6 = ppp_netif_output_ip6;
#endif /* PPP_IPV6_SUPPORT */
#if LWIP_NETIF_HOSTNAME
  /* @todo: Initialize interface hostname */
  /* netif_set_hostname(netif, "lwip"); */
#endif /* LWIP_NETIF_HOSTNAME */
  return ERR_OK;
}

static err_t ppp_netif_output_ip4(struct netif *netif, struct pbuf *pb,
                                  const ip4_addr_t *ipaddr) {
  LWIP_UNUSED_ARG(ipaddr);
  return ppp_netif_output(netif, pb, PPP_IP);
}

static err_t ppp_netif_output_ip6(struct netif *netif, struct pbuf *pb,
                                  const ip6_addr_t *ipaddr) {
  LWIP_UNUSED_ARG(ipaddr);
  return ppp_netif_output(netif, pb, PPP_IPV6);
}

static err_t ppp_netif_output(struct netif *netif, struct pbuf *pb,
                              u16_t protocol) {
  ppp_pcb *pcb = (ppp_pcb *)netif->state;
  err_t err;
  struct pbuf *fpb = NULL;

  /* Check that the link is up. */
  if (0
#if PPP_IPV4_SUPPORT
      || (protocol == PPP_IP && !pcb->if4_up)
#endif /* PPP_IPV4_SUPPORT */
#if PPP_IPV6_SUPPORT
      || (protocol == PPP_IPV6 && !pcb->if6_up)
#endif /* PPP_IPV6_SUPPORT */
  ) {
    PPPDEBUG(LOG_ERR, ("ppp_netif_output[%d]: link not up\n", pcb->netif->num));
    goto err_rte_drop;
  }

#if MPPE_SUPPORT
  /* If MPPE is required, refuse any IP packet until we are able to crypt them.
   */
  if (pcb->settings.require_mppe && pcb->ccp_transmit_method != CI_MPPE) {
    PPPDEBUG(LOG_ERR, ("ppp_netif_output[%d]: MPPE required, not up\n",
                       pcb->netif->num));
    goto err_rte_drop;
  }
#endif /* MPPE_SUPPORT */

#if VJ_SUPPORT
  /*
   * Attempt Van Jacobson header compression if VJ is configured and
   * this is an IP packet.
   */
  if (protocol == PPP_IP && pcb->vj_enabled) {
    switch (vj_compress_tcp(&pcb->vj_comp, &pb)) {
    case TYPE_IP:
      /* No change...
         protocol = PPP_IP; */
      break;
    case TYPE_COMPRESSED_TCP:
      /* vj_compress_tcp() returns a new allocated pbuf, indicate we should free
       * our duplicated pbuf later */
      fpb = pb;
      protocol = PPP_VJC_COMP;
      break;
    case TYPE_UNCOMPRESSED_TCP:
      /* vj_compress_tcp() returns a new allocated pbuf, indicate we should free
       * our duplicated pbuf later */
      fpb = pb;
      protocol = PPP_VJC_UNCOMP;
      break;
    default:
      PPPDEBUG(LOG_WARNING,
               ("ppp_netif_output[%d]: bad IP packet\n", pcb->netif->num));
      LINK_STATS_INC(link.proterr);
      LINK_STATS_INC(link.drop);
      MIB2_STATS_NETIF_INC(pcb->netif, ifoutdiscards);
      return ERR_VAL;
    }
  }
#endif /* VJ_SUPPORT */

#if CCP_SUPPORT
  switch (pcb->ccp_transmit_method) {
  case 0:
    break; /* Don't compress */
#if MPPE_SUPPORT
  case CI_MPPE:
    if ((err = mppe_compress(pcb, &pcb->mppe_comp, &pb, protocol)) != ERR_OK) {
      LINK_STATS_INC(link.memerr);
      LINK_STATS_INC(link.drop);
      MIB2_STATS_NETIF_INC(netif, ifoutdiscards);
      goto err;
    }
    /* if VJ compressor returned a new allocated pbuf, free it */
    if (fpb) {
      pbuf_free(fpb);
    }
    /* mppe_compress() returns a new allocated pbuf, indicate we should free
     * our duplicated pbuf later */
    fpb = pb;
    protocol = PPP_COMP;
    break;
#endif /* MPPE_SUPPORT */
  default:
    PPPDEBUG(LOG_ERR, ("ppp_netif_output[%d]: bad CCP transmit method\n",
                       pcb->netif->num));
    goto err_rte_drop; /* Cannot really happen, we only negotiate what we are
                          able to do */
  }
#endif /* CCP_SUPPORT */

  err = pcb->link_cb->netif_output(pcb, pcb->link_ctx_cb, pb, protocol);
  goto err;

err_rte_drop:
  err = ERR_RTE;
  LINK_STATS_INC(link.rterr);
  LINK_STATS_INC(link.drop);
  MIB2_STATS_NETIF_INC(netif, ifoutdiscards);
err:
  if (fpb) {
    pbuf_free(fpb);
  }
  return err;
}

int ppp_init(void) {
#if PPPOS_SUPPORT
  LWIP_MEMPOOL_INIT(PPPOS_PCB);
#endif
#if PPPOE_SUPPORT
  LWIP_MEMPOOL_INIT(PPPOE_IF);
#endif
#if PPPOL2TP_SUPPORT
  LWIP_MEMPOOL_INIT(PPPOL2TP_PCB);
#endif
#if LWIP_PPP_API && LWIP_MPU_COMPATIBLE
  LWIP_MEMPOOL_INIT(PPPAPI_MSG);
#endif

  LWIP_MEMPOOL_INIT(PPP_PCB);

  /*
   * Initialize magic number generator now so that protocols may
   * use magic numbers in initialization.
   */
  magic_init();

  return 0;
}

ppp_pcb *ppp_new(struct netif *pppif, const struct link_callbacks *callbacks,
                 void *link_ctx_cb, ppp_link_status_cb_fn link_status_cb,
                 void *ctx_cb) {
  ppp_pcb *pcb;
  const struct protent *protp;
  int i;

  /* PPP is single-threaded: without a callback,
   * there is no way to know when the link is up. */
  if (link_status_cb == NULL) {
    return NULL;
  }

  pcb = (ppp_pcb *)LWIP_MEMPOOL_ALLOC(PPP_PCB);
  if (pcb == NULL) {
    return NULL;
  }

  memset(pcb, 0, sizeof(ppp_pcb));

  /* default configuration */
#if PAP_SUPPORT
  pcb->settings.pap_timeout_time = UPAP_DEFTIMEOUT;
  pcb->settings.pap_max_transmits = UPAP_DEFTRANSMITS;
#if PPP_SERVER
  pcb->settings.pap_req_timeout = UPAP_DEFREQTIME;
#endif /* PPP_SERVER */
#endif /* PAP_SUPPORT */

#if CHAP_SUPPORT
#if PPP_SERVER
  pcb->settings.chap_timeout_time = CHAP_DEFTIMEOUT;
  pcb->settings.chap_max_transmits = CHAP_DEFTRANSMITS;
  pcb->settings.chap_rechallenge_time = CHAP_DEFRECHALLENGETIME;
#endif /* PPP_SERVER */
#endif /* CHAP_SUPPPORT */

#if EAP_SUPPORT
  pcb->settings.eap_req_time = EAP_DEFREQTIME;
  pcb->settings.eap_allow_req = EAP_DEFALLOWREQ;
#if PPP_SERVER
  pcb->settings.eap_timeout_time = EAP_DEFTIMEOUT;
  pcb->settings.eap_max_transmits = EAP_DEFTRANSMITS;
#endif /* PPP_SERVER */
#endif /* EAP_SUPPORT */

  pcb->settings.lcp_loopbackfail = LCP_DEFLOOPBACKFAIL;
  pcb->settings.lcp_echo_interval = LCP_ECHOINTERVAL;
  pcb->settings.lcp_echo_fails = LCP_MAXECHOFAILS;

  pcb->settings.fsm_timeout_time = FSM_DEFTIMEOUT;
  pcb->settings.fsm_max_conf_req_transmits = FSM_DEFMAXCONFREQS;
  pcb->settings.fsm_max_term_transmits = FSM_DEFMAXTERMREQS;
  pcb->settings.fsm_max_nak_loops = FSM_DEFMAXNAKLOOPS;

  pcb->netif = pppif;
  MIB2_INIT_NETIF(pppif, snmp_ifType_ppp, 0);
  if (!netif_add(pcb->netif,
#if LWIP_IPV4
                 IP4_ADDR_ANY4, IP4_ADDR_BROADCAST, IP4_ADDR_ANY4,
#endif /* LWIP_IPV4 */
                 (void *)pcb, ppp_netif_init_cb, NULL)) {
    LWIP_MEMPOOL_FREE(PPP_PCB, pcb);
    PPPDEBUG(LOG_ERR, ("ppp_new: netif_add failed\n"));
    return NULL;
  }
  /* FIXME: user application should be responsible to call netif_set_up(),
   * remove it for next release with allowed behavior break */
  netif_set_up(pcb->netif);

  pcb->link_cb = callbacks;
  pcb->link_ctx_cb = link_ctx_cb;
  pcb->link_status_cb = link_status_cb;
  pcb->ctx_cb = ctx_cb;

  /*
   * Initialize each protocol.
   */
  for (i = 0; (protp = protocols[i]) != NULL; ++i) {
    (*protp->init)(pcb);
  }

  new_phase(pcb, PPP_PHASE_DEAD);
  return pcb;
}

void ppp_start(ppp_pcb *pcb) {
  PPPDEBUG(LOG_DEBUG, ("ppp_start[%d]\n", pcb->netif->num));

  /* Clean data not taken care by anything else, mostly shared data. */
#if PPP_STATS_SUPPORT
  link_stats_valid = 0;
#endif /* PPP_STATS_SUPPORT */
#if MPPE_SUPPORT
  pcb->mppe_keys_set = 0;
  memset(&pcb->mppe_comp, 0, sizeof(pcb->mppe_comp));
  memset(&pcb->mppe_decomp, 0, sizeof(pcb->mppe_decomp));
#endif /* MPPE_SUPPORT */
#if VJ_SUPPORT
  vj_compress_init(&pcb->vj_comp);
#endif /* VJ_SUPPORT */

  /* Start protocol */
  new_phase(pcb, PPP_PHASE_ESTABLISH);
  lcp_open(pcb);
  lcp_lowerup(pcb);
  PPPDEBUG(LOG_DEBUG, ("ppp_start[%d]: finished\n", pcb->netif->num));
}

void ppp_link_failed(ppp_pcb *pcb) {
  PPPDEBUG(LOG_DEBUG, ("ppp_link_failed[%d]\n", pcb->netif->num));
  new_phase(pcb, PPP_PHASE_DEAD);
  pcb->err_code = PPPERR_OPEN;
  pcb->link_status_cb(pcb, pcb->err_code, pcb->ctx_cb);
}

void ppp_link_end(ppp_pcb *pcb) {
  PPPDEBUG(LOG_DEBUG, ("ppp_link_end[%d]\n", pcb->netif->num));
  new_phase(pcb, PPP_PHASE_DEAD);
  if (pcb->err_code == PPPERR_NONE) {
    pcb->err_code = PPPERR_CONNECT;
  }
  pcb->link_status_cb(pcb, pcb->err_code, pcb->ctx_cb);
}

void ppp_input(ppp_pcb *pcb, struct pbuf *pb) {
  u16_t protocol;
#if PPP_DEBUG && PPP_PROTOCOLNAME
  const char *pname;
#endif /* PPP_DEBUG && PPP_PROTOCOLNAME */
  LWIP_ASSERT(
      "pcb->phase >= PPP_PHASE_ESTABLISH && pcb->phase <= PPP_PHASE_TERMINATE",
      pcb->phase >= PPP_PHASE_ESTABLISH && pcb->phase <= PPP_PHASE_TERMINATE);

  magic_randomize();

  if (pb->len < 2) {
    PPPDEBUG(LOG_ERR, ("ppp_input[%d]: packet too short\n", pcb->netif->num));
    goto drop;
  }
  protocol = (((u8_t *)pb->payload)[0] << 8) | ((u8_t *)pb->payload)[1];

#if PRINTPKT_SUPPORT
  ppp_dump_packet(pcb, "rcvd", (unsigned char *)pb->payload, pb->len);
#endif /* PRINTPKT_SUPPORT */

  pbuf_remove_header(pb, sizeof(protocol));

  LINK_STATS_INC(link.recv);
  MIB2_STATS_NETIF_INC(pcb->netif, ifinucastpkts);
  MIB2_STATS_NETIF_ADD(pcb->netif, ifinoctets, pb->tot_len);

  /*
   * Toss all non-LCP packets unless LCP is OPEN.
   */
  if (protocol != PPP_LCP && pcb->lcp_fsm.state != PPP_FSM_OPENED) {
    ppp_dbglog(("Discarded non-LCP packet when LCP not open"));
    goto drop;
  }

  /*
   * Until we get past the authentication phase, toss all packets
   * except LCP, LQR and authentication packets.
   */
  if (pcb->phase <= PPP_PHASE_AUTHENTICATE && !(protocol == PPP_LCP
#if LQR_SUPPORT
                                                || protocol == PPP_LQR
#endif /* LQR_SUPPORT */
#if PAP_SUPPORT
                                                || protocol == PPP_PAP
#endif /* PAP_SUPPORT */
#if CHAP_SUPPORT
                                                || protocol == PPP_CHAP
#endif /* CHAP_SUPPORT */
#if EAP_SUPPORT
                                                || protocol == PPP_EAP
#endif /* EAP_SUPPORT */
                                                )) {
    ppp_dbglog(("discarding proto 0x%x in phase %d", protocol, pcb->phase));
    goto drop;
  }

#if CCP_SUPPORT
#if MPPE_SUPPORT
  /*
   * MPPE is required and unencrypted data has arrived (this
   * should never happen!). We should probably drop the link if
   * the protocol is in the range of what should be encrypted.
   * At the least, we drop this packet.
   */
  if (pcb->settings.require_mppe && protocol != PPP_COMP && protocol < 0x8000) {
    PPPDEBUG(LOG_ERR,
             ("ppp_input[%d]: MPPE required, received unencrypted data!\n",
              pcb->netif->num));
    goto drop;
  }
#endif /* MPPE_SUPPORT */

  if (protocol == PPP_COMP) {
    u8_t *pl;

    switch (pcb->ccp_receive_method) {
#if MPPE_SUPPORT
    case CI_MPPE:
      if (mppe_decompress(pcb, &pcb->mppe_decomp, &pb) != ERR_OK) {
        goto drop;
      }
      break;
#endif /* MPPE_SUPPORT */
    default:
      PPPDEBUG(LOG_ERR,
               ("ppp_input[%d]: bad CCP receive method\n", pcb->netif->num));
      goto drop; /* Cannot really happen, we only negotiate what we are able to
                    do */
    }

    /* Assume no PFC */
    if (pb->len < 2) {
      goto drop;
    }

    /* Extract and hide protocol (do PFC decompression if necessary) */
    pl = (u8_t *)pb->payload;
    if (pl[0] & 0x01) {
      protocol = pl[0];
      pbuf_remove_header(pb, 1);
    } else {
      protocol = (pl[0] << 8) | pl[1];
      pbuf_remove_header(pb, 2);
    }
  }
#endif /* CCP_SUPPORT */

  switch (protocol) {

#if PPP_IPV4_SUPPORT
  case PPP_IP: /* Internet Protocol */
    PPPDEBUG(LOG_INFO, ("ppp_input[%d]: ip in pbuf len=%d\n", pcb->netif->num,
                        pb->tot_len));
    ip4_input(pb, pcb->netif);
    return;
#endif /* PPP_IPV4_SUPPORT */

#if PPP_IPV6_SUPPORT
  case PPP_IPV6: /* Internet Protocol Version 6 */
    PPPDEBUG(LOG_INFO, ("ppp_input[%d]: ip6 in pbuf len=%d\n", pcb->netif->num,
                        pb->tot_len));
    ip6_input(pb, pcb->netif);
    return;
#endif /* PPP_IPV6_SUPPORT */

#if VJ_SUPPORT
  case PPP_VJC_COMP: /* VJ compressed TCP */
    /*
     * Clip off the VJ header and prepend the rebuilt TCP/IP header and
     * pass the result to IP.
     */
    PPPDEBUG(LOG_INFO, ("ppp_input[%d]: vj_comp in pbuf len=%d\n",
                        pcb->netif->num, pb->tot_len));
    if (pcb->vj_enabled && vj_uncompress_tcp(&pb, &pcb->vj_comp) >= 0) {
      ip4_input(pb, pcb->netif);
      return;
    }
    /* Something's wrong so drop it. */
    PPPDEBUG(LOG_WARNING,
             ("ppp_input[%d]: Dropping VJ compressed\n", pcb->netif->num));
    break;

  case PPP_VJC_UNCOMP: /* VJ uncompressed TCP */
    /*
     * Process the TCP/IP header for VJ header compression and then pass
     * the packet to IP.
     */
    PPPDEBUG(LOG_INFO, ("ppp_input[%d]: vj_un in pbuf len=%d\n",
                        pcb->netif->num, pb->tot_len));
    if (pcb->vj_enabled && vj_uncompress_uncomp(pb, &pcb->vj_comp) >= 0) {
      ip4_input(pb, pcb->netif);
      return;
    }
    /* Something's wrong so drop it. */
    PPPDEBUG(LOG_WARNING,
             ("ppp_input[%d]: Dropping VJ uncompressed\n", pcb->netif->num));
    break;
#endif /* VJ_SUPPORT */

  default: {
    int i;
    const struct protent *protp;

    /*
     * Upcall the proper protocol input routine.
     */
    for (i = 0; (protp = protocols[i]) != NULL; ++i) {
      if (protp->protocol == protocol) {
        pb = pbuf_coalesce(pb, PBUF_RAW);
        if (pb->next != NULL) {
          PPPDEBUG(LOG_WARNING,
                   ("ppp_input[%d]: Dropping (pbuf_coalesce failed), len=%d\n",
                    pcb->netif->num, pb->tot_len));
          goto drop;
        }
        (*protp->input)(pcb, (u8_t *)pb->payload, pb->len);
        goto out;
      }
#if 0  /* UNUSED                                                                \
        *                                                                       \
        * This is actually a (hacked?) way for the Linux kernel to pass a data  \
        * packet to pppd. pppd in normal condition only do signaling            \
        * (LCP, PAP, CHAP, IPCP, ...) and does not handle any data packet at    \
        * all.                                                                  \
        *                                                                       \
        * We don't even need this interface, which is only there because of PPP \
        * interface limitation between Linux kernel and pppd. For MPPE, which   \
        * uses  CCP to negotiate although it is not really a (de)compressor, we               \
        * added  ccp_resetrequest() in CCP and MPPE input data flow is calling                 \
        * either  ccp_resetrequest() or lcp_close() if the issue is,                            \
        * respectively, non-fatal  or fatal, this is what ccp_datainput() really                                 \
        * do.                                                                   \
        */
        if (protocol == (protp->protocol & ~0x8000)
          && protp->datainput != NULL) {
          (*protp->datainput)(pcb, pb->payload, pb->len);
          goto out;
        }
#endif /* UNUSED */
    }

#if PPP_DEBUG
#if PPP_PROTOCOLNAME
    pname = protocol_name(protocol);
    if (pname != NULL) {
      ppp_warn(("Unsupported protocol '%s' (0x%x) received", pname, protocol));
    } else
#endif /* PPP_PROTOCOLNAME */
      ppp_warn(("Unsupported protocol 0x%x received", protocol));
#endif /* PPP_DEBUG */

    if (pbuf_add_header(pb, sizeof(protocol))) {
      PPPDEBUG(LOG_WARNING,
               ("ppp_input[%d]: Dropping (pbuf_add_header failed)\n",
                pcb->netif->num));
      goto drop;
    }
    lcp_sprotrej(pcb, (u8_t *)pb->payload, pb->len);
  } break;
  }

drop:
  LINK_STATS_INC(link.drop);
  MIB2_STATS_NETIF_INC(pcb->netif, ifindiscards);

out:
  pbuf_free(pb);
}

