}

err_t pppapi_close(ppp_pcb *pcb, u8_t nocarrier) {
  err_t err;
  PPPAPI_VAR_DECLARE(msg);
  PPPAPI_VAR_ALLOC(msg);

  PPPAPI_VAR_REF(msg).msg.ppp = pcb;
  PPPAPI_VAR_REF(msg).msg.msg.close.nocarrier = nocarrier;
  err = tcpip_api_call(pppapi_do_ppp_close, &PPPAPI_VAR_REF(msg).call);
  PPPAPI_VAR_FREE(msg);
  return err;
}

static err_t pppapi_do_ppp_free(struct tcpip_api_call_data *m) {
  /* cast through void* to silence alignment warnings.
   * We know it works because the structs have been instantiated as struct
   * pppapi_msg */
  struct pppapi_msg *msg = (struct pppapi_msg *)(void *)m;

  return ppp_free(msg->msg.ppp);
}

err_t pppapi_free(ppp_pcb *pcb) {
  err_t err;
  PPPAPI_VAR_DECLARE(msg);
  PPPAPI_VAR_ALLOC(msg);

  PPPAPI_VAR_REF(msg).msg.ppp = pcb;
  err = tcpip_api_call(pppapi_do_ppp_free, &PPPAPI_VAR_REF(msg).call);
  PPPAPI_VAR_FREE(msg);
  return err;
}

static err_t pppapi_do_ppp_ioctl(struct tcpip_api_call_data *m) {
  /* cast through void* to silence alignment warnings.
   * We know it works because the structs have been instantiated as struct
   * pppapi_msg */
  struct pppapi_msg *msg = (struct pppapi_msg *)(void *)m;

  return ppp_ioctl(msg->msg.ppp, msg->msg.msg.ioctl.cmd,
                   msg->msg.msg.ioctl.arg);
}

err_t pppapi_ioctl(ppp_pcb *pcb, u8_t cmd, void *arg) {
  err_t err;
  PPPAPI_VAR_DECLARE(msg);
  PPPAPI_VAR_ALLOC(msg);

  PPPAPI_VAR_REF(msg).msg.ppp = pcb;
  PPPAPI_VAR_REF(msg).msg.msg.ioctl.cmd = cmd;
  PPPAPI_VAR_REF(msg).msg.msg.ioctl.arg = arg;
  err = tcpip_api_call(pppapi_do_ppp_ioctl, &PPPAPI_VAR_REF(msg).call);
  PPPAPI_VAR_FREE(msg);
  return err;
}

static u_char pppcrypt_get_7bits(u_char *input, int startBit) {
  unsigned int word;

  word = (unsigned)input[startBit / 8] << 8;
  word |= (unsigned)input[startBit / 8 + 1];

  word >>= 15 - (startBit % 8 + 7);

  return word & 0xFE;
}

void pppcrypt_56_to_64_bit_key(u_char *key, u_char *des_key) {
  des_key[0] = pppcrypt_get_7bits(key, 0);
  des_key[1] = pppcrypt_get_7bits(key, 7);
  des_key[2] = pppcrypt_get_7bits(key, 14);
  des_key[3] = pppcrypt_get_7bits(key, 21);
  des_key[4] = pppcrypt_get_7bits(key, 28);
  des_key[5] = pppcrypt_get_7bits(key, 35);
  des_key[6] = pppcrypt_get_7bits(key, 42);
  des_key[7] = pppcrypt_get_7bits(key, 49);
}

ppp_pcb *pppoe_create(struct netif *pppif, struct netif *ethif,
                      const char *service_name, const char *concentrator_name,
                      ppp_link_status_cb_fn link_status_cb, void *ctx_cb) {
  ppp_pcb *ppp;
  struct pppoe_softc *sc;
#if PPPOE_SCNAME_SUPPORT
  size_t l;
#else  /* PPPOE_SCNAME_SUPPORT */
  LWIP_UNUSED_ARG(service_name);
  LWIP_UNUSED_ARG(concentrator_name);
#endif /* PPPOE_SCNAME_SUPPORT */
  LWIP_ASSERT_CORE_LOCKED();

#if PPPOE_SCNAME_SUPPORT
  /*
   * Check that service_name and concentrator_name strings length will
   * not trigger integer overflows when computing packets length.
   */
  l = strlen(service_name);
  if (l > 1024) {
    return NULL;
  }
  l = strlen(concentrator_name);
  if (l > 1024) {
    return NULL;
  }
#endif /* PPPOE_SCNAME_SUPPORT */

  sc = (struct pppoe_softc *)LWIP_MEMPOOL_ALLOC(PPPOE_IF);
  if (sc == NULL) {
    return NULL;
  }

  ppp = ppp_new(pppif, &pppoe_callbacks, sc, link_status_cb, ctx_cb);
  if (ppp == NULL) {
    LWIP_MEMPOOL_FREE(PPPOE_IF, sc);
    return NULL;
  }

  memset(sc, 0, sizeof(struct pppoe_softc));
  sc->pcb = ppp;
  sc->sc_ethif = ethif;
#if PPPOE_SCNAME_SUPPORT
  sc->sc_service_name = service_name;
  sc->sc_concentrator_name = concentrator_name;
#endif /* PPPOE_SCNAME_SUPPORT */
  /* put the new interface at the head of the list */
  sc->next = pppoe_softc_list;
  pppoe_softc_list = sc;
  return ppp;
}

static err_t pppoe_write(ppp_pcb *ppp, void *ctx, struct pbuf *p) {
  struct pppoe_softc *sc = (struct pppoe_softc *)ctx;
  struct pbuf *ph; /* Ethernet + PPPoE header */
  err_t ret;
#if MIB2_STATS
  u16_t tot_len;
#else  /* MIB2_STATS */
  LWIP_UNUSED_ARG(ppp);
#endif /* MIB2_STATS */

  /* skip address & flags */
  pbuf_remove_header(p, 2);

  ph = pbuf_alloc(PBUF_LINK, (u16_t)(PPPOE_HEADERLEN), PBUF_RAM);
  if (!ph) {
    LINK_STATS_INC(link.memerr);
    LINK_STATS_INC(link.proterr);
    MIB2_STATS_NETIF_INC(ppp->netif, ifoutdiscards);
    pbuf_free(p);
    return ERR_MEM;
  }

  pbuf_remove_header(ph, PPPOE_HEADERLEN); /* hide PPPoE header */
  pbuf_cat(ph, p);
#if MIB2_STATS
  tot_len = ph->tot_len;
#endif /* MIB2_STATS */

  ret = pppoe_xmit(sc, ph);
  if (ret != ERR_OK) {
    LINK_STATS_INC(link.err);
    MIB2_STATS_NETIF_INC(ppp->netif, ifoutdiscards);
    return ret;
  }

  MIB2_STATS_NETIF_ADD(ppp->netif, ifoutoctets, (u16_t)tot_len);
  MIB2_STATS_NETIF_INC(ppp->netif, ifoutucastpkts);
  LINK_STATS_INC(link.xmit);
  return ERR_OK;
}

static err_t pppoe_netif_output(ppp_pcb *ppp, void *ctx, struct pbuf *p,
                                u_short protocol) {
  struct pppoe_softc *sc = (struct pppoe_softc *)ctx;
  struct pbuf *pb;
  u8_t *pl;
  err_t err;
#if MIB2_STATS
  u16_t tot_len;
#else  /* MIB2_STATS */
  LWIP_UNUSED_ARG(ppp);
#endif /* MIB2_STATS */

  /* @todo: try to use pbuf_header() here! */
  pb = pbuf_alloc(PBUF_LINK, PPPOE_HEADERLEN + sizeof(protocol), PBUF_RAM);
  if (!pb) {
    LINK_STATS_INC(link.memerr);
    LINK_STATS_INC(link.proterr);
    MIB2_STATS_NETIF_INC(ppp->netif, ifoutdiscards);
    return ERR_MEM;
  }

  pbuf_remove_header(pb, PPPOE_HEADERLEN);

  pl = (u8_t *)pb->payload;
  PUTSHORT(protocol, pl);

  pbuf_chain(pb, p);
#if MIB2_STATS
  tot_len = pb->tot_len;
#endif /* MIB2_STATS */

  if ((err = pppoe_xmit(sc, pb)) != ERR_OK) {
    LINK_STATS_INC(link.err);
    MIB2_STATS_NETIF_INC(ppp->netif, ifoutdiscards);
    return err;
  }

  MIB2_STATS_NETIF_ADD(ppp->netif, ifoutoctets, tot_len);
  MIB2_STATS_NETIF_INC(ppp->netif, ifoutucastpkts);
  LINK_STATS_INC(link.xmit);
  return ERR_OK;
}

static err_t pppoe_destroy(ppp_pcb *ppp, void *ctx) {
  struct pppoe_softc *sc = (struct pppoe_softc *)ctx;
  struct pppoe_softc **copp, *freep;
  LWIP_UNUSED_ARG(ppp);

  sys_untimeout(pppoe_timeout, sc);

  /* remove interface from list */
  for (copp = &pppoe_softc_list; (freep = *copp); copp = &freep->next) {
    if (freep == sc) {
      *copp = freep->next;
      break;
    }
  }
  LWIP_MEMPOOL_FREE(PPPOE_IF, sc);

  return ERR_OK;
}

static struct pppoe_softc *pppoe_find_softc_by_session(u_int session,
                                                       struct netif *rcvif) {
  struct pppoe_softc *sc;

  for (sc = pppoe_softc_list; sc != NULL; sc = sc->next) {
    if (sc->sc_state == PPPOE_STATE_SESSION && sc->sc_session == session &&
        sc->sc_ethif == rcvif) {
      return sc;
    }
  }
  return NULL;
}

static struct pppoe_softc *pppoe_find_softc_by_hunique(u8_t *token, size_t len,
                                                       struct netif *rcvif) {
  struct pppoe_softc *sc, *t;

  if (len != sizeof sc) {
    return NULL;
  }
  MEMCPY(&t, token, len);

  for (sc = pppoe_softc_list; sc != NULL; sc = sc->next) {
    if (sc == t) {
      break;
    }
  }

  if (sc == NULL) {
    PPPDEBUG(LOG_DEBUG, ("pppoe: alien host unique tag, no session found\n"));
    return NULL;
  }

  /* should be safe to access *sc now */
  if (sc->sc_state < PPPOE_STATE_PADI_SENT ||
      sc->sc_state >= PPPOE_STATE_SESSION) {
    PPPDEBUG(LOG_DEBUG, ("%c%c%" U16_F ": host unique tag found, but it "
                                       "belongs to a connection in state %d\n",
                         sc->sc_ethif->name[0], sc->sc_ethif->name[1],
                         sc->sc_ethif->num, sc->sc_state));
    return NULL;
  }
  if (sc->sc_ethif != rcvif) {
    PPPDEBUG(LOG_DEBUG,
             ("%c%c%" U16_F ": wrong interface, not accepting host unique\n",
              sc->sc_ethif->name[0], sc->sc_ethif->name[1], sc->sc_ethif->num));
    return NULL;
  }
  return sc;
}

void pppoe_disc_input(struct netif *netif, struct pbuf *pb) {
  u16_t tag, len, off;
  u16_t session, plen;
  struct pppoe_softc *sc;
#if PPP_DEBUG
  const char *err_msg = NULL;
#endif /* PPP_DEBUG */
  u8_t *ac_cookie;
  u16_t ac_cookie_len;
#ifdef PPPOE_SERVER
  u8_t *hunique;
  size_t hunique_len;
#endif
  struct pppoehdr *ph;
  struct pppoetag pt;
  int err;
  struct eth_hdr *ethhdr;

  /* don't do anything if there is not a single PPPoE instance */
  if (pppoe_softc_list == NULL) {
    pbuf_free(pb);
    return;
  }

  pb = pbuf_coalesce(pb, PBUF_RAW);
  if (pb->next != NULL) {
    PPPDEBUG(LOG_DEBUG, ("pppoe: pbuf_coalesce failed: %d\n", pb->tot_len));
    goto done;
  }

  ethhdr = (struct eth_hdr *)pb->payload;

  ac_cookie = NULL;
  ac_cookie_len = 0;
#ifdef PPPOE_SERVER
  hunique = NULL;
  hunique_len = 0;
#endif
  session = 0;
  off = sizeof(struct eth_hdr) + sizeof(struct pppoehdr);
  if (pb->len < off) {
    PPPDEBUG(LOG_DEBUG, ("pppoe: packet too short: %d\n", pb->len));
    goto done;
  }

  ph = (struct pppoehdr *)(ethhdr + 1);
  if (ph->vertype != PPPOE_VERTYPE) {
    PPPDEBUG(LOG_DEBUG,
             ("pppoe: unknown version/type packet: 0x%x\n", ph->vertype));
    goto done;
  }
  session = lwip_ntohs(ph->session);
  plen = lwip_ntohs(ph->plen);

  if (plen > (pb->len - off)) {
    PPPDEBUG(LOG_DEBUG, ("pppoe: packet content does not fit: data available = "
                         "%d, packet size = %u\n",
                         pb->len - off, plen));
    goto done;
  }
  if (pb->tot_len == pb->len) {
    u16_t framelen = off + plen;
    if (framelen < pb->len) {
      /* ignore trailing garbage */
      pb->tot_len = pb->len = framelen;
    }
  }
  tag = 0;
  len = 0;
  sc = NULL;
  while (off + sizeof(pt) <= pb->len) {
    MEMCPY(&pt, (u8_t *)pb->payload + off, sizeof(pt));
    tag = lwip_ntohs(pt.tag);
    len = lwip_ntohs(pt.len);
    if (off + sizeof(pt) + len > pb->len) {
      PPPDEBUG(LOG_DEBUG, ("pppoe: tag 0x%x len 0x%x is too long\n", tag, len));
      goto done;
    }
    switch (tag) {
    case PPPOE_TAG_EOL:
      goto breakbreak;
    case PPPOE_TAG_SNAME:
      break; /* ignored */
    case PPPOE_TAG_ACNAME:
      break; /* ignored */
    case PPPOE_TAG_HUNIQUE:
      if (sc != NULL) {
        break;
      }
#ifdef PPPOE_SERVER
      hunique = (u8_t *)pb->payload + off + sizeof(pt);
      hunique_len = len;
#endif
      sc = pppoe_find_softc_by_hunique((u8_t *)pb->payload + off + sizeof(pt),
                                       len, netif);
      break;
    case PPPOE_TAG_ACCOOKIE:
      if (ac_cookie == NULL) {
        if (len > PPPOE_MAX_AC_COOKIE_LEN) {
          PPPDEBUG(LOG_DEBUG,
                   ("pppoe: AC cookie is too long: len = %d, max = %d\n", len,
                    PPPOE_MAX_AC_COOKIE_LEN));
          goto done;
        }
        ac_cookie = (u8_t *)pb->payload + off + sizeof(pt);
        ac_cookie_len = len;
      }
      break;
#if PPP_DEBUG
    case PPPOE_TAG_SNAME_ERR:
      err_msg = "SERVICE NAME ERROR";
      break;
    case PPPOE_TAG_ACSYS_ERR:
      err_msg = "AC SYSTEM ERROR";
      break;
    case PPPOE_TAG_GENERIC_ERR:
      err_msg = "GENERIC ERROR";
      break;
#endif /* PPP_DEBUG */
    default:
      break;
    }
#if PPP_DEBUG
    if (err_msg != NULL) {
      char error_tmp[PPPOE_ERRORSTRING_LEN];
      u16_t error_len = LWIP_MIN(len, sizeof(error_tmp) - 1);
      strncpy(error_tmp, (char *)pb->payload + off + sizeof(pt), error_len);
      error_tmp[error_len] = '\0';
      if (sc) {
        PPPDEBUG(LOG_DEBUG, ("pppoe: %c%c%" U16_F ": %s: %s\n",
                             sc->sc_ethif->name[0], sc->sc_ethif->name[1],
                             sc->sc_ethif->num, err_msg, error_tmp));
      } else {
        PPPDEBUG(LOG_DEBUG, ("pppoe: %s: %s\n", err_msg, error_tmp));
      }
    }
#endif /* PPP_DEBUG */
    off += sizeof(pt) + len;
  }

breakbreak:;
  switch (ph->code) {
  case PPPOE_CODE_PADI:
#ifdef PPPOE_SERVER
    /*
     * got service name, concentrator name, and/or host unique.
     * ignore if we have no interfaces with IFF_PASSIVE|IFF_UP.
     */
    if (LIST_EMPTY(&pppoe_softc_list)) {
      goto done;
    }
    LIST_FOREACH(sc, &pppoe_softc_list, sc_list) {
      if (!(sc->sc_sppp.pp_if.if_flags & IFF_UP)) {
        continue;
      }
      if (!(sc->sc_sppp.pp_if.if_flags & IFF_PASSIVE)) {
        continue;
      }
      if (sc->sc_state == PPPOE_STATE_INITIAL) {
        break;
      }
    }
    if (sc == NULL) {
      /* PPPDEBUG(LOG_DEBUG, ("pppoe: free passive interface is not found\n"));
       */
      goto done;
    }
    if (hunique) {
      if (sc->sc_hunique) {
        mem_free(sc->sc_hunique);
      }
      sc->sc_hunique = mem_malloc(hunique_len);
      if (sc->sc_hunique == NULL) {
        goto done;
      }
      sc->sc_hunique_len = hunique_len;
      MEMCPY(sc->sc_hunique, hunique, hunique_len);
    }
    MEMCPY(&sc->sc_dest, eh->ether_shost, sizeof sc->sc_dest);
    sc->sc_state = PPPOE_STATE_PADO_SENT;
    pppoe_send_pado(sc);
    break;
#endif /* PPPOE_SERVER */
  case PPPOE_CODE_PADR:
#ifdef PPPOE_SERVER
    /*
     * get sc from ac_cookie if IFF_PASSIVE
     */
    if (ac_cookie == NULL) {
      /* be quiet if there is not a single pppoe instance */
      PPPDEBUG(LOG_DEBUG,
               ("pppoe: received PADR but not includes ac_cookie\n"));
      goto done;
    }
    sc = pppoe_find_softc_by_hunique(ac_cookie, ac_cookie_len, netif);
    if (sc == NULL) {
      /* be quiet if there is not a single pppoe instance */
      if (!LIST_EMPTY(&pppoe_softc_list)) {
        PPPDEBUG(LOG_DEBUG,
                 ("pppoe: received PADR but could not find request for it\n"));
      }
      goto done;
    }
    if (sc->sc_state != PPPOE_STATE_PADO_SENT) {
      PPPDEBUG(LOG_DEBUG, ("%c%c%" U16_F ": received unexpected PADR\n",
                           sc->sc_ethif->name[0], sc->sc_ethif->name[1],
                           sc->sc_ethif->num));
      goto done;
    }
    if (hunique) {
      if (sc->sc_hunique) {
        mem_free(sc->sc_hunique);
      }
      sc->sc_hunique = mem_malloc(hunique_len);
      if (sc->sc_hunique == NULL) {
        goto done;
      }
      sc->sc_hunique_len = hunique_len;
      MEMCPY(sc->sc_hunique, hunique, hunique_len);
    }
    pppoe_send_pads(sc);
    sc->sc_state = PPPOE_STATE_SESSION;
    ppp_start(sc->pcb); /* notify upper layers */
    break;
#else
    /* ignore, we are no access concentrator */
    goto done;
#endif /* PPPOE_SERVER */
  case PPPOE_CODE_PADO:
    if (sc == NULL) {
      /* be quiet if there is not a single pppoe instance */
      if (pppoe_softc_list != NULL) {
        PPPDEBUG(LOG_DEBUG,
                 ("pppoe: received PADO but could not find request for it\n"));
      }
      goto done;
    }
    if (sc->sc_state != PPPOE_STATE_PADI_SENT) {
      PPPDEBUG(LOG_DEBUG, ("%c%c%" U16_F ": received unexpected PADO\n",
                           sc->sc_ethif->name[0], sc->sc_ethif->name[1],
                           sc->sc_ethif->num));
      goto done;
    }
    if (ac_cookie) {
      sc->sc_ac_cookie_len = ac_cookie_len;
      MEMCPY(sc->sc_ac_cookie, ac_cookie, ac_cookie_len);
    }
    MEMCPY(&sc->sc_dest, ethhdr->src.addr, sizeof(sc->sc_dest.addr));
    sys_untimeout(pppoe_timeout, sc);
    sc->sc_padr_retried = 0;
    sc->sc_state = PPPOE_STATE_PADR_SENT;
    if ((err = pppoe_send_padr(sc)) != 0) {
      PPPDEBUG(LOG_DEBUG,
               ("pppoe: %c%c%" U16_F ": failed to send PADR, error=%d\n",
                sc->sc_ethif->name[0], sc->sc_ethif->name[1], sc->sc_ethif->num,
                err));
      LWIP_UNUSED_ARG(err); /* if PPPDEBUG is disabled */
    }
    sys_timeout(PPPOE_DISC_TIMEOUT * (1 + sc->sc_padr_retried), pppoe_timeout,
                sc);
    break;
  case PPPOE_CODE_PADS:
    if (sc == NULL) {
      goto done;
    }
    sc->sc_session = session;
    sys_untimeout(pppoe_timeout, sc);
    PPPDEBUG(LOG_DEBUG, ("pppoe: %c%c%" U16_F ": session 0x%x connected\n",
                         sc->sc_ethif->name[0], sc->sc_ethif->name[1],
                         sc->sc_ethif->num, session));
    sc->sc_state = PPPOE_STATE_SESSION;
    ppp_start(sc->pcb); /* notify upper layers */
    break;
  case PPPOE_CODE_PADT:
    /* Don't disconnect here, we let the LCP Echo/Reply find the fact
     * that PPP session is down. Asking the PPP stack to end the session
     * require strict checking about the PPP phase to prevent endless
     * disconnection loops.
     */
#if 0  /* UNUSED */
      if (sc == NULL) { /* PADT frames are rarely sent with a hunique tag, this is actually almost always true */
        goto done;
      }
      pppoe_clear_softc(sc, "received PADT");
#endif /* UNUSED */
    break;
  default:
    if (sc) {
      PPPDEBUG(LOG_DEBUG, ("%c%c%" U16_F ": unknown code (0x%" X16_F
                           ") session = 0x%" X16_F "\n",
                           sc->sc_ethif->name[0], sc->sc_ethif->name[1],
                           sc->sc_ethif->num, (u16_t)ph->code, session));
    } else {
      PPPDEBUG(LOG_DEBUG,
               ("pppoe: unknown code (0x%" X16_F ") session = 0x%" X16_F "\n",
                (u16_t)ph->code, session));
    }
    break;
  }

done:
  pbuf_free(pb);
  return;
}

void pppoe_data_input(struct netif *netif, struct pbuf *pb) {
  u16_t session, plen;
  struct pppoe_softc *sc;
  struct pppoehdr *ph;
#ifdef PPPOE_TERM_UNKNOWN_SESSIONS
  u8_t shost[ETHER_ADDR_LEN];
#endif

#ifdef PPPOE_TERM_UNKNOWN_SESSIONS
  MEMCPY(shost, ((struct eth_hdr *)pb->payload)->src.addr, sizeof(shost));
#endif
  if (pbuf_remove_header(pb, sizeof(struct eth_hdr)) != 0) {
    /* bail out */
    PPPDEBUG(LOG_ERR, ("pppoe_data_input: pbuf_remove_header failed\n"));
    LINK_STATS_INC(link.lenerr);
    goto drop;
  }

  if (pb->len < sizeof(*ph)) {
    PPPDEBUG(LOG_DEBUG, ("pppoe_data_input: could not get PPPoE header\n"));
    goto drop;
  }
  ph = (struct pppoehdr *)pb->payload;

  if (ph->vertype != PPPOE_VERTYPE) {
    PPPDEBUG(LOG_DEBUG, ("pppoe (data): unknown version/type packet: 0x%x\n",
                         ph->vertype));
    goto drop;
  }
  if (ph->code != 0) {
    goto drop;
  }

  session = lwip_ntohs(ph->session);
  sc = pppoe_find_softc_by_session(session, netif);
  if (sc == NULL) {
#ifdef PPPOE_TERM_UNKNOWN_SESSIONS
    PPPDEBUG(
        LOG_DEBUG,
        ("pppoe: input for unknown session 0x%x, sending PADT\n", session));
    pppoe_send_padt(netif, session, shost);
#endif
    goto drop;
  }

  plen = lwip_ntohs(ph->plen);

  if (pbuf_remove_header(pb, PPPOE_HEADERLEN) != 0) {
    /* bail out */
    PPPDEBUG(LOG_ERR,
             ("pppoe_data_input: pbuf_remove_header PPPOE_HEADERLEN failed\n"));
    LINK_STATS_INC(link.lenerr);
    goto drop;
  }

  PPPDEBUG(LOG_DEBUG,
           ("pppoe_data_input: %c%c%" U16_F ": pkthdr.len=%d, pppoe.len=%d\n",
            sc->sc_ethif->name[0], sc->sc_ethif->name[1], sc->sc_ethif->num,
            pb->len, plen));

  if (pb->tot_len < plen) {
    goto drop;
  }

  /* Dispatch the packet thereby consuming it. */
  ppp_input(sc->pcb, pb);
  return;

drop:
  pbuf_free(pb);
}

static err_t pppoe_output(struct pppoe_softc *sc, struct pbuf *pb) {
  struct eth_hdr *ethhdr;
  u16_t etype;
  err_t res;

  /* make room for Ethernet header - should not fail */
  if (pbuf_add_header(pb, sizeof(struct eth_hdr)) != 0) {
    /* bail out */
    PPPDEBUG(LOG_ERR,
             ("pppoe: %c%c%" U16_F
              ": pppoe_output: could not allocate room for Ethernet header\n",
              sc->sc_ethif->name[0], sc->sc_ethif->name[1], sc->sc_ethif->num));
    LINK_STATS_INC(link.lenerr);
    pbuf_free(pb);
    return ERR_BUF;
  }
  ethhdr = (struct eth_hdr *)pb->payload;
  etype =
      sc->sc_state == PPPOE_STATE_SESSION ? ETHTYPE_PPPOE : ETHTYPE_PPPOEDISC;
  ethhdr->type = lwip_htons(etype);
  MEMCPY(&ethhdr->dest.addr, &sc->sc_dest.addr, sizeof(ethhdr->dest.addr));
  MEMCPY(&ethhdr->src.addr, &sc->sc_ethif->hwaddr, sizeof(ethhdr->src.addr));

  PPPDEBUG(LOG_DEBUG,
           ("pppoe: %c%c%" U16_F
            " (%x) state=%d, session=0x%x output -> %02" X16_F ":%02" X16_F
            ":%02" X16_F ":%02" X16_F ":%02" X16_F ":%02" X16_F ", len=%d\n",
            sc->sc_ethif->name[0], sc->sc_ethif->name[1], sc->sc_ethif->num,
            etype, sc->sc_state, sc->sc_session, sc->sc_dest.addr[0],
            sc->sc_dest.addr[1], sc->sc_dest.addr[2], sc->sc_dest.addr[3],
            sc->sc_dest.addr[4], sc->sc_dest.addr[5], pb->tot_len));

  res = sc->sc_ethif->linkoutput(sc->sc_ethif, pb);

  pbuf_free(pb);

  return res;
}

static err_t pppoe_send_padi(struct pppoe_softc *sc) {
  struct pbuf *pb;
  u8_t *p;
  size_t len;
#if PPPOE_SCNAME_SUPPORT
  size_t l1 = 0, l2 = 0; /* XXX: gcc */
#endif                   /* PPPOE_SCNAME_SUPPORT */

  /* calculate length of frame (excluding ethernet header + pppoe header) */
  len = 2 + 2 + 2 + 2 +
        sizeof sc; /* service name tag is required, host unique is send too */
#if PPPOE_SCNAME_SUPPORT
  if (sc->sc_service_name != NULL) {
    l1 = strlen(sc->sc_service_name);
    len += l1;
  }
  if (sc->sc_concentrator_name != NULL) {
    l2 = strlen(sc->sc_concentrator_name);
    len += 2 + 2 + l2;
  }
#endif /* PPPOE_SCNAME_SUPPORT */
  LWIP_ASSERT("sizeof(struct eth_hdr) + PPPOE_HEADERLEN + len <= 0xffff",
              sizeof(struct eth_hdr) + PPPOE_HEADERLEN + len <= 0xffff);

  /* allocate a buffer */
  pb = pbuf_alloc(PBUF_LINK, (u16_t)(PPPOE_HEADERLEN + len), PBUF_RAM);
  if (!pb) {
    return ERR_MEM;
  }
  LWIP_ASSERT("pb->tot_len == pb->len", pb->tot_len == pb->len);

  p = (u8_t *)pb->payload;
  /* fill in pkt */
  PPPOE_ADD_HEADER(p, PPPOE_CODE_PADI, 0, (u16_t)len);
  PPPOE_ADD_16(p, PPPOE_TAG_SNAME);
#if PPPOE_SCNAME_SUPPORT
  if (sc->sc_service_name != NULL) {
    PPPOE_ADD_16(p, l1);
    MEMCPY(p, sc->sc_service_name, l1);
    p += l1;
  } else
#endif /* PPPOE_SCNAME_SUPPORT */
  {
    PPPOE_ADD_16(p, 0);
  }
#if PPPOE_SCNAME_SUPPORT
  if (sc->sc_concentrator_name != NULL) {
    PPPOE_ADD_16(p, PPPOE_TAG_ACNAME);
    PPPOE_ADD_16(p, l2);
    MEMCPY(p, sc->sc_concentrator_name, l2);
    p += l2;
  }
#endif /* PPPOE_SCNAME_SUPPORT */
  PPPOE_ADD_16(p, PPPOE_TAG_HUNIQUE);
  PPPOE_ADD_16(p, sizeof(sc));
  MEMCPY(p, &sc, sizeof sc);

  /* send pkt */
  return pppoe_output(sc, pb);
}

static void pppoe_timeout(void *arg) {
  u32_t retry_wait;
  int err;
  struct pppoe_softc *sc = (struct pppoe_softc *)arg;

  PPPDEBUG(LOG_DEBUG,
           ("pppoe: %c%c%" U16_F ": timeout\n", sc->sc_ethif->name[0],
            sc->sc_ethif->name[1], sc->sc_ethif->num));

  switch (sc->sc_state) {
  case PPPOE_STATE_PADI_SENT:
    /*
     * We have two basic ways of retrying:
     *  - Quick retry mode: try a few times in short sequence
     *  - Slow retry mode: we already had a connection successfully
     *    established and will try infinitely (without user
     *    intervention)
     * We only enter slow retry mode if IFF_LINK1 (aka autodial)
     * is not set.
     */
    if (sc->sc_padi_retried < 0xff) {
      sc->sc_padi_retried++;
    }
    if (!sc->pcb->settings.persist &&
        sc->sc_padi_retried >= PPPOE_DISC_MAXPADI) {
#if 0
        if ((sc->sc_sppp.pp_if.if_flags & IFF_LINK1) == 0) {
          /* slow retry mode */
          retry_wait = PPPOE_SLOW_RETRY;
        } else
#endif
      {
        pppoe_abort_connect(sc);
        return;
      }
    }
    /* initialize for quick retry mode */
    retry_wait =
        LWIP_MIN(PPPOE_DISC_TIMEOUT * sc->sc_padi_retried, PPPOE_SLOW_RETRY);
    if ((err = pppoe_send_padi(sc)) != 0) {
      PPPDEBUG(LOG_DEBUG,
               ("pppoe: %c%c%" U16_F ": failed to transmit PADI, error=%d\n",
                sc->sc_ethif->name[0], sc->sc_ethif->name[1], sc->sc_ethif->num,
                err));
      LWIP_UNUSED_ARG(err); /* if PPPDEBUG is disabled */
    }
    sys_timeout(retry_wait, pppoe_timeout, sc);
    break;

  case PPPOE_STATE_PADR_SENT:
    sc->sc_padr_retried++;
    if (sc->sc_padr_retried >= PPPOE_DISC_MAXPADR) {
      MEMCPY(&sc->sc_dest, ethbroadcast.addr, sizeof(sc->sc_dest));
      sc->sc_state = PPPOE_STATE_PADI_SENT;
      sc->sc_padr_retried = 0;
      if ((err = pppoe_send_padi(sc)) != 0) {
        PPPDEBUG(LOG_DEBUG,
                 ("pppoe: %c%c%" U16_F ": failed to send PADI, error=%d\n",
                  sc->sc_ethif->name[0], sc->sc_ethif->name[1],
                  sc->sc_ethif->num, err));
        LWIP_UNUSED_ARG(err); /* if PPPDEBUG is disabled */
      }
      sys_timeout(PPPOE_DISC_TIMEOUT * (1 + sc->sc_padi_retried), pppoe_timeout,
                  sc);
      return;
    }
    if ((err = pppoe_send_padr(sc)) != 0) {
      PPPDEBUG(LOG_DEBUG,
               ("pppoe: %c%c%" U16_F ": failed to send PADR, error=%d\n",
                sc->sc_ethif->name[0], sc->sc_ethif->name[1], sc->sc_ethif->num,
                err));
      LWIP_UNUSED_ARG(err); /* if PPPDEBUG is disabled */
    }
    sys_timeout(PPPOE_DISC_TIMEOUT * (1 + sc->sc_padr_retried), pppoe_timeout,
                sc);
    break;
  default:
    return; /* all done, work in peace */
  }
}

static void pppoe_connect(ppp_pcb *ppp, void *ctx) {
  err_t err;
  struct pppoe_softc *sc = (struct pppoe_softc *)ctx;
  lcp_options *lcp_wo;
  lcp_options *lcp_ao;
#if PPP_IPV4_SUPPORT && VJ_SUPPORT
  ipcp_options *ipcp_wo;
  ipcp_options *ipcp_ao;
#endif /* PPP_IPV4_SUPPORT && VJ_SUPPORT */

  sc->sc_session = 0;
  sc->sc_ac_cookie_len = 0;
  sc->sc_padi_retried = 0;
  sc->sc_padr_retried = 0;
  /* changed to real address later */
  MEMCPY(&sc->sc_dest, ethbroadcast.addr, sizeof(sc->sc_dest));
#ifdef PPPOE_SERVER
  /* wait PADI if IFF_PASSIVE */
  if ((sc->sc_sppp.pp_if.if_flags & IFF_PASSIVE)) {
    return 0;
  }
#endif

  lcp_wo = &ppp->lcp_wantoptions;
  lcp_wo->mru = sc->sc_ethif->mtu - PPPOE_HEADERLEN -
                2; /* two byte PPP protocol discriminator, then IP data */
  lcp_wo->neg_asyncmap = 0;
  lcp_wo->neg_pcompression = 0;
  lcp_wo->neg_accompression = 0;
  lcp_wo->passive = 0;
  lcp_wo->silent = 0;

  lcp_ao = &ppp->lcp_allowoptions;
  lcp_ao->mru = sc->sc_ethif->mtu - PPPOE_HEADERLEN -
                2; /* two byte PPP protocol discriminator, then IP data */
  lcp_ao->neg_asyncmap = 0;
  lcp_ao->neg_pcompression = 0;
  lcp_ao->neg_accompression = 0;

#if PPP_IPV4_SUPPORT && VJ_SUPPORT
  ipcp_wo = &ppp->ipcp_wantoptions;
  ipcp_wo->neg_vj = 0;
  ipcp_wo->old_vj = 0;

  ipcp_ao = &ppp->ipcp_allowoptions;
  ipcp_ao->neg_vj = 0;
  ipcp_ao->old_vj = 0;
#endif /* PPP_IPV4_SUPPORT && VJ_SUPPORT */

  /* save state, in case we fail to send PADI */
  sc->sc_state = PPPOE_STATE_PADI_SENT;
  if ((err = pppoe_send_padi(sc)) != 0) {
    PPPDEBUG(LOG_DEBUG,
             ("pppoe: %c%c%" U16_F ": failed to send PADI, error=%d\n",
              sc->sc_ethif->name[0], sc->sc_ethif->name[1], sc->sc_ethif->num,
              err));
  }
  sys_timeout(PPPOE_DISC_TIMEOUT, pppoe_timeout, sc);
}

static void pppoe_disconnect(ppp_pcb *ppp, void *ctx) {
  struct pppoe_softc *sc = (struct pppoe_softc *)ctx;

  PPPDEBUG(LOG_DEBUG,
           ("pppoe: %c%c%" U16_F ": disconnecting\n", sc->sc_ethif->name[0],
            sc->sc_ethif->name[1], sc->sc_ethif->num));
  if (sc->sc_state == PPPOE_STATE_SESSION) {
    pppoe_send_padt(sc->sc_ethif, sc->sc_session, (const u8_t *)&sc->sc_dest);
  }

  /* stop any timer, disconnect can be called while initiating is in progress */
  sys_untimeout(pppoe_timeout, sc);
  sc->sc_state = PPPOE_STATE_INITIAL;
#ifdef PPPOE_SERVER
  if (sc->sc_hunique) {
    mem_free(sc->sc_hunique);
    sc->sc_hunique = NULL; /* probably not necessary, if state is initial we
                              shouldn't have to access hunique anyway  */
  }
  sc->sc_hunique_len = 0; /* probably not necessary, if state is initial we
                             shouldn't have to access hunique anyway  */
#endif
  ppp_link_end(ppp); /* notify upper layers */
  return;
}

static void pppoe_abort_connect(struct pppoe_softc *sc) {
  PPPDEBUG(LOG_DEBUG,
           ("%c%c%" U16_F ": could not establish connection\n",
            sc->sc_ethif->name[0], sc->sc_ethif->name[1], sc->sc_ethif->num));
  sc->sc_state = PPPOE_STATE_INITIAL;
  ppp_link_failed(sc->pcb); /* notify upper layers */
}

static err_t pppoe_send_padr(struct pppoe_softc *sc) {
  struct pbuf *pb;
  u8_t *p;
  size_t len;
#if PPPOE_SCNAME_SUPPORT
  size_t l1 = 0; /* XXX: gcc */
#endif           /* PPPOE_SCNAME_SUPPORT */

  len = 2 + 2 + 2 + 2 + sizeof(sc); /* service name, host unique */
#if PPPOE_SCNAME_SUPPORT
  if (sc->sc_service_name != NULL) { /* service name tag maybe empty */
    l1 = strlen(sc->sc_service_name);
    len += l1;
  }
#endif /* PPPOE_SCNAME_SUPPORT */
  if (sc->sc_ac_cookie_len > 0) {
    len += 2 + 2 + sc->sc_ac_cookie_len; /* AC cookie */
  }
  LWIP_ASSERT("sizeof(struct eth_hdr) + PPPOE_HEADERLEN + len <= 0xffff",
              sizeof(struct eth_hdr) + PPPOE_HEADERLEN + len <= 0xffff);
  pb = pbuf_alloc(PBUF_LINK, (u16_t)(PPPOE_HEADERLEN + len), PBUF_RAM);
  if (!pb) {
    return ERR_MEM;
  }
  LWIP_ASSERT("pb->tot_len == pb->len", pb->tot_len == pb->len);
  p = (u8_t *)pb->payload;
  PPPOE_ADD_HEADER(p, PPPOE_CODE_PADR, 0, len);
  PPPOE_ADD_16(p, PPPOE_TAG_SNAME);
#if PPPOE_SCNAME_SUPPORT
  if (sc->sc_service_name != NULL) {
    PPPOE_ADD_16(p, l1);
    MEMCPY(p, sc->sc_service_name, l1);
    p += l1;
  } else
#endif /* PPPOE_SCNAME_SUPPORT */
  {
    PPPOE_ADD_16(p, 0);
  }
  if (sc->sc_ac_cookie_len > 0) {
    PPPOE_ADD_16(p, PPPOE_TAG_ACCOOKIE);
    PPPOE_ADD_16(p, sc->sc_ac_cookie_len);
    MEMCPY(p, sc->sc_ac_cookie, sc->sc_ac_cookie_len);
    p += sc->sc_ac_cookie_len;
  }
  PPPOE_ADD_16(p, PPPOE_TAG_HUNIQUE);
  PPPOE_ADD_16(p, sizeof(sc));
  MEMCPY(p, &sc, sizeof sc);

  return pppoe_output(sc, pb);
}

static err_t pppoe_send_padt(struct netif *outgoing_if, u_int session,
                             const u8_t *dest) {
  struct pbuf *pb;
  struct eth_hdr *ethhdr;
  err_t res;
  u8_t *p;

  pb = pbuf_alloc(PBUF_LINK, (u16_t)(PPPOE_HEADERLEN), PBUF_RAM);
  if (!pb) {
    return ERR_MEM;
  }
  LWIP_ASSERT("pb->tot_len == pb->len", pb->tot_len == pb->len);

  if (pbuf_add_header(pb, sizeof(struct eth_hdr))) {
    PPPDEBUG(
        LOG_ERR,
        ("pppoe: pppoe_send_padt: could not allocate room for PPPoE header\n"));
    LINK_STATS_INC(link.lenerr);
    pbuf_free(pb);
    return ERR_BUF;
  }
  ethhdr = (struct eth_hdr *)pb->payload;
  ethhdr->type = PP_HTONS(ETHTYPE_PPPOEDISC);
  MEMCPY(&ethhdr->dest.addr, dest, sizeof(ethhdr->dest.addr));
  MEMCPY(&ethhdr->src.addr, &outgoing_if->hwaddr, sizeof(ethhdr->src.addr));

  p = (u8_t *)(ethhdr + 1);
  PPPOE_ADD_HEADER(p, PPPOE_CODE_PADT, session, 0);

  res = outgoing_if->linkoutput(outgoing_if, pb);

  pbuf_free(pb);

  return res;
}

static err_t pppoe_send_pado(struct pppoe_softc *sc) {
  struct pbuf *pb;
  u8_t *p;
  size_t len;

  /* calc length */
  len = 0;
  /* include ac_cookie */
  len += 2 + 2 + sizeof(sc);
  /* include hunique */
  len += 2 + 2 + sc->sc_hunique_len;
  pb = pbuf_alloc(PBUF_LINK, (u16_t)(PPPOE_HEADERLEN + len), PBUF_RAM);
  if (!pb) {
    return ERR_MEM;
  }
  LWIP_ASSERT("pb->tot_len == pb->len", pb->tot_len == pb->len);
  p = (u8_t *)pb->payload;
  PPPOE_ADD_HEADER(p, PPPOE_CODE_PADO, 0, len);
  PPPOE_ADD_16(p, PPPOE_TAG_ACCOOKIE);
  PPPOE_ADD_16(p, sizeof(sc));
  MEMCPY(p, &sc, sizeof(sc));
  p += sizeof(sc);
  PPPOE_ADD_16(p, PPPOE_TAG_HUNIQUE);
  PPPOE_ADD_16(p, sc->sc_hunique_len);
  MEMCPY(p, sc->sc_hunique, sc->sc_hunique_len);
  return pppoe_output(sc, pb);
}

static err_t pppoe_send_pads(struct pppoe_softc *sc) {
  struct pbuf *pb;
  u8_t *p;
  size_t len, l1 = 0; /* XXX: gcc */

  sc->sc_session = mono_time.tv_sec % 0xff + 1;
  /* calc length */
  len = 0;
  /* include hunique */
  len += 2 + 2 + 2 + 2 + sc->sc_hunique_len; /* service name, host unique*/
  if (sc->sc_service_name != NULL) {         /* service name tag maybe empty */
    l1 = strlen(sc->sc_service_name);
    len += l1;
  }
  pb = pbuf_alloc(PBUF_LINK, (u16_t)(PPPOE_HEADERLEN + len), PBUF_RAM);
  if (!pb) {
    return ERR_MEM;
  }
  LWIP_ASSERT("pb->tot_len == pb->len", pb->tot_len == pb->len);
  p = (u8_t *)pb->payload;
  PPPOE_ADD_HEADER(p, PPPOE_CODE_PADS, sc->sc_session, len);
  PPPOE_ADD_16(p, PPPOE_TAG_SNAME);
  if (sc->sc_service_name != NULL) {
    PPPOE_ADD_16(p, l1);
    MEMCPY(p, sc->sc_service_name, l1);
    p += l1;
  } else {
    PPPOE_ADD_16(p, 0);
  }
  PPPOE_ADD_16(p, PPPOE_TAG_HUNIQUE);
  PPPOE_ADD_16(p, sc->sc_hunique_len);
  MEMCPY(p, sc->sc_hunique, sc->sc_hunique_len);
  return pppoe_output(sc, pb);
}

static err_t pppoe_xmit(struct pppoe_softc *sc, struct pbuf *pb) {
  u8_t *p;
  size_t len;

  len = pb->tot_len;

  /* make room for PPPoE header - should not fail */
  if (pbuf_add_header(pb, PPPOE_HEADERLEN) != 0) {
    /* bail out */
    PPPDEBUG(LOG_ERR,
             ("pppoe: %c%c%" U16_F
              ": pppoe_xmit: could not allocate room for PPPoE header\n",
              sc->sc_ethif->name[0], sc->sc_ethif->name[1], sc->sc_ethif->num));
    LINK_STATS_INC(link.lenerr);
    pbuf_free(pb);
    return ERR_BUF;
  }

  p = (u8_t *)pb->payload;
  PPPOE_ADD_HEADER(p, 0, sc->sc_session, len);

  return pppoe_output(sc, pb);
}

static int
pppoe_ifattach_hook(void *arg, struct pbuf **mp, struct netif *ifp, int dir)
{
  struct pppoe_softc *sc;
  int s;

  if (mp != (struct pbuf **)PFIL_IFNET_DETACH) {
    return 0;
  }

  LIST_FOREACH(sc, &pppoe_softc_list, sc_list) {
    if (sc->sc_ethif != ifp) {
      continue;
    }
    if (sc->sc_sppp.pp_if.if_flags & IFF_UP) {
      sc->sc_sppp.pp_if.if_flags &= ~(IFF_UP|IFF_RUNNING);
      PPPDEBUG(LOG_DEBUG, ("%c%c%"U16_F": ethernet interface detached, going down\n",
          sc->sc_ethif->name[0], sc->sc_ethif->name[1], sc->sc_ethif->num));
    }
    sc->sc_ethif = NULL;
    pppoe_clear_softc(sc, "ethernet interface detached");
  }

  return 0;
}

static void
pppoe_clear_softc(struct pppoe_softc *sc, const char *message)
{
  LWIP_UNUSED_ARG(message);

  /* stop timer */
  sys_untimeout(pppoe_timeout, sc);
  PPPDEBUG(LOG_DEBUG, ("pppoe: %c%c%"U16_F": session 0x%x terminated, %s\n", sc->sc_ethif->name[0], sc->sc_ethif->name[1], sc->sc_ethif->num, sc->sc_session, message));
  sc->sc_state = PPPOE_STATE_INITIAL;
  ppp_link_end(sc->pcb);  /* notify upper layers - /!\ dangerous /!\ - see pppoe_disc_input() */
}

ppp_pcb *pppol2tp_create(struct netif *pppif, struct netif *netif,
                         const ip_addr_t *ipaddr, u16_t port,
                         const u8_t *secret, u8_t secret_len,
                         ppp_link_status_cb_fn link_status_cb, void *ctx_cb) {
  ppp_pcb *ppp;
  pppol2tp_pcb *l2tp;
  struct udp_pcb *udp;
#if !PPPOL2TP_AUTH_SUPPORT
  LWIP_UNUSED_ARG(secret);
  LWIP_UNUSED_ARG(secret_len);
#endif /* !PPPOL2TP_AUTH_SUPPORT */

  if (ipaddr == NULL) {
    goto ipaddr_check_failed;
  }

  l2tp = (pppol2tp_pcb *)LWIP_MEMPOOL_ALLOC(PPPOL2TP_PCB);
  if (l2tp == NULL) {
    goto memp_malloc_l2tp_failed;
  }

  udp = udp_new_ip_type(IP_GET_TYPE(ipaddr));
  if (udp == NULL) {
    goto udp_new_failed;
  }
  udp_recv(udp, pppol2tp_input, l2tp);

  ppp = ppp_new(pppif, &pppol2tp_callbacks, l2tp, link_status_cb, ctx_cb);
  if (ppp == NULL) {
    goto ppp_new_failed;
  }

  memset(l2tp, 0, sizeof(pppol2tp_pcb));
  l2tp->phase = PPPOL2TP_STATE_INITIAL;
  l2tp->ppp = ppp;
  l2tp->udp = udp;
  l2tp->netif = netif;
  ip_addr_copy(l2tp->remote_ip, *ipaddr);
  l2tp->remote_port = port;
#if PPPOL2TP_AUTH_SUPPORT
  l2tp->secret = secret;
  l2tp->secret_len = secret_len;
#endif /* PPPOL2TP_AUTH_SUPPORT */

  return ppp;

ppp_new_failed:
  udp_remove(udp);
udp_new_failed:
  LWIP_MEMPOOL_FREE(PPPOL2TP_PCB, l2tp);
memp_malloc_l2tp_failed:
ipaddr_check_failed:
  return NULL;
}

static err_t pppol2tp_write(ppp_pcb *ppp, void *ctx, struct pbuf *p) {
  pppol2tp_pcb *l2tp = (pppol2tp_pcb *)ctx;
  struct pbuf *ph; /* UDP + L2TP header */
  err_t ret;
#if MIB2_STATS
  u16_t tot_len;
#else  /* MIB2_STATS */
  LWIP_UNUSED_ARG(ppp);
#endif /* MIB2_STATS */

  /* skip address & flags */
  pbuf_remove_header(p, 2);

  ph = pbuf_alloc(PBUF_TRANSPORT, (u16_t)(PPPOL2TP_OUTPUT_DATA_HEADER_LEN),
                  PBUF_RAM);
  if (!ph) {
    LINK_STATS_INC(link.memerr);
    LINK_STATS_INC(link.proterr);
    MIB2_STATS_NETIF_INC(ppp->netif, ifoutdiscards);
    pbuf_free(p);
    return ERR_MEM;
  }

  pbuf_remove_header(ph,
                     PPPOL2TP_OUTPUT_DATA_HEADER_LEN); /* hide L2TP header */
  pbuf_cat(ph, p);
#if MIB2_STATS
  tot_len = ph->tot_len;
#endif /* MIB2_STATS */

  ret = pppol2tp_xmit(l2tp, ph);
  if (ret != ERR_OK) {
    LINK_STATS_INC(link.err);
    MIB2_STATS_NETIF_INC(ppp->netif, ifoutdiscards);
    return ret;
  }

  MIB2_STATS_NETIF_ADD(ppp->netif, ifoutoctets, (u16_t)tot_len);
  MIB2_STATS_NETIF_INC(ppp->netif, ifoutucastpkts);
  LINK_STATS_INC(link.xmit);
  return ERR_OK;
}

static err_t pppol2tp_netif_output(ppp_pcb *ppp, void *ctx, struct pbuf *p,
                                   u_short protocol) {
  pppol2tp_pcb *l2tp = (pppol2tp_pcb *)ctx;
  struct pbuf *pb;
  u8_t *pl;
  err_t err;
#if MIB2_STATS
  u16_t tot_len;
#else  /* MIB2_STATS */
  LWIP_UNUSED_ARG(ppp);
#endif /* MIB2_STATS */

  /* @todo: try to use pbuf_header() here! */
  pb = pbuf_alloc(PBUF_TRANSPORT,
                  PPPOL2TP_OUTPUT_DATA_HEADER_LEN + sizeof(protocol), PBUF_RAM);
  if (!pb) {
    LINK_STATS_INC(link.memerr);
    LINK_STATS_INC(link.proterr);
    MIB2_STATS_NETIF_INC(ppp->netif, ifoutdiscards);
    return ERR_MEM;
  }

  pbuf_remove_header(pb, PPPOL2TP_OUTPUT_DATA_HEADER_LEN);

  pl = (u8_t *)pb->payload;
  PUTSHORT(protocol, pl);

  pbuf_chain(pb, p);
#if MIB2_STATS
  tot_len = pb->tot_len;
#endif /* MIB2_STATS */

  if ((err = pppol2tp_xmit(l2tp, pb)) != ERR_OK) {
    LINK_STATS_INC(link.err);
    MIB2_STATS_NETIF_INC(ppp->netif, ifoutdiscards);
    return err;
  }

  MIB2_STATS_NETIF_ADD(ppp->netif, ifoutoctets, tot_len);
  MIB2_STATS_NETIF_INC(ppp->netif, ifoutucastpkts);
  LINK_STATS_INC(link.xmit);
  return ERR_OK;
}

static err_t pppol2tp_destroy(ppp_pcb *ppp, void *ctx) {
  pppol2tp_pcb *l2tp = (pppol2tp_pcb *)ctx;
  LWIP_UNUSED_ARG(ppp);

  sys_untimeout(pppol2tp_timeout, l2tp);
  udp_remove(l2tp->udp);
  LWIP_MEMPOOL_FREE(PPPOL2TP_PCB, l2tp);
  return ERR_OK;
}

static void pppol2tp_connect(ppp_pcb *ppp, void *ctx) {
  err_t err;
  pppol2tp_pcb *l2tp = (pppol2tp_pcb *)ctx;
  lcp_options *lcp_wo;
  lcp_options *lcp_ao;
#if PPP_IPV4_SUPPORT && VJ_SUPPORT
  ipcp_options *ipcp_wo;
  ipcp_options *ipcp_ao;
#endif /* PPP_IPV4_SUPPORT && VJ_SUPPORT */

  l2tp->tunnel_port = l2tp->remote_port;
  l2tp->our_ns = 0;
  l2tp->peer_nr = 0;
  l2tp->peer_ns = 0;
  l2tp->source_tunnel_id = 0;
  l2tp->remote_tunnel_id = 0;
  l2tp->source_session_id = 0;
  l2tp->remote_session_id = 0;
  /* l2tp->*_retried are cleared when used */

  lcp_wo = &ppp->lcp_wantoptions;
  lcp_wo->mru = PPPOL2TP_DEFMRU;
  lcp_wo->neg_asyncmap = 0;
  lcp_wo->neg_pcompression = 0;
  lcp_wo->neg_accompression = 0;
  lcp_wo->passive = 0;
  lcp_wo->silent = 0;

  lcp_ao = &ppp->lcp_allowoptions;
  lcp_ao->mru = PPPOL2TP_DEFMRU;
  lcp_ao->neg_asyncmap = 0;
  lcp_ao->neg_pcompression = 0;
  lcp_ao->neg_accompression = 0;

#if PPP_IPV4_SUPPORT && VJ_SUPPORT
  ipcp_wo = &ppp->ipcp_wantoptions;
  ipcp_wo->neg_vj = 0;
  ipcp_wo->old_vj = 0;

  ipcp_ao = &ppp->ipcp_allowoptions;
  ipcp_ao->neg_vj = 0;
  ipcp_ao->old_vj = 0;
#endif /* PPP_IPV4_SUPPORT && VJ_SUPPORT */

  /* Listen to a random source port, we need to do that instead of using
   * udp_connect() because the L2TP LNS might answer with its own random source
   * port (!= 1701)
   */
#if LWIP_IPV6
  if (IP_IS_V6_VAL(l2tp->udp->local_ip)) {
    udp_bind(l2tp->udp, IP6_ADDR_ANY, 0);
  } else
#endif /* LWIP_IPV6 */
    udp_bind(l2tp->udp, IP_ADDR_ANY, 0);

#if PPPOL2TP_AUTH_SUPPORT
  /* Generate random vector */
  if (l2tp->secret != NULL) {
    magic_random_bytes(l2tp->secret_rv, sizeof(l2tp->secret_rv));
  }
#endif /* PPPOL2TP_AUTH_SUPPORT */

  do {
    l2tp->remote_tunnel_id = magic();
  } while (l2tp->remote_tunnel_id == 0);
  /* save state, in case we fail to send SCCRQ */
  l2tp->sccrq_retried = 0;
  l2tp->phase = PPPOL2TP_STATE_SCCRQ_SENT;
  if ((err = pppol2tp_send_sccrq(l2tp)) != 0) {
    PPPDEBUG(LOG_DEBUG, ("pppol2tp: failed to send SCCRQ, error=%d\n", err));
  }
  sys_timeout(PPPOL2TP_CONTROL_TIMEOUT, pppol2tp_timeout, l2tp);
}

static void pppol2tp_disconnect(ppp_pcb *ppp, void *ctx) {
  pppol2tp_pcb *l2tp = (pppol2tp_pcb *)ctx;

  l2tp->our_ns++;
  pppol2tp_send_stopccn(l2tp, l2tp->our_ns);

  /* stop any timer, disconnect can be called while initiating is in progress */
  sys_untimeout(pppol2tp_timeout, l2tp);
  l2tp->phase = PPPOL2TP_STATE_INITIAL;
  ppp_link_end(ppp); /* notify upper layers */
}

static void pppol2tp_input(void *arg, struct udp_pcb *pcb, struct pbuf *p,
                           const ip_addr_t *addr, u16_t port) {
  pppol2tp_pcb *l2tp = (pppol2tp_pcb *)arg;
  u16_t hflags, hlen, len = 0, tunnel_id = 0, session_id = 0, ns = 0, nr = 0,
                      offset = 0;
  u8_t *inp;
  LWIP_UNUSED_ARG(pcb);

  /* we can't unbound a UDP pcb, thus we can still receive UDP frames after the
   * link is closed */
  if (l2tp->phase < PPPOL2TP_STATE_SCCRQ_SENT) {
    goto free_and_return;
  }

  if (!ip_addr_eq(&l2tp->remote_ip, addr)) {
    goto free_and_return;
  }

  /* discard packet if port mismatch, but only if we received a SCCRP */
  if (l2tp->phase > PPPOL2TP_STATE_SCCRQ_SENT && l2tp->tunnel_port != port) {
    goto free_and_return;
  }

  /* printf("-----------\nL2TP INPUT, %d\n", p->len); */

  /* L2TP header */
  if (p->len < sizeof(hflags) + sizeof(tunnel_id) + sizeof(session_id)) {
    goto packet_too_short;
  }

  inp = (u8_t *)p->payload;
  GETSHORT(hflags, inp);

  if (hflags & PPPOL2TP_HEADERFLAG_CONTROL) {
    /* check mandatory flags for a control packet */
    if ((hflags & PPPOL2TP_HEADERFLAG_CONTROL_MANDATORY) !=
        PPPOL2TP_HEADERFLAG_CONTROL_MANDATORY) {
      PPPDEBUG(
          LOG_DEBUG,
          ("pppol2tp: mandatory header flags for control packet not set\n"));
      goto free_and_return;
    }
    /* check forbidden flags for a control packet */
    if (hflags & PPPOL2TP_HEADERFLAG_CONTROL_FORBIDDEN) {
      PPPDEBUG(LOG_DEBUG,
               ("pppol2tp: forbidden header flags for control packet found\n"));
      goto free_and_return;
    }
  } else {
    /* check mandatory flags for a data packet */
    if ((hflags & PPPOL2TP_HEADERFLAG_DATA_MANDATORY) !=
        PPPOL2TP_HEADERFLAG_DATA_MANDATORY) {
      PPPDEBUG(LOG_DEBUG,
               ("pppol2tp: mandatory header flags for data packet not set\n"));
      goto free_and_return;
    }
  }

  /* Expected header size  */
  hlen = sizeof(hflags) + sizeof(tunnel_id) + sizeof(session_id);
  if (hflags & PPPOL2TP_HEADERFLAG_LENGTH) {
    hlen += sizeof(len);
  }
  if (hflags & PPPOL2TP_HEADERFLAG_SEQUENCE) {
    hlen += sizeof(ns) + sizeof(nr);
  }
  if (hflags & PPPOL2TP_HEADERFLAG_OFFSET) {
    hlen += sizeof(offset);
  }
  if (p->len < hlen) {
    goto packet_too_short;
  }

  if (hflags & PPPOL2TP_HEADERFLAG_LENGTH) {
    GETSHORT(len, inp);
    if (p->len < len || len < hlen) {
      goto packet_too_short;
    }
  }
  GETSHORT(tunnel_id, inp);
  GETSHORT(session_id, inp);
  if (hflags & PPPOL2TP_HEADERFLAG_SEQUENCE) {
    GETSHORT(ns, inp);
    GETSHORT(nr, inp);
  }
  if (hflags & PPPOL2TP_HEADERFLAG_OFFSET) {
    GETSHORT(offset, inp)
    if (offset > 4096) { /* don't be fooled with large offset which might
                            overflow hlen */
      PPPDEBUG(LOG_DEBUG,
               ("pppol2tp: strange packet received, offset=%d\n", offset));
      goto free_and_return;
    }
    hlen += offset;
    if (p->len < hlen) {
      goto packet_too_short;
    }
    INCPTR(offset, inp);
  }

  /* printf("HLEN = %d\n", hlen); */

  /* skip L2TP header */
  if (pbuf_remove_header(p, hlen) != 0) {
    goto free_and_return;
  }

  /* printf("LEN=%d, TUNNEL_ID=%d, SESSION_ID=%d, NS=%d, NR=%d, OFFSET=%d\n",
   * len, tunnel_id, session_id, ns, nr, offset); */
  PPPDEBUG(LOG_DEBUG, ("pppol2tp: input packet, len=%" U16_F ", tunnel=%" U16_F
                       ", session=%" U16_F ", ns=%" U16_F ", nr=%" U16_F "\n",
                       p->tot_len, tunnel_id, session_id, ns, nr));

  /* Control packet */
  if (hflags & PPPOL2TP_HEADERFLAG_CONTROL) {
    pppol2tp_dispatch_control_packet(l2tp, port, p, ns, nr);
    goto free_and_return;
  }

  /* Data packet */
  if (l2tp->phase != PPPOL2TP_STATE_DATA) {
    goto free_and_return;
  }
  if (tunnel_id != l2tp->remote_tunnel_id) {
    PPPDEBUG(LOG_DEBUG,
             ("pppol2tp: tunnel ID mismatch, assigned=%d, received=%d\n",
              l2tp->remote_tunnel_id, tunnel_id));
    goto free_and_return;
  }
  if (session_id != l2tp->remote_session_id) {
    PPPDEBUG(LOG_DEBUG,
             ("pppol2tp: session ID mismatch, assigned=%d, received=%d\n",
              l2tp->remote_session_id, session_id));
    goto free_and_return;
  }
  /*
   * skip address & flags if necessary
   *
   * RFC 2661 (L2TPv2) does not specify whether the PPP frame in the L2TP
   * payload should have a HDLC header or not, both behaviors are seen in the
   * wild.
   *
   * On the other hand, L2TPv3 draft-ietf-l2tpext-l2tp-ppp versions 00 and 01
   * say it must be included, versions 02 to 05 say it must be omitted, and
   * versions 06 and onwards say it should be omitted so it changed along the
   * path when L2TPv3 was designed.  Latest versions state that receivers must
   * handle both cases.
   *
   * We handle both cases for compatibility.
   */
  if (p->len >= 2) {
    GETSHORT(hflags, inp);
    if (hflags == 0xff03) {
      pbuf_remove_header(p, 2);
    }
  }
  /* Dispatch the packet thereby consuming it. */
  ppp_input(l2tp->ppp, p);
  return;

packet_too_short:
  PPPDEBUG(LOG_DEBUG, ("pppol2tp: packet too short: %d\n", p->len));
free_and_return:
  pbuf_free(p);
}

static void pppol2tp_dispatch_control_packet(pppol2tp_pcb *l2tp, u16_t port,
                                             struct pbuf *p, u16_t ns,
                                             u16_t nr) {
  u8_t *inp;
  u16_t avplen, avpflags, vendorid, attributetype, messagetype = 0;
  err_t err;
#if PPPOL2TP_AUTH_SUPPORT
  lwip_md5_context md5_ctx;
  u8_t md5_hash[16];
  u8_t challenge_id = 0;
#endif /* PPPOL2TP_AUTH_SUPPORT */

  /* printf("L2TP CTRL INPUT, ns=%d, nr=%d, len=%d\n", ns, nr, p->len); */

  /* Drop unexpected packet */
  if (ns != l2tp->peer_ns) {
    PPPDEBUG(
        LOG_DEBUG,
        ("pppol2tp: drop unexpected packet: received NS=%d, expected NS=%d\n",
         ns, l2tp->peer_ns));
    /*
     * In order to ensure that all messages are acknowledged properly
     * (particularly in the case of a lost ZLB ACK message), receipt
     * of duplicate messages MUST be acknowledged.
     *
     * In this very special case we Ack a packet we previously received.
     * Therefore our NS is the NR we just received. And our NR is the
     * NS we just received plus one.
     */
    if ((s16_t)(ns - l2tp->peer_ns) < 0) {
      pppol2tp_send_zlb(l2tp, nr, ns + 1);
    }
    return;
  }

  l2tp->peer_nr = nr;

  /* Handle the special case of the ICCN acknowledge */
  if (l2tp->phase == PPPOL2TP_STATE_ICCN_SENT &&
      (s16_t)(l2tp->peer_nr - l2tp->our_ns) > 0) {
    l2tp->phase = PPPOL2TP_STATE_DATA;
    sys_untimeout(pppol2tp_timeout, l2tp);
    ppp_start(l2tp->ppp); /* notify upper layers */
  }

  /* ZLB packets */
  if (p->tot_len == 0) {
    return;
  }
  /* A ZLB packet does not consume a NS slot thus we don't record the NS value
   * for ZLB packets */
  l2tp->peer_ns = ns + 1;

  p = pbuf_coalesce(p, PBUF_RAW);
  if (p->next != NULL) {
    PPPDEBUG(LOG_DEBUG, ("pppol2tp: pbuf_coalesce failed: %d\n", p->tot_len));
    return;
  }

  inp = (u8_t *)p->payload;
  /* Decode AVPs */
  while (p->len > 0) {
    if (p->len < sizeof(avpflags) + sizeof(vendorid) + sizeof(attributetype)) {
      goto packet_too_short;
    }
    GETSHORT(avpflags, inp);
    avplen = avpflags & PPPOL2TP_AVPHEADERFLAG_LENGTHMASK;
    /* printf("AVPLEN = %d\n", avplen); */
    if (p->len < avplen ||
        avplen < sizeof(avpflags) + sizeof(vendorid) + sizeof(attributetype)) {
      goto packet_too_short;
    }
    GETSHORT(vendorid, inp);
    GETSHORT(attributetype, inp);
    avplen -= sizeof(avpflags) + sizeof(vendorid) + sizeof(attributetype);

    /* Message type must be the first AVP */
    if (messagetype == 0) {
      if (attributetype != 0 || vendorid != 0 ||
          avplen != sizeof(messagetype)) {
        PPPDEBUG(LOG_DEBUG, ("pppol2tp: message type must be the first AVP\n"));
        return;
      }
      GETSHORT(messagetype, inp);
      /* printf("Message type = %d\n", messagetype); */
      switch (messagetype) {
      /* Start Control Connection Reply */
      case PPPOL2TP_MESSAGETYPE_SCCRP:
        /* Only accept SCCRP packet if we sent a SCCRQ */
        if (l2tp->phase != PPPOL2TP_STATE_SCCRQ_SENT) {
          goto send_zlb;
        }
        break;
      /* Incoming Call Reply */
      case PPPOL2TP_MESSAGETYPE_ICRP:
        /* Only accept ICRP packet if we sent a IRCQ */
        if (l2tp->phase != PPPOL2TP_STATE_ICRQ_SENT) {
          goto send_zlb;
        }
        break;
      /* Stop Control Connection Notification */
      case PPPOL2TP_MESSAGETYPE_STOPCCN:
        pppol2tp_send_zlb(
            l2tp, l2tp->our_ns + 1,
            l2tp->peer_ns); /* Ack the StopCCN before we switch to down state */
        if (l2tp->phase < PPPOL2TP_STATE_DATA) {
          pppol2tp_abort_connect(l2tp);
        } else if (l2tp->phase == PPPOL2TP_STATE_DATA) {
          /* Don't disconnect here, we let the LCP Echo/Reply find the fact
           * that PPP session is down. Asking the PPP stack to end the session
           * require strict checking about the PPP phase to prevent endless
           * disconnection loops.
           */
        }
        return;
      default:
        break;
      }
      goto nextavp;
    }

    /* Skip proprietary L2TP extensions */
    if (vendorid != 0) {
      goto skipavp;
    }

    switch (messagetype) {
    /* Start Control Connection Reply */
    case PPPOL2TP_MESSAGETYPE_SCCRP:
      switch (attributetype) {
      case PPPOL2TP_AVPTYPE_TUNNELID:
        if (avplen != sizeof(l2tp->source_tunnel_id)) {
          PPPDEBUG(LOG_DEBUG,
                   ("pppol2tp: AVP Assign tunnel ID length check failed\n"));
          return;
        }
        GETSHORT(l2tp->source_tunnel_id, inp);
        PPPDEBUG(LOG_DEBUG, ("pppol2tp: Assigned tunnel ID %" U16_F "\n",
                             l2tp->source_tunnel_id));
        goto nextavp;
#if PPPOL2TP_AUTH_SUPPORT
      case PPPOL2TP_AVPTYPE_CHALLENGE:
        if (avplen == 0) {
          PPPDEBUG(LOG_DEBUG, ("pppol2tp: Challenge length check failed\n"));
          return;
        }
        if (l2tp->secret == NULL) {
          PPPDEBUG(LOG_DEBUG, ("pppol2tp: Received challenge from peer and no "
                               "secret key available\n"));
          pppol2tp_abort_connect(l2tp);
          return;
        }
        /* Generate hash of ID, secret, challenge */
        lwip_md5_init(&md5_ctx);
        lwip_md5_starts(&md5_ctx);
        challenge_id = PPPOL2TP_MESSAGETYPE_SCCCN;
        lwip_md5_update(&md5_ctx, &challenge_id, 1);
        lwip_md5_update(&md5_ctx, l2tp->secret, l2tp->secret_len);
        lwip_md5_update(&md5_ctx, inp, avplen);
        lwip_md5_finish(&md5_ctx, l2tp->challenge_hash);
        lwip_md5_free(&md5_ctx);
        l2tp->send_challenge = 1;
        goto skipavp;
      case PPPOL2TP_AVPTYPE_CHALLENGERESPONSE:
        if (avplen != PPPOL2TP_AVPTYPE_CHALLENGERESPONSE_SIZE) {
          PPPDEBUG(LOG_DEBUG,
                   ("pppol2tp: AVP Challenge Response length check failed\n"));
          return;
        }
        /* Generate hash of ID, secret, challenge */
        lwip_md5_init(&md5_ctx);
        lwip_md5_starts(&md5_ctx);
        challenge_id = PPPOL2TP_MESSAGETYPE_SCCRP;
        lwip_md5_update(&md5_ctx, &challenge_id, 1);
        lwip_md5_update(&md5_ctx, l2tp->secret, l2tp->secret_len);
        lwip_md5_update(&md5_ctx, l2tp->secret_rv, sizeof(l2tp->secret_rv));
        lwip_md5_finish(&md5_ctx, md5_hash);
        lwip_md5_free(&md5_ctx);
        if (memcmp(inp, md5_hash, sizeof(md5_hash))) {
          PPPDEBUG(LOG_DEBUG, ("pppol2tp: Received challenge response from "
                               "peer and secret key do not match\n"));
          pppol2tp_abort_connect(l2tp);
          return;
        }
        goto skipavp;
#endif /* PPPOL2TP_AUTH_SUPPORT */
      default:
        break;
      }
      break;
    /* Incoming Call Reply */
    case PPPOL2TP_MESSAGETYPE_ICRP:
      switch (attributetype) {
      case PPPOL2TP_AVPTYPE_SESSIONID:
        if (avplen != sizeof(l2tp->source_session_id)) {
          PPPDEBUG(LOG_DEBUG,
                   ("pppol2tp: AVP Assign session ID length check failed\n"));
          return;
        }
        GETSHORT(l2tp->source_session_id, inp);
        PPPDEBUG(LOG_DEBUG, ("pppol2tp: Assigned session ID %" U16_F "\n",
                             l2tp->source_session_id));
        goto nextavp;
      default:
        break;
      }
      break;
    default:
      break;
    }

  skipavp:
    INCPTR(avplen, inp);
  nextavp:
    /* printf("AVP Found, vendor=%d, attribute=%d, len=%d\n", vendorid,
     * attributetype, avplen); */
    /* next AVP */
    if (pbuf_remove_header(p, avplen + sizeof(avpflags) + sizeof(vendorid) +
                                  sizeof(attributetype)) != 0) {
      return;
    }
  }

  switch (messagetype) {
  /* Start Control Connection Reply */
  case PPPOL2TP_MESSAGETYPE_SCCRP:
    do {
      l2tp->remote_session_id = magic();
    } while (l2tp->remote_session_id == 0);
    l2tp->tunnel_port =
        port; /* LNS server might have chosen its own local port */
    l2tp->icrq_retried = 0;
    l2tp->phase = PPPOL2TP_STATE_ICRQ_SENT;
    l2tp->our_ns++;
    if ((err = pppol2tp_send_scccn(l2tp, l2tp->our_ns)) != 0) {
      PPPDEBUG(LOG_DEBUG, ("pppol2tp: failed to send SCCCN, error=%d\n", err));
      LWIP_UNUSED_ARG(err); /* if PPPDEBUG is disabled */
    }
    l2tp->our_ns++;
    if ((err = pppol2tp_send_icrq(l2tp, l2tp->our_ns)) != 0) {
      PPPDEBUG(LOG_DEBUG, ("pppol2tp: failed to send ICRQ, error=%d\n", err));
      LWIP_UNUSED_ARG(err); /* if PPPDEBUG is disabled */
    }
    sys_untimeout(pppol2tp_timeout, l2tp);
    sys_timeout(PPPOL2TP_CONTROL_TIMEOUT, pppol2tp_timeout, l2tp);
    break;
  /* Incoming Call Reply */
  case PPPOL2TP_MESSAGETYPE_ICRP:
    l2tp->iccn_retried = 0;
    l2tp->phase = PPPOL2TP_STATE_ICCN_SENT;
    l2tp->our_ns++;
    if ((err = pppol2tp_send_iccn(l2tp, l2tp->our_ns)) != 0) {
      PPPDEBUG(LOG_DEBUG, ("pppol2tp: failed to send ICCN, error=%d\n", err));
      LWIP_UNUSED_ARG(err); /* if PPPDEBUG is disabled */
    }
    sys_untimeout(pppol2tp_timeout, l2tp);
    sys_timeout(PPPOL2TP_CONTROL_TIMEOUT, pppol2tp_timeout, l2tp);
    break;
  /* Unhandled packet, send ZLB ACK */
  default:
    goto send_zlb;
  }
  return;

send_zlb:
  pppol2tp_send_zlb(l2tp, l2tp->our_ns + 1, l2tp->peer_ns);
  return;
packet_too_short:
  PPPDEBUG(LOG_DEBUG, ("pppol2tp: packet too short: %d\n", p->len));
}

static void pppol2tp_timeout(void *arg) {
  pppol2tp_pcb *l2tp = (pppol2tp_pcb *)arg;
  err_t err;
  u32_t retry_wait;

  PPPDEBUG(LOG_DEBUG, ("pppol2tp: timeout\n"));

  switch (l2tp->phase) {
  case PPPOL2TP_STATE_SCCRQ_SENT:
    /* backoff wait */
    if (l2tp->sccrq_retried < 0xff) {
      l2tp->sccrq_retried++;
    }
    if (!l2tp->ppp->settings.persist &&
        l2tp->sccrq_retried >= PPPOL2TP_MAXSCCRQ) {
      pppol2tp_abort_connect(l2tp);
      return;
    }
    retry_wait = LWIP_MIN(PPPOL2TP_CONTROL_TIMEOUT * l2tp->sccrq_retried,
                          PPPOL2TP_SLOW_RETRY);
    PPPDEBUG(LOG_DEBUG, ("pppol2tp: sccrq_retried=%d\n", l2tp->sccrq_retried));
    if ((err = pppol2tp_send_sccrq(l2tp)) != 0) {
      PPPDEBUG(LOG_DEBUG, ("pppol2tp: failed to send SCCRQ, error=%d\n", err));
      LWIP_UNUSED_ARG(err); /* if PPPDEBUG is disabled */
    }
    sys_timeout(retry_wait, pppol2tp_timeout, l2tp);
    break;

  case PPPOL2TP_STATE_ICRQ_SENT:
    l2tp->icrq_retried++;
    if (l2tp->icrq_retried >= PPPOL2TP_MAXICRQ) {
      pppol2tp_abort_connect(l2tp);
      return;
    }
    PPPDEBUG(LOG_DEBUG, ("pppol2tp: icrq_retried=%d\n", l2tp->icrq_retried));
    if ((s16_t)(l2tp->peer_nr - l2tp->our_ns) <
        0) { /* the SCCCN was not acknowledged */
      if ((err = pppol2tp_send_scccn(l2tp, l2tp->our_ns - 1)) != 0) {
        PPPDEBUG(LOG_DEBUG,
                 ("pppol2tp: failed to send SCCCN, error=%d\n", err));
        LWIP_UNUSED_ARG(err); /* if PPPDEBUG is disabled */
        sys_timeout(PPPOL2TP_CONTROL_TIMEOUT, pppol2tp_timeout, l2tp);
        break;
      }
    }
    if ((err = pppol2tp_send_icrq(l2tp, l2tp->our_ns)) != 0) {
      PPPDEBUG(LOG_DEBUG, ("pppol2tp: failed to send ICRQ, error=%d\n", err));
      LWIP_UNUSED_ARG(err); /* if PPPDEBUG is disabled */
    }
    sys_timeout(PPPOL2TP_CONTROL_TIMEOUT, pppol2tp_timeout, l2tp);
    break;

  case PPPOL2TP_STATE_ICCN_SENT:
    l2tp->iccn_retried++;
    if (l2tp->iccn_retried >= PPPOL2TP_MAXICCN) {
      pppol2tp_abort_connect(l2tp);
      return;
    }
    PPPDEBUG(LOG_DEBUG, ("pppol2tp: iccn_retried=%d\n", l2tp->iccn_retried));
    if ((err = pppol2tp_send_iccn(l2tp, l2tp->our_ns)) != 0) {
      PPPDEBUG(LOG_DEBUG, ("pppol2tp: failed to send ICCN, error=%d\n", err));
      LWIP_UNUSED_ARG(err); /* if PPPDEBUG is disabled */
    }
    sys_timeout(PPPOL2TP_CONTROL_TIMEOUT, pppol2tp_timeout, l2tp);
    break;

  default:
    return; /* all done, work in peace */
  }
}

static void pppol2tp_abort_connect(pppol2tp_pcb *l2tp) {
  PPPDEBUG(LOG_DEBUG, ("pppol2tp: could not establish connection\n"));
  l2tp->phase = PPPOL2TP_STATE_INITIAL;
  ppp_link_failed(l2tp->ppp); /* notify upper layers */
}

static err_t pppol2tp_send_sccrq(pppol2tp_pcb *l2tp) {
  struct pbuf *pb;
  u8_t *p;
  u16_t len;

  /* calculate UDP packet length */
  len = 12 + 8 + 8 + 10 + 10 + 6 + sizeof(PPPOL2TP_HOSTNAME) - 1 + 6 +
        sizeof(PPPOL2TP_VENDORNAME) - 1 + 8 + 8;
#if PPPOL2TP_AUTH_SUPPORT
  if (l2tp->secret != NULL) {
    len += 6 + sizeof(l2tp->secret_rv);
  }
#endif /* PPPOL2TP_AUTH_SUPPORT */

  /* allocate a buffer */
  pb = pbuf_alloc(PBUF_TRANSPORT, len, PBUF_RAM);
  if (pb == NULL) {
    return ERR_MEM;
  }
  LWIP_ASSERT("pb->tot_len == pb->len", pb->tot_len == pb->len);

  p = (u8_t *)pb->payload;
  /* fill in pkt */
  /* L2TP control header */
  PUTSHORT(PPPOL2TP_HEADERFLAG_CONTROL_MANDATORY, p);
  PUTSHORT(len, p); /* Length */
  PUTSHORT(0, p);   /* Tunnel Id */
  PUTSHORT(0, p);   /* Session Id */
  PUTSHORT(0, p);   /* NS Sequence number - to peer */
  PUTSHORT(0, p);   /* NR Sequence number - expected for peer */

  /* AVP - Message type */
  PUTSHORT(PPPOL2TP_AVPHEADERFLAG_MANDATORY + 8,
           p);                           /* Mandatory flag + len field */
  PUTSHORT(0, p);                        /* Vendor ID */
  PUTSHORT(PPPOL2TP_AVPTYPE_MESSAGE, p); /* Attribute type: Message Type */
  PUTSHORT(PPPOL2TP_MESSAGETYPE_SCCRQ,
           p); /* Attribute value: Message type: SCCRQ */

  /* AVP - L2TP Version */
  PUTSHORT(PPPOL2TP_AVPHEADERFLAG_MANDATORY + 8,
           p);                           /* Mandatory flag + len field */
  PUTSHORT(0, p);                        /* Vendor ID */
  PUTSHORT(PPPOL2TP_AVPTYPE_VERSION, p); /* Attribute type: Version */
  PUTSHORT(PPPOL2TP_VERSION, p);         /* Attribute value: L2TP Version */

  /* AVP - Framing capabilities */
  PUTSHORT(PPPOL2TP_AVPHEADERFLAG_MANDATORY + 10,
           p);    /* Mandatory flag + len field */
  PUTSHORT(0, p); /* Vendor ID */
  PUTSHORT(PPPOL2TP_AVPTYPE_FRAMINGCAPABILITIES,
           p); /* Attribute type: Framing capabilities */
  PUTLONG(PPPOL2TP_FRAMINGCAPABILITIES,
          p); /* Attribute value: Framing capabilities */

  /* AVP - Bearer capabilities */
  PUTSHORT(PPPOL2TP_AVPHEADERFLAG_MANDATORY + 10,
           p);    /* Mandatory flag + len field */
  PUTSHORT(0, p); /* Vendor ID */
  PUTSHORT(PPPOL2TP_AVPTYPE_BEARERCAPABILITIES,
           p); /* Attribute type: Bearer capabilities */
  PUTLONG(PPPOL2TP_BEARERCAPABILITIES,
          p); /* Attribute value: Bearer capabilities */

  /* AVP - Host name */
  PUTSHORT(PPPOL2TP_AVPHEADERFLAG_MANDATORY + 6 + sizeof(PPPOL2TP_HOSTNAME) - 1,
           p);                            /* Mandatory flag + len field */
  PUTSHORT(0, p);                         /* Vendor ID */
  PUTSHORT(PPPOL2TP_AVPTYPE_HOSTNAME, p); /* Attribute type: Hostname */
  MEMCPY(p, PPPOL2TP_HOSTNAME,
         sizeof(PPPOL2TP_HOSTNAME) - 1); /* Attribute value: Hostname */
  INCPTR(sizeof(PPPOL2TP_HOSTNAME) - 1, p);

  /* AVP - Vendor name */
  PUTSHORT(6 + sizeof(PPPOL2TP_VENDORNAME) - 1, p); /* len field */
  PUTSHORT(0, p);                                   /* Vendor ID */
  PUTSHORT(PPPOL2TP_AVPTYPE_VENDORNAME, p); /* Attribute type: Vendor name */
  MEMCPY(p, PPPOL2TP_VENDORNAME,
         sizeof(PPPOL2TP_VENDORNAME) - 1); /* Attribute value: Vendor name */
  INCPTR(sizeof(PPPOL2TP_VENDORNAME) - 1, p);

  /* AVP - Assign tunnel ID */
  PUTSHORT(PPPOL2TP_AVPHEADERFLAG_MANDATORY + 8,
           p);                            /* Mandatory flag + len field */
  PUTSHORT(0, p);                         /* Vendor ID */
  PUTSHORT(PPPOL2TP_AVPTYPE_TUNNELID, p); /* Attribute type: Tunnel ID */
  PUTSHORT(l2tp->remote_tunnel_id, p);    /* Attribute value: Tunnel ID */

  /* AVP - Receive window size */
  PUTSHORT(PPPOL2TP_AVPHEADERFLAG_MANDATORY + 8,
           p);    /* Mandatory flag + len field */
  PUTSHORT(0, p); /* Vendor ID */
  PUTSHORT(PPPOL2TP_AVPTYPE_RECEIVEWINDOWSIZE,
           p); /* Attribute type: Receive window size */
  PUTSHORT(PPPOL2TP_RECEIVEWINDOWSIZE,
           p); /* Attribute value: Receive window size */

#if PPPOL2TP_AUTH_SUPPORT
  /* AVP - Challenge */
  if (l2tp->secret != NULL) {
    PUTSHORT(PPPOL2TP_AVPHEADERFLAG_MANDATORY + 6 + sizeof(l2tp->secret_rv),
             p);                             /* Mandatory flag + len field */
    PUTSHORT(0, p);                          /* Vendor ID */
    PUTSHORT(PPPOL2TP_AVPTYPE_CHALLENGE, p); /* Attribute type: Challenge */
    MEMCPY(p, l2tp->secret_rv,
           sizeof(l2tp->secret_rv)); /* Attribute value: Random vector */
    INCPTR(sizeof(l2tp->secret_rv), p);
  }
#endif /* PPPOL2TP_AUTH_SUPPORT */

  return pppol2tp_udp_send(l2tp, pb);
}

static err_t pppol2tp_send_scccn(pppol2tp_pcb *l2tp, u16_t ns) {
  struct pbuf *pb;
  u8_t *p;
  u16_t len;

  /* calculate UDP packet length */
  len = 12 + 8;
#if PPPOL2TP_AUTH_SUPPORT
  if (l2tp->send_challenge) {
    len += 6 + sizeof(l2tp->challenge_hash);
  }
#endif /* PPPOL2TP_AUTH_SUPPORT */

  /* allocate a buffer */
  pb = pbuf_alloc(PBUF_TRANSPORT, len, PBUF_RAM);
  if (pb == NULL) {
    return ERR_MEM;
  }
  LWIP_ASSERT("pb->tot_len == pb->len", pb->tot_len == pb->len);

  p = (u8_t *)pb->payload;
  /* fill in pkt */
  /* L2TP control header */
  PUTSHORT(PPPOL2TP_HEADERFLAG_CONTROL_MANDATORY, p);
  PUTSHORT(len, p);                    /* Length */
  PUTSHORT(l2tp->source_tunnel_id, p); /* Tunnel Id */
  PUTSHORT(0, p);                      /* Session Id */
  PUTSHORT(ns, p);                     /* NS Sequence number - to peer */
  PUTSHORT(l2tp->peer_ns, p); /* NR Sequence number - expected for peer */

  /* AVP - Message type */
  PUTSHORT(PPPOL2TP_AVPHEADERFLAG_MANDATORY + 8,
           p);                           /* Mandatory flag + len field */
  PUTSHORT(0, p);                        /* Vendor ID */
  PUTSHORT(PPPOL2TP_AVPTYPE_MESSAGE, p); /* Attribute type: Message Type */
  PUTSHORT(PPPOL2TP_MESSAGETYPE_SCCCN,
           p); /* Attribute value: Message type: SCCCN */

#if PPPOL2TP_AUTH_SUPPORT
  /* AVP - Challenge response */
  if (l2tp->send_challenge) {
    PUTSHORT(PPPOL2TP_AVPHEADERFLAG_MANDATORY + 6 +
                 sizeof(l2tp->challenge_hash),
             p);    /* Mandatory flag + len field */
    PUTSHORT(0, p); /* Vendor ID */
    PUTSHORT(PPPOL2TP_AVPTYPE_CHALLENGERESPONSE,
             p); /* Attribute type: Challenge response */
    MEMCPY(
        p, l2tp->challenge_hash,
        sizeof(l2tp->challenge_hash)); /* Attribute value: Computed challenge */
    INCPTR(sizeof(l2tp->challenge_hash), p);
  }
#endif /* PPPOL2TP_AUTH_SUPPORT */

  return pppol2tp_udp_send(l2tp, pb);
}

