int checkenvname(char *s) {
  if ((*s >= 'A' && *s <= 'Z') || (*s >= 'a' && *s <= 'z') || *s == '_')
    ;
  else
    return 0;
  char *tmp = s + 1;
  while ((*tmp >= 'A' && *tmp <= 'Z') || (*tmp >= 'a' && *tmp <= 'z') ||
         (*tmp >= '0' && *tmp <= '9') || *tmp == '_')
    tmp++;
  return (int)(tmp - s);
}

int export(char *argv[]) {
