void copyinstr3(char *s) {
  sbrk(8192);
  uint64 top = (uint64)sbrk(0);
  if ((top % PGSIZE) != 0) {
    sbrk(PGSIZE - (top % PGSIZE));
  }
  top = (uint64)sbrk(0);
