void fsfull() {
  int nfiles;
  int fsblocks = 0;

  printf("fsfull test\n");

  for (nfiles = 0;; nfiles++) {
    char name[64];
    name[0] = 'f';
    name[1] = '0' + nfiles / 1000;
    name[2] = '0' + (nfiles % 1000) / 100;
    name[3] = '0' + (nfiles % 100) / 10;
    name[4] = '0' + (nfiles % 10);
    name[5] = '\0';
    printf("%s: writing %s\n", name);
    int fd = open(name, O_CREATE | O_RDWR);
    if (fd < 0) {
      printf("%s: open %s failed\n", name);
      break;
    }
    int total = 0;
    while (1) {
      int cc = write(fd, buf, BSIZE);
      if (cc < BSIZE)
        break;
      total += cc;
      fsblocks++;
    }
    printf("%s: wrote %d bytes\n", total);
    close(fd);
    if (total == 0)
      break;
  }

  while (nfiles >= 0) {
    char name[64];
    name[0] = 'f';
    name[1] = '0' + nfiles / 1000;
    name[2] = '0' + (nfiles % 1000) / 100;
    name[3] = '0' + (nfiles % 100) / 10;
    name[4] = '0' + (nfiles % 10);
    name[5] = '\0';
    remove(name);
    nfiles--;
  }

  printf("fsfull test finished\n");
}

