    int pid = fork();
    if (pid < 0) {
      printf("fork failed\n");
      exit(1);
    } else if (pid == 0) {
      // allocate all of memory.
      while (1) {
        uint64 a = (uint64)sbrk(4096);
        if (a == 0xffffffffffffffffLL)
          break;
        *(char *)(a + 4096 - 1) = 1;
      }

      // free a few pages, in order to let exec() make some
      // progress.
      for (int i = 0; i < avail; i++)
        sbrk(-4096);

      close(1);
      char *args[] = {"echo", "x", 0};
      exec("echo", args);
      exit(0);
    } else {
      wait((int *)0);
    }
  }

  exit(0);
}

int countfree() {
  int fds[2];

  if (pipe(fds) < 0) {
    printf("pipe() failed in countfree()\n");
    exit(1);
  }

  int pid = fork();

  if (pid < 0) {
    printf("fork failed in countfree()\n");
    exit(1);
  }

  if (pid == 0) {
    close(fds[0]);

    while (1) {
      uint64 a = (uint64)sbrk(4096);
      if (a == 0xffffffffffffffff) {
        break;
      }

      // modify the memory to make sure it's really allocated.
      *(char *)(a + 4096 - 1) = 1;

      // report back one more page.
      if (write(fds[1], "x", 1) != 1) {
        printf("write() failed in countfree()\n");
        exit(1);
      }
    }

    exit(0);
  }

  close(fds[1]);

  int n = 0;
  while (1) {
    char c;
    int cc = read(fds[0], &c, 1);
    if (cc < 0) {
      printf("read() failed in countfree()\n");
      exit(1);
    }
    if (cc == 0)
      break;
    n += 1;
  }

  close(fds[0]);
  wait((int *)0);

  return n;
}

int run(void f(char *), char *s) {
  int pid;
  int xstatus;

  printf("test %s: ", s);
  if ((pid = fork()) < 0) {
    printf("runtest: fork error\n");
    exit(1);
  }
  if (pid == 0) {
    f(s);
    exit(0);
  } else {
    wait(&xstatus);
    if (xstatus != 0)
      printf("FAILED\n");
    else
      printf("OK\n");
    return xstatus == 0;
  }
}

int main(int argc, char *argv[]) {
  int continuous = 0;
  char *justone = 0;

  if (argc == 2 && strcmp(argv[1], "-c") == 0) {
    continuous = 1;
  } else if (argc == 2 && strcmp(argv[1], "-C") == 0) {
    continuous = 2;
  } else if (argc == 2 && argv[1][0] != '-') {
    justone = argv[1];
  } else if (argc > 1) {
    printf("Usage: usertests [-c] [testname]\n");
    exit(1);
  }

  struct test {
    void (*f)(char *);
    char *s;
  } tests[] = {
      {execout, "execout"},
      {copyin, "copyin"},
      {copyout, "copyout"},
      {copyinstr1, "copyinstr1"},
      {copyinstr2, "copyinstr2"},
      {copyinstr3, "copyinstr3"},
      {truncate1, "truncate1"},
      {truncate2, "truncate2"},
